// sam-vwo.js — samenvattingen (SAM_RICH) voor VWO, lazy geladen via ensureSamData() in data.js.
// Backtick-literals; injecteer hier nieuwe/aangepaste samenvattingen (niet meer in data.js).
Object.assign(SAM_RICH,{
'vwo_gr_B':`<div class="sam-intro"><strong>Literatuur &amp; Cultuur</strong> gaat over het lezen en duiden van Griekse literatuur in zijn <strong>context</strong>. Je leert de grote <strong>auteurs</strong> en <strong>genres</strong>, de <strong>metriek</strong> (dactylische hexameter bij Homerus), veelgebruikte <strong>stijlfiguren</strong>, en de <strong>Griekse cultuur</strong> waarin de teksten ontstonden.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Auteurs</td><td>Homerus, Sophocles, Euripides, Herodotus…</td></tr><tr><td>Genres</td><td>epos, tragedie, geschiedschrijving</td></tr><tr><td>Metriek</td><td>dactylische hexameter (epos)</td></tr><tr><td>Stijlfiguren</td><td>epitheton, vergelijking, chiasme</td></tr><tr><td>Cultuur</td><td>Griekse waarden, goden, polis</td></tr></tbody></table><div class="sam-head">Auteurs en genres</div><p>Het pensum wisselt per jaar, maar ken de grote namen en hun <strong>genre</strong>: <strong>Homerus</strong> (het epos — <em>Ilias</em>, <em>Odyssee</em>), de tragici <strong>Sophocles</strong> en <strong>Euripides</strong> (tragedie), <strong>Herodotus</strong> (geschiedschrijving). Weet welk genre bij welke tekst hoort en wat de kenmerken zijn.</p><div class="sam-head">Metriek en stijl</div><p>Het epos van Homerus is geschreven in de <strong>dactylische hexameter</strong> (zes versvoeten, dactylus — ⏑ ⏑ of spondee — —). Je <strong>scandeert</strong> door lange en korte lettergrepen te bepalen. Kenmerkend voor Homerus is het <strong>epitheton ornans</strong>: een vast bijvoeglijk sierwoord ("de snelvoetige Achilles").</p><div class="sam-tip"><strong>Duid een stijlfiguur met effect.</strong> Benoem niet alleen de figuur, maar leg uit wat hij <em>doet</em>: een uitgebreide <strong>vergelijking</strong> (bij Homerus) maakt een tafereel aanschouwelijk; een <strong>chiasme</strong> (ABBA) plaatst begrippen tegenover elkaar. Het effect aan de inhoud koppelen levert de punten op.</div><div class="sam-head">Griekse cultuur</div><p>Teksten begrijp je in hun <strong>context</strong>: de wereld van de <strong>polis</strong> (stadstaat), de <strong>goden</strong> en het orakel, en waarden als <strong>aretè</strong> (voortreffelijkheid) en <strong>hybris</strong> (overmoed die de goden straffen). In de tragedie draait het vaak om het <strong>noodlot</strong> en de val van een held.</p><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — genre koppelen</div><div class="sam-worked-q">Een toneeltekst toont de ondergang van een vorst die door overmoed de goden tart. Welk genre en welk cultureel begrip passen?</div><ol class="sam-worked-steps"><li>Toneel + ondergang van een held = tragedie.</li><li>Overmoed die de goden tart = hybris.</li><li>Auteurs: Sophocles/Euripides.</li></ol><div class="sam-worked-ans">✅ Het genre is de tragedie; het begrip is hybris (overmoed), die tot de val van de held leidt.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — stijlkenmerk</div><div class="sam-worked-q">Bij Homerus lees je herhaaldelijk "de snelvoetige Achilles". Welk stijlkenmerk is dit?</div><ol class="sam-worked-steps"><li>Een vast sierend bijvoeglijk naamwoord bij een naam.</li><li>Dat heet een epitheton ornans.</li><li>Het is typisch voor de epische stijl (en het metrum).</li></ol><div class="sam-worked-ans">✅ Een epitheton ornans: een vast sierwoord bij een personage, kenmerkend voor Homerus' epische stijl.</div></div>`,
'vwo_gr_A':`<div class="sam-intro"><strong>Taal &amp; Vertalen</strong> is de kern van Grieks: je vertaalt een originele Griekse tekst naar goed Nederlands. Je leert de <strong>naamvallen (casus)</strong>, de rijke <strong>werkwoordvormen</strong> (met o.a. de aoristus), de <strong>congruentie</strong>, en een vaste <strong>vertaalstrategie</strong>.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Naamvallen</td><td>nom, gen, dat, acc, voc</td></tr><tr><td>Werkwoord</td><td>tijd, wijs, aspect (o.a. aoristus)</td></tr><tr><td>Congruentie</td><td>lidwoord/bijv. nw. bij zelfst. nw.</td></tr><tr><td>Partikels</td><td>μέν … δέ, γάρ, οὖν</td></tr><tr><td>Vertaalstrategie</td><td>persoonsvorm en onderwerp eerst</td></tr></tbody></table><div class="sam-head">De naamvallen en het werkwoord</div><p>Grieks is een <strong>naamvalstaal</strong>: de <strong>uitgang</strong> bepaalt de functie. Er zijn vijf casus (nominativus = onderwerp, genitivus = bezit/"van", dativus = "aan/voor/met", accusativus = lijdend voorwerp, vocativus = aanspreken). Het <strong>werkwoord</strong> is rijk aan vormen; let vooral op het <strong>aspect</strong>: de <strong>aoristus</strong> geeft een afgeronde handeling weer.</p><div class="sam-head">Vertaalstrategie</div><p>Vertaal niet woord-voor-woord, maar <strong>ontleed</strong> de zin: zoek eerst de <strong>persoonsvorm</strong>, dan het <strong>onderwerp</strong> (nominativus, congruent met de pv), dan de rest, en giet het geheel in lopend Nederlands. Het <strong>lidwoord</strong> is een handig baken: het hoort bij een zelfstandig naamwoord en verraadt de naamval.</p><div class="sam-tip"><strong>Partikels sturen de zin.</strong> Kleine woordjes als <strong>μέν … δέ</strong> ("enerzijds … anderzijds") plaatsen twee delen tegenover elkaar; <strong>γάρ</strong> geeft een reden ("want"), <strong>οὖν</strong> een gevolg ("dus"). Herken je ze, dan doorzie je de structuur van de zin sneller.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — casus en functie</div><div class="sam-worked-q">Waaraan zie je in een Griekse zin welk woord het onderwerp is?</div><ol class="sam-worked-steps"><li>Het onderwerp staat in de nominativus.</li><li>Het congrueert met de persoonsvorm (getal).</li><li>Vaak herken je de naamval aan het lidwoord + uitgang.</li></ol><div class="sam-worked-ans">✅ Het woord in de nominativus dat congrueert met de persoonsvorm — herkenbaar aan lidwoord en uitgang.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — partikel</div><div class="sam-worked-q">Een zin bevat de constructie "μέν … δέ". Wat vertelt dat je over de structuur?</div><ol class="sam-worked-steps"><li>μέν en δέ horen bij elkaar.</li><li>Ze markeren twee tegenover elkaar staande delen.</li><li>Vertaal met "enerzijds … anderzijds" of een tegenstelling.</li></ol><div class="sam-worked-ans">✅ "μέν … δέ" zet twee zinsdelen tegenover elkaar (enerzijds … anderzijds) — een tegenstelling of vergelijking.</div></div>`,
'vwo_la_B':`<div class="sam-intro"><strong>Literatuur &amp; Cultuur</strong> gaat over het lezen en duiden van Latijnse literatuur in zijn <strong>context</strong>. Je leert de belangrijke <strong>auteurs</strong> en <strong>genres</strong>, de <strong>metriek</strong> (dactylische hexameter), veelgebruikte <strong>stijlfiguren</strong>, en de <strong>Romeinse cultuur</strong> waarin de teksten ontstonden.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Auteurs</td><td>Vergilius, Ovidius, Cicero, Catullus…</td></tr><tr><td>Genres</td><td>epos, lyriek, redevoering, brief</td></tr><tr><td>Metriek</td><td>dactylische hexameter</td></tr><tr><td>Stijlfiguren</td><td>alliteratie, chiasme, metafoor</td></tr><tr><td>Cultuur</td><td>Romeinse samenleving en waarden</td></tr></tbody></table><div class="sam-head">Auteurs en genres</div><p>Het pensum (de examenauteur) wisselt per jaar, maar je moet de grote namen en hun <strong>genre</strong> kennen: <strong>Vergilius</strong> (het epos <em>Aeneis</em>), <strong>Ovidius</strong> (mythologie, <em>Metamorphosen</em>), <strong>Cicero</strong> (redevoeringen), <strong>Catullus</strong> (lyriek). Weet welk genre hoort bij welke tekst.</p><div class="sam-head">Metriek: de dactylische hexameter</div><p>Epische poëzie (Vergilius, Ovidius) is geschreven in de <strong>dactylische hexameter</strong>: zes versvoeten per regel, elk een <strong>dactylus</strong> (— ⏑ ⏑) of een <strong>spondee</strong> (— —). Je <strong>scandeert</strong> door lange en korte lettergrepen te bepalen; dat geeft het ritme en soms extra betekenis.</p><div class="sam-tip"><strong>Stijlfiguren duiden.</strong> Benoem niet alleen een stijlfiguur, maar leg het <strong>effect</strong> uit: een <strong>alliteratie</strong> (herhaalde beginklank) versterkt of verklankt iets; een <strong>chiasme</strong> (ABBA-volgorde) plaatst begrippen tegenover elkaar. Het effect koppelen aan de inhoud levert de punten op.</div><div class="sam-head">Romeinse cultuur</div><p>Teksten begrijp je pas goed in hun <strong>culturele context</strong>: Romeinse waarden als <strong>pietas</strong> (plichtsbesef jegens goden, familie, staat) en <strong>virtus</strong> (moed), de rol van het <strong>lot</strong> (fatum), en de politieke wereld van Rome. Die kennis kleurt je interpretatie.</p><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — genre koppelen</div><div class="sam-worked-q">Een tekst verhaalt in verheven stijl de zwerftochten en oorlogen van een held, in hexameters. Welk genre en welke auteur passen?</div><ol class="sam-worked-steps"><li>Heldendaden in verheven stijl + hexameter = epos.</li><li>Het bekendste Latijnse epos is de Aeneis.</li><li>Auteur: Vergilius.</li></ol><div class="sam-worked-ans">✅ Het genre is het epos; de klassieke auteur is Vergilius (de Aeneis).</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — stijlfiguur duiden</div><div class="sam-worked-q">In een vers staat "magno cum murmure montis" (veel m-klanken). Welke stijlfiguur en welk effect?</div><ol class="sam-worked-steps"><li>Herhaalde beginklank (m) = alliteratie.</li><li>De m's verklanken een dof, dreigend geluid.</li><li>Vorm versterkt de inhoud (het gerommel van de berg).</li></ol><div class="sam-worked-ans">✅ Alliteratie (de m-klanken); het effect is klanknabootsend: het versterkt het dreigende gerommel dat beschreven wordt.</div></div>`,
'vwo_la_A':`<div class="sam-intro"><strong>Taal &amp; Vertalen</strong> is de kern van Latijn: je vertaalt een originele Latijnse tekst naar goed Nederlands. Je leert de <strong>naamvallen (casus)</strong> en hun functies, de <strong>werkwoordvormen</strong>, de <strong>congruentie</strong> tussen woorden, en een vaste <strong>vertaalstrategie</strong>.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Naamvallen</td><td>nom, gen, dat, acc, abl, voc</td></tr><tr><td>Congruentie</td><td>bijv. nw. past bij zelfst. nw.</td></tr><tr><td>Werkwoord</td><td>persoon, tijd, wijs, genus verbi</td></tr><tr><td>Zinsdelen</td><td>persoonsvorm en onderwerp eerst zoeken</td></tr><tr><td>Vertaalstrategie</td><td>systematisch ontleden</td></tr></tbody></table><div class="sam-head">De naamvallen</div><p>Latijn is een <strong>naamvalstaal</strong>: de <strong>uitgang</strong> van een woord verraadt zijn functie in de zin, niet de plaats. Ken de zes casus en hun kernfuncties:</p><table class="sam-table"><thead><tr><th>Casus</th><th>Kernfunctie</th></tr></thead><tbody><tr><td>Nominativus</td><td>onderwerp</td></tr><tr><td>Genitivus</td><td>bezit ("van")</td></tr><tr><td>Dativus</td><td>meewerkend voorwerp ("aan/voor")</td></tr><tr><td>Accusativus</td><td>lijdend voorwerp</td></tr><tr><td>Ablativus</td><td>bijwoordelijk (met/door/in)</td></tr></tbody></table><div class="sam-head">Vertaalstrategie</div><p>Vertaal niet woord-voor-woord van links naar rechts, maar <strong>ontleed</strong> eerst de zin. Een beproefde volgorde:</p><div class="sam-figure"><svg viewBox="0 0 300 78" role="img" aria-label="Vertaalstappen: zoek de persoonsvorm, dan het onderwerp, dan de rest, dan mooi Nederlands"><g font-size="6.5" font-weight="700" fill="var(--dk)" text-anchor="middle"><rect x="6" y="30" width="62" height="24" rx="5" fill="var(--or)" opacity=".2"/><text x="37" y="41">persoons-</text><text x="37" y="50">vorm</text><rect x="82" y="30" width="58" height="24" rx="5" fill="var(--mu)" opacity=".14"/><text x="111" y="45">onderwerp</text><rect x="154" y="30" width="58" height="24" rx="5" fill="var(--mu)" opacity=".14"/><text x="183" y="45">rest</text><rect x="226" y="30" width="66" height="24" rx="5" fill="var(--mu)" opacity=".14"/><text x="259" y="41">lopend</text><text x="259" y="50">Nederlands</text></g><g stroke="var(--or)" stroke-width="1.2"><line x1="68" y1="42" x2="80" y2="42" marker-end="url(#laAar)"/><line x1="140" y1="42" x2="152" y2="42" marker-end="url(#laAar)"/><line x1="212" y1="42" x2="224" y2="42" marker-end="url(#laAar)"/></g><defs><marker id="laAar" markerWidth="7" markerHeight="7" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L5,3 L0,6 Z" fill="var(--or)"/></marker></defs></svg><div class="sam-figcap"><strong>Vertaalstappen:</strong> zoek eerst de <strong>persoonsvorm</strong> (die geeft persoon en tijd), daarna het <strong>onderwerp</strong> (nominativus, congruent met de pv), dan de <strong>rest</strong> (voorwerpen, bijwoordelijke bepalingen), en giet het geheel ten slotte in <strong>lopend Nederlands</strong>.</div></div><div class="sam-tip"><strong>Congruentie</strong> is je beste hulpmiddel: een bijvoeglijk naamwoord komt overeen met zijn zelfstandig naamwoord in <strong>naamval, getal en geslacht</strong>. Zo weet je welke woorden bij elkaar horen, ook als ze uit elkaar staan in de zin.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — casus herkennen</div><div class="sam-worked-q">In "puella rosam videt" is "puella" nominativus en "rosam" accusativus. Vertaal en benoem de functies.</div><ol class="sam-worked-steps"><li>videt = persoonsvorm (hij/zij ziet).</li><li>puella (nom.) = onderwerp; rosam (acc.) = lijdend voorwerp.</li><li>"Het meisje ziet de roos."</li></ol><div class="sam-worked-ans">✅ "Het meisje ziet de roos": puella (onderwerp), rosam (lijdend voorwerp), videt (persoonsvorm).</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — vertaalstrategie</div><div class="sam-worked-q">Wat is bij een lange Latijnse zin de verstandige eerste stap?</div><ol class="sam-worked-steps"><li>Niet meteen woord-voor-woord vertalen.</li><li>Zoek eerst de persoonsvorm (het werkwoord).</li><li>Bepaal daarna het onderwerp dat erbij congrueert.</li></ol><div class="sam-worked-ans">✅ Eerst de persoonsvorm zoeken, dan het onderwerp — daarna bouw je de zin systematisch op.</div></div>`,
'vwo_fr_E':`<div class="sam-intro"><strong>Littérature</strong> gaat over het lezen en bespreken van Franstalige literatuur. Je leert de kernbegrippen — <strong>thème</strong>, <strong>point de vue</strong> (vertelperspectief), <strong>motif</strong> en <strong>figures de style</strong> — en het plaatsen van een werk in zijn <strong>tijd en stroming</strong>.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Begrip</th><th>Kern</th></tr></thead><tbody><tr><td>Thème</td><td>het centrale onderwerp/idee</td></tr><tr><td>Point de vue</td><td>door wiens ogen (je / il-elle)</td></tr><tr><td>Motif</td><td>terugkerend element dat het thema draagt</td></tr><tr><td>Figures de style</td><td>métaphore, comparaison, ironie</td></tr><tr><td>Mouvement</td><td>literaire periode/stroming</td></tr></tbody></table><div class="sam-head">Thème, perspectief en motief</div><p>Het <strong>thème</strong> is het abstracte centrale onderwerp (bv. l'amour, la liberté). Het <strong>point de vue</strong> bepaalt door wiens ogen je het verhaal beleeft: <strong>je</strong>-verteller (beperkt), of een verteller in de derde persoon (<strong>il/elle</strong>), soms alwetend. Een <strong>motif</strong> is een concreet terugkerend element dat het thema zichtbaar maakt.</p><div class="sam-head">Figures de style</div><table class="sam-table"><thead><tr><th>Figure de style</th><th>Wat is het?</th></tr></thead><tbody><tr><td>Comparaison</td><td>vergelijking met "comme"</td></tr><tr><td>Métaphore</td><td>beeld zónder "comme"</td></tr><tr><td>Personnification</td><td>iets levenloos krijgt menselijke trekken</td></tr><tr><td>Ironie</td><td>het tegenovergestelde bedoelen</td></tr></tbody></table><div class="sam-tip"><strong>Plaats een werk in zijn mouvement.</strong> Koppel kenmerken van de tekst aan de literaire periode (bv. gevoel en natuur → le Romantisme; objectieve maatschappijkritiek → le Réalisme). Zo onderbouw je je interpretatie historisch — precies wat een mondeling/examenvraag vaak vraagt.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — point de vue</div><div class="sam-worked-q">Een verhaal begint met: "Je ne savais pas ce qui m'attendait." Welk point de vue is dit?</div><ol class="sam-worked-steps"><li>De verteller is zelf personage ("Je").</li><li>Je weet alleen wat de verteller zelf ervaart.</li><li>Dat is de je-verteller (première personne).</li></ol><div class="sam-worked-ans">✅ Een je-verteller (eerste persoon): een begrensd, persoonlijk perspectief.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — figure de style</div><div class="sam-worked-q">"Le temps est un voleur." Comparaison of métaphore?</div><ol class="sam-worked-steps"><li>Tijd wordt gelijkgesteld aan een dief.</li><li>Er staat geen "comme".</li><li>Zonder "comme" → métaphore.</li></ol><div class="sam-worked-ans">✅ Een métaphore: tijd wordt rechtstreeks een dief genoemd, zonder vergelijkingswoord "comme".</div></div>`,
'vwo_fr_D':`<div class="sam-intro"><strong>Gespreksvaardigheid</strong> gaat over spreken in het Frans: een <strong>presentatie</strong> houden en aan een <strong>gesprek</strong> deelnemen. Je leert je verhaal <strong>opbouwen</strong>, nuttige <strong>expressions</strong> (vaste zinnen) om je mening te geven en beleefd te reageren, en <strong>fillers</strong> om tijd te winnen.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Structuur</td><td>introduction, développement, conclusion</td></tr><tr><td>Expressions</td><td>vaste zinnen voor mening/reactie</td></tr><tr><td>Fillers</td><td>bedenktijd zonder stilte</td></tr><tr><td>Politesse</td><td>beleefd blijven (vous)</td></tr></tbody></table><div class="sam-head">Presentatie en expressions</div><p>Structureer met een <strong>introduction</strong> (begroeting + onderwerp), een <strong>développement</strong> (je punten) en een <strong>conclusion</strong>. Leer <strong>expressions</strong> uit je hoofd — daarmee klink je vloeiend en beleefd:</p><table class="sam-table"><thead><tr><th>Functie</th><th>Expression</th></tr></thead><tbody><tr><td>Mening geven</td><td>"À mon avis…", "Je pense que…"</td></tr><tr><td>Instemmen</td><td>"C'est vrai", "Je suis d'accord"</td></tr><tr><td>Beleefd oneens</td><td>"Je ne suis pas d'accord, car…"</td></tr><tr><td>Ophelderen</td><td>"Pouvez-vous répéter, s'il vous plaît ?"</td></tr></tbody></table><div class="sam-tip"><strong>Fillers en niet begrepen:</strong> val niet stil maar win tijd met "Alors…", "Eh bien…". Begrijp je iets niet, vraag dan beleefd om herhaling ("Pardon ?" / "Pouvez-vous répéter ?") — dat toont taalvaardigheid en levert meer op dan een gok.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — mening geven</div><div class="sam-worked-q">Je wilt in een gesprek beleefd zeggen dat je het oneens bent. Welke expression gebruik je?</div><ol class="sam-worked-steps"><li>Je wilt beleefd een andere mening geven.</li><li>Gebruik een vaste zin met reden.</li><li>Bv. "Je ne suis pas d'accord, car…".</li></ol><div class="sam-worked-ans">✅ "Je ne suis pas d'accord, car…": je geeft beleefd je afwijkende mening met een reden.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — filler</div><div class="sam-worked-q">Je hebt een moment nodig om na te denken. Lange stilte of een filler?</div><ol class="sam-worked-steps"><li>Een stilte oogt onzeker.</li><li>Een filler houdt het gesprek gaande.</li><li>Bv. "Alors, c'est une bonne question…".</li></ol><div class="sam-worked-ans">✅ Een filler zoals "Alors…" of "Eh bien…" geeft bedenktijd zonder ongemakkelijke stilte.</div></div>`,
'vwo_fr_C':`<div class="sam-intro"><strong>Schrijfvaardigheid</strong> gaat over correcte Franse teksten schrijven, vooral de <strong>formele brief en e-mail</strong>. Je leert de vaste <strong>conventies</strong> (aanhef, afsluiting), het verschil tussen <strong>vous</strong> en <strong>tu</strong>, en het correct gebruiken van <strong>accents</strong>.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Vous vs. tu</td><td>formeel vs. informeel aanspreken</td></tr><tr><td>Brief-conventies</td><td>Madame, Monsieur / Cordialement</td></tr><tr><td>Accents</td><td>é, è, ê, à, ç veranderen betekenis</td></tr><tr><td>Werkwoordtijden</td><td>présent, passé composé, futur</td></tr></tbody></table><div class="sam-head">Vous of tu, en de conventies</div><p>Kies het juiste <strong>register</strong>: in een formele brief gebruik je <strong>vous</strong>, tegen bekenden/leeftijdgenoten <strong>tu</strong>. De vaste formele <strong>conventies</strong>: aanhef <em>Madame, Monsieur,</em> en een afsluiting als <em>Cordialement</em> of formeler <em>Je vous prie d'agréer mes salutations distinguées</em>.</p><div class="sam-head">Accents</div><p><strong>Accents</strong> zijn in het Frans geen versiering: ze veranderen uitspraak én <strong>betekenis</strong>. Verwar <em>ou</em> (of) niet met <em>où</em> (waar), of <em>a</em> (heeft) met <em>à</em> (naar/te). De <strong>cédille</strong> (ç) maakt de c zacht (<em>français</em>).</p><div class="sam-tip"><strong>Werkwoordtijden:</strong> gebruik de <strong>présent</strong> voor het heden, de <strong>passé composé</strong> voor een afgeronde handeling in het verleden (<em>j'ai mangé</em>), en de <strong>futur</strong> voor de toekomst (<em>je mangerai</em>). Let op de juiste vervoeging bij de persoon.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — register</div><div class="sam-worked-q">Je schrijft een klachtbrief aan een Frans bedrijf. Gebruik je vous of tu, en welke aanhef?</div><ol class="sam-worked-steps"><li>Een klachtbrief aan een bedrijf is formeel.</li><li>Formeel → vous.</li><li>Aanhef zonder bekende naam: "Madame, Monsieur,".</li></ol><div class="sam-worked-ans">✅ Vous, met de aanhef "Madame, Monsieur," en een formele afsluiting zoals "Cordialement".</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — accent</div><div class="sam-worked-q">Wat is het betekenisverschil tussen "ou" en "où"?</div><ol class="sam-worked-steps"><li>"ou" zonder accent = of.</li><li>"où" met accent grave = waar.</li><li>Het accent verandert de betekenis.</li></ol><div class="sam-worked-ans">✅ "ou" = of, "où" = waar. Het accent is betekenisdragend — laat het niet weg.</div></div>`,
'vwo_fr_B':`<div class="sam-intro"><strong>Luistervaardigheid</strong> traint het begrijpen van gesproken Frans: nieuws, interviews, fragmenten. Je leert <strong>luisterstrategieën</strong> (eerst de grote lijn), Franse <strong>signaalwoorden</strong> herkennen, de <strong>toon</strong> oppikken, en omgaan met tempo en liaisons.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Idée principale eerst</td><td>eerst de grote lijn, niet elk woord</td></tr><tr><td>Mots de liaison</td><td>mais, donc, par exemple</td></tr><tr><td>Toon</td><td>houding van de spreker</td></tr><tr><td>Contexte</td><td>gemiste woorden invullen</td></tr><tr><td>Chiffres &amp; noms</td><td>getallen en namen gericht opvangen</td></tr></tbody></table><div class="sam-head">Strategie: eerst de hoofdlijn</div><p>Luister de <strong>eerste keer</strong> naar de <strong>idée principale</strong>: waar gaat het over, wat is het standpunt? Probeer niet elk woord te verstaan — Frans kent veel <strong>liaisons</strong> (woorden lopen in elkaar over). De tweede keer let je op <strong>details</strong> die de vraag nodig heeft.</p><div class="sam-head">Signaalwoorden en toon</div><p>Gesproken Frans gebruikt dezelfde <strong>mots de liaison</strong> als geschreven Frans: <em>mais</em> (maar), <em>donc</em> (dus), <em>par exemple</em> (bijvoorbeeld), <em>en résumé</em> (samenvattend). De <strong>toon</strong> (intonatie, woordkeuze) verraadt of de spreker enthousiast, kritisch of ironisch is.</p><div class="sam-tip"><strong>Chiffres et noms</strong> (getallen en namen) zijn favoriete detailvragen. Train het gericht opvangen van jaartallen, prijzen en eigennamen; noteer ze kort tijdens het luisteren, want ze zijn zo weer kwijt.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — strategie</div><div class="sam-worked-q">Bij de eerste keer luisteren naar een snel Frans interview, waar richt je je op?</div><ol class="sam-worked-steps"><li>Eerste keer = oriëntatie op de hoofdlijn.</li><li>Onderwerp en boodschap, niet elk woord.</li><li>Details bewaar je voor de tweede keer.</li></ol><div class="sam-worked-ans">✅ Op de idée principale (de grote lijn): waar het over gaat — nog niet op de losse details.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — signaalwoord</div><div class="sam-worked-q">Een spreker zegt "en résumé…". Wat komt er nu?</div><ol class="sam-worked-steps"><li>"En résumé" = samenvattend.</li><li>Dat kondigt een samenvatting/conclusie aan.</li><li>Let op de kernboodschap.</li></ol><div class="sam-worked-ans">✅ Een samenvatting/conclusie: de spreker vat zijn punt samen — hier komt vaak een examenvraag over.</div></div>`,
'vwo_fr_A':`<div class="sam-intro"><strong>Leesvaardigheid</strong> is het centraal examen Frans: je leest Franse teksten en beantwoordt vragen. Je leert <strong>skimmen en scannen</strong>, betekenis <strong>afleiden</strong> uit de context, <strong>cognaten</strong> benutten, en Franse <strong>signaalwoorden</strong> (mots de liaison) herkennen.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Skimming &amp; scanning</td><td>globaal lezen vs. gericht zoeken</td></tr><tr><td>Cognaten</td><td>Frans-Nederlandse/Engelse gelijkenis</td></tr><tr><td>Mots de liaison</td><td>verbanden herkennen</td></tr><tr><td>Contexte</td><td>onbekende woorden raden</td></tr><tr><td>Question d'abord</td><td>eerst de vraag lezen</td></tr></tbody></table><div class="sam-head">Onbekende woorden aanpakken</div><p>Veel Franse woorden lijken op Engelse of Nederlandse: gebruik <strong>cognaten</strong> (<em>important</em> = belangrijk, <em>nécessaire</em> = noodzakelijk). Ken je een woord echt niet, raad het dan uit de <strong>context</strong>: de rest van de zin, een voorbeeld of een tegenstelling helpt je verder.</p><div class="sam-head">Mots de liaison (signaalwoorden)</div><p>Franse <strong>verbindingswoorden</strong> tonen hoe zinnen samenhangen — herken ze, want examenvragen draaien er vaak om:</p><table class="sam-table"><thead><tr><th>Verband</th><th>Mots de liaison</th></tr></thead><tbody><tr><td>Tegenstelling</td><td>mais, cependant, pourtant</td></tr><tr><td>Oorzaak/gevolg</td><td>parce que, donc, car, ainsi</td></tr><tr><td>Toevoeging</td><td>de plus, en outre, aussi</td></tr><tr><td>Conclusie</td><td>enfin, en somme, bref</td></tr></tbody></table><div class="sam-tip"><strong>Lees eerst de vraag (la question d'abord).</strong> Bepaal of je globaal moet lezen (voor de hoofdgedachte) of gericht een detail moet zoeken. Baseer je antwoord op wat er in de tekst <em>staat</em>, niet op je eigen kennis van het onderwerp.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — cognaat</div><div class="sam-worked-q">Je komt het woord "développement" tegen. Wat betekent het waarschijnlijk?</div><ol class="sam-worked-steps"><li>Het lijkt op het Engelse "development".</li><li>Cognaten helpen bij de betekenis.</li><li>Frans-Engels-Nederlands: ontwikkeling.</li></ol><div class="sam-worked-ans">✅ "développement" = ontwikkeling — af te leiden via de cognaat (Engels "development").</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — mot de liaison</div><div class="sam-worked-q">"L'idée est bonne, pourtant elle coûte trop cher." Welk verband geeft "pourtant" aan?</div><ol class="sam-worked-steps"><li>"Pourtant" = toch/echter.</li><li>Het zet iets tegenover de eerste zin.</li><li>Goed idee → toch een bezwaar (te duur).</li></ol><div class="sam-worked-ans">✅ Een tegenstelling: ondanks dat het idee goed is, volgt een bezwaar (te duur).</div></div>`,
'vwo_du_E':`<div class="sam-intro"><strong>Literatur</strong> gaat over het lezen en bespreken van Duitstalige literatuur. Je leert de kernbegrippen — <strong>Thema</strong>, <strong>Erzählperspektive</strong> (vertelperspectief), <strong>Motiv</strong> en <strong>Stilmittel</strong> — en het plaatsen van een werk in zijn <strong>tijd en stroming</strong>.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Begrip</th><th>Kern</th></tr></thead><tbody><tr><td>Thema</td><td>het centrale onderwerp/idee</td></tr><tr><td>Erzählperspektive</td><td>door wiens ogen (Ich-/Er-Erzähler)</td></tr><tr><td>Motiv</td><td>terugkerend element dat het thema draagt</td></tr><tr><td>Stilmittel</td><td>Metapher, Vergleich, Ironie</td></tr><tr><td>Epoche</td><td>literaire periode/stroming</td></tr></tbody></table><div class="sam-head">Thema, perspectief en motief</div><p>Het <strong>Thema</strong> is het abstracte centrale onderwerp (bv. Freiheit, Schuld). De <strong>Erzählperspektive</strong> bepaalt door wiens ogen je het verhaal beleeft: <strong>Ich-Erzähler</strong> (ik, beperkt), <strong>personaler Erzähler</strong> (via één personage) of <strong>auktorialer Erzähler</strong> (alwetend). Een <strong>Motiv</strong> is een concreet terugkerend element dat het thema zichtbaar maakt.</p><div class="sam-head">Stilmittel</div><table class="sam-table"><thead><tr><th>Stilmittel</th><th>Wat is het?</th></tr></thead><tbody><tr><td>Vergleich</td><td>vergelijking met "wie"</td></tr><tr><td>Metapher</td><td>beeld zónder "wie"</td></tr><tr><td>Personifikation</td><td>iets levenloos krijgt menselijke trekken</td></tr><tr><td>Ironie</td><td>het tegenovergestelde bedoelen</td></tr></tbody></table><div class="sam-tip"><strong>Plaats een werk in zijn Epoche.</strong> Koppel kenmerken van de tekst aan de literaire periode (bv. gevoel en natuur → Romantik; maatschappijkritiek en objectiviteit → Realismus). Zo onderbouw je je interpretatie historisch — precies wat een mondeling/examenvraag vaak vraagt.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — perspectief</div><div class="sam-worked-q">Een verhaal begint met: "Ich wusste nicht, was mich erwartete." Welke Erzählperspektive is dit?</div><ol class="sam-worked-steps"><li>De verteller is zelf personage ("Ich").</li><li>Je weet alleen wat de verteller zelf ervaart.</li><li>Dat is de Ich-Erzähler.</li></ol><div class="sam-worked-ans">✅ Ich-Erzähler: de verteller is een personage met een begrensd, eigen perspectief.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — Stilmittel</div><div class="sam-worked-q">"Die Zeit ist ein Dieb." Vergleich of Metapher?</div><ol class="sam-worked-steps"><li>Tijd wordt gelijkgesteld aan een dief.</li><li>Er staat geen "wie".</li><li>Zonder "wie" → Metapher.</li></ol><div class="sam-worked-ans">✅ Een Metapher: tijd wordt rechtstreeks een dief genoemd, zonder vergelijkingswoord "wie".</div></div>`,
'vwo_du_D':`<div class="sam-intro"><strong>Gespreksvaardigheid</strong> gaat over spreken in het Duits: een <strong>presentatie</strong> houden en aan een <strong>gesprek</strong> deelnemen. Je leert je verhaal <strong>opbouwen</strong>, nuttige <strong>Redemittel</strong> (vaste zinnen) om je mening te geven en beleefd te reageren, en <strong>fillers</strong> om tijd te winnen.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Structuur</td><td>Einleitung, Hauptteil, Schluss</td></tr><tr><td>Redemittel</td><td>vaste zinnen voor mening/reactie</td></tr><tr><td>Fillers</td><td>bedenktijd zonder stilte</td></tr><tr><td>Ophelderen</td><td>om herhaling vragen</td></tr></tbody></table><div class="sam-head">Presentatie en Redemittel</div><p>Structureer met <strong>Einleitung</strong> (begroeting + onderwerp), <strong>Hauptteil</strong> (je punten) en <strong>Schluss</strong> (samenvatten). Leer <strong>Redemittel</strong> uit je hoofd — daarmee klink je vloeiend en beleefd:</p><table class="sam-table"><thead><tr><th>Functie</th><th>Redemittel</th></tr></thead><tbody><tr><td>Mening geven</td><td>"Meiner Meinung nach…", "Ich finde, dass…"</td></tr><tr><td>Instemmen</td><td>"Das stimmt", "Da hast du recht"</td></tr><tr><td>Beleefd oneens</td><td>"Das sehe ich anders", "Einerseits…, andererseits…"</td></tr><tr><td>Ophelderen</td><td>"Können Sie das wiederholen?"</td></tr></tbody></table><div class="sam-tip"><strong>Fillers en niet begrepen:</strong> val niet stil maar win tijd met "Also…", "Moment mal…". Begrijp je iets niet, vraag dan om herhaling ("Wie bitte?" / "Können Sie das bitte wiederholen?") — dat toont taalvaardigheid en levert meer op dan een gok.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — mening geven</div><div class="sam-worked-q">Je wilt in een gesprek beleefd zeggen dat je het oneens bent. Welke Redemittel gebruik je?</div><ol class="sam-worked-steps"><li>Je wilt beleefd een andere mening geven.</li><li>Gebruik een vaste zin daarvoor.</li><li>Bv. "Das sehe ich anders, weil…".</li></ol><div class="sam-worked-ans">✅ "Das sehe ich anders, weil…": je geeft beleefd je afwijkende mening met een reden.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — filler</div><div class="sam-worked-q">Je hebt een moment nodig om na te denken. Lange stilte of een filler?</div><ol class="sam-worked-steps"><li>Een stilte oogt onzeker.</li><li>Een filler houdt het gesprek gaande.</li><li>Bv. "Also, das ist eine gute Frage…".</li></ol><div class="sam-worked-ans">✅ Een filler zoals "Also…" of "Moment mal…" geeft bedenktijd zonder ongemakkelijke stilte.</div></div>`,
'vwo_du_C':`<div class="sam-intro"><strong>Schrijfvaardigheid</strong> gaat over correcte Duitse teksten schrijven, vooral de <strong>formele brief en e-mail</strong>. Je leert de vaste <strong>conventies</strong> (aanhef, afsluiting), het verschil tussen <strong>Sie</strong> en <strong>du</strong>, en de basis van de Duitse <strong>naamvallen</strong> die je zinnen correct maken.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Sie vs. du</td><td>formeel vs. informeel aanspreken</td></tr><tr><td>Brief-conventies</td><td>Sehr geehrte… / Mit freundlichen Grüßen</td></tr><tr><td>Naamvallen</td><td>Nominativ, Akkusativ, Dativ, Genitiv</td></tr><tr><td>Woordvolgorde</td><td>werkwoord op plaats 2; bijzin achteraan</td></tr></tbody></table><div class="sam-head">Sie of du, en de briefconventies</div><p>Kies het juiste <strong>register</strong>: in een formele brief gebruik je <strong>Sie</strong> (met hoofdletter), tegen bekenden/leeftijdgenoten <strong>du</strong>. De vaste formele <strong>conventies</strong>: aanhef <em>Sehr geehrte Frau … / Sehr geehrter Herr …</em>, afsluiting <em>Mit freundlichen Grüßen</em>.</p><div class="sam-head">De naamvallen</div><p>Duits heeft vier <strong>naamvallen (Kasus)</strong> die de vorm van lidwoorden en bijvoeglijke naamwoorden bepalen. Herken de functie in de zin:</p><table class="sam-table"><thead><tr><th>Naamval</th><th>Functie</th><th>der (mnl.)</th></tr></thead><tbody><tr><td>Nominativ</td><td>onderwerp</td><td>der</td></tr><tr><td>Akkusativ</td><td>lijdend voorwerp</td><td>den</td></tr><tr><td>Dativ</td><td>meewerkend voorwerp</td><td>dem</td></tr><tr><td>Genitiv</td><td>bezit</td><td>des</td></tr></tbody></table><div class="sam-tip"><strong>Woordvolgorde:</strong> in een Duitse hoofdzin staat de <strong>persoonsvorm op de tweede plaats</strong> (<em>Heute gehe ich…</em>). In een <strong>bijzin</strong> (na weil, dass, obwohl) gaat het werkwoord juist <strong>naar het einde</strong> (<em>…, weil ich müde bin</em>).</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — register</div><div class="sam-worked-q">Je schrijft een sollicitatiebrief aan een Duits bedrijf. Gebruik je Sie of du, en welke afsluiting?</div><ol class="sam-worked-steps"><li>Sollicitatie = formeel.</li><li>Formeel → Sie (met hoofdletter).</li><li>Afsluiting: "Mit freundlichen Grüßen".</li></ol><div class="sam-worked-ans">✅ Sie, met de formele afsluiting "Mit freundlichen Grüßen" (en aanhef "Sehr geehrte Damen und Herren," als je geen naam kent).</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — woordvolgorde</div><div class="sam-worked-q">Zet in de juiste volgorde: "…, weil / bin / ich / krank."</div><ol class="sam-worked-steps"><li>Na "weil" volgt een bijzin.</li><li>In een bijzin gaat het werkwoord naar het einde.</li><li>…, weil ich krank bin.</li></ol><div class="sam-worked-ans">✅ "…, weil ich krank bin": in de bijzin staat de persoonsvorm (bin) achteraan.</div></div>`,
'vwo_du_B':`<div class="sam-intro"><strong>Luistervaardigheid</strong> traint het begrijpen van gesproken Duits: nieuws, interviews, fragmenten. Je leert <strong>luisterstrategieën</strong> (eerst de grote lijn), Duitse <strong>signaalwoorden</strong> herkennen, de <strong>toon</strong> oppikken, en omgaan met tempo en uitspraak.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Hauptidee eerst</td><td>eerst de grote lijn, niet elk woord</td></tr><tr><td>Signaalwoorden</td><td>aber, deshalb, zum Beispiel</td></tr><tr><td>Toon</td><td>houding van de spreker</td></tr><tr><td>Kontext</td><td>gemiste woorden invullen</td></tr><tr><td>Getallen &amp; namen</td><td>gericht opvangen</td></tr></tbody></table><div class="sam-head">Strategie: eerst de hoofdlijn</div><p>Luister de <strong>eerste keer</strong> naar de <strong>Hauptidee</strong>: waar gaat het over, wat is het standpunt? Probeer niet elk woord te verstaan. De tweede keer let je op <strong>details</strong> (getallen, namen, redenen) die de vraag nodig heeft.</p><div class="sam-head">Signaalwoorden en toon</div><p>Gesproken Duits gebruikt dezelfde <strong>signaalwoorden</strong> als geschreven Duits: <em>aber</em> (maar), <em>deshalb</em> (daarom), <em>zum Beispiel</em> (bijvoorbeeld), <em>zusammenfassend</em> (samenvattend). De <strong>toon</strong> (intonatie, woordkeuze) verraadt of een spreker enthousiast, kritisch of ironisch is.</p><div class="sam-tip"><strong>Getallen en namen</strong> zijn favoriete detailvragen. Train het gericht opvangen van jaartallen, prijzen en eigennamen — schrijf ze desnoods kort op tijdens het luisteren, want ze zijn makkelijk weer kwijt.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — strategie</div><div class="sam-worked-q">Bij de eerste keer luisteren naar een moeilijk Duits nieuwsitem, waar richt je je op?</div><ol class="sam-worked-steps"><li>Eerste keer = oriëntatie op de hoofdlijn.</li><li>Onderwerp en boodschap, niet elk woord.</li><li>Details bewaar je voor de tweede keer.</li></ol><div class="sam-worked-ans">✅ Op de Hauptidee (de grote lijn): waar het over gaat — nog niet op de losse details.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — signaalwoord</div><div class="sam-worked-q">Een spreker zegt "zusammenfassend lässt sich sagen…". Wat komt er nu?</div><ol class="sam-worked-steps"><li>"Zusammenfassend" = samenvattend.</li><li>Dat kondigt een samenvatting/conclusie aan.</li><li>Let dus op de kernboodschap.</li></ol><div class="sam-worked-ans">✅ Een samenvatting/conclusie: de spreker vat zijn punt samen — hier komt vaak een examenvraag over.</div></div>`,
'vwo_du_A':`<div class="sam-intro"><strong>Leesvaardigheid</strong> is het centraal examen Duits: je leest Duitse teksten en beantwoordt vragen. Je leert <strong>skimmen en scannen</strong>, betekenis <strong>afleiden</strong> uit de context, <strong>samengestelde woorden</strong> en <strong>cognaten</strong> gebruiken, en Duitse <strong>signaalwoorden</strong> herkennen.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Skimming &amp; scanning</td><td>globaal lezen vs. gericht zoeken</td></tr><tr><td>Cognaten</td><td>Duits-Nederlandse gelijkenis benutten</td></tr><tr><td>Samenstellingen</td><td>lange woorden ontleden</td></tr><tr><td>Signalwörter</td><td>verbanden herkennen</td></tr><tr><td>Kontext</td><td>onbekende woorden raden</td></tr></tbody></table><div class="sam-head">Onbekende woorden aanpakken</div><p>Duits lijkt vaak op Nederlands: gebruik <strong>cognaten</strong> (<em>Wasser</em> = water, <em>Freund</em> = vriend). Lange Duitse <strong>samengestelde woorden</strong> knip je op in delen: <em>Geschwindigkeitsbegrenzung</em> = Geschwindigkeit + Begrenzung (snelheids­begrenzing). En raad betekenis uit de <strong>context</strong> als een woord echt onbekend is.</p><div class="sam-head">Signalwörter</div><p>Duitse <strong>signaalwoorden</strong> tonen het verband tussen zinnen — herken ze, want examenvragen draaien er vaak om:</p><table class="sam-table"><thead><tr><th>Verband</th><th>Signalwörter</th></tr></thead><tbody><tr><td>Tegenstelling</td><td>aber, jedoch, dennoch, trotzdem</td></tr><tr><td>Oorzaak/gevolg</td><td>weil, deshalb, daher, denn</td></tr><tr><td>Toevoeging</td><td>außerdem, zudem, auch</td></tr><tr><td>Toegeving</td><td>obwohl, zwar … aber</td></tr></tbody></table><div class="sam-tip"><strong>Lees de vraag eerst.</strong> Bepaal of je globaal moet lezen (skimming, voor de hoofdgedachte) of gericht een detail moet zoeken (scanning). Baseer je antwoord op wat er in de tekst <em>staat</em>, niet op je eigen kennis van het onderwerp.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — samenstelling ontleden</div><div class="sam-worked-q">Wat betekent het woord "Umweltverschmutzung"? Ontleed het.</div><ol class="sam-worked-steps"><li>Umwelt = milieu; Verschmutzung = vervuiling.</li><li>Samengesteld: Umwelt + Verschmutzung.</li><li>Samen: milieuvervuiling.</li></ol><div class="sam-worked-ans">✅ "Umweltverschmutzung" = milieuvervuiling — je leidt het af door het woord in delen te knippen.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — Signalwort</div><div class="sam-worked-q">"Das Konzept klingt gut. Trotzdem ist es zu teuer." Welk verband geeft "trotzdem" aan?</div><ol class="sam-worked-steps"><li>"Trotzdem" = toch/desondanks.</li><li>Het zet iets tegenover de eerste zin.</li><li>Goed idee → toch een bezwaar (te duur).</li></ol><div class="sam-worked-ans">✅ Een tegenstelling: ondanks dat het concept goed klinkt, volgt een bezwaar (te duur).</div></div>`,
'vwo_en_E':`<div class="sam-intro"><strong>Literature</strong> gaat over het lezen en analyseren van Engelstalige literatuur. Je leert de kernbegrippen — <strong>theme</strong>, <strong>character</strong>-typen, <strong>narrative perspective</strong>, <strong>conflict</strong> — de belangrijkste <strong>literary devices</strong>, en het plaatsen van werken in hun <strong>literaire periode</strong>.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Theme</td><td>de centrale boodschap/idee</td></tr><tr><td>Character</td><td>round/flat, dynamic/static</td></tr><tr><td>Narrative perspective</td><td>door wiens ogen (first/third person)</td></tr><tr><td>Conflict</td><td>de strijd die het verhaal drijft</td></tr><tr><td>Literary devices</td><td>metaphor, simile, foreshadowing, irony</td></tr></tbody></table><div class="sam-head">Theme, character en perspective</div><p>The <strong>theme</strong> is the central <strong>idea</strong> of a work (love, power, identity) — not the plot, but what it <em>says</em> about life. Personages verschillen in diepte (<strong>round</strong> vs. <strong>flat</strong>) en ontwikkeling (<strong>dynamic</strong> vs. <strong>static</strong>). Het <strong>narrative perspective</strong> bepaalt door wiens ogen — en met hoeveel kennis — je het verhaal beleeft.</p><div class="sam-head">Conflict en literary devices</div><p><strong>Conflict</strong> is de strijd die het verhaal drijft: <em>extern</em> (personage vs. ander, maatschappij of natuur) of <em>intern</em> (een worsteling binnenin). Schrijvers gebruiken <strong>literary devices</strong> voor effect:</p><table class="sam-table"><thead><tr><th>Device</th><th>Wat is het?</th><th>Voorbeeld</th></tr></thead><tbody><tr><td>Simile</td><td>vergelijking met "like"/"as"</td><td>as brave as a lion</td></tr><tr><td>Metaphor</td><td>beeld zónder "like"/"as"</td><td>time is a thief</td></tr><tr><td>Foreshadowing</td><td>hint naar wat komt</td><td>gathering dark clouds</td></tr><tr><td>Irony</td><td>het tegenovergestelde bedoelen</td><td>"great," she sighed</td></tr></tbody></table><div class="sam-tip"><strong>Simile vs. metaphor:</strong> een <strong>simile</strong> vergelijkt mét "like"/"as" ("as cold as ice"); een <strong>metaphor</strong> stelt iets rechtstreeks gelijk zónder die woorden ("her voice is music"). Dat kleine woordje maakt het verschil.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — character</div><div class="sam-worked-q">A ruthless character learns compassion and completely changes by the end. Which term applies?</div><ol class="sam-worked-steps"><li>The character changes significantly → over ontwikkeling.</li><li>Verandert = dynamic (niet static).</li></ol><div class="sam-worked-ans">✅ A dynamic character: one who changes significantly during the story.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — device</div><div class="sam-worked-q">"Her words cut deeper than any knife." Simile or metaphor?</div><ol class="sam-worked-steps"><li>Er is een vergelijking ("than any knife"), maar zonder "like/as".</li><li>Het beeld stelt woorden gelijk aan een snijdend mes.</li><li>Zonder "like/as" → metaphor.</li></ol><div class="sam-worked-ans">✅ A metaphor: the words are directly likened to a cutting knife, without "like" or "as".</div></div>`,
'vwo_en_D':`<div class="sam-intro"><strong>Schrijfvaardigheid</strong> (writing, B2) gaat over correcte, samenhangende Engelse teksten, vooral de <strong>formele brief en e-mail</strong>. Je leert de vaste <strong>conventies</strong> (aanhef, beleefde verzoeken, afsluiting), een sterke <strong>paragraph</strong> bouwen, en met <strong>linking words</strong> een lopende tekst maken.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Formal register</td><td>beleefd, geen samentrekkingen</td></tr><tr><td>Salutation &amp; closing</td><td>Dear Sir/Madam … Yours faithfully</td></tr><tr><td>Polite requests</td><td>"I would be grateful if…"</td></tr><tr><td>Paragraph (PIE)</td><td>Point, Illustration, Explanation</td></tr><tr><td>Linking words</td><td>verbinden en structureren</td></tr></tbody></table><div class="sam-head">De formele brief en e-mail</div><p>Bij een formele tekst horen vaste <strong>conventies</strong>; aanhef en afsluiting horen bij elkaar en hangen af van of je de naam kent:</p><table class="sam-table"><thead><tr><th>Situatie</th><th>Aanhef</th><th>Afsluiting</th></tr></thead><tbody><tr><td>Naam onbekend</td><td>Dear Sir or Madam,</td><td>Yours faithfully,</td></tr><tr><td>Naam bekend</td><td>Dear Mr Jones,</td><td>Yours sincerely,</td></tr></tbody></table><div class="sam-head">De paragraph: topic sentence en PIE</div><p>Een <strong>paragraph</strong> behandelt één idee en opent met een <strong>topic sentence</strong>. Een sterke opbouw is <strong>PIE</strong>: <strong>Point</strong> (het hoofdidee), <strong>Illustration</strong> (voorbeeld/bewijs), <strong>Explanation</strong> (waarom dat je punt steunt).</p><div class="sam-tip"><strong>Formeel register:</strong> vermijd samentrekkingen (schrijf "do not", niet "don't") en spreektaal; vraag beleefd ("I would be grateful if you could…"). Vermijd <strong>hakkelzinnen</strong>: verbind korte zinnen met linking words tot een lopend geheel.</div><div class="sam-head">Linking words</div><table class="sam-table"><thead><tr><th>Verband</th><th>Linking words</th></tr></thead><tbody><tr><td>Contrast</td><td>however, although, whereas</td></tr><tr><td>Addition</td><td>moreover, furthermore, in addition</td></tr><tr><td>Cause/effect</td><td>therefore, as a result, consequently</td></tr><tr><td>Conclusion</td><td>in conclusion, to sum up</td></tr></tbody></table><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — salutation</div><div class="sam-worked-q">You write a formal application but don't know the recipient's name. Which salutation and closing?</div><ol class="sam-worked-steps"><li>Naam onbekend → "Dear Sir or Madam,".</li><li>Die hoort bij "Yours faithfully,".</li><li>"Yours sincerely" hoort bij een bekende naam.</li></ol><div class="sam-worked-ans">✅ "Dear Sir or Madam," … "Yours faithfully,".</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — writing problem</div><div class="sam-worked-q">A student writes: "The plan is good. It is cheap. It helps people." What is the main problem, and how do you fix it?</div><ol class="sam-worked-steps"><li>Drie korte, losse zinnen (choppy).</li><li>Geen verband of variatie.</li><li>Combineer met linking words.</li></ol><div class="sam-worked-ans">✅ Choppy sentences: combineer tot "The plan is not only cheap but also beneficial, as it helps people." — vloeiender en volwassener.</div></div>`,
'vwo_en_C':`<div class="sam-intro"><strong>Gespreksvaardigheid</strong> (speaking, B2) gaat over spreken in het Engels: een <strong>presentatie</strong> houden en aan een <strong>discussie</strong> deelnemen. Je leert je verhaal <strong>opbouwen</strong>, nuttige <strong>vaste zinnen</strong> (mening geven, beleefd oneens zijn), <strong>fillers</strong> om tijd te winnen, en om verduidelijking vragen.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Structuur</td><td>introduction, body, conclusion</td></tr><tr><td>Useful phrases</td><td>opinion, agreeing, disagreeing</td></tr><tr><td>Fillers</td><td>bedenktijd zonder stilte</td></tr><tr><td>B2-niveau</td><td>vloeiend over uiteenlopende onderwerpen</td></tr><tr><td>Ophelderen</td><td>om herhaling/uitleg vragen</td></tr></tbody></table><div class="sam-head">Presentatie en vaste zinnen</div><p>Structureer met een <strong>introduction</strong> (begroeting + onderwerp + opbouw), een <strong>body</strong> (punten met voorbeelden) en een <strong>conclusion</strong>. Leer <strong>useful phrases</strong> uit je hoofd zodat je vloeiend en beleefd klinkt:</p><table class="sam-table"><thead><tr><th>Functie</th><th>Phrase</th></tr></thead><tbody><tr><td>Mening geven</td><td>"In my view…", "I'd argue that…"</td></tr><tr><td>Instemmen</td><td>"That's a fair point", "I agree"</td></tr><tr><td>Beleefd oneens</td><td>"I see your point, but…", "I'm not convinced"</td></tr><tr><td>Ophelderen</td><td>"Could you clarify what you mean?"</td></tr></tbody></table><div class="sam-tip"><strong>Fillers en niet begrepen:</strong> val niet stil maar win tijd met "Well…", "Let me think…". Begrijp je een vraag niet, vraag dan beleefd om verduidelijking ("Sorry, could you rephrase that?") — dat toont juist taalvaardigheid en levert meer op dan een misser.</div><div class="sam-head">B2-niveau</div><p>Het VWO mikt op <strong>B2</strong>: je kunt vrij vloeiend over <strong>uiteenlopende onderwerpen</strong> praten, een standpunt beargumenteren en een discussie voeren. Kleine fouten mogen, mits je <strong>begrijpelijk</strong> en <strong>samenhangend</strong> blijft.</p><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — polite disagreement</div><div class="sam-worked-q">In a debate someone claims social media should be banned for under-16s. You disagree but want to stay polite. What do you say?</div><ol class="sam-worked-steps"><li>Erken eerst het punt van de ander.</li><li>Geef dan je eigen mening met een reden.</li><li>Gebruik "I see your point, but…".</li></ol><div class="sam-worked-ans">✅ "I see your point, but a complete ban is hard to enforce and ignores the benefits — better digital education might work." Beleefd én onderbouwd.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — filler</div><div class="sam-worked-q">You need a moment to think about a difficult question. Long silence or a filler?</div><ol class="sam-worked-steps"><li>Een lange stilte oogt onzeker.</li><li>Een filler houdt het gesprek gaande.</li><li>Bv. "That's a good question, let me think…".</li></ol><div class="sam-worked-ans">✅ Een filler: het geeft je bedenktijd zonder ongemakkelijke stilte en klinkt vloeiender.</div></div>`,
'vwo_en_B':`<div class="sam-intro"><strong>Kijk- en luistervaardigheid</strong> (listening, B2) traint het begrijpen van gesproken Engels: nieuws, interviews, documentaires. Je leert <strong>luisterstrategieën</strong> (eerst de grote lijn), <strong>signal phrases</strong> herkennen, <strong>tone</strong> en <strong>implicit meaning</strong> oppikken, en omgaan met tempo en accenten.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Gist first</td><td>eerst de grote lijn, niet elk woord</td></tr><tr><td>Signal phrases</td><td>markeren structuur (contrast, samenvatting)</td></tr><tr><td>Tone</td><td>houding: serious, ironic, critical…</td></tr><tr><td>Implicit meaning</td><td>wat bedoeld wordt zonder het te zeggen</td></tr><tr><td>Fast speech</td><td>focus op content words</td></tr></tbody></table><div class="sam-head">Strategie: eerst de gist</div><p>Luister de <strong>eerste keer</strong> naar de <strong>hoofdlijn</strong>: waar gaat het over, wat is het standpunt? Probeer niet elk woord te verstaan. Let de tweede keer op de <strong>details</strong> die de vraag nodig heeft (namen, cijfers, redenen).</p><div class="sam-head">Signal phrases en tone</div><p><strong>Signal phrases</strong> kondigen structuur aan: "to sum up" (samenvatting), "on the other hand" (contrast), "for instance" (voorbeeld). De <strong>tone</strong> hoor je aan woordkeuze en intonatie; bij <strong>implicit meaning</strong> zegt de spreker iets niet letterlijk — je leidt de bedoeling af.</p><div class="sam-tip"><strong>Irony herkennen:</strong> zegt een spreker "brilliant plan — if you like waiting five years", dan botsen de positieve woorden met de negatieve inhoud. De tone is dan <strong>ironic/critical</strong>: hij bedoelt het tegenovergestelde.</div><div class="sam-head">Snel spreektempo</div><p>Bij <strong>fast speech</strong> of een onbekend accent: raak niet in paniek om één gemist woord. Focus op de <strong>content words</strong> (zelfstandige naamwoorden, werkwoorden) die de betekenis dragen, en vul de rest in met de context.</p><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — tone</div><div class="sam-worked-q">A critic says about a policy: "Oh, wonderful — another rule nobody asked for." What is the tone?</div><ol class="sam-worked-steps"><li>"Wonderful" botst met "nobody asked for".</li><li>De positieve woorden zijn niet gemeend.</li><li>De tone is ironic/critical.</li></ol><div class="sam-worked-ans">✅ Ironic/critical: de spreker bedoelt het tegenovergestelde van "wonderful" (implicit meaning).</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — strategie</div><div class="sam-worked-q">During the first listening of a fast interview, what should you focus on?</div><ol class="sam-worked-steps"><li>Eerste keer = oriëntatie op de hoofdlijn.</li><li>Onderwerp en standpunt, niet elk woord.</li><li>Details bewaar je voor de tweede keer.</li></ol><div class="sam-worked-ans">✅ Op de gist: waar het over gaat en wat de boodschap is — details komen later.</div></div>`,
'vwo_en_A':`<div class="sam-intro"><strong>Leesvaardigheid</strong> (reading, niveau B2) is het centraal examen Engels: je leest complexe Engelse teksten en beantwoordt vragen. Je leert <strong>skimmen en scannen</strong>, betekenis <strong>afleiden</strong> (inference), onbekende woorden aanpakken, <strong>signal words</strong> en <strong>reference words</strong> herkennen, en <strong>tone</strong> van <strong>purpose</strong> onderscheiden.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Skimming &amp; scanning</td><td>globaal lezen vs. gericht zoeken</td></tr><tr><td>Inference</td><td>afleiden wat niet letterlijk staat</td></tr><tr><td>Unknown words</td><td>betekenis raden uit de context</td></tr><tr><td>Signal words</td><td>linking words wijzen het verband</td></tr><tr><td>Reference words</td><td>waar verwijst "it/this/they" naar?</td></tr><tr><td>Tone &amp; purpose</td><td>houding vs. doel van de schrijver</td></tr></tbody></table><div class="sam-head">Inference en onbekende woorden</div><p>Op B2-niveau ken je niet elk woord — en dat hoeft ook niet. Met <strong>inference</strong> leid je betekenis af uit de <strong>context</strong>: de rest van de zin, een voorbeeld, een tegenstelling. Kijk bij een onbekend woord naar (1) de bouw (prefix/suffix), (2) de toon van de zin (positief/negatief) en (3) of er uitleg volgt.</p><div class="sam-head">Signal words en reference words</div><p><strong>Signal words</strong> tonen hoe zinnen samenhangen; <strong>reference words</strong> (it, this, they) verwijzen terug naar iets eerder genoemd.</p><table class="sam-table"><thead><tr><th>Verband</th><th>Signal words</th></tr></thead><tbody><tr><td>Contrast</td><td>however, although, whereas, yet</td></tr><tr><td>Cause/effect</td><td>therefore, thus, as a result, since</td></tr><tr><td>Addition</td><td>moreover, furthermore, in addition</td></tr><tr><td>Concession</td><td>admittedly, even though, nonetheless</td></tr></tbody></table><div class="sam-head">Tone en purpose</div><p>Verwar deze niet. <strong>Purpose</strong> is het <em>doel</em> (to inform, persuade, entertain); <strong>tone</strong> is de <em>houding</em> van de schrijver (serious, ironic, critical, enthusiastic), af te lezen aan woordkeuze. <strong>Irony</strong> is een valkuil: de schrijver zegt het tegenovergestelde van wat hij bedoelt.</p><div class="sam-tip"><strong>Beantwoord de vraag met tekstbewijs.</strong> VWO-teksten zijn subtiel; kies je antwoord op grond van wat er <em>staat</em>, niet van je eigen mening. Bij "which statement is correct according to the text" zoek je de zin die het letterlijk (of via inference) ondersteunt.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — inference</div><div class="sam-worked-q">"The lecture hall emptied within minutes, chairs scraping, nobody looking back." What can you infer about the lecture?</div><ol class="sam-worked-steps"><li>Iedereen vertrekt haastig, niemand kijkt om.</li><li>Dat wijst op weinig enthousiasme/betrokkenheid.</li><li>Je leidt af (inference) dat het saai of onbevredigend was.</li></ol><div class="sam-worked-ans">✅ The lecture was probably dull/unengaging — afgeleid uit het gedrag, niet letterlijk gezegd (inference).</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — signal word</div><div class="sam-worked-q">"The theory is elegant. Nonetheless, it fails to explain the data." What does "nonetheless" signal?</div><ol class="sam-worked-steps"><li>"Nonetheless" is a concession/contrast signal.</li><li>Het zet iets tegenover de eerste zin.</li><li>Elegant → toch een tekortkoming.</li></ol><div class="sam-worked-ans">✅ Contrast/concession: ondanks de elegantie volgt een bezwaar (de theorie verklaart de data niet).</div></div>`,
'vwo_nl_E':`<div class="sam-intro"><strong>Literatuur</strong> op het VWO combineert het <strong>analyseren</strong> van teksten met <strong>literatuurgeschiedenis</strong>. Je leert de <strong>narratologische begrippen</strong> (perspectief, motief, thema), de <strong>stijlfiguren</strong>, en de grote <strong>literaire stromingen</strong> door de eeuwen heen — nodig voor je leeslijst van 12 werken (waarvan ≥3 van vóór 1880).</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Vertelperspectief</td><td>door wiens ogen zie je het verhaal?</td></tr><tr><td>Motief &amp; thema</td><td>terugkerend element vs. onderwerp</td></tr><tr><td>Stijlfiguren</td><td>metafoor, vergelijking, personificatie</td></tr><tr><td>Stromingen</td><td>van middeleeuwen tot modernisme</td></tr><tr><td>Leeslijst</td><td>12 werken, ≥3 van vóór 1880</td></tr></tbody></table><div class="sam-head">Analyseren: perspectief, motief, thema</div><p>Het <strong>vertelperspectief</strong> bepaalt door wiens ogen je het verhaal beleeft: <strong>ik</strong>-perspectief (beperkt), <strong>personaal</strong> (via één personage, hij/zij) of <strong>alwetend</strong>. Het <strong>thema</strong> is het abstracte onderwerp (bv. vergankelijkheid); een <strong>motief</strong> is een concreet, terugkerend element dat dat thema draagt.</p><div class="sam-head">Literatuurgeschiedenis: de stromingen</div><p>VWO vraagt om <strong>literatuurhistorisch</strong> inzicht: je plaatst een werk in zijn tijd en stroming. Ken de hoofdlijn en de kenmerken:</p><div class="sam-figure"><svg viewBox="0 0 300 82" role="img" aria-label="Tijdbalk van literaire stromingen: middeleeuwen, renaissance, verlichting, romantiek, realisme, modernisme"><line x1="16" y1="44" x2="288" y2="44" stroke="var(--mu)" stroke-width="1.4"/><g font-size="6" font-weight="700" fill="var(--dk)" text-anchor="middle"><circle cx="30" cy="44" r="3" fill="var(--or)"/><text x="30" y="60">M.E.</text><circle cx="83" cy="44" r="3" fill="var(--or)"/><text x="83" y="60">renais.</text><circle cx="136" cy="44" r="3" fill="var(--or)"/><text x="136" y="60">verlicht.</text><circle cx="189" cy="44" r="3" fill="var(--or)"/><text x="189" y="60">romantiek</text><circle cx="242" cy="44" r="3" fill="var(--or)"/><text x="242" y="60">realisme</text><circle cx="282" cy="44" r="3" fill="var(--or)"/><text x="282" y="60">modern.</text></g><text x="150" y="20" font-size="7" fill="var(--mu)" text-anchor="middle">ouder ← → recenter</text></svg><div class="sam-figcap"><strong>Grote lijn:</strong> van de <strong>middeleeuwen</strong> (ridderepiek, religie) via <strong>renaissance</strong> (de mens centraal), <strong>verlichting</strong> (rede), <strong>romantiek</strong> (gevoel, verbeelding), <strong>realisme/naturalisme</strong> (de werkelijkheid, sociale misstanden) naar het <strong>modernisme</strong> (experiment, innerlijk, stream of consciousness).</div></div><div class="sam-head">Stijlfiguren</div><table class="sam-table"><thead><tr><th>Stijlfiguur</th><th>Wat is het?</th></tr></thead><tbody><tr><td>Vergelijking</td><td>met "als"/"zoals"</td></tr><tr><td>Metafoor</td><td>beeld zónder "als"</td></tr><tr><td>Personificatie</td><td>iets levenloos krijgt menselijke trekken</td></tr><tr><td>Ironie</td><td>het tegenovergestelde bedoelen</td></tr></tbody></table><div class="sam-tip"><strong>Plaats een werk in zijn tijd.</strong> Bij een examen- of mondelingvraag koppel je kenmerken van de tekst aan de stroming: individualisme en gevoel → romantiek; objectieve weergave van armoede → naturalisme. Zo onderbouw je je interpretatie historisch.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — motief of thema</div><div class="sam-worked-q">In een roman over vergankelijkheid keert steeds een wegtikkende klok terug. Wat is het thema en wat het motief?</div><ol class="sam-worked-steps"><li>Het abstracte onderwerp is vergankelijkheid → thema.</li><li>Het concrete terugkerende element is de klok → motief.</li></ol><div class="sam-worked-ans">✅ Thema: vergankelijkheid (abstract); motief: de wegtikkende klok (concreet, terugkerend, ondersteunt het thema).</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — stroming herkennen</div><div class="sam-worked-q">Een 19e-eeuwse roman beschrijft nuchter en objectief de armoede en uitzichtloosheid in een arbeiderswijk; het milieu bepaalt het lot van de personages. Welke stroming?</div><ol class="sam-worked-steps"><li>Objectieve weergave van sociale misstanden.</li><li>Het milieu bepaalt de mens (determinisme).</li><li>Dat zijn kenmerken van het naturalisme.</li></ol><div class="sam-worked-ans">✅ Het naturalisme: objectieve weergave van armoede, waarbij milieu en afkomst het lot bepalen.</div></div>`,
'vwo_nl_D':`<div class="sam-intro"><strong>Argumentatieve vaardigheden</strong> zijn op het VWO-examen cruciaal: veel leesvragen gaan over betogende teksten. Je leert een <strong>standpunt</strong> en <strong>argumenten</strong> herkennen, het <strong>argumentatieschema</strong> (nevenschikkend/onderschikkend) doorzien, <strong>argumentatietypen</strong> onderscheiden, en argumenten beoordelen op <strong>aanvaardbaarheid</strong> — inclusief het betrappen van <strong>drogredenen</strong>.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Standpunt</td><td>de verdedigde mening</td></tr><tr><td>Argumentatieschema</td><td>nevenschikkend vs. onderschikkend</td></tr><tr><td>Argumentatietypen</td><td>voorbeeld, autoriteit, gevolg, vergelijking</td></tr><tr><td>Beoordelen</td><td>aanvaardbaarheid &amp; relevantie</td></tr><tr><td>Drogredenen</td><td>argumenten die niet deugen</td></tr></tbody></table><div class="sam-head">Standpunt en argument beoordelen</div><p>Een <strong>standpunt</strong> is de mening die verdedigd wordt; een <strong>argument</strong> een reden die dat standpunt steunt. Je toetst een argument op <strong>aanvaardbaarheid</strong> (klopt de bewering?) én <strong>relevantie</strong> (steunt hij écht het standpunt?). Een waar maar irrelevant argument is waardeloos.</p><div class="sam-head">Het argumentatieschema</div><p>Bij meerdere argumenten analyseer je de <strong>structuur</strong>:</p><div class="sam-figure"><svg viewBox="0 0 300 122" role="img" aria-label="Nevenschikkende argumentatie met losse argumenten en onderschikkende met een keten"><g font-size="7.5" font-weight="700" fill="var(--dk)" text-anchor="middle"><text x="76" y="14">nevenschikkend</text><rect x="46" y="20" width="60" height="18" rx="5" fill="var(--or)" opacity=".2" stroke="var(--or)" stroke-width="1.1"/><text x="76" y="32">standpunt</text><rect x="14" y="70" width="52" height="16" rx="5" fill="var(--mu)" opacity=".14"/><text x="40" y="81">arg 1</text><rect x="88" y="70" width="52" height="16" rx="5" fill="var(--mu)" opacity=".14"/><text x="114" y="81">arg 2</text><line x1="66" y1="38" x2="40" y2="70" stroke="var(--mu)" stroke-width="1.1"/><line x1="86" y1="38" x2="114" y2="70" stroke="var(--mu)" stroke-width="1.1"/></g><line x1="160" y1="12" x2="160" y2="118" stroke="var(--bo)" stroke-width="1"/><g font-size="7.5" font-weight="700" fill="var(--dk)" text-anchor="middle"><text x="230" y="14">onderschikkend</text><rect x="200" y="20" width="60" height="16" rx="5" fill="var(--or)" opacity=".2" stroke="var(--or)" stroke-width="1.1"/><text x="230" y="31">standpunt</text><rect x="200" y="58" width="60" height="16" rx="5" fill="var(--mu)" opacity=".14"/><text x="230" y="69">argument</text><rect x="200" y="94" width="60" height="16" rx="5" fill="var(--mu)" opacity=".1"/><text x="230" y="105">arg daarvoor</text><line x1="230" y1="36" x2="230" y2="58" stroke="var(--mu)" stroke-width="1.1"/><line x1="230" y1="74" x2="230" y2="94" stroke="var(--mu)" stroke-width="1.1"/></g></svg><div class="sam-figcap"><strong>Twee schema's:</strong> bij <strong>nevenschikkende</strong> argumentatie steunen meerdere argumenten <em>los naast elkaar</em> het standpunt (elk kan op zich staan). Bij <strong>onderschikkende</strong> argumentatie steunt een argument weer op een ánder — een keten waarin elke schakel de vorige onderbouwt.</div></div><div class="sam-head">Argumentatietypen en drogredenen</div><p>Een argument onderbouwt via een <strong>type</strong>: voorbeeld, autoriteit, oorzaak-gevolg of vergelijking. Deugt de redenering niet, dan is het een <strong>drogreden</strong>. Veelvoorkomend: de <strong>persoonlijke aanval</strong>, de <strong>onterechte autoriteit</strong>, de <strong>overhaaste generalisatie</strong> en de <strong>cirkelredenering</strong>.</p><div class="sam-tip"><strong>Drogreden of niet?</strong> Toets of het argument het standpunt écht en op geldige wijze steunt. Wordt niet de zaak maar de <em>persoon</em> aangevallen, of een "deskundige" buiten zijn vakgebied ingezet, dan is het meestal een drogreden.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — argumentatietype</div><div class="sam-worked-q">"Meer groen in de stad is goed, want in steden met veel parken voelen bewoners zich aantoonbaar gezonder." Welk argumentatietype?</div><ol class="sam-worked-steps"><li>De onderbouwing wijst op een gevolg van meer groen.</li><li>Gezondere bewoners = een effect.</li><li>Dat is argumentatie op basis van oorzaak-gevolg.</li></ol><div class="sam-worked-ans">✅ Oorzaak-gevolg: het positieve gevolg (gezondere bewoners) onderbouwt het standpunt.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — drogreden</div><div class="sam-worked-q">"Je hoeft niet naar haar klimaatplan te luisteren; ze vliegt zelf vaak." Welke drogreden?</div><ol class="sam-worked-steps"><li>Het plan zelf wordt niet weerlegd.</li><li>De persoon wordt aangevallen op haar gedrag.</li><li>Dat is de man spelen i.p.v. de bal.</li></ol><div class="sam-worked-ans">✅ Een persoonlijke aanval: de persoon wordt aangevallen in plaats van het argument — de inhoud blijft onbesproken.</div></div>`,
'vwo_nl_C':`<div class="sam-intro"><strong>Schrijfvaardigheid</strong> gaat over zelf goede teksten schrijven op VWO-niveau. Je leert de <strong>tekstsoorten</strong> (betoog, beschouwing, uiteenzetting), een sterke <strong>alinea</strong> en <strong>tekststructuur</strong> bouwen, een <strong>stelling</strong> onderbouwen, en correct met <strong>bronnen</strong>, register en stijl werken.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Tekstsoorten</td><td>betoog, beschouwing, uiteenzetting</td></tr><tr><td>Alinea-opbouw</td><td>kernzin + uitwerking</td></tr><tr><td>Structuur</td><td>inleiding, kern, slot</td></tr><tr><td>Bronnen</td><td>correct verwijzen en parafraseren</td></tr><tr><td>Register &amp; stijl</td><td>formeel, foutloos, helder</td></tr></tbody></table><div class="sam-head">Drie tekstsoorten</div><p>Elke tekstsoort heeft een eigen <strong>doel</strong> — houd ze uit elkaar:</p><table class="sam-table"><thead><tr><th>Tekstsoort</th><th>Doel</th></tr></thead><tbody><tr><td>Uiteenzetting</td><td>informeren (neutraal uitleggen)</td></tr><tr><td>Beschouwing</td><td>ter overweging aanbieden (afwegen)</td></tr><tr><td>Betoog</td><td>overtuigen (één standpunt verdedigen)</td></tr></tbody></table><div class="sam-head">Alinea en structuur</div><p>Een tekst bestaat uit <strong>alinea's</strong> die elk één deelonderwerp behandelen. Een sterke alinea opent met een <strong>kernzin</strong> en werkt die uit met uitleg, voorbeelden of argumenten. Het geheel volgt de drieslag <strong>inleiding – kern – slot</strong>, met heldere overgangen.</p><div class="sam-tip"><strong>Bronnen verwerken:</strong> op het VWO parafraseer je bronnen in eigen woorden en verwijs je correct naar de herkomst. Letterlijk overnemen zonder verwijzing is plagiaat; goed brongebruik versterkt juist je betoog.</div><div class="sam-head">Register en stijl</div><p>Schrijf <strong>formeel</strong>: geen spreektaal, volledige zinnen, correcte spelling en interpunctie. Een <strong>stijlfout</strong> (te informeel, dubbelop, onduidelijk) kost punten. Gebruik <strong>signaalwoorden</strong> (daardoor, echter, bovendien) om verbanden expliciet te maken.</p><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — tekstsoort kiezen</div><div class="sam-worked-q">Je moet één duidelijk standpunt over cameratoezicht verdedigen met argumenten. Welke tekstsoort schrijf je?</div><ol class="sam-worked-steps"><li>Eén standpunt verdedigen met argumenten.</li><li>Doel is overtuigen.</li><li>Dat is een betoog.</li></ol><div class="sam-worked-ans">✅ Een betoog: je kiest partij en onderbouwt dat ene standpunt met argumenten.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — stijlfout</div><div class="sam-worked-q">In een formeel betoog staat: "Sociale media zijn gewoon echt heel slecht voor je." Wat is het probleem?</div><ol class="sam-worked-steps"><li>"gewoon echt heel" is spreektaal en vaag.</li><li>Het register is te informeel en niet onderbouwd.</li><li>Herformuleer verzorgd en concreet.</li></ol><div class="sam-worked-ans">✅ Te informeel en ongefundeerd; beter: "Intensief gebruik van sociale media kan het welzijn van jongeren aantoonbaar schaden, doordat…".</div></div>`,
'vwo_nl_B':`<div class="sam-intro"><strong>Mondelinge taalvaardigheid</strong> gaat over spreken, presenteren en debatteren op VWO-niveau. Je leert een <strong>presentatie</strong> opbouwen, het juiste <strong>register</strong> kiezen, <strong>non-verbale communicatie</strong> inzetten, en in een <strong>debat</strong> scherp argumenteren en weerleggen.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Presentatiestructuur</td><td>inleiding, kern, slot</td></tr><tr><td>Spreekdoel</td><td>informatief of overtuigend</td></tr><tr><td>Register</td><td>formeel vs. informeel</td></tr><tr><td>Non-verbaal</td><td>houding, oogcontact, stem</td></tr><tr><td>Debat</td><td>argument + weerlegging</td></tr></tbody></table><div class="sam-head">Presentatie en spreekdoel</div><p>Bouw je verhaal op met een <strong>inleiding</strong> (aandacht + onderwerp + opbouw), een <strong>kern</strong> (punten met voorbeelden en bronnen) en een <strong>slot</strong> (samenvatten, afsluiten). Bepaal vooraf je <strong>spreekdoel</strong>: <strong>informeren</strong> (uitleggen) of <strong>overtuigen</strong> (je publiek voor een standpunt winnen).</p><div class="sam-head">Register en non-verbaal</div><p>Kies een passend <strong>register</strong>: bij een presentatie of examen spreek je <strong>formeel</strong> (verzorgd, geen straattaal). Je <strong>non-verbale</strong> communicatie bepaalt sterk je geloofwaardigheid: oogcontact, een open houding en een duidelijke, rustige stem.</p><div class="sam-tip"><strong>Oogcontact</strong> heeft tijdens presenteren de grootste invloed op je geloofwaardigheid — kijk je publiek aan in plaats van je sheets voor te lezen. Aflezen breekt het contact en maakt je minder overtuigend.</div><div class="sam-head">Debatteren</div><p>In een <strong>debat</strong> verdedig je een standpunt en reageer je op de tegenpartij. Een <strong>sterk argument</strong> is relevant, onderbouwd en aanvaardbaar. In de <strong>weerleggingsronde</strong> toon je waaróm het argument van de ander niet klopt of minder zwaar weegt — je richt je op de <em>redenering</em>, niet op de persoon.</p><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — spreekdoel</div><div class="sam-worked-q">Een presentatie eindigt met: "Daarom zouden wij allemaal vaker de trein moeten nemen." Informatief of overtuigend?</div><ol class="sam-worked-steps"><li>De spreker geeft een standpunt, geen neutrale info.</li><li>"Wij zouden moeten…" wil het publiek meekrijgen.</li><li>Dat is overtuigen.</li></ol><div class="sam-worked-ans">✅ Overtuigend: de spreker wil het publiek een mening of gedrag laten overnemen.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — weerlegging</div><div class="sam-worked-q">De tegenpartij zegt: "Gratis openbaar vervoer is onbetaalbaar." Hoe weerleg je dit inhoudelijk?</div><ol class="sam-worked-steps"><li>Val het argument (de kosten) aan, niet de persoon.</li><li>Zet er de baten tegenover.</li><li>Bv. minder files, schonere lucht, lagere zorgkosten.</li></ol><div class="sam-worked-ans">✅ "De kosten wegen op tegen de baten: minder files en schonere lucht besparen op termijn geld." Je weerlegt de redenering zelf.</div></div>`,
'vwo_nl_A':`<div class="sam-intro"><strong>Leesvaardigheid</strong> (niveau 4F) is de kern van het centraal examen Nederlands: je analyseert complexe teksten en beantwoordt vragen. Je leert <strong>tekstsoorten</strong> herkennen, de <strong>tekststructuur</strong> en <strong>relaties</strong> doorzien, de <strong>hoofdgedachte</strong> en het <strong>tekstdoel</strong> bepalen, en teksten beknopt <strong>samenvatten</strong>.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Tekstsoorten</td><td>uiteenzettend, beschouwend, betogend</td></tr><tr><td>Tekstrelaties</td><td>oorzaak-gevolg, tegenstelling, middel-doel…</td></tr><tr><td>Hoofdgedachte</td><td>de kernboodschap in één zin</td></tr><tr><td>Tekstdoel</td><td>informeren, overtuigen, aanzetten…</td></tr><tr><td>Samenvatten</td><td>reduceren tot hoofd­uitspraken</td></tr></tbody></table><div class="sam-head">Tekstsoorten en tekstdoel</div><p>Op 4F-niveau zijn teksten complex en niet altijd direct helder gestructureerd. Bepaal eerst het <strong>karakter</strong>: een <strong>uiteenzetting</strong> informeert, een <strong>beschouwing</strong> biedt iets ter overweging (weegt af), een <strong>betoog</strong> overtuigt. Combinaties komen voor — stel vast welk karakter <strong>domineert</strong>.</p><table class="sam-table"><thead><tr><th>Tekstsoort</th><th>Doel</th></tr></thead><tbody><tr><td>Uiteenzetting</td><td>informeren (neutraal uitleggen)</td></tr><tr><td>Beschouwing</td><td>ter overweging aanbieden (afwegen)</td></tr><tr><td>Betoog</td><td>overtuigen (één standpunt verdedigen)</td></tr></tbody></table><div class="sam-head">Tekstrelaties en signaalwoorden</div><p>Een tekst hangt samen via <strong>relaties</strong> tussen tekstdelen. Herken ze — vaak aan <strong>signaalwoorden</strong> — want examenvragen draaien er vaak om.</p><table class="sam-table"><thead><tr><th>Relatie</th><th>Signaalwoorden</th></tr></thead><tbody><tr><td>Oorzaak-gevolg</td><td>doordat, daardoor, zodat</td></tr><tr><td>Tegenstelling</td><td>echter, daarentegen, toch</td></tr><tr><td>Middel-doel</td><td>om te, daarmee, zodat</td></tr><tr><td>Voorwaarde</td><td>als, mits, tenzij</td></tr><tr><td>Toelichting</td><td>namelijk, immers, zo</td></tr></tbody></table><div class="sam-head">Samenvatten</div><p>Bij <strong>samenvatten</strong> reduceer je de tekst tot de <strong>hoofduitspraken</strong> plus de relevante ondergeschikte uitspraken; bijzaken (voorbeelden, uitweidingen) laat je weg. Je moet ook een gegeven samenvatting kunnen <strong>beoordelen</strong> op volledigheid en juistheid.</p><div class="sam-tip"><strong>Verwijswoorden en tekststructuur:</strong> bij een vraag "waar verwijst 'dit' naar?" zoek je het passende, meestal dichtstbijzijnde antecedent ervóór en controleer je of invullen klopt. Bij "functie van alinea X" bepaal je de rol in het geheel (inleiding, deelargument, tegenwerping, conclusie).</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — tekstsoort</div><div class="sam-worked-q">Een tekst belicht de voor- én nadelen van kernenergie, weegt ze tegen elkaar af en trekt geen stellige eindconclusie. Welke tekstsoort domineert?</div><ol class="sam-worked-steps"><li>Meerdere kanten worden afgewogen.</li><li>Er wordt geen partij gekozen.</li><li>Dat past bij een beschouwing.</li></ol><div class="sam-worked-ans">✅ Een beschouwing: de schrijver biedt de kwestie ter overweging aan zonder één standpunt te verdedigen.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — relatie herkennen</div><div class="sam-worked-q">"De subsidie verdween. Daardoor moesten veel verenigingen sluiten." Welke tekstrelatie is dit?</div><ol class="sam-worked-steps"><li>Signaalwoord "daardoor" wijst op een gevolg.</li><li>Wegvallen subsidie (oorzaak) → sluiting (gevolg).</li></ol><div class="sam-worked-ans">✅ Een oorzaak-gevolgrelatie: het wegvallen van de subsidie is de oorzaak, de sluitingen het gevolg.</div></div>`,
'vwo_mw_A':`<div class="sam-intro"><strong>Vaardigheden</strong> is de onderzoeks- en denkwijze van de maatschappijwetenschappen — op het examen getoetst in samenhang met de inhoud. Je leert <strong>sociaalwetenschappelijk redeneren</strong>, goed <strong>onderzoek</strong> opzetten (betrouwbaarheid, validiteit, steekproef) en <strong>bronnen</strong> kritisch beoordelen.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Begrip</th><th>Kern</th></tr></thead><tbody><tr><td>Betrouwbaarheid</td><td>meet je consistent (herhaalbaar)?</td></tr><tr><td>Validiteit</td><td>meet je wat je wilt meten?</td></tr><tr><td>Kwan vs. kwal</td><td>cijfers vs. verdieping</td></tr><tr><td>Representativiteit</td><td>afspiegeling van de populatie</td></tr><tr><td>Correlatie/causaliteit</td><td>samenhang ≠ oorzaak</td></tr></tbody></table><div class="sam-head">Betrouwbaarheid en validiteit</div><p>Twee kwaliteitseisen die je niet mag verwarren. <strong>Betrouwbaarheid</strong> gaat over <em>consistentie</em>: krijg je bij herhaling dezelfde uitkomst? <strong>Validiteit</strong> gaat over <em>raakheid</em>: meet je écht wat je bedoelt te meten? Een meting kan betrouwbaar zijn (steeds hetzelfde) maar toch niet valide (steeds hetzelfde verkeerde).</p><div class="sam-figure"><svg viewBox="0 0 300 116" role="img" aria-label="Schietschijf: betrouwbaar maar niet valide versus betrouwbaar en valide"><g><circle cx="80" cy="56" r="38" fill="none" stroke="var(--mu)" stroke-width="1.2"/><circle cx="80" cy="56" r="24" fill="none" stroke="var(--mu)" stroke-width="1.2"/><circle cx="80" cy="56" r="10" fill="var(--or)" opacity=".2" stroke="var(--or)" stroke-width="1.2"/><g fill="var(--dk)"><circle cx="110" cy="32" r="3"/><circle cx="116" cy="38" r="3"/><circle cx="112" cy="44" r="3"/></g><text x="80" y="106" font-size="7" fill="var(--dk)" text-anchor="middle">betrouwbaar, niet valide</text></g><g><circle cx="220" cy="56" r="38" fill="none" stroke="var(--mu)" stroke-width="1.2"/><circle cx="220" cy="56" r="24" fill="none" stroke="var(--mu)" stroke-width="1.2"/><circle cx="220" cy="56" r="10" fill="var(--or)" opacity=".2" stroke="var(--or)" stroke-width="1.2"/><g fill="var(--dk)"><circle cx="218" cy="54" r="3"/><circle cx="223" cy="58" r="3"/><circle cx="219" cy="60" r="3"/></g><text x="220" y="106" font-size="7" fill="var(--dk)" text-anchor="middle">betrouwbaar én valide</text></g></svg><div class="sam-figcap"><strong>Schietschijf-beeld:</strong> links zitten de schoten dicht op elkaar (betrouwbaar) maar náást de roos (niet valide); rechts dicht op elkaar én in de roos (allebei). Consistentie zonder juistheid is dus mogelijk.</div></div><div class="sam-head">Onderzoek opzetten</div><p>Je toetst een <strong>hypothese</strong> met kwantitatief (cijfers, enquête) of kwalitatief (verdieping, interview) onderzoek. Een <strong>representatieve</strong> steekproef is een goede afspiegeling van de populatie; een <strong>aselecte</strong> trekking voorkomt <strong>selectiebias</strong>.</p><div class="sam-tip"><strong>Samenhang is geen oorzaak.</strong> Twee variabelen die samen bewegen (correlatie) hoeven elkaar niet te veroorzaken; vaak speelt een <strong>derde factor</strong> (confounder). Wees voorzichtig met de conclusie "A veroorzaakt B" — daarvoor is gecontroleerd onderzoek nodig.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — betrouwbaar of valide</div><div class="sam-worked-q">Een vragenlijst geeft bij herhaling steeds dezelfde uitkomst, maar meet eigenlijk iets anders dan bedoeld. Betrouwbaar, valide, of beide?</div><ol class="sam-worked-steps"><li>Steeds dezelfde uitkomst = consistent = betrouwbaar.</li><li>Meet iets anders dan bedoeld = niet valide.</li></ol><div class="sam-worked-ans">✅ Betrouwbaar maar niet valide: consistent, maar het meet niet wat het zou moeten meten.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — confounder</div><div class="sam-worked-q">Wijken met meer politie op straat kennen ook meer geregistreerde criminaliteit. Mag je concluderen dat politie criminaliteit veroorzaakt?</div><ol class="sam-worked-steps"><li>Er is een samenhang, geen bewezen oorzaak.</li><li>Meer politie gaat vaak naar wijken die al onveiliger zijn.</li><li>De onveiligheid verklaart beide (confounder).</li></ol><div class="sam-worked-ans">✅ Nee: waarschijnlijk plaatst men méér politie in onveiliger wijken — een derde factor verklaart de samenhang, het is geen oorzaak.</div></div>`,
'vwo_ak_A':`<div class="sam-intro"><strong>Vaardigheden</strong> is de geografische manier van werken: <strong>kaartvaardigheden</strong>, het <strong>combineren van bronnen en data</strong>, en <strong>geografisch redeneren</strong> — denken in schaalniveaus en het waar én waarom van verschijnselen.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Kaartvaardigheden</td><td>thematische kaart, legenda, schaal</td></tr><tr><td>Schaalniveau</td><td>lokaal → regionaal → mondiaal</td></tr><tr><td>Bronnen &amp; data</td><td>combineren voor een compleet beeld</td></tr><tr><td>Geografisch redeneren</td><td>waar, waarom dáár, welk gevolg</td></tr><tr><td>Ruimtelijk patroon</td><td>niet-willekeurige verdeling</td></tr></tbody></table><div class="sam-head">Geografisch redeneren</div><p>Aardrijkskunde vraagt naar het <strong>waar</strong> én het <strong>waarom daar</strong>. Je zoekt de <strong>samenhang</strong>: waarom ligt een verschijnsel juist op deze plek, en welke gevolgen heeft dat? Daarbij <strong>schakel</strong> je tussen schaalniveaus — van lokaal tot mondiaal.</p><div class="sam-figure"><svg viewBox="0 0 300 92" role="img" aria-label="Schaalniveaus van lokaal via regionaal en nationaal naar mondiaal"><g font-size="7.5" font-weight="700" fill="var(--dk)" text-anchor="middle"><circle cx="40" cy="46" r="13" fill="var(--or)" opacity=".3" stroke="var(--or)" stroke-width="1.2"/><text x="40" y="76">lokaal</text><circle cx="112" cy="46" r="19" fill="var(--or)" opacity=".22" stroke="var(--or)" stroke-width="1.2"/><text x="112" y="80">regionaal</text><circle cx="192" cy="46" r="25" fill="var(--or)" opacity=".15" stroke="var(--or)" stroke-width="1.2"/><text x="192" y="82">nationaal</text><circle cx="268" cy="46" r="17" fill="var(--mu)" opacity=".18" stroke="var(--mu)" stroke-width="1.2"/><text x="268" y="78">mondiaal</text></g></svg><div class="sam-figcap"><strong>Schakelen in schaal:</strong> hetzelfde verschijnsel ziet er op elk <strong>schaalniveau</strong> anders uit. Een sterke analyse verbindt niveaus — bijvoorbeeld de <strong>lokale</strong> gevolgen van een <strong>mondiaal</strong> proces als klimaatverandering.</div></div><div class="sam-head">Kaarten en bronnen</div><p>Een <strong>thematische kaart</strong> toont één onderwerp per gebied (bv. neerslag, inkomen). Lees altijd eerst de <strong>legenda</strong> en de <strong>schaal</strong>. Eén bron vertelt maar een deel: door <strong>bronnen te combineren</strong> (kaart + tabel + tekst) zie je verbanden die in één bron onzichtbaar blijven.</p><div class="sam-tip"><strong>Absolute vs. relatieve afstand:</strong> de <strong>absolute</strong> afstand (km) verandert niet; de <strong>relatieve</strong> afstand (in reistijd of kosten) wél. Een snelle treinverbinding maakt twee steden "dichterbij" zonder dat de kilometers wijzigen.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — schaalniveau</div><div class="sam-worked-q">Een studie onderzoekt wereldwijde zeespiegelstijging. Op welk schaalniveau speelt dit vooral, en hoe onderzoek je de gevolgen voor Nederland?</div><ol class="sam-worked-steps"><li>"Wereldwijd" = mondiaal schaalniveau.</li><li>De gevolgen voor Nederland analyseer je op een lager (nationaal/lokaal) niveau.</li><li>Je schakelt dus tussen niveaus.</li></ol><div class="sam-worked-ans">✅ Het proces speelt mondiaal; de gevolgen bekijk je op nationaal/lokaal niveau — geografisch redeneren betekent schakelen tussen schaalniveaus.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — bronnen combineren</div><div class="sam-worked-q">Waarom is het bij een vraag over armoede in een stad verstandig een kaart met inkomens én een kaart met werkgelegenheid te gebruiken?</div><ol class="sam-worked-steps"><li>Eén kaart toont maar één variabele.</li><li>Samen laten ze een verband zien (inkomen ↔ werk).</li><li>Broncombinatie geeft een completer beeld.</li></ol><div class="sam-worked-ans">✅ Door bronnen te combineren zie je het verband tussen lage inkomens en weinig werk — meer dan één kaart alleen kan tonen.</div></div>`,
'vwo_ec_A':`<div class="sam-intro"><strong>Vaardigheden</strong> is de manier van denken en rekenen in economie: <strong>economisch redeneren</strong> (oorzaak-gevolg, keuzes onder schaarste) en het <strong>rekenen met grafieken</strong>, procenten en indexcijfers. Dit gereedschap gebruik je in elk economiedomein.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Economisch redeneren</td><td>keuzes, oorzaak-gevolg, ceteris paribus</td></tr><tr><td>Procenten</td><td>toename, afname, procentpunt</td></tr><tr><td>Indexcijfers</td><td>waarde t.o.v. een basisjaar (=100)</td></tr><tr><td>Grafieken</td><td>vraag/aanbod, evenwicht aflezen</td></tr><tr><td>Reëel vs. nominaal</td><td>gecorrigeerd voor inflatie of niet</td></tr></tbody></table><div class="sam-head">Economisch redeneren</div><p>Economie draait om <strong>keuzes onder schaarste</strong> en hun gevolgen. Je redeneert vaak <strong>ceteris paribus</strong> ("al het overige gelijk"): je bekijkt het effect van één verandering terwijl je de rest constant houdt — net als een gecontroleerd experiment.</p><div class="sam-head">Indexcijfers</div><p>Een <strong>indexcijfer</strong> zet een waarde af tegen een <strong>basisjaar</strong> dat je op 100 stelt. Zo zie je in één oogopslag de <strong>procentuele</strong> verandering ten opzichte van dat startpunt.</p><div class="sam-formula-box"><div class="sam-formula-label">Indexcijfer</div><div class="sam-formula-eq">indexcijfer = (waarde in jaar / waarde in basisjaar) × 100</div><div class="sam-formula-note">Een index van 112 betekent +12% t.o.v. het basisjaar. Let op het verschil tussen <strong>procent</strong> (verhouding) en <strong>procentpunt</strong> (verschil tussen twee percentages).</div></div><div class="sam-figure"><svg viewBox="0 0 300 116" role="img" aria-label="Vraag- en aanbodlijn met een evenwichtspunt"><line x1="34" y1="96" x2="288" y2="96" stroke="var(--mu)" stroke-width="1.4"/><line x1="40" y1="104" x2="40" y2="12" stroke="var(--mu)" stroke-width="1.4"/><text x="285" y="110" font-size="7.5" fill="var(--mu)" text-anchor="end">hoeveelheid</text><text x="14" y="20" font-size="7.5" fill="var(--mu)">prijs</text><line x1="48" y1="30" x2="256" y2="90" stroke="var(--or)" stroke-width="2.2"/><line x1="48" y1="90" x2="256" y2="30" stroke="var(--mu)" stroke-width="2.2"/><circle cx="152" cy="60" r="4" fill="var(--dk)"/><text x="240" y="26" font-size="7" fill="var(--mu)">aanbod</text><text x="240" y="96" font-size="7" fill="var(--or)">vraag</text><text x="158" y="52" font-size="7" font-weight="700" fill="var(--dk)">evenwicht</text></svg><div class="sam-figcap"><strong>Marktdiagram:</strong> de dalende <strong>vraaglijn</strong> en de stijgende <strong>aanbodlijn</strong> snijden in het <strong>evenwicht</strong>: daar horen de evenwichtsprijs en -hoeveelheid. Verschuift een lijn, dan verschuift ook het evenwicht — een standaard redeneerstap.</div></div><div class="sam-tip"><strong>Reëel of nominaal?</strong> Een <strong>nominaal</strong> bedrag is in lopende euro's; een <strong>reëel</strong> bedrag is gecorrigeerd voor <strong>inflatie</strong>. Als je loon 3% stijgt maar de prijzen ook 3%, is je koopkracht (reëel) gelijk gebleven.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — indexcijfer</div><div class="sam-worked-q">Een product kostte in het basisjaar € 50 en nu € 60. Wat is het indexcijfer?</div><ol class="sam-worked-steps"><li>index = (nieuwe / basis) × 100.</li><li>= (60 / 50) × 100.</li><li>= 120.</li></ol><div class="sam-worked-ans">✅ Indexcijfer 120: de prijs is 20% gestegen t.o.v. het basisjaar.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — procent vs. procentpunt</div><div class="sam-worked-q">De werkloosheid stijgt van 4% naar 6%. Is dat een stijging van 2% of 2 procentpunt?</div><ol class="sam-worked-steps"><li>Het verschil tussen twee percentages = procentpunt.</li><li>6% − 4% = 2 procentpunt.</li><li>Relatief is het wél +50% (van 4 naar 6).</li></ol><div class="sam-worked-ans">✅ 2 procentpunt (en relatief een stijging van 50%). Verwar procent en procentpunt niet.</div></div>`,
'vwo_na_A':`<div class="sam-intro"><strong>Vaardigheden</strong> is het rekenkundige en onderzoekende gereedschap van natuurkunde: correct <strong>rekenen met significantie en eenheden</strong>, <strong>grafieken en verbanden</strong> aflezen, <strong>modelleren</strong>, en zuiver <strong>practicum</strong> doen.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Significante cijfers</td><td>niet nauwkeuriger dan je meet</td></tr><tr><td>Eenheden</td><td>SI; omrekenen en controleren</td></tr><tr><td>Grafieken</td><td>helling en oppervlakte betekenis geven</td></tr><tr><td>Verbanden</td><td>recht evenredig, kwadratisch, omgekeerd</td></tr><tr><td>Modelleren</td><td>stapsgewijs doorrekenen</td></tr></tbody></table><div class="sam-head">Significante cijfers en eenheden</div><p>Rond een antwoord af op net zoveel <strong>significante cijfers</strong> als de minst nauwkeurige meetwaarde — meer cijfers suggereren schijnnauwkeurigheid. Werk in <strong>SI-eenheden</strong> en controleer je uitkomst op de juiste eenheid: klopt de eenheid niet, dan klopt de berekening niet.</p><div class="sam-head">Grafieken: helling en oppervlakte</div><p>Een grafiek is meer dan een plaatje. De <strong>helling</strong> en de <strong>oppervlakte onder</strong> de grafiek hebben vaak een natuurkundige betekenis:</p><div class="sam-figure"><svg viewBox="0 0 300 116" role="img" aria-label="Snelheid-tijd-grafiek: de helling is de versnelling, de oppervlakte eronder de afstand"><line x1="34" y1="96" x2="288" y2="96" stroke="var(--mu)" stroke-width="1.4"/><line x1="34" y1="104" x2="34" y2="12" stroke="var(--mu)" stroke-width="1.4"/><text x="285" y="110" font-size="7.5" fill="var(--mu)" text-anchor="end">tijd (s)</text><text x="12" y="20" font-size="7.5" fill="var(--mu)">v (m/s)</text><polygon points="34,96 250,40 250,96" fill="var(--or)" opacity=".14"/><line x1="34" y1="96" x2="250" y2="40" stroke="var(--or)" stroke-width="2.2"/><text x="150" y="80" font-size="7" fill="var(--dk)" text-anchor="middle">oppervlakte = afstand</text><text x="150" y="52" font-size="7" fill="var(--or)" text-anchor="middle" transform="rotate(-15 150 52)">helling = versnelling</text></svg><div class="sam-figcap"><strong>Betekenis van een grafiek:</strong> bij een <strong>v,t-grafiek</strong> is de <strong>helling</strong> de versnelling (m/s²) en de <strong>oppervlakte onder</strong> de grafiek de afgelegde afstand (m). Vraag je altijd af wat helling en oppervlakte hier fysisch betekenen.</div></div><div class="sam-tip"><strong>Verbanden herkennen:</strong> is y recht evenredig met x (y = a·x, rechte lijn door de oorsprong), met x² (parabool), of omgekeerd evenredig (y = a/x, hyperbool)? Uit de vorm van de grafiek of de tabel lees je het type verband — en daarmee de bijpassende formule.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — significantie</div><div class="sam-worked-q">Je meet een afstand van 12,0 m in 2,5 s. Met hoeveel significante cijfers geef je de snelheid?</div><ol class="sam-worked-steps"><li>v = 12,0 / 2,5 = 4,8 m/s.</li><li>Minst nauwkeurige waarde (2,5) heeft 2 significante cijfers.</li><li>Dus 2 significante cijfers.</li></ol><div class="sam-worked-ans">✅ 4,8 m/s (2 significante cijfers): niet nauwkeuriger dan de minst nauwkeurige meting.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — oppervlakte aflezen</div><div class="sam-worked-q">In een v,t-grafiek rijdt een auto 4 s lang met constant 10 m/s. Wat stelt de oppervlakte onder de grafiek voor, en hoe groot is die?</div><ol class="sam-worked-steps"><li>Oppervlakte onder een v,t-grafiek = afstand.</li><li>Rechthoek: 10 m/s × 4 s.</li><li>= 40 m.</li></ol><div class="sam-worked-ans">✅ De oppervlakte is de afgelegde afstand: 10 × 4 = 40 m.</div></div>`,
'vwo_sk_A':`<div class="sam-intro"><strong>Vaardigheden</strong> is het rekenwerk en de werkwijze van scheikunde: <strong>rekenen aan reacties</strong> met de <strong>mol</strong> en molverhoudingen, en veilig, systematisch <strong>practicum</strong> doen. Dit gereedschap gebruik je bij elk scheikundig onderwerp.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Mol</td><td>n = m / M; rekeneenheid voor stof</td></tr><tr><td>Molverhouding</td><td>coëfficiënten in de reactievergelijking</td></tr><tr><td>Concentratie</td><td>c = n / V (mol/L)</td></tr><tr><td>Practicum</td><td>zuiver werken, GHS-veiligheid</td></tr></tbody></table><div class="sam-head">Rekenen met de mol</div><p>De <strong>mol</strong> is de scheikundige rekeneenheid voor hoeveelheid stof. Met de molaire massa M (g/mol, uit BINAS) schakel je tussen massa en mol; met het volume tussen mol en concentratie.</p><div class="sam-formula-box"><div class="sam-formula-label">De basisformules</div><div class="sam-formula-eq">n = m / M     (mol = massa / molaire massa)<br>c = n / V     (concentratie in mol/L)</div><div class="sam-formula-note">In een reactievergelijking geven de coëfficiënten de <strong>molverhouding</strong>. Reken altijd via mol: van massa/volume → mol → (via de verhouding) mol andere stof → massa/volume.</div></div><div class="sam-head">Rekenen aan reacties</div><p>De <strong>coëfficiënten</strong> in een kloppende reactievergelijking zeggen in welke <strong>molverhouding</strong> stoffen reageren — niet in welke massaverhouding. Daarom reken je een massa eerst om naar mol, dan via de verhouding, en pas op het eind terug naar massa of volume.</p><div class="sam-tip"><strong>Practicum en veiligheid:</strong> lees vooraf de <strong>GHS-pictogrammen</strong> op de etiketten (vlam = brandbaar, doodshoofd = giftig, uitroepteken = schadelijk). Werk zuiver: schone materialen, nauwkeurig afmeten en herhaalmetingen voor betrouwbaarheid.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — mol en verhouding</div><div class="sam-worked-q">Bij 2 H₂ + O₂ → 2 H₂O reageert 4,0 mol H₂ volledig. Hoeveel mol H₂O ontstaat?</div><ol class="sam-worked-steps"><li>Molverhouding H₂ : H₂O = 2 : 2 = 1 : 1.</li><li>4,0 mol H₂ geeft dus evenveel mol H₂O.</li><li>= 4,0 mol H₂O.</li></ol><div class="sam-worked-ans">✅ 4,0 mol H₂O: de coëfficiënten (2 : 2) geven een 1-op-1-molverhouding.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — concentratie</div><div class="sam-worked-q">Je lost 0,10 mol NaCl op tot 0,50 L oplossing. Wat is de concentratie?</div><ol class="sam-worked-steps"><li>c = n / V.</li><li>= 0,10 / 0,50.</li><li>= 0,20 mol/L.</li></ol><div class="sam-worked-ans">✅ 0,20 mol/L.</div></div>`,
'vwo_bi_A':`<div class="sam-intro"><strong>Vaardigheden</strong> is de wetenschappelijke werkwijze van biologie: <strong>onderzoek en experiment</strong> opzetten met de juiste variabelen en controle, <strong>biologische tekeningen</strong> maken en lezen, en <strong>data interpreteren</strong> uit grafieken en tabellen — inclusief het verschil tussen correlatie en causaliteit.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Variabelen</td><td>onafhankelijk, afhankelijk, constant</td></tr><tr><td>Controlegroep</td><td>vergelijkingsgroep zonder behandeling</td></tr><tr><td>Betrouwbaarheid</td><td>herhalen, grote steekproef</td></tr><tr><td>Data interpreteren</td><td>grafiek/tabel lezen; optimum</td></tr><tr><td>Correlatie vs. causaliteit</td><td>samenhang ≠ oorzaak</td></tr></tbody></table><div class="sam-head">Onderzoek en experiment</div><p>In een zuiver experiment varieer je één <strong>onafhankelijke</strong> variabele, meet je de <strong>afhankelijke</strong>, en houd je de rest <strong>constant</strong>. Een <strong>controlegroep</strong> (zonder de behandeling) geeft je een vergelijkingspunt. Door te <strong>herhalen</strong> en een grote steekproef te gebruiken vergroot je de <strong>betrouwbaarheid</strong>.</p><div class="sam-head">Data interpreteren: het optimum</div><p>Biologische grafieken tonen vaak een <strong>optimum</strong>: een piekwaarde waarna het weer daalt. Klassiek voorbeeld: enzymactiviteit stijgt tot de optimumtemperatuur en stort daarna in doordat het enzym <strong>denatureert</strong> (vorm verandert onomkeerbaar).</p><div class="sam-figure"><svg viewBox="0 0 300 116" role="img" aria-label="Enzymactiviteit met een optimum: stijgt tot een piek en daalt daarna snel"><line x1="34" y1="98" x2="288" y2="98" stroke="var(--mu)" stroke-width="1.4"/><line x1="34" y1="106" x2="34" y2="12" stroke="var(--mu)" stroke-width="1.4"/><text x="285" y="112" font-size="7.5" fill="var(--mu)" text-anchor="end">temperatuur</text><text x="10" y="20" font-size="7.5" fill="var(--mu)">activiteit</text><path d="M40,94 C110,84 138,28 158,28 C176,28 190,68 250,96" fill="none" stroke="var(--or)" stroke-width="2.4"/><circle cx="158" cy="28" r="4" fill="var(--or)"/><line x1="158" y1="28" x2="158" y2="98" stroke="var(--or)" stroke-width="1" stroke-dasharray="2 2"/><text x="158" y="112" font-size="7" font-weight="700" fill="var(--or)" text-anchor="middle">optimum</text></svg><div class="sam-figcap"><strong>Optimumkromme:</strong> de activiteit stijgt tot een <strong>optimum</strong> en <strong>daalt daarna snel</strong>. Bij een grafiekvraag benoem je waar de piek ligt en verklaar je de daling (bij enzymen: denaturatie boven de optimumtemperatuur).</div></div><div class="sam-tip"><strong>Biologische tekening:</strong> maak hem groot, met scherpe, dunne lijnen (geen arcering), en zet er <strong>bijschriften</strong> en een <strong>vergroting/schaal</strong> bij. Teken wat je écht ziet, niet wat je "hoort" te zien.</div><div class="sam-head">Correlatie en causaliteit</div><p>Twee grootheden die <strong>samen</strong> veranderen (correlatie) hoeven elkaar niet te <strong>veroorzaken</strong>. Vaak speelt een derde factor mee. Alleen een goed opgezet experiment, dat andere factoren uitsluit, toont een <strong>oorzakelijk</strong> verband aan.</p><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — zuiver experiment</div><div class="sam-worked-q">Een onderzoeker varieert de lichtintensiteit bij planten maar houdt de temperatuur niet constant. Welk probleem ontstaat?</div><ol class="sam-worked-steps"><li>Nu veranderen twee factoren tegelijk (licht én temperatuur).</li><li>Je weet niet meer waardoor een effect komt.</li><li>De proef is niet zuiver — de temperatuur is een storende variabele.</li></ol><div class="sam-worked-ans">✅ Het effect is niet meer aan het licht toe te schrijven: door de niet-constante temperatuur is er een storende variabele.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — grafiek lezen</div><div class="sam-worked-q">Een grafiek toont dat de reactiesnelheid van een enzym stijgt tot 37 °C en daarna snel daalt. Hoe heet dat punt en waarom daalt de curve erna?</div><ol class="sam-worked-steps"><li>De piek is de optimumtemperatuur (hier ±37 °C).</li><li>Boven die temperatuur verandert de vorm van het enzym.</li><li>Dat heet denaturatie; het enzym werkt dan niet meer.</li></ol><div class="sam-worked-ans">✅ Het optimum (±37 °C); erna daalt de activiteit doordat het enzym denatureert.</div></div>`,
'vwo_wb_A':`<div class="sam-intro"><strong>Vaardigheden</strong> zijn het gereedschap onder alle wiskunde B: sterke <strong>algebraïsche</strong> technieken, <strong>exact rekenen</strong> (zonder afronden waar dat moet), en <strong>bewijzen</strong> — een sluitende redenering opschrijven van gegeven naar conclusie.</div><div class="sam-chips"><span class="sam-chip sam-chip-lead">Kern</span><span class="sam-chip">Exact rekenen</span><span class="sam-chip">Herleiden</span><span class="sam-chip">Ontbinden</span><span class="sam-chip">Bewijzen</span><span class="sam-chip">Redeneren</span><span class="sam-chip">Notatie</span></div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Algebra</td><td>herleiden, ontbinden, breuken</td></tr><tr><td>Exact rekenen</td><td>√, π en breuken laten staan</td></tr><tr><td>Bewijzen</td><td>elke stap met geldige reden</td></tr><tr><td>Notatie</td><td>volledig en ondubbelzinnig opschrijven</td></tr></tbody></table><div class="sam-head">Exact rekenen</div><p>Bij wiskunde B is <strong>exact</strong> vaak verplicht: je laat wortels, π en breuken <strong>staan</strong> in plaats van ze af te ronden. √2 blijft √2; 1/3 blijft 1/3. Een afgeronde decimaal is dan fout, want die is niet exact.</p><div class="sam-head">Bewijzen</div><p>Een <strong>bewijs</strong> is een sluitende redenering: je gaat van het <strong>gegeven</strong> via geldige stappen naar de <strong>te bewijzen</strong> bewering. Elke stap moet een reden hebben; je mag niets aannemen wat je nog moet bewijzen.</p><div class="sam-figure"><svg viewBox="0 0 300 66" role="img" aria-label="Bewijs: van gegeven via tussenstappen naar de conclusie"><g font-size="7.5" font-weight="700" fill="var(--dk)" text-anchor="middle"><rect x="8" y="22" width="60" height="22" rx="5" fill="var(--mu)" opacity=".14"/><text x="38" y="36">gegeven</text><rect x="94" y="22" width="72" height="22" rx="5" fill="var(--mu)" opacity=".12"/><text x="130" y="36">tussenstappen</text><rect x="212" y="22" width="76" height="22" rx="5" fill="var(--or)" opacity=".2"/><text x="250" y="36">conclusie (QED)</text></g><g stroke="var(--or)" stroke-width="1.3"><line x1="68" y1="33" x2="92" y2="33" marker-end="url(#wbAar)"/><line x1="166" y1="33" x2="210" y2="33" marker-end="url(#wbAar)"/></g><defs><marker id="wbAar" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--or)"/></marker></defs></svg><div class="sam-figcap"><strong>De structuur van een bewijs:</strong> begin bij het <strong>gegeven</strong>, redeneer via <strong>geldige tussenstappen</strong> (elk met reden) naar de <strong>conclusie</strong>. Geen sprongen: het nakijkmodel beloont juist die tussenstappen.</div></div><div class="sam-tip"><strong>Schrijf volledig op.</strong> Bij een bewijs of exacte berekening tellen de tussenstappen mee, niet alleen het eindantwoord. Noteer wélke regel of stelling je gebruikt ("volgens Pythagoras", "differentiëren geeft…"), zodat je redenering controleerbaar is.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — exact rekenen</div><div class="sam-worked-q">Bereken exact de lengte van de schuine zijde van een rechthoekige driehoek met rechthoekszijden 1 en 1.</div><ol class="sam-worked-steps"><li>Pythagoras: c² = 1² + 1² = 2.</li><li>c = √2.</li><li>Niet afronden naar 1,41 — dat is niet exact.</li></ol><div class="sam-worked-ans">✅ c = √2 (exact). Een decimaal als 1,41 zou hier fout gerekend worden.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — geldige stap</div><div class="sam-worked-q">In een bewijs schrijf je "stel dat de bewering waar is, dan…". Wat is hier mis?</div><ol class="sam-worked-steps"><li>Je gebruikt de te bewijzen bewering als gegeven.</li><li>Dat is een cirkelredenering.</li><li>Je mag alleen van het gegeven uitgaan.</li></ol><div class="sam-worked-ans">✅ Fout: je neemt aan wat je moet bewijzen (cirkelredenering). Redeneer vanuit het gegeven naar de conclusie, niet andersom.</div></div><div class="sam-head">Herleiden en ontbinden</div><p>Veel opgaven beginnen met <strong>herleiden</strong>: een uitdrukking netjes vereenvoudigen. Ken de <strong>merkwaardige producten</strong> uit je hoofd — daarmee ontbind je snel in factoren:</p><div class="sam-formula-box"><div class="sam-formula-label">Merkwaardige producten</div><div class="sam-formula-eq">(a + b)² = a² + 2ab + b²<br>(a − b)² = a² − 2ab + b²<br>(a + b)(a − b) = a² − b²</div><div class="sam-formula-note">Van links naar rechts is het uitwerken, van rechts naar links <strong>ontbinden</strong>. Ontbinden heb je nodig om vergelijkingen op te lossen (product = 0).</div></div><div class="sam-definitie"><div class="sam-definitie-term">Exact antwoord</div><div class="sam-definitie-body">Een antwoord waarin je wortels, π en breuken láát staan in plaats van ze af te ronden. √2, ⅓ en ½π zijn exact; 1,41 en 0,33 zijn dat niet.</div></div><div class="sam-head">Soorten bewijs</div><p>Op het examen kom je een paar bewijsvormen tegen. Weet welke je inzet:</p><div class="sam-proces"><div class="sam-proces-step"><span class="sam-proces-num">1</span><span><strong>Direct bewijs</strong> — redeneer van het gegeven via geldige stappen naar de bewering.</span></div><div class="sam-proces-step"><span class="sam-proces-num">2</span><span><strong>Uit het ongerijmde</strong> — neem aan dat het níét waar is en leid een tegenspraak af.</span></div><div class="sam-proces-step"><span class="sam-proces-num">3</span><span><strong>Tegenvoorbeeld</strong> — om een bewering te weerleggen is één tegenvoorbeeld genoeg.</span></div></div><div class="sam-val"><ul><li>Afronden waar <strong>exact</strong> gevraagd wordt — dan is het antwoord fout, ook al klopt de decimaal ongeveer.</li><li>Bij ontbinden een <strong>teken</strong> vergeten: x² − 5x + 6 = (x − 2)(x − 3), niet (x + 2)(x + 3).</li><li><strong>Cirkelredenering</strong>: de te bewijzen bewering al als gegeven gebruiken.</li><li>Tussenstappen weglaten — het nakijkmodel beloont juist de <strong>redenering</strong>, niet alleen de uitkomst.</li></ul></div><div class="sam-onthoud"><ul style="margin:0;padding-left:16px"><li style="margin-bottom:3px">Exact = wortels, π en breuken laten staan.</li><li style="margin-bottom:3px">Merkwaardige producten uit je hoofd → snel ontbinden.</li><li style="margin-bottom:3px">Elke bewijsstap heeft een <strong>benoemde reden</strong>.</li><li style="margin-bottom:3px">Van gegeven → conclusie, nooit andersom.</li></ul></div>`,
'vwo_wa_A':`<div class="sam-intro"><strong>Vaardigheden</strong> zijn het gereedschap onder alle wiskunde A: vlot <strong>algebraïsch</strong> werken, handig <strong>rekenen met de grafische rekenmachine (GR)</strong>, en <strong>formules herleiden</strong> zodat je de gevraagde grootheid vrijmaakt.</div><div class="sam-chips"><span class="sam-chip sam-chip-lead">Kern</span><span class="sam-chip">Algebra</span><span class="sam-chip">Formules herleiden</span><span class="sam-chip">GR</span><span class="sam-chip">Exact vs. benaderen</span><span class="sam-chip">Interpreteren</span></div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Algebra</td><td>haakjes, breuken, machten netjes bewerken</td></tr><tr><td>Formules herleiden</td><td>een variabele vrijmaken</td></tr><tr><td>GR gebruiken</td><td>snijpunten, tabellen, opties</td></tr><tr><td>Exact vs. benaderen</td><td>wanneer een decimaal, wanneer exact</td></tr></tbody></table><div class="sam-head">Formules herleiden</div><p>Vaak staat de gezochte grootheid niet alleen. <strong>Herleiden</strong> is het stap voor stap vrijmaken van die variabele, door aan beide kanten dezelfde bewerking te doen (optellen, delen, worteltrekken). De balans blijft in evenwicht zolang je links én rechts hetzelfde doet.</p><div class="sam-formula-box"><div class="sam-formula-label">Voorbeeld van herleiden</div><div class="sam-formula-eq">A = ½·b·h   →   maak h vrij<br>2A = b·h   →   h = 2A / b</div><div class="sam-formula-note">Werk symmetrisch: eerst ×2 aan beide kanten, dan delen door b. Zo isoleer je h zonder de gelijkheid te verstoren.</div></div><div class="sam-head">Rekenen met de GR</div><p>De <strong>grafische rekenmachine</strong> is op het examen onmisbaar. Kies bewust je gereedschap: teken een grafiek om het <em>type</em> verband te zien, gebruik <strong>intersect</strong> voor snijpunten (vergelijkingen), en een <strong>tabel</strong> om waarden af te lezen. Noteer wél de gebruikte methode in je uitwerking.</p><div class="sam-tip"><strong>Exact of benaderd?</strong> Vraagt de opgave "exact", dan mag er geen afgeronde decimaal in je antwoord staan (laat bv. een breuk of √2 staan). Vraagt hij een aantal decimalen of "met de GR", dan mag je benaderen — rond pas op het eind af.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — formule herleiden</div><div class="sam-worked-q">Gegeven de formule T = 2π√(L/g). Maak L vrij.</div><ol class="sam-worked-steps"><li>Deel door 2π: T/(2π) = √(L/g).</li><li>Kwadrateer beide kanten: (T/(2π))² = L/g.</li><li>Vermenigvuldig met g: L = g·(T/(2π))².</li></ol><div class="sam-worked-ans">✅ L = g·(T/(2π))²: stap voor stap dezelfde bewerking links en rechts.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — GR-methode</div><div class="sam-worked-q">Je moet de oplossing van 2ˣ = x + 3 vinden, wat algebraïsch niet lukt. Hoe pak je dit met de GR aan?</div><ol class="sam-worked-steps"><li>Voer y₁ = 2ˣ en y₂ = x + 3 in.</li><li>Teken beide grafieken.</li><li>Gebruik intersect voor het snijpunt (de x-waarde).</li></ol><div class="sam-worked-ans">✅ Snijpunt van y = 2ˣ en y = x + 3 met de intersect-functie; de x-coördinaat is de oplossing.</div></div><div class="sam-head">GR-functies die je moet beheersen</div><table class="sam-table"><thead><tr><th>Wil je…</th><th>GR-functie</th></tr></thead><tbody><tr><td>een vergelijking oplossen</td><td>grafieken tekenen + <strong>intersect</strong></td></tr><tr><td>waarden aflezen</td><td><strong>table</strong> (tabel)</td></tr><tr><td>een top/dal vinden</td><td><strong>maximum/minimum</strong> in calc-menu</td></tr><tr><td>een kans berekenen</td><td><strong>binomcdf</strong> / <strong>normalcdf</strong></td></tr></tbody></table><div class="sam-definitie"><div class="sam-definitie-term">Herleiden</div><div class="sam-definitie-body">Een formule stap voor stap omschrijven om één variabele vrij te maken. Je doet links én rechts dezelfde bewerking, zodat de gelijkheid blijft kloppen.</div></div><div class="sam-head">Exact of benaderen — wanneer wat</div><p>Staat er <strong>"exact"</strong>, dan mag er geen afgeronde decimaal in je antwoord: laat √, π of een breuk staan. Vraagt de opgave om decimalen of "met de GR", dan mag je <strong>benaderen</strong> — maar rond pas op het <strong>allerlaatst</strong> af, anders stapelen afrondfouten zich op.</p><div class="sam-val"><ul><li><strong>Te vroeg afronden</strong> in tussenstappen → eindantwoord net verkeerd.</li><li>De <strong>gebruikte GR-methode niet noteren</strong> — dan mist het nakijkmodel je onderbouwing.</li><li>Bij herleiden een bewerking maar aan <strong>één kant</strong> uitvoeren.</li><li>Haakjes/tekens fout: −(a − b) = −a + b, niet −a − b.</li></ul></div><div class="sam-onthoud"><ul style="margin:0;padding-left:16px"><li style="margin-bottom:3px">Herleiden = dezelfde bewerking links én rechts.</li><li style="margin-bottom:3px">intersect voor vergelijkingen, table voor aflezen.</li><li style="margin-bottom:3px">Exact → √/π/breuk laten staan; anders pas op het eind afronden.</li><li style="margin-bottom:3px">Noteer altijd welke methode je gebruikt.</li></ul></div>`,
'vwo_wb_F':`<div class="sam-intro"><strong>Keuzeonderwerpen</strong> zijn wiskunde-B-onderwerpen die per <strong>school</strong> (en examenjaar) verschillen: je school kiest een verdiepend thema uit de syllabus. Omdat de inhoud wisselt, gaat deze samenvatting over <strong>hoe</strong> je een keuzeonderwerp aanpakt — en over de vaardigheden die er altijd bij horen.</div><div class="sam-chips"><span class="sam-chip sam-chip-lead">Kern</span><span class="sam-chip">Schoolspecifiek</span><span class="sam-chip">Syllabus</span><span class="sam-chip">Bewijzen</span><span class="sam-chip">Oude examens</span></div><div class="sam-head">Wat je moet weten over keuzeonderwerpen</div><table class="sam-table"><thead><tr><th>Punt</th><th>Kern</th></tr></thead><tbody><tr><td>Schoolspecifiek</td><td>je docent/school kiest het onderwerp</td></tr><tr><td>Uit de syllabus</td><td>vaste lijst mogelijke thema's per jaar</td></tr><tr><td>Op het CE</td><td>het gekozen onderwerp kan op het examen komen</td></tr><tr><td>Vaardigheden</td><td>bewijzen, redeneren, algebraïsch rekenen</td></tr></tbody></table><div class="sam-head">Wat is een keuzeonderwerp?</div><p>De syllabus laat voor wiskunde B ruimte voor een <strong>verdiepend thema</strong> dat de school kiest. Voorbeelden die in de loop der jaren voorkwamen zijn <strong>complexe getallen</strong>, <strong>bewijzen in de meetkunde</strong> of <strong>dynamische systemen</strong>. Welk onderwerp jóúw examen betreft, hoor je van je docent — controleer de vakspecifieke informatie op examenblad.nl voor jouw jaar.</p><div class="sam-tip"><strong>Zoek eerst uit wélk keuzeonderwerp jouw school doet.</strong> Anders leer je de verkeerde stof. Vraag je docent of raadpleeg de vakspecifieke informatie/syllabus van jouw examenjaar; oefen daarna gericht met oude examens over dat thema.</div><div class="sam-head">Hoe pak je het aan?</div><p>Welk thema het ook is, je leunt op de <strong>kernvaardigheden</strong> van wiskunde B:</p><ul><li><strong>Bewijzen:</strong> redeneer stap voor stap, met geldige argumenten, naar de conclusie.</li><li><strong>Algebraïsch rekenen:</strong> herleiden, differentiëren/integreren, vergelijkingen oplossen.</li><li><strong>Meetkundig inzicht:</strong> figuren, symmetrie en verbanden herkennen.</li><li><strong>Exact formuleren:</strong> noteer je stappen volledig en ondubbelzinnig.</li></ul><div class="sam-head">Oefenen met oude examens</div><p>De beste voorbereiding is <strong>oefenen met oude examenopgaven</strong> over het specifieke keuzeonderwerp. Je leert het vraagtype, de standaardaanpak en — via de <strong>nakijkmodellen</strong> — precies hoe je een bewijs of berekening moet opschrijven om alle punten te pakken.</p><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — juiste stof leren</div><div class="sam-worked-q">Je weet niet welk keuzeonderwerp op jouw examen komt. Wat is de verstandigste eerste stap?</div><ol class="sam-worked-steps"><li>Het onderwerp is schoolspecifiek.</li><li>Alleen jouw school/docent weet welke gekozen is.</li><li>Vraag het na (of check de syllabus van jouw jaar).</li></ol><div class="sam-worked-ans">✅ Eerst uitzoeken wélk keuzeonderwerp jouw school behandelt — pas dan leer je de juiste stof.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — bewijsvraag</div><div class="sam-worked-q">Bij veel wiskunde-B-keuzeonderwerpen hoort een bewijs. Waar moet je bij het opschrijven vooral op letten?</div><ol class="sam-worked-steps"><li>Elke stap moet een geldige, benoemde reden hebben.</li><li>Ga van het gegeven naar de te bewijzen bewering.</li><li>Laat geen sprongen over; noteer volledig.</li></ol><div class="sam-worked-ans">✅ Redeneer volledig en stap voor stap met geldige argumenten, van gegeven naar conclusie — het nakijkmodel beloont juist die tussenstappen.</div></div><div class="sam-head">Voorbeelden van keuzeonderwerpen</div><p>Welk thema je school ook koos, de aanpak lijkt op elkaar. Veelvoorkomende keuzeonderwerpen:</p><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Waar het om draait</th></tr></thead><tbody><tr><td>Complexe getallen</td><td>rekenen met i (i² = −1), modulus en argument, het complexe vlak</td></tr><tr><td>Meetkundig bewijzen</td><td>stellingen bewijzen met hoeken, gelijkvormigheid en cirkels</td></tr><tr><td>Dynamische systemen / rijen</td><td>recursie, evenwicht en gedrag op lange termijn</td></tr></tbody></table><div class="sam-val"><ul><li>De <strong>verkeerde stof</strong> leren omdat je niet nagevraagd hebt welk onderwerp jouw school doet.</li><li>Een syllabus van het <strong>verkeerde examenjaar</strong> gebruiken.</li><li>Bij een bewijs stappen overslaan — juist hier telt de volledige redenering.</li></ul></div><div class="sam-onthoud"><ul style="margin:0;padding-left:16px"><li style="margin-bottom:3px">Zoek éérst uit wélk keuzeonderwerp jouw school behandelt.</li><li style="margin-bottom:3px">Check de vakspecifieke info/syllabus van jóúw examenjaar.</li><li style="margin-bottom:3px">Oefen gericht met oude examens over dat thema.</li><li style="margin-bottom:3px">Kernvaardigheden blijven: bewijzen, algebra, exact noteren.</li></ul></div>`,
'vwo_wa_F':`<div class="sam-intro"><strong>Keuzeonderwerpen</strong> zijn wiskunde-A-onderwerpen die per <strong>school</strong> (en examenjaar) verschillen: je school kiest een verdiepend thema uit de syllabus. Omdat de inhoud wisselt, draait deze samenvatting om <strong>hoe</strong> je een keuzeonderwerp aanpakt — en om de vaardigheden die er altijd bij horen.</div><div class="sam-chips"><span class="sam-chip sam-chip-lead">Kern</span><span class="sam-chip">Schoolspecifiek</span><span class="sam-chip">Syllabus</span><span class="sam-chip">Modelleren</span><span class="sam-chip">Oude examens</span></div><div class="sam-head">Wat je moet weten over keuzeonderwerpen</div><table class="sam-table"><thead><tr><th>Punt</th><th>Kern</th></tr></thead><tbody><tr><td>Schoolspecifiek</td><td>je docent/school kiest het onderwerp</td></tr><tr><td>Uit de syllabus</td><td>vaste lijst mogelijke thema's per jaar</td></tr><tr><td>Op het CE</td><td>het gekozen onderwerp kan op het examen komen</td></tr><tr><td>Vaardigheden</td><td>modelleren, redeneren, rekentechniek</td></tr></tbody></table><div class="sam-head">Wat is een keuzeonderwerp?</div><p>De syllabus laat voor wiskunde A ruimte voor een <strong>verdiepend thema</strong> dat de school kiest. Voorbeelden die in de loop der jaren voorkwamen zijn <strong>differentievergelijkingen</strong>, verdiepende <strong>statistiek</strong> of een toepassing van <strong>analyse</strong>. Welk onderwerp jóúw examen betreft, hoor je van je docent — check de vakspecifieke informatie op examenblad.nl voor jouw jaar.</p><div class="sam-tip"><strong>Zoek eerst uit wélk keuzeonderwerp jouw school doet.</strong> Anders leer je de verkeerde stof. Vraag je docent, of kijk in de vakspecifieke informatie/syllabus van jouw examenjaar. Pas daarna kun je gericht oefenen met oude examens over dat onderwerp.</div><div class="sam-head">Hoe pak je het aan?</div><p>Ongeacht het gekozen thema gebruik je dezelfde <strong>kernvaardigheden</strong> van wiskunde A:</p><ul><li><strong>Modelleren:</strong> vertaal een situatie naar een formule, tabel of grafiek en terug.</li><li><strong>Redeneren:</strong> onderbouw stappen; gebruik een tegenvoorbeeld om iets te weerleggen.</li><li><strong>Rekentechniek:</strong> werk nauwkeurig met formules, de GR en eenheden.</li><li><strong>Interpreteren:</strong> geef je antwoord betekenis in de context.</li></ul><div class="sam-head">Oefenen met oude examens</div><p>De beste voorbereiding op een keuzeonderwerp is <strong>oefenen met oude examenopgaven</strong> over dat specifieke thema. Zo leer je het type vraag kennen, de standaardaanpak, en welke stappen punten opleveren. Let daarbij op de <strong>nakijkmodellen</strong>: die laten precies zien hoe je moet noteren.</p><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — juiste stof leren</div><div class="sam-worked-q">Je weet niet welk keuzeonderwerp op jouw examen komt. Wat is de verstandigste eerste stap?</div><ol class="sam-worked-steps"><li>Het onderwerp is schoolspecifiek.</li><li>Alleen jouw school/docent weet welke gekozen is.</li><li>Vraag het na (of check de syllabus van jouw jaar).</li></ol><div class="sam-worked-ans">✅ Eerst uitzoeken wélk keuzeonderwerp jouw school behandelt — pas dan leer je de juiste stof.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — aanpak</div><div class="sam-worked-q">Je krijgt een contextopgave over het keuzeonderwerp. Welke algemene aanpak past altijd?</div><ol class="sam-worked-steps"><li>Vertaal de context naar een wiskundig model.</li><li>Reken netjes en met de juiste eenheden.</li><li>Vertaal het antwoord terug naar de context.</li></ol><div class="sam-worked-ans">✅ Modelleren → rekenen → terugvertalen: de vaste wiskunde-A-aanpak werkt bij elk keuzeonderwerp.</div></div><div class="sam-head">Voorbeelden van keuzeonderwerpen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Waar het om draait</th></tr></thead><tbody><tr><td>Differentievergelijkingen / rijen</td><td>recursie, groei stap voor stap, evenwicht</td></tr><tr><td>Verdiepende statistiek</td><td>correlatie, regressie, toetsen</td></tr><tr><td>Toepassing van analyse</td><td>optimaliseren met de afgeleide in een context</td></tr></tbody></table><div class="sam-val"><ul><li>De <strong>verkeerde stof</strong> leren omdat je niet nagevraagd hebt welk onderwerp jouw school doet.</li><li>Een syllabus van het <strong>verkeerde examenjaar</strong> gebruiken.</li><li>Het antwoord niet <strong>terugvertalen</strong> naar de context.</li></ul></div><div class="sam-onthoud"><ul style="margin:0;padding-left:16px"><li style="margin-bottom:3px">Zoek éérst uit wélk keuzeonderwerp jouw school behandelt.</li><li style="margin-bottom:3px">Check de vakspecifieke info/syllabus van jóúw examenjaar.</li><li style="margin-bottom:3px">Oefen gericht met oude examens over dat thema.</li><li style="margin-bottom:3px">Vaste aanpak: modelleren → rekenen → terugvertalen.</li></ul></div>`,
'vwo_gs_E':`<div class="sam-intro"><strong>Oriëntatie op studie en beroep</strong> laat zien wat geschiedenis je oplevert ná school. Je leert welke <strong>transferabele vaardigheden</strong> het vak traint — <strong>bronkritiek</strong>, <strong>argumenteren</strong>, chronologisch en causaal denken — en bij welke <strong>opleidingen en beroepen</strong> die van pas komen.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Transferabele vaardigheden</td><td>breed inzetbaar buiten het vak</td></tr><tr><td>Bronkritiek</td><td>informatie op betrouwbaarheid beoordelen</td></tr><tr><td>Argumenteren</td><td>standpunt onderbouwen met bewijs</td></tr><tr><td>Historisch redeneren</td><td>oorzaak-gevolg, continuïteit-verandering</td></tr><tr><td>Beroepen &amp; studies</td><td>waar historisch inzicht telt</td></tr></tbody></table><div class="sam-head">Transferabele vaardigheden</div><p><strong>Transferabele vaardigheden</strong> zijn vaardigheden die je in geschiedenis leert maar <strong>breed</strong> kunt gebruiken — in een studie, beroep of het dagelijks leven. Geschiedenis is er sterk in:</p><table class="sam-table"><thead><tr><th>Vaardigheid</th><th>Waar je die later gebruikt</th></tr></thead><tbody><tr><td>Bronkritiek</td><td>nieuws, data en claims op waarde schatten</td></tr><tr><td>Argumenteren</td><td>een onderbouwd betoog opbouwen</td></tr><tr><td>Causaal &amp; chronologisch denken</td><td>oorzaken, gevolgen en volgorde ordenen</td></tr><tr><td>Perspectief nemen</td><td>een kwestie van meerdere kanten bezien</td></tr></tbody></table><div class="sam-tip"><strong>Bronkritiek</strong> is misschien wel de nuttigste vaardigheid: dezelfde vragen die je bij een historische bron stelt — wie, wanneer, met welk doel? — pas je toe op een nieuwsbericht of social-mediapost om nepnieuws te herkennen.</div><div class="sam-head">Opleidingen en beroepen</div><p>Historisch inzicht en deze vaardigheden komen terug in veel richtingen:</p><table class="sam-table"><thead><tr><th>Richting/beroep</th><th>Wat je met geschiedenis kunt</th></tr></thead><tbody><tr><td>Archivaris / historicus</td><td>bronnen bewaren, ontsluiten, onderzoeken</td></tr><tr><td>Journalistiek</td><td>bronnen checken, context bieden</td></tr><tr><td>Rechten / bestuurskunde</td><td>staat, politiek en recht analyseren</td></tr><tr><td>Erfgoed / musea</td><td>cultureel erfgoed beheren en duiden</td></tr></tbody></table><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — vaardigheid koppelen</div><div class="sam-worked-q">Welke historische vaardigheid gebruik je direct bij het beoordelen van nieuwsberichten op betrouwbaarheid?</div><ol class="sam-worked-steps"><li>Je vraagt: wie maakte dit, wanneer, met welk doel?</li><li>Dat zijn precies de vragen van bronkritiek.</li><li>Zo scheid je betrouwbaar van gekleurd.</li></ol><div class="sam-worked-ans">✅ Bronkritiek: informatie beoordelen op herkomst, doel en betrouwbaarheid — cruciaal tegen nepnieuws.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — studie kiezen</div><div class="sam-worked-q">Iemand wil historisch inzicht combineren met de analyse van politiek en staatsinrichting. Welke universitaire richting past?</div><ol class="sam-worked-steps"><li>Het gaat om politiek en de inrichting van de staat.</li><li>Gecombineerd met historisch inzicht.</li><li>Dat past bij bestuurskunde/politicologie of rechten.</li></ol><div class="sam-worked-ans">✅ Een richting als politicologie/bestuurskunde of rechten: daar komen historisch inzicht en staatsinrichting samen.</div></div>`,
'vwo_mw_D':`<div class="sam-intro"><strong>Binding</strong> is een van de vier hoofdconcepten: het gaat over wat mensen en groepen met de samenleving <strong>verbindt</strong>. Je leert wat <strong>sociale cohesie</strong> is, welke rol <strong>instituties</strong> (gezin, school, staat) spelen, wat er gebeurt bij <strong>anomie</strong>, en hoe de <strong>verzorgingsstaat</strong> binding organiseert.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Begrip</th><th>Kern</th></tr></thead><tbody><tr><td>Sociale cohesie</td><td>samenhang; verbondenheid in een groep</td></tr><tr><td>Instituties</td><td>vaste patronen: gezin, school, staat</td></tr><tr><td>Socialisatie</td><td>normen en waarden overdragen</td></tr><tr><td>Anomie</td><td>normverval; zwakke binding</td></tr><tr><td>Verzorgingsstaat</td><td>collectieve zekerheid en zorg</td></tr></tbody></table><div class="sam-head">Sociale cohesie</div><p><strong>Sociale cohesie</strong> is de mate waarin mensen zich met elkaar en met de samenleving <strong>verbonden</strong> voelen en zich naar gedeelde normen gedragen. Sterke cohesie geeft stabiliteit; zwakke cohesie leidt tot onderling wantrouwen en uitsluiting.</p><div class="sam-head">Instituties</div><p><strong>Instituties</strong> zijn vaste, algemeen erkende patronen van gedrag en regels — zoals het <strong>gezin</strong>, de <strong>school</strong>, de <strong>kerk</strong> en de <strong>staat</strong>. Ze vervullen twee kernfuncties voor binding:</p><div class="sam-compare"><div class="sam-compare-col"><div class="sam-compare-head">Socialisatie</div><ul><li>normen en waarden overdragen</li><li>bv. gezin en school</li><li>vorming van nieuwe leden</li></ul></div><div class="sam-compare-col"><div class="sam-compare-head">Sociale controle</div><ul><li>gedrag in het spoor houden</li><li>formeel (wetten) en informeel</li><li>afwijking corrigeren</li></ul></div></div><div class="sam-head">Anomie: als binding wegvalt</div><p><strong>Anomie</strong> (Durkheim) is een toestand van <strong>normverval</strong>: de gedeelde normen verzwakken of ontbreken, bijvoorbeeld bij snelle maatschappelijke verandering. Mensen weten dan niet meer goed wat "hoort", wat de sociale binding ondermijnt.</p><div class="sam-figure"><svg viewBox="0 0 300 96" role="img" aria-label="Sterke binding met veel verbindingen tussen mensen versus anomie met weinig verbindingen"><g><text x="75" y="14" font-size="7.5" font-weight="700" fill="var(--dk)" text-anchor="middle">sterke cohesie</text><g fill="var(--or)"><circle cx="45" cy="40" r="4"/><circle cx="105" cy="40" r="4"/><circle cx="60" cy="72" r="4"/><circle cx="95" cy="72" r="4"/><circle cx="75" cy="54" r="4"/></g><g stroke="var(--or)" stroke-width="1.1"><line x1="45" y1="40" x2="105" y2="40"/><line x1="45" y1="40" x2="75" y2="54"/><line x1="105" y1="40" x2="75" y2="54"/><line x1="60" y1="72" x2="75" y2="54"/><line x1="95" y1="72" x2="75" y2="54"/><line x1="60" y1="72" x2="95" y2="72"/></g></g><line x1="160" y1="18" x2="160" y2="86" stroke="var(--bo)" stroke-width="1"/><g><text x="235" y="14" font-size="7.5" font-weight="700" fill="var(--dk)" text-anchor="middle">anomie</text><g fill="var(--mu)"><circle cx="205" cy="40" r="4"/><circle cx="265" cy="40" r="4"/><circle cx="220" cy="72" r="4"/><circle cx="255" cy="72" r="4"/><circle cx="235" cy="54" r="4"/></g><line x1="205" y1="40" x2="235" y2="54" stroke="var(--mu)" stroke-width="1.1"/></g></svg><div class="sam-figcap"><strong>Veel of weinig binding:</strong> bij sterke <strong>cohesie</strong> zijn er veel verbindingen tussen mensen (links). Bij <strong>anomie</strong> vallen die grotendeels weg (rechts): weinig gedeelde normen, weinig binding.</div></div><div class="sam-head">De verzorgingsstaat</div><p>De <strong>verzorgingsstaat</strong> organiseert binding op nationaal niveau: de overheid zorgt via <strong>collectieve voorzieningen</strong> (uitkeringen, zorg, onderwijs, AOW) voor bestaanszekerheid. Zo bindt de staat burgers en dempt hij ongelijkheid — al staat de betaalbaarheid ervan onder druk (individualisering, vergrijzing).</p><div class="sam-tip"><strong>Koppel aan het hoofdconcept binding:</strong> cohesie, instituties, socialisatie, sociale controle en de verzorgingsstaat zijn allemaal manieren waarop de samenleving <em>samenhang</em> creëert. Anomie is juist het <em>tekort</em> aan binding. Benoem dat verband in een analysevraag.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — functie van een institutie</div><div class="sam-worked-q">Welke twee functies hebben instituties zoals het gezin en de school voor de binding in de samenleving?</div><ol class="sam-worked-steps"><li>Ze dragen normen en waarden over → socialisatie.</li><li>Ze houden gedrag in het spoor → sociale controle.</li><li>Beide versterken de sociale cohesie.</li></ol><div class="sam-worked-ans">✅ Socialisatie (normen en waarden overdragen) en sociale controle (gedrag reguleren) — samen versterken ze de binding.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — anomie herkennen</div><div class="sam-worked-q">Na een snelle maatschappelijke omwenteling weten veel mensen niet meer welke normen gelden en neemt wantrouwen toe. Welk begrip past?</div><ol class="sam-worked-steps"><li>De gedeelde normen zijn onduidelijk geworden.</li><li>Dat is normverval.</li><li>Durkheim noemt dit anomie.</li></ol><div class="sam-worked-ans">✅ Anomie: een toestand van normverval en zwakke binding, vaak door snelle verandering.</div></div>`,
'vwo_wa_D':`<div class="sam-intro"><strong>Verandering</strong> is de differentiaalrekening van wiskunde A: je gebruikt de <strong>afgeleide</strong> om te bepalen hoe snel iets verandert. Je leert het verschil tussen <strong>gemiddelde</strong> en <strong>momentane</strong> verandering, hoe je met f′(x) <strong>toppen</strong> en <strong>buigpunten</strong> vindt, en hoe je dit in een context (snelheid, groei) toepast.</div><div class="sam-chips"><span class="sam-chip sam-chip-lead">Kern</span><span class="sam-chip">Afgeleide</span><span class="sam-chip">Gemiddeld vs. momentaan</span><span class="sam-chip">Extremen</span><span class="sam-chip">Buigpunt</span><span class="sam-chip">Context</span></div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Afgeleide</td><td>f′(x) = helling / veranderingssnelheid</td></tr><tr><td>Gemiddeld vs. momentaan</td><td>over een interval vs. op één punt</td></tr><tr><td>Extremen</td><td>f′(x) = 0: top of dal</td></tr><tr><td>Buigpunt</td><td>waar de kromming omslaat</td></tr><tr><td>Context</td><td>snelheid, toename, afname</td></tr></tbody></table><div class="sam-head">Gemiddelde en momentane verandering</div><p>De <strong>gemiddelde verandering</strong> tussen twee punten is de helling van de lijn ertussen (het differentiequotiënt). De <strong>momentane verandering</strong> is de verandering op één <strong>moment</strong> — de helling van de <strong>raaklijn</strong>, oftewel de afgeleide f′(x).</p><div class="sam-formula-box"><div class="sam-formula-label">Verandering</div><div class="sam-formula-eq">gemiddeld:  Δy/Δx = (f(b) − f(a)) / (b − a)<br>momentaan:  f′(x)   (helling van de raaklijn)</div><div class="sam-formula-note">De afgeleide bereken je met vaste regels (o.a. de machtsregel: f(x)=a·xⁿ → f′(x)=a·n·xⁿ⁻¹). f′(x) is zelf weer een functie.</div></div><div class="sam-head">Toppen en buigpunten</div><p>De afgeleide vertelt je alles over het <strong>verloop</strong> van de grafiek. Waar f′(x) = 0 ligt een <strong>top</strong> of <strong>dal</strong>; het teken van f′ eromheen zegt welke:</p><div class="sam-figure"><svg viewBox="0 0 300 120" role="img" aria-label="Een grafiek met een maximum, een minimum en het bijbehorende teken van de afgeleide"><line x1="30" y1="100" x2="288" y2="100" stroke="var(--mu)" stroke-width="1.3"/><line x1="40" y1="110" x2="40" y2="12" stroke="var(--mu)" stroke-width="1.3"/><path d="M48,70 C90,20 120,20 150,60 C180,100 210,100 250,50" fill="none" stroke="var(--or)" stroke-width="2.4"/><circle cx="112" cy="30" r="3.5" fill="var(--or)"/><circle cx="188" cy="90" r="3.5" fill="var(--or)"/><text x="112" y="22" font-size="7" font-weight="700" fill="var(--or)" text-anchor="middle">max: f′=0</text><text x="188" y="112" font-size="7" font-weight="700" fill="var(--or)" text-anchor="middle">min: f′=0</text><text x="72" y="52" font-size="6.5" fill="var(--mu)">f′&gt;0</text><text x="150" y="52" font-size="6.5" fill="var(--mu)">f′&lt;0</text><text x="228" y="52" font-size="6.5" fill="var(--mu)">f′&gt;0</text></svg><div class="sam-figcap"><strong>Teken van de afgeleide:</strong> f′ &gt; 0 → stijgend, f′ &lt; 0 → dalend. In een <strong>maximum</strong> gaat f′ van + naar −, in een <strong>minimum</strong> van − naar +. Een <strong>buigpunt</strong> is waar de grafiek van hol naar bol overgaat (daar heeft f′ zelf een uiterste).</div></div><div class="sam-tip"><strong>Afgeleide in context:</strong> is y de afstand en x de tijd, dan is f′(x) de <strong>snelheid</strong>. Bij groei is f′ de groeisnelheid. Een <strong>negatieve</strong> afgeleide betekent afname; f′ = 0 een even stilstaand (maximaal/minimaal) moment.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — extremen bepalen</div><div class="sam-worked-q">Gegeven f(x) = x³ − 3x. Bepaal de x-waarden van de toppen.</div><ol class="sam-worked-steps"><li>f′(x) = 3x² − 3.</li><li>f′(x) = 0 → 3x² = 3 → x² = 1 → x = 1 of x = −1.</li><li>Tekenverloop: bij x = −1 max, bij x = 1 min.</li></ol><div class="sam-worked-ans">✅ Toppen bij x = −1 (maximum) en x = 1 (minimum).</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — momentane snelheid</div><div class="sam-worked-q">De afstand (m) is s(t) = t² (t in s). Wat is de momentane snelheid op t = 3 s?</div><ol class="sam-worked-steps"><li>Snelheid = afgeleide: s′(t) = 2t.</li><li>Op t = 3: s′(3) = 2·3.</li><li>= 6 m/s.</li></ol><div class="sam-worked-ans">✅ 6 m/s: de momentane snelheid is de afgeleide s′(t) = 2t, ingevuld op t = 3.</div></div><div class="sam-definitie"><div class="sam-definitie-term">Momentane verandering</div><div class="sam-definitie-body">De veranderingssnelheid op één moment — de helling van de raaklijn in dat punt, oftewel de afgeleide f′(x). Anders dan de gemiddelde verandering, die over een heel interval geldt.</div></div><div class="sam-head">De afgeleide bepalen — regels</div><div class="sam-formula-box"><div class="sam-formula-label">Basisregels</div><div class="sam-formula-eq">machtsregel: f(x) = a·xⁿ → f′(x) = a·n·xⁿ⁻¹<br>som: (f + g)′ = f′ + g′<br>constante: (c)′ = 0</div><div class="sam-formula-note">De afgeleide f′ is zélf weer een functie; vul een x-waarde in voor de helling daar.</div></div><div class="sam-head">Stappenplan: toppen bepalen</div><div class="sam-proces"><div class="sam-proces-step"><span class="sam-proces-num">1</span><span>Bereken f′(x).</span></div><div class="sam-proces-step"><span class="sam-proces-num">2</span><span>Los f′(x) = 0 op → kandidaat-extremen.</span></div><div class="sam-proces-step"><span class="sam-proces-num">3</span><span>Onderzoek het <strong>teken</strong> van f′ eromheen.</span></div><div class="sam-proces-step"><span class="sam-proces-num">4</span><span>+ naar − = maximum, − naar + = minimum.</span></div></div><div class="sam-val"><ul><li><strong>Gemiddelde</strong> en <strong>momentane</strong> verandering verwarren.</li><li>Een extreem claimen zonder <strong>tekenonderzoek</strong>.</li><li>In een context de <strong>eenheden</strong> vergeten (m/s, €/jaar…).</li><li>Machtsregel fout: de −1 in de nieuwe exponent vergeten.</li></ul></div><div class="sam-onthoud"><ul style="margin:0;padding-left:16px"><li style="margin-bottom:3px">f′(x) = helling van de raaklijn = momentane verandering.</li><li style="margin-bottom:3px">Machtsregel: a·xⁿ → a·n·xⁿ⁻¹.</li><li style="margin-bottom:3px">f′ = 0 → mogelijk extreem; teken van f′ beslist max/min.</li><li style="margin-bottom:3px">In context: f′ = snelheid / groeisnelheid, met eenheid.</li></ul></div>`,
'vwo_wa_B':`<div class="sam-intro"><strong>Algebra en tellen</strong> is de rekentechnische basis van wiskunde A: vlot werken met <strong>machten</strong> en <strong>logaritmen</strong>, <strong>vergelijkingen en ongelijkheden</strong> oplossen, en <strong>telproblemen</strong> aanpakken met permutaties en combinaties.</div><div class="sam-chips"><span class="sam-chip sam-chip-lead">Kern</span><span class="sam-chip">Machten</span><span class="sam-chip">Logaritmen</span><span class="sam-chip">Exponentieel oplossen</span><span class="sam-chip">Permutatie</span><span class="sam-chip">Combinatie</span></div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Machten</td><td>rekenregels met exponenten</td></tr><tr><td>Logaritmen</td><td>de omgekeerde van machtsverheffen</td></tr><tr><td>Vergelijkingen</td><td>exponentieel &amp; logaritmisch oplossen</td></tr><tr><td>Telproblemen</td><td>permutaties (volgorde) vs. combinaties</td></tr></tbody></table><div class="sam-head">Machten en logaritmen</div><p>Een <strong>logaritme</strong> beantwoordt de vraag "tot welke macht moet ik het grondtal verheffen?". <sup>g</sup>log(a) = x betekent g<sup>x</sup> = a. Machten en logaritmen zijn elkaars omgekeerde, met bijbehorende rekenregels:</p><div class="sam-formula-box"><div class="sam-formula-label">Reken­regels</div><div class="sam-formula-eq">machten:  g<sup>a</sup> · g<sup>b</sup> = g<sup>a+b</sup>,   (g<sup>a</sup>)<sup>b</sup> = g<sup>a·b</sup><br>logaritmen:  <sup>g</sup>log(a) + <sup>g</sup>log(b) = <sup>g</sup>log(a·b)<br><sup>g</sup>log(a<sup>n</sup>) = n · <sup>g</sup>log(a)</div><div class="sam-formula-note">Voorbeeld: ²log(8) + ²log(4) = ²log(32) = 5, want 2⁵ = 32. Of los apart op: ²log(8)=3, ²log(4)=2, samen 5.</div></div><div class="sam-head">Exponentiële vergelijkingen</div><p>Bij een <strong>exponentiële vergelijking</strong> staat de onbekende in de exponent. Maak zo mogelijk de <strong>grondtallen gelijk</strong>, dan mag je de exponenten aan elkaar gelijkstellen; lukt dat niet, gebruik dan de logaritme.</p><div class="sam-head">Telproblemen: volgorde of niet?</div><p>De sleutelvraag bij <strong>tellen</strong>: doet de <strong>volgorde</strong> ertoe? Zo ja → <strong>permutatie</strong>; zo nee → <strong>combinatie</strong>.</p><div class="sam-figure"><svg viewBox="0 0 300 96" role="img" aria-label="Permutatie let op volgorde, combinatie niet"><g font-size="8" font-weight="700" fill="var(--dk)" text-anchor="middle"><rect x="14" y="20" width="122" height="24" rx="6" fill="var(--or)" opacity=".2" stroke="var(--or)" stroke-width="1.2"/><text x="75" y="35">permutatie: volgorde telt</text><rect x="164" y="20" width="122" height="24" rx="6" fill="var(--mu)" opacity=".14" stroke="var(--mu)" stroke-width="1.1"/><text x="225" y="35">combinatie: volgorde niet</text></g><text x="75" y="62" font-size="7" fill="var(--mu)" text-anchor="middle">bv. een podium (1e/2e/3e)</text><text x="225" y="62" font-size="7" fill="var(--mu)" text-anchor="middle">bv. een team van 3</text><text x="75" y="82" font-size="8" fill="var(--dk)" text-anchor="middle">nPr = n! / (n−r)!</text><text x="225" y="82" font-size="8" fill="var(--dk)" text-anchor="middle">nCr = n! / (r!·(n−r)!)</text></svg><div class="sam-figcap"><strong>Volgorde of niet:</strong> bij een <strong>permutatie</strong> maakt de volgorde uit (goud/zilver/brons is anders dan brons/zilver/goud) → nPr. Bij een <strong>combinatie</strong> telt alleen wélke je kiest, niet in welke volgorde (een team) → nCr = de "n boven r".</div></div><div class="sam-tip"><strong>Vuistregel tellen:</strong> "op hoeveel manieren kun je … <em>rangschikken</em>" → permutatie. "op hoeveel manieren kun je … <em>kiezen</em>" (zonder rangorde) → combinatie. Bij "en/na elkaar" vermenigvuldig je de mogelijkheden, bij "of" tel je op.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — exponentiële vergelijking</div><div class="sam-worked-q">Los op: 3<sup>x+2</sup> = 243.</div><ol class="sam-worked-steps"><li>243 = 3⁵, dus schrijf beide als macht van 3.</li><li>3<sup>x+2</sup> = 3⁵ → gelijke grondtallen, dus exponenten gelijk.</li><li>x + 2 = 5 → x = 3.</li></ol><div class="sam-worked-ans">✅ x = 3 (want 3³⁺² = 3⁵ = 243).</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — combinatie</div><div class="sam-worked-q">Uit een klas van 10 leerlingen kies je een groepje van 3 (volgorde maakt niet uit). Op hoeveel manieren kan dat?</div><ol class="sam-worked-steps"><li>Volgorde telt niet → combinatie: 10C3.</li><li>10C3 = 10! / (3!·7!) = (10·9·8)/(3·2·1).</li><li>= 720 / 6 = 120.</li></ol><div class="sam-worked-ans">✅ 120 manieren: er zijn 10-boven-3 = 120 mogelijke groepjes.</div></div><div class="sam-definitie"><div class="sam-definitie-term">Logaritme</div><div class="sam-definitie-body"><sup>g</sup>log(a) is het antwoord op de vraag "tot welke macht verhef ik g om a te krijgen?". Dus <sup>g</sup>log(a) = x ⇔ gˣ = a. Machtsverheffen en logaritme zijn elkaars omgekeerde.</div></div><div class="sam-head">Logaritme-rekenregels (compleet)</div><div class="sam-formula-box"><div class="sam-formula-label">Alle regels op een rij</div><div class="sam-formula-eq"><sup>g</sup>log(a·b) = <sup>g</sup>log a + <sup>g</sup>log b<br><sup>g</sup>log(a/b) = <sup>g</sup>log a − <sup>g</sup>log b<br><sup>g</sup>log(aⁿ) = n · <sup>g</sup>log a</div><div class="sam-formula-note">Let op: <sup>g</sup>log(a + b) is <strong>níét</strong> <sup>g</sup>log a + <sup>g</sup>log b. De regels gelden alleen voor keer/delen/macht.</div></div><div class="sam-head">Tellen: "en/of" en herhaling</div><div class="sam-proces"><div class="sam-proces-step"><span class="sam-proces-num">1</span><span><strong>"en" / na elkaar</strong> → de mogelijkheden <strong>vermenigvuldigen</strong>.</span></div><div class="sam-proces-step"><span class="sam-proces-num">2</span><span><strong>"of" / elkaar uitsluitend</strong> → de mogelijkheden <strong>optellen</strong>.</span></div><div class="sam-proces-step"><span class="sam-proces-num">3</span><span><strong>Volgorde telt</strong> → permutatie nPr = n!/(n−r)!.</span></div><div class="sam-proces-step"><span class="sam-proces-num">4</span><span><strong>Volgorde telt niet</strong> → combinatie nCr = n!/(r!(n−r)!).</span></div></div><div class="sam-val"><ul><li><strong>Permutatie en combinatie verwisselen</strong>: "kiezen" = combinatie, "rangschikken" = permutatie.</li><li>De logaritme van een <strong>som</strong> uitsplitsen (mag niet).</li><li>Bij gelijke grondtallen de exponenten gelijkstellen, maar vergeten dat het <strong>alleen</strong> mag als de grondtallen écht gelijk zijn.</li><li>0! = 1 vergeten.</li></ul></div><div class="sam-onthoud"><ul style="margin:0;padding-left:16px"><li style="margin-bottom:3px"><sup>g</sup>log(a) = x ⇔ gˣ = a.</li><li style="margin-bottom:3px">log van keer/delen/macht → +, −, ·n; nooit van een som.</li><li style="margin-bottom:3px">"en" → ×, "of" → +.</li><li style="margin-bottom:3px">Volgorde telt → permutatie; niet → combinatie.</li></ul></div>`,
'vwo_na_I':`<div class="sam-intro"><strong>Onderzoek en ontwerp</strong> gaat over de natuurkundige werkwijze: <strong>experimenteel onderzoek</strong> opzetten, iets <strong>ontwerpen</strong> volgens een programma van eisen, en vooral het correct omgaan met <strong>meetonzekerheid</strong> — significante cijfers, foutmarges en foutbalken in een grafiek.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Experimenteel onderzoek</td><td>variabelen, meetopstelling, herhalen</td></tr><tr><td>Ontwerpen</td><td>programma van eisen, testen, bijstellen</td></tr><tr><td>Meetonzekerheid</td><td>elke meting heeft een marge</td></tr><tr><td>Significante cijfers</td><td>niet nauwkeuriger dan je meet</td></tr><tr><td>Foutbalken</td><td>onzekerheid in een grafiek</td></tr></tbody></table><div class="sam-head">Experimenteel onderzoek en ontwerpen</div><p>Bij <strong>onderzoek</strong> beantwoord je een vraag door te meten: je varieert de <strong>onafhankelijke</strong> variabele, meet de <strong>afhankelijke</strong>, en houdt de rest constant. Bij <strong>ontwerpen</strong> maak je iets dat aan een <strong>programma van eisen</strong> voldoet; je bouwt een prototype, <strong>test</strong> het aan de eisen en <strong>stelt bij</strong>.</p><div class="sam-head">Meetonzekerheid</div><p>Geen enkele meting is oneindig nauwkeurig. Elke meetwaarde heeft een <strong>onzekerheid</strong> (marge), bijvoorbeeld 12,3 ± 0,1 cm. Je noteert een resultaat met het juiste aantal <strong>significante cijfers</strong>: niet nauwkeuriger dan je meetinstrument toelaat.</p><div class="sam-formula-box"><div class="sam-formula-label">Onzekerheid en significante cijfers</div><div class="sam-formula-eq">resultaat = meetwaarde ± onzekerheid<br>bij optellen: absolute onzekerheden optellen<br>bij ×/÷: relatieve (procentuele) onzekerheden optellen</div><div class="sam-formula-note">Rond het eindantwoord af op net zoveel significante cijfers als de minst nauwkeurige meting. Meer cijfers opschrijven suggereert een schijnnauwkeurigheid die er niet is.</div></div><div class="sam-head">Foutbalken en een trendlijn</div><p>In een grafiek geef je de onzekerheid weer met <strong>foutbalken</strong>: streepjes die aangeven hoe zeker elk punt is. Een goede <strong>trendlijn</strong> hoeft niet exact door de punten te gaan, maar wél binnen de foutbalken te passen.</p><div class="sam-figure"><svg viewBox="0 0 300 120" role="img" aria-label="Grafiek met meetpunten, foutbalken en een trendlijn die binnen de marges past"><line x1="34" y1="100" x2="288" y2="100" stroke="var(--mu)" stroke-width="1.4"/><line x1="34" y1="108" x2="34" y2="12" stroke="var(--mu)" stroke-width="1.4"/><text x="285" y="114" font-size="7.5" fill="var(--mu)" text-anchor="end">x</text><text x="12" y="20" font-size="7.5" fill="var(--mu)">y</text><line x1="40" y1="96" x2="270" y2="30" stroke="var(--or)" stroke-width="2"/><g stroke="var(--dk)" stroke-width="1.2"><line x1="80" y1="74" x2="80" y2="94"/><line x1="76" y1="74" x2="84" y2="74"/><line x1="76" y1="94" x2="84" y2="94"/><line x1="150" y1="54" x2="150" y2="74"/><line x1="146" y1="54" x2="154" y2="54"/><line x1="146" y1="74" x2="154" y2="74"/><line x1="220" y1="34" x2="220" y2="54"/><line x1="216" y1="34" x2="224" y2="34"/><line x1="216" y1="54" x2="224" y2="54"/></g><g fill="var(--dk)"><circle cx="80" cy="84" r="2.6"/><circle cx="150" cy="64" r="2.6"/><circle cx="220" cy="44" r="2.6"/></g><text x="250" y="28" font-size="7" fill="var(--or)">trendlijn</text></svg><div class="sam-figcap"><strong>Foutbalken:</strong> elk meetpunt heeft een verticale marge (de onzekerheid). De <strong>trendlijn</strong> is goed als hij binnen (bijna) alle foutbalken valt — hij hoeft niet precies door de punten te lopen. Zo scheid je een echte trend van meetruis.</div></div><div class="sam-tip"><strong>Systematisch vs. toevallig:</strong> een <strong>toevallige</strong> fout verschilt per meting (verklein je door vaker te meten en te middelen); een <strong>systematische</strong> fout zit er steeds hetzelfde in (bv. een verkeerd geijkte meter) en verdwijnt níét door herhalen — die moet je opsporen en corrigeren.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — significante cijfers</div><div class="sam-worked-q">Je meet een lengte van 2,5 m en een breedte van 1,20 m. Met hoeveel significante cijfers geef je de oppervlakte?</div><ol class="sam-worked-steps"><li>Oppervlakte = 2,5 × 1,20 = 3,0 m².</li><li>Bij vermenigvuldigen telt de minst nauwkeurige factor.</li><li>2,5 heeft 2 significante cijfers.</li></ol><div class="sam-worked-ans">✅ 3,0 m² (2 significante cijfers): niet nauwkeuriger dan de minst nauwkeurige meting (2,5 m).</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — soort fout</div><div class="sam-worked-q">Een liniaal mist de eerste 2 mm, zodat elke meting 2 mm te kort uitvalt. Helpt vaker meten hiertegen?</div><ol class="sam-worked-steps"><li>De fout is elke keer dezelfde 2 mm.</li><li>Dat is een systematische fout.</li><li>Middelen van herhalingen haalt hem er niet uit.</li></ol><div class="sam-worked-ans">✅ Nee: dit is een systematische fout. Vaker meten helpt niet; je moet de liniaal corrigeren (of vanaf 2 mm meten).</div></div>`,
'vwo_na_H':`<div class="sam-intro"><strong>Natuurwetten en modellen</strong> gaat over de manier waarop de natuurkunde de werkelijkheid beschrijft: met <strong>behoudswetten</strong> (energie, impuls, lading blijven behouden), met <strong>modellen</strong> die je numeriek kunt doorrekenen, en met besef van de <strong>grenzen</strong> waarbinnen een model geldig is.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Behoud van energie</td><td>energie gaat niet verloren, alleen over</td></tr><tr><td>Behoud van impuls</td><td>totale impuls blijft gelijk (botsingen)</td></tr><tr><td>Behoud van lading</td><td>totale lading verandert niet</td></tr><tr><td>Modelvorming</td><td>stapsgewijs (numeriek) doorrekenen</td></tr><tr><td>Grenzen van modellen</td><td>klassiek vs. quantum/relativiteit</td></tr></tbody></table><div class="sam-head">Behoudswetten</div><p>Een <strong>behoudswet</strong> zegt dat een grootheid in een gesloten systeem <strong>constant</strong> blijft. Ze zijn een krachtig gereedschap: je hoeft de details van het proces niet te kennen, alleen de begin- en eindtoestand.</p><div class="sam-formula-box"><div class="sam-formula-label">De belangrijkste behoudswetten</div><div class="sam-formula-eq">energie:  E<sub>voor</sub> = E<sub>na</sub>   (som van alle energievormen)<br>impuls:   p = m·v,   Σp<sub>voor</sub> = Σp<sub>na</sub><br>lading:   Σq<sub>voor</sub> = Σq<sub>na</sub></div><div class="sam-formula-note">Bij een botsing gebruik je impulsbehoud; bij hoogte/snelheid energiebehoud. Let op: bij een inelastische botsing blijft impuls behouden, maar gaat kinetische energie (deels) over in warmte.</div></div><div class="sam-head">Modelvorming</div><p>Veel processen zijn niet met één formule op te lossen. Dan maak je een <strong>numeriek model</strong>: je verdeelt de tijd in kleine stapjes Δt en berekent stap voor stap hoe snelheid en plaats veranderen. Zo simuleer je bijvoorbeeld een vallende parachutist mét luchtweerstand.</p><div class="sam-figure"><svg viewBox="0 0 300 100" role="img" aria-label="Numeriek model: per tijdstap wordt de nieuwe snelheid en plaats berekend"><g font-size="7" font-weight="700" fill="var(--dk)" text-anchor="middle"><rect x="10" y="40" width="58" height="24" rx="5" fill="var(--mu)" opacity=".14"/><text x="39" y="55">F bepalen</text><rect x="86" y="40" width="58" height="24" rx="5" fill="var(--mu)" opacity=".14"/><text x="115" y="51">a = F/m</text><rect x="162" y="40" width="58" height="24" rx="5" fill="var(--or)" opacity=".2"/><text x="191" y="51">v, x</text><text x="191" y="59" font-size="6" fill="var(--mu)">bijwerken</text></g><path d="M68,52 L84,52" stroke="var(--mu)" stroke-width="1.1" marker-end="url(#naHar)"/><path d="M144,52 L160,52" stroke="var(--mu)" stroke-width="1.1" marker-end="url(#naHar)"/><path d="M191,40 C191,18 100,18 39,38" fill="none" stroke="var(--or)" stroke-width="1.3" marker-end="url(#naHar)"/><text x="115" y="16" font-size="6.5" fill="var(--or)" text-anchor="middle">herhaal elke Δt</text><defs><marker id="naHar" markerWidth="7" markerHeight="7" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L5,3 L0,6 Z" fill="var(--mu)"/></marker></defs></svg><div class="sam-figcap"><strong>De modelcyclus per tijdstap:</strong> bepaal de <strong>kracht</strong>, daaruit de <strong>versnelling</strong> (a = F/m), werk daarmee <strong>snelheid en plaats</strong> bij, en herhaal voor de volgende Δt. Hoe kleiner Δt, hoe nauwkeuriger het model — maar hoe meer stappen.</div></div><div class="sam-head">De grenzen van modellen</div><p>Elk model geldt binnen een bepaald <strong>domein</strong>. De <strong>klassieke</strong> (Newtoniaanse) mechanica werkt uitstekend voor alledaagse snelheden en groottes, maar faalt bij het heel <strong>kleine</strong> (dan heb je <strong>quantummechanica</strong> nodig) en het heel <strong>snelle</strong>, dicht bij de lichtsnelheid (dan geldt de <strong>relativiteitstheorie</strong>).</p><div class="sam-tip"><strong>Weet wanneer een model stopt te werken.</strong> Newton volstaat voor een auto of planeet; voor een elektron in een atoom of een deeltje bijna met lichtsnelheid moet je naar quantum- of relativistische modellen. Een examenvraag test vaak of je die grens herkent.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — impulsbehoud</div><div class="sam-worked-q">Een wagentje van 2 kg rijdt met 3 m/s tegen een stilstaand wagentje van 1 kg en ze koppelen samen. Wat is hun gezamenlijke snelheid?</div><ol class="sam-worked-steps"><li>Impuls voor = 2·3 + 1·0 = 6 kg·m/s.</li><li>Na de botsing bewegen ze samen: (2+1)·v = 6.</li><li>v = 6 / 3 = 2 m/s.</li></ol><div class="sam-worked-ans">✅ 2 m/s: door impulsbehoud (Σp gelijk) rijden de gekoppelde wagentjes samen met 2 m/s verder.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — model kiezen</div><div class="sam-worked-q">Mag je de beweging van een elektron in een waterstofatoom met de klassieke mechanica van Newton beschrijven?</div><ol class="sam-worked-steps"><li>Een elektron in een atoom is extreem klein.</li><li>Op die schaal faalt de klassieke mechanica.</li><li>Je hebt quantummechanica nodig.</li></ol><div class="sam-worked-ans">✅ Nee: op atomaire schaal geldt de klassieke mechanica niet meer; daar is een quantummechanisch model nodig.</div></div>`,
'vwo_sk_E':`<div class="sam-intro"><strong>Innovatie en chemisch onderzoek</strong> gaat over hoe nieuwe chemische kennis en producten ontstaan: via systematisch <strong>onderzoek</strong> (van hypothese tot conclusie) en volgens de principes van <strong>groene chemie</strong> — duurzaam produceren met zo min mogelijk afval en energie.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Onderzoekscyclus</td><td>hypothese → experiment → conclusie</td></tr><tr><td>Variabelen</td><td>onafhankelijk, afhankelijk, constant</td></tr><tr><td>Groene chemie</td><td>duurzaam, weinig afval</td></tr><tr><td>Atoomeconomie</td><td>% atomen in het product</td></tr><tr><td>Duurzaamheid</td><td>biobased, hernieuwbaar, recyclen</td></tr></tbody></table><div class="sam-head">Chemisch onderzoek doen</div><p>Onderzoek verloopt in een <strong>cyclus</strong>: uit een vraag volgt een toetsbare <strong>hypothese</strong>, die je toetst met een <strong>experiment</strong> waarin je één variabele varieert en de rest constant houdt. Uit de metingen trek je een <strong>conclusie</strong> — die weer nieuwe vragen oproept.</p><div class="sam-head">Groene chemie</div><p><strong>Groene chemie</strong> wil chemische processen <strong>duurzaam</strong> maken: minder grondstoffen en energie, minder gevaarlijke stoffen, en zo weinig mogelijk <strong>afval</strong>. Een belangrijke maat is de <strong>atoomeconomie</strong>: welk deel van de ingezette atomen belandt in het gewenste product?</p><div class="sam-formula-box"><div class="sam-formula-label">Atoomeconomie</div><div class="sam-formula-eq">atoomeconomie (%) = (massa gewenst product / totale massa reactanten) × 100%</div><div class="sam-formula-note">Hoe hoger, hoe minder bijproduct (afval). Een <strong>additiereactie</strong> heeft in principe 100% atoomeconomie; bij een <strong>substitutie</strong> gaat een deel als bijproduct verloren.</div></div><div class="sam-figure"><svg viewBox="0 0 300 92" role="img" aria-label="Twee routes naar hetzelfde product: de groene route heeft minder afval"><g font-size="7.5" font-weight="700" fill="var(--dk)" text-anchor="middle"><rect x="12" y="14" width="60" height="20" rx="5" fill="var(--mu)" opacity=".14"/><text x="42" y="27">grondstof</text><rect x="228" y="14" width="60" height="20" rx="5" fill="var(--or)" opacity=".2"/><text x="258" y="27">product</text></g><path d="M72,24 C120,24 150,20 226,22" fill="none" stroke="var(--or)" stroke-width="2.2" marker-end="url(#skEar)"/><path d="M72,30 C120,52 150,64 226,30" fill="none" stroke="var(--mu)" stroke-width="1.8" stroke-dasharray="5 3" marker-end="url(#skEar)"/><defs><marker id="skEar" markerWidth="8" markerHeight="8" refX="5" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--dk)"/></marker></defs><text x="150" y="14" font-size="7" fill="var(--or)" text-anchor="middle">groene route (hoge atoomeconomie)</text><text x="150" y="72" font-size="7" fill="var(--mu)" text-anchor="middle">klassieke route → meer afval</text></svg><div class="sam-figcap"><strong>Twee routes, één product:</strong> de <strong>groene route</strong> (boven) verspilt weinig atomen — hoge atoomeconomie, weinig afval. De klassieke route (onder, gestippeld) levert hetzelfde product maar met meer bijproduct. Groene chemie zoekt steeds de bovenste route.</div></div><div class="sam-tip"><strong>Duurzaam denken:</strong> naast atoomeconomie tellen ook de <strong>herkomst</strong> van grondstoffen (biobased/hernieuwbaar i.p.v. fossiel), het <strong>energieverbruik</strong>, en of het product en de oplosmiddelen te <strong>recyclen</strong> zijn. Een reactie met 100% atoomeconomie kan alsnog onduurzaam zijn door veel energie of een giftig oplosmiddel.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — atoomeconomie</div><div class="sam-worked-q">Etheen (28 u) reageert via additie met water (18 u) tot ethanol (46 u), zonder bijproduct. Wat is de atoomeconomie?</div><ol class="sam-worked-steps"><li>Totale massa reactanten = 28 + 18 = 46 u.</li><li>Massa gewenst product (ethanol) = 46 u.</li><li>(46 / 46) × 100% = 100%.</li></ol><div class="sam-worked-ans">✅ 100%: bij deze additie komen alle atomen in het product terecht — geen afval.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — duurzaam beoordelen</div><div class="sam-worked-q">Een proces heeft 95% atoomeconomie maar gebruikt een giftig oplosmiddel en veel warmte. Is dit "groen"? Leg uit.</div><ol class="sam-worked-steps"><li>Atoomeconomie is hoog (goed teken).</li><li>Maar groene chemie kijkt breder: oplosmiddel en energie.</li><li>Een giftig oplosmiddel en hoog energiegebruik zijn onduurzaam.</li></ol><div class="sam-worked-ans">✅ Niet zonder meer groen: ondanks de hoge atoomeconomie maken het giftige oplosmiddel en het hoge energieverbruik het proces minder duurzaam.</div></div>`,
'vwo_sk_D':`<div class="sam-intro"><strong>Ontwikkelen van chemische kennis</strong> gaat over hóé scheikundigen kennis opbouwen: met <strong>modellen</strong> op verschillende schaalniveaus (macro, meso, micro) en met <strong>analysemethoden</strong> om te achterhalen welke stoffen ergens in zitten en hoeveel. Je leert de sterke én zwakke kanten van modellen kennen.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>Schaalniveaus</td><td>macro, meso, micro</td></tr><tr><td>Modellen</td><td>vereenvoudigde weergave; grenzen</td></tr><tr><td>Kwalitatieve analyse</td><td>wélke stof zit erin?</td></tr><tr><td>Kwantitatieve analyse</td><td>hoevéél zit erin?</td></tr><tr><td>Methoden</td><td>chromatografie, spectrometrie, titratie</td></tr></tbody></table><div class="sam-head">Denken op drie schaalniveaus</div><p>Chemie speelt zich op verschillende niveaus af, en je moet ertussen kunnen schakelen:</p><div class="sam-figure"><svg viewBox="0 0 300 96" role="img" aria-label="Drie schaalniveaus: macro (wat je ziet), meso (structuur), micro (deeltjes)"><g font-size="7.5" font-weight="700" fill="var(--dk)" text-anchor="middle"><rect x="14" y="30" width="78" height="30" rx="6" fill="var(--or)" opacity=".22" stroke="var(--or)" stroke-width="1.2"/><text x="53" y="43">macro</text><text x="53" y="54" font-size="6" fill="var(--mu)">wat je ziet</text><rect x="111" y="30" width="78" height="30" rx="6" fill="var(--or)" opacity=".16" stroke="var(--or)" stroke-width="1.2"/><text x="150" y="43">meso</text><text x="150" y="54" font-size="6" fill="var(--mu)">structuur/rooster</text><rect x="208" y="30" width="78" height="30" rx="6" fill="var(--or)" opacity=".1" stroke="var(--or)" stroke-width="1.2"/><text x="247" y="43">micro</text><text x="247" y="54" font-size="6" fill="var(--mu)">atomen/moleculen</text></g><g stroke="var(--mu)" stroke-width="1.1"><line x1="92" y1="45" x2="110" y2="45" marker-end="url(#skDar)"/><line x1="189" y1="45" x2="207" y2="45" marker-end="url(#skDar)"/></g><defs><marker id="skDar" markerWidth="7" markerHeight="7" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L5,3 L0,6 Z" fill="var(--mu)"/></marker></defs></svg><div class="sam-figcap"><strong>Van groot naar klein:</strong> <strong>macro</strong> is wat je waarneemt (kleur, kookpunt); <strong>meso</strong> is de structuur (kristalrooster, keten); <strong>micro</strong> is het niveau van atomen en moleculen. Een goede verklaring koppelt een macro-eigenschap aan de micro-bouw.</div></div><div class="sam-head">Modellen en hun grenzen</div><p>Een <strong>model</strong> is een vereenvoudigde weergave van de werkelijkheid — handig om te verklaren en voorspellen, maar nooit compleet. Het <strong>bolletjesmodel</strong> laat bindingen zien maar niet de echte elektronenwolk; een <strong>structuurformule</strong> toont de volgorde van atomen maar niet de 3D-vorm. Weet steeds wélk model je gebruikt en wat het <strong>niet</strong> laat zien.</p><div class="sam-tip"><strong>Elk model heeft grenzen.</strong> Bij een examenvraag "waarom is dit model hier ontoereikend?" benoem je wat het verschijnsel wél vraagt (bv. 3D-vorm, lading, dynamiek) en wat het gekozen model juist weglaat.</div><div class="sam-head">Analysemethoden</div><p>Om te bepalen wat en hoeveel er in een monster zit, gebruik je <strong>analysemethoden</strong>. Onderscheid <strong>kwalitatief</strong> (wélke stof) van <strong>kwantitatief</strong> (hoevéél):</p><table class="sam-table"><thead><tr><th>Methode</th><th>Waarvoor?</th></tr></thead><tbody><tr><td>Chromatografie</td><td>een mengsel scheiden in componenten</td></tr><tr><td>Massaspectrometrie</td><td>molecuulmassa / atoommassa bepalen</td></tr><tr><td>Spectroscopie (IR)</td><td>functionele groepen herkennen</td></tr><tr><td>Titratie</td><td>concentratie bepalen (kwantitatief)</td></tr></tbody></table><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — schaalniveau koppelen</div><div class="sam-worked-q">Diamant is keihard. Op welk schaalniveau ligt de verklaring, en wat is die?</div><ol class="sam-worked-steps"><li>Hardheid is een macro-eigenschap.</li><li>De verklaring zit in de bouw: een netwerk van sterke covalente bindingen.</li><li>Dat is het micro/meso-niveau (atoomrooster).</li></ol><div class="sam-worked-ans">✅ De macro-eigenschap "hard" verklaar je op micro/meso-niveau: elk C-atoom zit met vier sterke covalente bindingen vast in een 3D-netwerk.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — methode kiezen</div><div class="sam-worked-q">Je wilt weten hoeveel azijnzuur er in een fles schoonmaakazijn zit. Kwalitatieve of kwantitatieve analyse, en welke methode?</div><ol class="sam-worked-steps"><li>"Hoeveel" → kwantitatieve analyse.</li><li>Voor een concentratie van een zuur gebruik je een titratie.</li><li>Je titreert met een base van bekende concentratie.</li></ol><div class="sam-worked-ans">✅ Kwantitatief, met een zuur-basetitratie: uit het verbruik van de base bereken je de concentratie azijnzuur.</div></div>`,
'vwo_gs_C':`<div class="sam-intro">Bij het domein <strong>Thema's</strong> bestudeer je één onderwerp <strong>diepgaand en over een lange periode</strong>. Het examenthema <strong>wisselt per jaar</strong>, maar de aanpak blijft gelijk: je volgt een ontwikkeling door de tijd en verklaart <strong>continuïteit en verandering</strong>.</div><div class="sam-head">Wat is thematische geschiedenis?</div><p>Waar de tijdvakken de hele geschiedenis in stukken verdelen, snijdt een <strong>thema</strong> er juist dwars doorheen: je volgt één onderwerp (bijvoorbeeld 'steden en burgers' of 'verhouding kerk–staat') door meerdere tijdvakken heen, van begin tot heden.</p><div class="sam-figure"><svg viewBox="0 0 320 110" role="img" aria-label="Een historisch thema dat zich door verschillende tijdvakken heen ontwikkelt"><defs><marker id="gsCa" markerWidth="9" markerHeight="9" refX="5" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L7,3 L0,6 Z" fill="var(--or)"/></marker></defs><line x1="20" y1="55" x2="300" y2="55" stroke="var(--or)" stroke-width="2.4" marker-end="url(#gsCa)"/><g fill="var(--or)"><circle cx="55" cy="55" r="4"/><circle cx="130" cy="55" r="4"/><circle cx="205" cy="55" r="4"/><circle cx="275" cy="55" r="4"/></g><g font-size="7.5" fill="var(--mu)" text-anchor="middle"><text x="55" y="72">ontstaan</text><text x="130" y="72">groei</text><text x="205" y="72">verandering</text><text x="275" y="72">heden</text></g><text x="160" y="30" font-size="9.5" font-weight="700" fill="var(--dk)" text-anchor="middle">één thema door de tijd →</text></svg><div class="sam-figcap"><strong>Thema door de tijd:</strong> je volgt de ontwikkeling van één onderwerp van zijn ontstaan, via groei en verandering, tot het heden — en let daarbij op oorzaken, gevolgen en keerpunten.</div></div><div class="sam-head">Hoe je een thema analyseert</div><table class="sam-table"><thead><tr><th>Vraag</th><th>Waar je op let</th></tr></thead><tbody><tr><td>Ontwikkeling</td><td>hoe verandert het thema door de tijdvakken heen?</td></tr><tr><td>Oorzaak &amp; gevolg</td><td>waardoor treedt verandering op, en wat volgt eruit?</td></tr><tr><td>Continuïteit</td><td>wat blijft juist lange tijd hetzelfde?</td></tr><tr><td>Keerpunten</td><td>welke gebeurtenissen vormen een breuk?</td></tr></tbody></table><div class="sam-head">Continuïteit en verandering</div><p>De kern van een thema is de wisselwerking tussen <strong>continuïteit</strong> (wat blijft) en <strong>verandering</strong> (wat verschuift). Zo zie je dat geschiedenis geen losse feiten is, maar een samenhangend proces met lange lijnen.</p><div class="sam-warn"><strong>Let op:</strong> het exacte examenthema wordt jaarlijks door het CvTE vastgesteld (bijvoorbeeld 'Steden en burgers in de Lage Landen 1050–1700'). De <em>manier</em> van analyseren — ontwikkeling, oorzaak-gevolg, continuïteit en verandering — geldt voor elk thema.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave</div><div class="sam-worked-q">Waarom bekijk je bij een thema zowel continuïteit als verandering?</div><ol class="sam-worked-steps"><li>Een thema ontwikkelt zich over een lange periode.</li><li>Sommige zaken veranderen (bijv. door revoluties of uitvindingen), andere blijven juist lang hetzelfde.</li><li>Door beide te bekijken snap je het proces als geheel, niet alleen de losse momenten.</li></ol><div class="sam-worked-ans">✅ Continuïteit en verandering samen laten de lange lijnen én de keerpunten van het thema zien.</div></div></div>`,
'vwo_sk_G':`<div class="sam-intro">Chemie staat midden in de samenleving: van kunststoffen en medicijnen tot brandstoffen en meststoffen. Dit domein gaat over de <strong>wisselwerking</strong> tussen chemie, <strong>technologie</strong> en <strong>maatschappij</strong> — met de nadruk op <strong>milieu</strong> en <strong>duurzaamheid</strong>.</div><div class="sam-head">Chemie in het dagelijks leven</div><p>Vrijwel alles om je heen is het product van chemische kennis: <strong>materialen</strong> (kunststoffen, metalen, glas), <strong>medicijnen</strong>, <strong>voeding</strong>, <strong>brandstoffen</strong> en <strong>meststoffen</strong>. Technologische vooruitgang en scheikunde gaan hand in hand.</p><div class="sam-head">Van lineair naar circulair</div><p>Lang werkte de economie <strong>lineair</strong>: grondstof → product → afval. Duurzamer is een <strong>circulaire economie</strong>, waarin materialen na gebruik worden hergebruikt of gerecycled, zodat er weinig afval en grondstofverbruik overblijft.</p><div class="sam-figure"><svg viewBox="0 0 300 160" role="img" aria-label="Circulaire economie: grondstof, product, gebruik en recycling in een kringloop"><defs><marker id="skGa" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--or)"/></marker></defs><circle cx="150" cy="80" r="55" fill="none" stroke="var(--or)" stroke-width="1.4" stroke-dasharray="4 4" opacity=".5"/><g font-size="8.5" font-weight="700" fill="var(--dk)" text-anchor="middle"><text x="150" y="22">grondstof</text><text x="222" y="84">product</text><text x="150" y="146">gebruik</text><text x="78" y="84">recycling</text></g><g stroke="var(--or)" stroke-width="1.8" fill="none"><path d="M178,33 A55,55 0 0,1 197,58" marker-end="url(#skGa)"/><path d="M203,102 A55,55 0 0,1 178,127" marker-end="url(#skGa)"/><path d="M122,127 A55,55 0 0,1 97,102" marker-end="url(#skGa)"/><path d="M103,58 A55,55 0 0,1 122,33" marker-end="url(#skGa)"/></g></svg><div class="sam-figcap"><strong>Circulaire economie:</strong> grondstof → product → gebruik → recycling en weer terug. Materialen blijven in de kringloop, zodat afval en nieuw grondstofverbruik minimaal zijn.</div></div><div class="sam-head">Chemie en milieu</div><table class="sam-table"><thead><tr><th>Uitdaging</th><th>Chemische bijdrage</th></tr></thead><tbody><tr><td>Klimaat</td><td>CO₂-uitstoot beperken, groene brandstoffen</td></tr><tr><td>Afval</td><td>recycling, afbreekbare kunststoffen</td></tr><tr><td>Water &amp; lucht</td><td>zuivering, katalysatoren tegen uitstoot</td></tr></tbody></table><div class="sam-head">Kansen en risico's afwegen</div><p>Nieuwe stoffen en technologieën brengen <strong>kansen</strong> (betere materialen, medicijnen, energie) maar ook <strong>risico's</strong> (giftigheid, milieuschade, uitputting). De maatschappij weegt die tegen elkaar af — een chemicus levert de feiten voor die keuze.</p><div class="sam-tip">Een <strong>levenscyclusanalyse</strong> (LCA) bekijkt de milieubelasting van een product van grondstof tot afval ('van wieg tot graf'), zodat je eerlijk kunt vergelijken welke optie echt duurzamer is.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave</div><div class="sam-worked-q">Waarom is het recyclen van aluminium veel duurzamer dan het opnieuw winnen ervan?</div><ol class="sam-worked-steps"><li>Aluminium winnen uit erts kost enorm veel energie (elektrolyse).</li><li>Omsmelten van bestaand aluminium kost daar maar een fractie van.</li><li>Recycling bespaart dus grondstoffen én veel energie en uitstoot.</li></ol><div class="sam-worked-ans">✅ Recycling houdt het materiaal in de kringloop en scheelt een groot deel van de energie en milieubelasting.</div></div></div>`,
'vwo_sk_F':`<div class="sam-intro"><strong>Industriële chemische processen</strong> draaien om één vraag: hoe maak je een stof <strong>snel, met veel opbrengst en zo duurzaam mogelijk</strong>? Daarvoor combineer je <strong>reactiesnelheid</strong> (hoe snel), <strong>chemisch evenwicht</strong> (hoe ver) en slim <strong>procesontwerp</strong> (blokschema, rendement, groene chemie).</div><div class="sam-head">Wat je voor het examen moet kennen</div><p>Dit domein bindt reactiekinetiek, evenwicht en procestechniek samen. De onderdelen:</p><table class="sam-table"><thead><tr><th>Deel</th><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>1</td><td>Reactiesnelheid</td><td>botsingstheorie, factoren die de snelheid bepalen</td></tr><tr><td>2</td><td>Activeringsenergie &amp; katalyse</td><td>reactieprofiel, katalysator verlaagt E<sub>a</sub></td></tr><tr><td>3</td><td>Evenwicht in de industrie</td><td>Le Chatelier voor maximale opbrengst</td></tr><tr><td>4</td><td>Procesontwerp</td><td>blokschema, rendement, atoomeconomie, duurzaamheid</td></tr></tbody></table><div class="sam-head">1 · Reactiesnelheid</div><p>De <strong>reactiesnelheid</strong> is de hoeveelheid stof die per seconde wordt omgezet. Volgens de <strong>botsingstheorie</strong> treedt een reactie alleen op als deeltjes <strong>botsen</strong> met voldoende energie én de juiste oriëntatie. Alles wat het aantal geslaagde botsingen per seconde vergroot, versnelt de reactie:</p><table class="sam-table"><thead><tr><th>Factor</th><th>Effect op de snelheid</th></tr></thead><tbody><tr><td>Hogere concentratie</td><td>meer deeltjes per volume → meer botsingen</td></tr><tr><td>Hogere temperatuur</td><td>deeltjes sneller → vaker én harder botsen</td></tr><tr><td>Grotere verdelingsgraad</td><td>meer contactoppervlak (bv. poeder i.p.v. brok)</td></tr><tr><td>Katalysator</td><td>verlaagt de activeringsenergie (zie hieronder)</td></tr></tbody></table><div class="sam-head">2 · Activeringsenergie en katalyse</div><p>Voordat reactanten kunnen reageren, moeten ze een energiedrempel over: de <strong>activeringsenergie</strong> E<sub>a</sub>. Dat lees je af in een <strong>reactieprofiel</strong> (energiediagram):</p><div class="sam-figure"><svg viewBox="0 0 300 160" role="img" aria-label="Reactieprofiel met en zonder katalysator; de katalysator verlaagt de activeringsenergie"><defs><marker id="giSF1" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--mu)"/></marker></defs><line x1="34" y1="140" x2="290" y2="140" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#giSF1)"/><line x1="34" y1="150" x2="34" y2="14" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#giSF1)"/><text x="286" y="154" font-size="8" fill="var(--mu)" text-anchor="end">reactieverloop</text><text x="12" y="20" font-size="8" fill="var(--mu)">E</text><path d="M50,60 C90,60 100,24 140,24 C180,24 190,104 250,104" fill="none" stroke="var(--or)" stroke-width="2.4"/><path d="M50,60 C92,60 104,54 140,54 C176,54 188,104 250,104" fill="none" stroke="var(--mu)" stroke-width="2" stroke-dasharray="5 4"/><line x1="50" y1="60" x2="50" y2="104" stroke="var(--mu)" stroke-width="1" stroke-dasharray="2 2"/><line x1="34" y1="60" x2="52" y2="60" stroke="var(--mu)" stroke-width="1"/><text x="60" y="46" font-size="7.5" fill="var(--or)" text-anchor="middle">E</text><text x="66" y="46" font-size="6" fill="var(--or)">a</text><text x="150" y="18" font-size="7" fill="var(--or)" text-anchor="middle">zonder kat.</text><text x="152" y="66" font-size="7" fill="var(--mu)" text-anchor="middle">met katalysator</text><text x="70" y="74" font-size="7" fill="var(--dk)">reactanten</text><text x="238" y="118" font-size="7" fill="var(--dk)" text-anchor="end">producten</text></svg><div class="sam-figcap"><strong>Reactieprofiel:</strong> de top is de energiedrempel. Hier zijn de producten lager dan de reactanten → <strong>exotherm</strong> (energie komt vrij). Een <strong>katalysator</strong> biedt een route met lagere E<sub>a</sub> (gestippeld), zodat de reactie sneller gaat.</div></div><div class="sam-warn"><strong>Veelgemaakte fout:</strong> een katalysator versnelt zowel de heen- als de terugreactie en wordt zelf niet verbruikt. Hij verandert de <strong>ligging</strong> van een evenwicht dus <em>niet</em> — het evenwicht wordt alleen sneller bereikt.</div><div class="sam-head">3 · Evenwicht in de industrie</div><p>Veel industriële reacties zijn <strong>evenwichtsreacties</strong>: ze lopen niet volledig af. Met het <strong>principe van Le Chatelier</strong> (domein C) stuur je het evenwicht naar de productkant om de opbrengst te vergroten.</p><ul><li><strong>Concentratie:</strong> een product continu afvoeren verschuift het evenwicht naar rechts (meer product).</li><li><strong>Druk</strong> (gassen): hogere druk verschuift naar de kant met <em>minder</em> gasdeeltjes.</li><li><strong>Temperatuur:</strong> bij een exotherme reactie geeft een lágere temperatuur meer product — maar dat maakt de reactie trager. In de praktijk kies je een <strong>compromis</strong> (matige temperatuur + katalysator).</li></ul><div class="sam-tip">Snelheid en opbrengst botsen vaak: wat de opbrengst verhoogt (lage T bij exotherm) verlaagt de snelheid. De industrie zoekt het <strong>economisch optimum</strong>: genoeg product per tijd tegen zo laag mogelijke kosten (bv. het Haber-Boschproces voor ammoniak).</div><div class="sam-head">4 · Procesontwerp: blokschema, rendement, duurzaamheid</div><p>Een proces teken je als <strong>blokschema</strong>: rechthoeken zijn bewerkingen, pijlen zijn stofstromen. Niet-omgezette reactanten voer je terug (<strong>recycling</strong>) om zo min mogelijk te verspillen.</p><div class="sam-figure"><svg viewBox="0 0 300 120" role="img" aria-label="Blokschema van een industrieel proces met reactor, scheiding, product en terugvoer van reactanten"><defs><marker id="giSF2" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--or)"/></marker></defs><g font-size="8" font-weight="700" fill="var(--dk)" text-anchor="middle"><rect x="70" y="26" width="60" height="34" rx="5" fill="var(--or)" opacity=".16" stroke="var(--or)" stroke-width="1.2"/><text x="100" y="47">reactor</text><rect x="170" y="26" width="60" height="34" rx="5" fill="var(--or)" opacity=".14" stroke="var(--or)" stroke-width="1.1"/><text x="200" y="43">scheiding</text></g><line x1="20" y1="43" x2="68" y2="43" stroke="var(--or)" stroke-width="1.6" marker-end="url(#giSF2)"/><text x="16" y="37" font-size="7" fill="var(--mu)" text-anchor="start">grondstof</text><line x1="130" y1="43" x2="168" y2="43" stroke="var(--or)" stroke-width="1.6" marker-end="url(#giSF2)"/><line x1="230" y1="43" x2="284" y2="43" stroke="var(--or)" stroke-width="1.6" marker-end="url(#giSF2)"/><text x="270" y="37" font-size="7" fill="var(--dk)" text-anchor="middle">product</text><path d="M200,60 L200,98 L100,98 L100,62" fill="none" stroke="var(--mu)" stroke-width="1.5" stroke-dasharray="4 3" marker-end="url(#giSF2)"/><text x="150" y="110" font-size="7" fill="var(--mu)" text-anchor="middle">terugvoer niet-omgezette reactanten</text></svg><div class="sam-figcap"><strong>Blokschema:</strong> de grondstof reageert in de reactor; de scheiding haalt het product eruit en voert de rest terug. Zo stijgt het totale <strong>rendement</strong>.</div></div><div class="sam-formula-box"><div class="sam-formula-label">Rendement en atoomeconomie</div><div class="sam-formula-eq">rendement = (werkelijke opbrengst / maximale opbrengst) × 100%<br>atoomeconomie = (massa gewenst product / totale massa reactanten) × 100%</div><div class="sam-formula-note">Rendement zegt hoeveel je haalt van wat mogelijk is; atoomeconomie zegt welk deel van de reactanten in het gewenste product terechtkomt — een hoge atoomeconomie betekent weinig afval.</div></div><p><strong>Groene chemie</strong> streeft naar duurzame processen: hoge atoomeconomie, weinig afval, veilige stoffen, minder energie, hernieuwbare grondstoffen en <strong>katalyse</strong>. Dit past bij de omslag van een <strong>lineaire</strong> naar een <strong>circulaire</strong> economie (grondstoffen hergebruiken).</p><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — reactiesnelheid</div><div class="sam-worked-q">Een marmerblok (CaCO₃) reageert met zoutzuur. Noem twee manieren om deze reactie te versnellen, met uitleg via de botsingstheorie.</div><ol class="sam-worked-steps"><li>Het marmer fijnmalen: grotere verdelingsgraad → meer contactoppervlak → meer botsingen per seconde.</li><li>Een geconcentreerder zuur gebruiken: meer H⁺-deeltjes per volume → meer botsingen.</li><li>(Ook mogelijk: verwarmen — deeltjes bewegen sneller en botsen vaker met genoeg energie.)</li></ol><div class="sam-worked-ans">✅ Fijnmalen en/of hogere concentratie (of hogere temperatuur): allemaal méér geslaagde botsingen per seconde.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — evenwicht sturen</div><div class="sam-worked-q">In een gasevenwicht 2 A(g) ⇌ B(g) wil je meer B. Helpt een hogere druk? Leg uit met Le Chatelier.</div><ol class="sam-worked-steps"><li>Links staan 2 gasdeeltjes, rechts 1 gasdeeltje.</li><li>Le Chatelier: hogere druk verschuift het evenwicht naar de kant met minder gasdeeltjes.</li><li>Dat is de kant van B (rechts).</li></ol><div class="sam-worked-ans">✅ Ja: hogere druk verschuift het evenwicht naar B (de kant met de minste gasdeeltjes).</div></div>`,
'vwo_wb_B':`<div class="sam-intro">Domein B is de basis van wiskunde B: je herkent en gebruikt <strong>standaardfuncties</strong>, past <strong>transformaties</strong> toe, en lost <strong>vergelijkingen</strong> en <strong>ongelijkheden</strong> op — algebraïsch én met de grafiek.</div><div class="sam-chips"><span class="sam-chip sam-chip-lead">Kern</span><span class="sam-chip">Standaardfuncties</span><span class="sam-chip">Nulpunten</span><span class="sam-chip">Discriminant</span><span class="sam-chip">Transformaties</span><span class="sam-chip">Ongelijkheden</span></div><div class="sam-head">Standaardfuncties</div><table class="sam-table"><thead><tr><th>Functie</th><th>Vorm</th><th>Grafiek</th></tr></thead><tbody><tr><td>Lineair</td><td>y = ax + b</td><td>rechte lijn</td></tr><tr><td>Kwadratisch</td><td>y = ax² + bx + c</td><td>parabool</td></tr><tr><td>Machtsfunctie</td><td>y = a·xⁿ</td><td>hangt van n af</td></tr><tr><td>Exponentieel</td><td>y = b·gˣ</td><td>groei/afname</td></tr></tbody></table><div class="sam-head">Nulpunten en top van een parabool</div><p>De <strong>nulpunten</strong> zijn de x-waarden waar de grafiek de x-as snijdt (y = 0). De <strong>top</strong> ligt precies tussen de nulpunten in en is het maximum of minimum.</p><div class="sam-figure"><svg viewBox="0 0 320 172" role="img" aria-label="Parabool met twee nulpunten op de x-as en een top ertussen"><defs><marker id="wbBa" markerWidth="9" markerHeight="9" refX="5" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L7,3 L0,6 Z" fill="var(--mu)"/></marker></defs><line x1="20" y1="140" x2="312" y2="140" stroke="var(--mu)" stroke-width="1.5" marker-end="url(#wbBa)"/><line x1="40" y1="160" x2="40" y2="20" stroke="var(--mu)" stroke-width="1.5" marker-end="url(#wbBa)"/><path d="M70.0,140.0 L86.0,112.0 L102.0,88.9 L118.0,70.7 L134.0,57.3 L150.0,48.8 L166.0,45.2 L170.0,45.0 L178.0,45.6 L194.0,50.5 L210.0,60.2 L226.0,74.8 L242.0,94.2 L258.0,118.6 L270.0,140.0" fill="none" stroke="var(--or)" stroke-width="2.6" stroke-linecap="round"/><circle cx="70" cy="140" r="4" fill="var(--dk)"/><circle cx="270" cy="140" r="4" fill="var(--dk)"/><circle cx="170" cy="45" r="4" fill="var(--or)"/><text x="66" y="156" font-size="9" fill="var(--dk)">nulpunt</text><text x="248" y="156" font-size="9" fill="var(--dk)">nulpunt</text><text x="176" y="42" font-size="9" font-weight="700" fill="var(--or)">top</text></svg><div class="sam-figcap"><strong>Parabool:</strong> de twee nulpunten liggen op de x-as (y = 0); de top ligt er symmetrisch tussenin. Bij een neerwaartse parabool is de top een maximum.</div></div><div class="sam-formula-box"><div class="sam-formula-label">Nulpunten (abc-formule)</div><div class="sam-formula-eq">x = (−b ± √(b² − 4ac)) / (2a)</div><div class="sam-formula-note">De discriminant D = b² − 4ac bepaalt het aantal nulpunten: D &gt; 0 twee, D = 0 één, D &lt; 0 geen (reële) nulpunten.</div></div><div class="sam-head">Vergelijkingen en ongelijkheden</div><p>Een <strong>vergelijking</strong> los je op door beide kanten gelijk te stellen (algebraïsch of via snijpunten). Bij een <strong>ongelijkheid</strong> (bijv. f(x) &gt; 0) zoek je waar de grafiek boven of onder een grens ligt — let op: bij delen door een negatief getal draait het teken om.</p><div class="sam-warn"><strong>Let op:</strong> vermenigvuldig of deel je een ongelijkheid met een <em>negatief</em> getal, dan klapt het ongelijkheidsteken om (van &lt; naar &gt;).</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave</div><div class="sam-worked-q">Bepaal de nulpunten van f(x) = x² − 5x + 6.</div><ol class="sam-worked-steps"><li>Ontbinden: x² − 5x + 6 = (x − 2)(x − 3).</li><li>Elk product-deel gelijk aan 0: x − 2 = 0 of x − 3 = 0.</li><li>x = 2 of x = 3.</li></ol><div class="sam-worked-ans">✅ De nulpunten zijn x = 2 en x = 3; de top ligt er middenin, bij x = 2,5.</div></div><div class="sam-head">Transformaties van grafieken</div><p>Uit een standaardfunctie maak je een nieuwe door hem te <strong>verschuiven</strong>, <strong>rekken</strong> of <strong>spiegelen</strong>. Herken je dit, dan hoef je niet elke grafiek opnieuw te berekenen.</p><table class="sam-table"><thead><tr><th>Bewerking</th><th>Effect op de grafiek</th></tr></thead><tbody><tr><td>y = f(x) + c</td><td>c omhoog (c &gt; 0) of omlaag</td></tr><tr><td>y = f(x − a)</td><td>a naar rechts (let op het minteken!)</td></tr><tr><td>y = a·f(x)</td><td>verticaal rekken met factor a</td></tr><tr><td>y = f(bx)</td><td>horizontaal met factor 1/b</td></tr><tr><td>y = −f(x)</td><td>spiegelen in de x-as</td></tr></tbody></table><div class="sam-definitie"><div class="sam-definitie-term">Discriminant</div><div class="sam-definitie-body">D = b² − 4ac bij y = ax² + bx + c. D &gt; 0 → twee nulpunten, D = 0 → één (de top raakt de x-as), D &lt; 0 → geen reële nulpunten.</div></div><div class="sam-head">Ongelijkheden met een schets</div><p>Bij f(x) &gt; 0 zoek je waar de grafiek <strong>boven</strong> de x-as ligt. Handige aanpak: bepaal eerst de <strong>nulpunten</strong> (de grenzen), schets grof het verloop en lees af welke intervallen voldoen. Zo voorkom je tekenfouten.</p><div class="sam-val"><ul><li>Bij y = f(x − a): de grafiek gaat naar <strong>rechts</strong>, niet naar links.</li><li>Ongelijkheid delen door een <strong>negatief</strong> getal → teken omklappen (&lt; wordt &gt;).</li><li>Alleen de nulpunten geven, terwijl er een <strong>interval</strong> gevraagd wordt.</li><li>D &lt; 0 betekent geen reële nulpunten — niet "geen oplossing van de opgave".</li></ul></div><div class="sam-onthoud"><ul style="margin:0;padding-left:16px"><li style="margin-bottom:3px">abc-formule + discriminant geven de nulpunten.</li><li style="margin-bottom:3px">Transformaties: +c omhoog, f(x−a) naar rechts, −f(x) spiegelen.</li><li style="margin-bottom:3px">Ongelijkheid oplossen: nulpunten → schets → interval.</li><li style="margin-bottom:3px">Delen door negatief → ongelijkheidsteken klapt om.</li></ul></div></div>`,
'vwo_na_G':`<div class="sam-intro">Van de kleinste kern tot het grootste sterrenstelsel: dit domein verbindt <strong>straling</strong> met <strong>astrofysica</strong> (sterren en het heelal) en met <strong>medische beeldvorming</strong>. Overal gebruik je hetzelfde <strong>elektromagnetisch spectrum</strong>.</div><div class="sam-head">Het elektromagnetisch spectrum</div><p>Alle <strong>elektromagnetische straling</strong> reist met de lichtsnelheid, maar verschilt in <strong>golflengte</strong> en <strong>frequentie</strong>. Hoe korter de golflengte, hoe hoger de frequentie en de energie per foton (E = h·f).</p><div class="sam-figure"><svg viewBox="0 0 320 130" role="img" aria-label="Het elektromagnetisch spectrum van radiogolven tot gammastraling"><defs><marker id="naGa" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--mu)"/></marker></defs><g stroke="none"><rect x="20" y="45" width="43" height="26" fill="var(--or)" opacity=".18"/><rect x="63" y="45" width="43" height="26" fill="var(--or)" opacity=".30"/><rect x="106" y="45" width="43" height="26" fill="var(--or)" opacity=".42"/><rect x="149" y="45" width="26" height="26" fill="var(--or)" opacity=".60"/><rect x="175" y="45" width="43" height="26" fill="var(--or)" opacity=".72"/><rect x="218" y="45" width="43" height="26" fill="var(--or)" opacity=".85"/><rect x="261" y="45" width="43" height="26" fill="var(--or)"/></g><g font-size="6.5" fill="var(--dk)" text-anchor="middle"><text x="41" y="61">radio</text><text x="84" y="61">micro</text><text x="127" y="61">infrar.</text><text x="162" y="61">zicht</text><text x="196" y="61">UV</text><text x="239" y="61">röntgen</text><text x="282" y="61">gamma</text></g><line x1="20" y1="82" x2="304" y2="82" stroke="var(--mu)" stroke-width="1" marker-start="url(#naGa)" marker-end="url(#naGa)"/><text x="40" y="95" font-size="7.5" fill="var(--mu)">grote golflengte</text><text x="300" y="95" font-size="7.5" fill="var(--mu)" text-anchor="end">hoge frequentie/energie</text></svg><div class="sam-figcap"><strong>EM-spectrum:</strong> van links (radiogolven, lange golflengte, lage energie) naar rechts (gammastraling, korte golflengte, hoge energie). Zichtbaar licht is maar een smalle strook in het midden.</div></div><div class="sam-head">Astrofysica: sterren en het heelal</div><p>Sterren zenden een <strong>spectrum</strong> uit waaruit je hun temperatuur en samenstelling afleidt. Uit de <strong>roodverschuiving</strong> van ver weg gelegen sterrenstelsels (het Doppler-effect voor licht) blijkt dat het heelal <strong>uitdijt</strong>: hoe verder weg, hoe sneller ze zich van ons af bewegen.</p><div class="sam-tip"><strong>Roodverschuiving:</strong> licht van een wegbewegende bron verschuift naar langere golflengten (roder). Bijna alle sterrenstelsels vertonen roodverschuiving — het bewijs dat het heelal uitdijt.</div><div class="sam-head">Medische beeldvorming</div><table class="sam-table"><thead><tr><th>Techniek</th><th>Gebruikt</th><th>Toepassing</th></tr></thead><tbody><tr><td>Röntgen</td><td>röntgenstraling</td><td>botten, longen</td></tr><tr><td>Echografie</td><td>ultrageluid</td><td>zwangerschap, organen</td></tr><tr><td>MRI</td><td>magneetvelden + radiogolven</td><td>weke delen, hersenen</td></tr></tbody></table><div class="sam-warn"><strong>Let op:</strong> röntgen- en gammastraling zijn <em>ioniserend</em> (schadelijk in hoge dosis), terwijl echografie (geluid) en MRI (magneetvelden) dat niet zijn. Daarom kies je per situatie de veiligste techniek.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave</div><div class="sam-worked-q">Waarom kun je uit de roodverschuiving van een sterrenstelsel afleiden dat het zich van ons af beweegt?</div><ol class="sam-worked-steps"><li>Bij een wegbewegende bron worden de lichtgolven 'uitgerekt' (Doppler-effect).</li><li>Langere golflengte betekent een verschuiving naar het rode deel van het spectrum.</li><li>Roodverschuiving hoort dus bij een bron die zich verwijdert.</li></ol><div class="sam-worked-ans">✅ Roodverschuiving = wegbeweging; de mate ervan verraadt hoe snel het stelsel zich verwijdert.</div></div></div>`,
'vwo_ak_D':`<div class="sam-intro">Bij het domein <strong>Gebied</strong> analyseer je één <strong>ontwikkelingsregio</strong> diepgaand (de examenregio <strong>wisselt per jaar</strong>; recent Zuid-Amerika). Je verbindt de <strong>fysische</strong> en de <strong>sociale</strong> geografie tot één samenhangend beeld van het gebied.</div><div class="sam-head">Een gebied analyseren</div><p>Een geograaf kijkt naar een gebied via twee 'lagen', en vooral naar hun <strong>samenhang</strong>: hoe de natuur de mens beïnvloedt en andersom.</p><div class="sam-figure"><svg viewBox="0 0 300 140" role="img" aria-label="Gebiedsanalyse: de fysische en sociale laag komen samen tot een beeld van het gebied"><rect x="20" y="20" width="120" height="44" rx="8" fill="var(--or)" opacity=".14" stroke="var(--or)" stroke-width="1.3"/><text x="80" y="38" font-size="9.5" font-weight="700" fill="var(--dk)" text-anchor="middle">Fysische geografie</text><text x="80" y="53" font-size="7.5" fill="var(--mu)" text-anchor="middle">klimaat · reliëf · bodem</text><rect x="160" y="20" width="120" height="44" rx="8" fill="var(--mu)" opacity=".12" stroke="var(--mu)" stroke-width="1.2"/><text x="220" y="38" font-size="9.5" font-weight="700" fill="var(--dk)" text-anchor="middle">Sociale geografie</text><text x="220" y="53" font-size="7.5" fill="var(--mu)" text-anchor="middle">bevolking · economie</text><rect x="90" y="98" width="120" height="34" rx="8" fill="var(--or)" opacity=".2" stroke="var(--or)" stroke-width="1.4"/><text x="150" y="119" font-size="9.5" font-weight="700" fill="var(--dk)" text-anchor="middle">beeld van het gebied</text><defs><marker id="akDa" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--mu)"/></marker></defs><line x1="80" y1="64" x2="130" y2="96" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#akDa)"/><line x1="220" y1="64" x2="170" y2="96" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#akDa)"/></svg><div class="sam-figcap"><strong>Gebiedsanalyse:</strong> de fysische laag (klimaat, reliëf, bodem) en de sociale laag (bevolking, economie) komen samen tot een verklarend beeld van het gebied.</div></div><div class="sam-head">Fysische geografie</div><table class="sam-table"><thead><tr><th>Aspect</th><th>Waar je op let</th></tr></thead><tbody><tr><td>Klimaat</td><td>temperatuur, neerslag, seizoenen</td></tr><tr><td>Reliëf</td><td>gebergten, laagvlaktes, rivieren</td></tr><tr><td>Bodem &amp; natuur</td><td>vruchtbaarheid, vegetatie, grondstoffen</td></tr></tbody></table><div class="sam-head">Sociale geografie</div><table class="sam-table"><thead><tr><th>Aspect</th><th>Waar je op let</th></tr></thead><tbody><tr><td>Bevolking</td><td>spreiding, groei, migratie, verstedelijking</td></tr><tr><td>Economie</td><td>landbouw, industrie, diensten, handel</td></tr><tr><td>Ontwikkeling</td><td>welvaart, HDI, ongelijkheid tussen regio's</td></tr></tbody></table><div class="sam-tip">De kern van dit domein is de <strong>samenhang</strong>: verklaar bijvoorbeeld hoe het klimaat en reliëf de landbouw, bevolkingsspreiding en economie van de regio bepalen — en hoe de mens het landschap terugverandert.</div><div class="sam-warn"><strong>Let op:</strong> de exacte examenregio wordt jaarlijks vastgesteld in de syllabus. De <em>manier</em> van analyseren (fysisch + sociaal + samenhang) blijft hetzelfde; de feitelijke regio kan wisselen.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave</div><div class="sam-worked-q">Hoe kan het reliëf van een regio de bevolkingsspreiding verklaren?</div><ol class="sam-worked-steps"><li>Hooggebergte en droge of natte gebieden zijn moeilijk bewoonbaar.</li><li>Vlakke, vruchtbare gebieden met water trekken juist landbouw en steden aan.</li><li>Daardoor woont de bevolking geconcentreerd in de gunstige gebieden.</li></ol><div class="sam-worked-ans">✅ De fysische geografie (reliëf, klimaat) stuurt waar mensen zich vestigen — een klassiek voorbeeld van samenhang.</div></div></div>`,
'vwo_ak_E':`<div class="sam-intro">Nederland is een <strong>deltaland</strong>: een groot deel ligt onder zeeniveau. Dit domein gaat over de eigen <strong>leefomgeving</strong> — het <strong>waterbeheer</strong> en overstromingsrisico, de <strong>stedelijke gebieden</strong> en de <strong>ruimtelijke inrichting</strong> van Nederland.</div><div class="sam-head">Leven onder de zeespiegel</div><p>Ongeveer een kwart van Nederland ligt onder <strong>NAP</strong> (Normaal Amsterdams Peil). Zonder <strong>dijken</strong>, <strong>duinen</strong> en <strong>gemalen</strong> zou een groot deel van het land onder water staan. Waterbeheer is daarom van levensbelang.</p><div class="sam-figure"><svg viewBox="0 0 320 150" role="img" aria-label="Dwarsdoorsnede van een polder: de zee met dijk, het lager gelegen land en het grondwaterpeil"><rect x="0" y="55" width="90" height="70" fill="var(--or)" opacity=".18"/><path d="M0,55 Q45,50 90,55" fill="none" stroke="var(--or)" stroke-width="1.5"/><text x="40" y="90" font-size="9" font-weight="700" fill="var(--dk)">zee</text><path d="M90,55 L120,40 L150,55 Z" fill="var(--mu)" opacity=".35" stroke="var(--mu)" stroke-width="1.2"/><text x="120" y="34" font-size="8" fill="var(--mu)" text-anchor="middle">dijk</text><rect x="150" y="95" width="170" height="30" fill="var(--mu)" opacity=".2"/><line x1="150" y1="95" x2="320" y2="95" stroke="var(--dk)" stroke-width="1.5"/><text x="235" y="115" font-size="9" font-weight="700" fill="var(--dk)" text-anchor="middle">polder (onder NAP)</text><line x1="0" y1="55" x2="90" y2="55" stroke="var(--dk)" stroke-width="1" stroke-dasharray="4 2"/><text x="300" y="52" font-size="7.5" fill="var(--mu)" text-anchor="end">zeeniveau (NAP)</text><line x1="150" y1="55" x2="320" y2="55" stroke="var(--mu)" stroke-width="0.8" stroke-dasharray="3 3"/><path d="M150,55 L150,95" stroke="var(--mu)" stroke-width="1" marker-end="url(#akEa)"/><defs><marker id="akEa" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--mu)"/></marker></defs><text x="158" y="78" font-size="7" fill="var(--mu)">↕ onder NAP</text></svg><div class="sam-figcap"><strong>Polder in dwarsdoorsnede:</strong> de dijk houdt de zee tegen; het land erachter (de polder) ligt lager dan het zeeniveau (NAP). Gemalen pompen overtollig water weg.</div></div><div class="sam-head">Overstromingsrisico</div><p>Het <strong>risico</strong> is een combinatie van <strong>kans</strong> (hoe waarschijnlijk is een overstroming?) en <strong>gevolg</strong> (hoeveel schade en slachtoffers?). In dichtbevolkte, laaggelegen gebieden zijn de gevolgen groot, dus daar zijn de dijken het sterkst.</p><div class="sam-formula-box"><div class="sam-formula-label">Overstromingsrisico</div><div class="sam-formula-eq">risico = kans × gevolg</div><div class="sam-formula-note">Je verkleint het risico door de kans te verlagen (hogere dijken, 'Ruimte voor de Rivier') óf de gevolgen te beperken (evacuatieplannen, aangepast bouwen).</div></div><div class="sam-head">Stedelijke gebieden en ruimte</div><p>Nederland is dichtbevolkt, met de <strong>Randstad</strong> als economisch kerngebied. Ruimte is schaars, dus er zijn voortdurend keuzes en conflicten over de <strong>ruimtelijke inrichting</strong>: wonen, werken, natuur, landbouw en infrastructuur strijden om dezelfde grond.</p><div class="sam-tip"><strong>Ruimte voor de Rivier:</strong> in plaats van alleen hogere dijken geeft Nederland rivieren op sommige plekken juist méér ruimte (uiterwaarden), zodat hoogwater veilig weg kan.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave</div><div class="sam-worked-q">Waarom zijn de dijken rond de Randstad extra sterk?</div><ol class="sam-worked-steps"><li>Risico = kans × gevolg.</li><li>De Randstad is dichtbevolkt en economisch cruciaal, dus de gevolgen van een overstroming zijn enorm.</li><li>Om het risico beheersbaar te houden moet de kans daar extra klein zijn.</li></ol><div class="sam-worked-ans">✅ Door de grote gevolgen moeten de dijken hier aan de hoogste veiligheidsnormen voldoen.</div></div></div>`,
'vwo_mw_E':`<div class="sam-intro">Samenlevingen staan niet stil. Het hoofdconcept <strong>verandering</strong> gaat over de grote processen die de moderne samenleving vormden: <strong>modernisering</strong>, <strong>individualisering</strong> en <strong>globalisering</strong>.</div><div class="sam-head">Modernisering</div><p><strong>Modernisering</strong> is de langdurige overgang van een traditionele naar een moderne samenleving. Kenmerken: industrialisatie, verstedelijking, rationalisering, en een groeiende rol van wetenschap en de staat.</p><div class="sam-figure"><svg viewBox="0 0 320 120" role="img" aria-label="Overgang van een traditionele naar een moderne samenleving"><rect x="12" y="35" width="120" height="60" rx="8" fill="var(--mu)" opacity=".12" stroke="var(--mu)" stroke-width="1.2"/><text x="72" y="55" font-size="10" font-weight="700" fill="var(--dk)" text-anchor="middle">traditioneel</text><text x="72" y="72" font-size="7.5" fill="var(--mu)" text-anchor="middle">gemeenschap, geloof,</text><text x="72" y="83" font-size="7.5" fill="var(--mu)" text-anchor="middle">landbouw, vaste rollen</text><rect x="188" y="35" width="120" height="60" rx="8" fill="var(--or)" opacity=".14" stroke="var(--or)" stroke-width="1.3"/><text x="248" y="55" font-size="10" font-weight="700" fill="var(--dk)" text-anchor="middle">modern</text><text x="248" y="72" font-size="7.5" fill="var(--mu)" text-anchor="middle">individu, wetenschap,</text><text x="248" y="83" font-size="7.5" fill="var(--mu)" text-anchor="middle">industrie, vrije keuze</text><defs><marker id="mwEa" markerWidth="9" markerHeight="9" refX="5" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L7,3 L0,6 Z" fill="var(--or)"/></marker></defs><line x1="136" y1="65" x2="184" y2="65" stroke="var(--or)" stroke-width="2.4" marker-end="url(#mwEa)"/><text x="160" y="58" font-size="8" fill="var(--or)" text-anchor="middle">modernisering</text></svg><div class="sam-figcap"><strong>Modernisering:</strong> de samenleving verschuift van gemeenschap, geloof en vaste rollen naar individu, wetenschap, industrie en vrije keuze.</div></div><div class="sam-head">Individualisering</div><p><strong>Individualisering</strong> is het proces waarbij mensen losser komen te staan van vaste verbanden (kerk, klasse, buurt) en meer hun eigen keuzes maken. Dat geeft <strong>vrijheid</strong>, maar ook minder vanzelfsprekende <strong>binding</strong> en zekerheid.</p><div class="sam-head">Globalisering</div><p><strong>Globalisering</strong> is de toenemende wereldwijde verwevenheid — economisch, cultureel en politiek. Ze brengt kansen (handel, uitwisseling) maar ook spanningen (concurrentie, verlies van eigen identiteit, ongelijkheid).</p><table class="sam-table"><thead><tr><th>Proces</th><th>Kern</th></tr></thead><tbody><tr><td>Modernisering</td><td>traditioneel → modern (industrie, wetenschap)</td></tr><tr><td>Individualisering</td><td>minder vaste verbanden, meer eigen keuze</td></tr><tr><td>Globalisering</td><td>toenemende wereldwijde verwevenheid</td></tr></tbody></table><div class="sam-warn"><strong>Let op de samenhang:</strong> deze processen versterken elkaar. Globalisering en modernisering voeden de individualisering, en individualisering zet de traditionele binding en de verzorgingsstaat verder onder druk.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave</div><div class="sam-worked-q">Hoe kan individualisering de sociale cohesie onder druk zetten?</div><ol class="sam-worked-steps"><li>Mensen komen losser te staan van vaste verbanden (kerk, vereniging, buurt).</li><li>Daardoor nemen vanzelfsprekende contacten en gedeelde normen af.</li><li>Minder gedeelde binding kan de onderlinge verbondenheid verzwakken.</li></ol><div class="sam-worked-ans">✅ Meer individuele vrijheid gaat samen met minder vanzelfsprekende sociale binding.</div></div></div>`,
'vwo_gs_D':`<div class="sam-intro">Dit domein volgt hoe Nederland een <strong>rechtsstaat</strong> en een <strong>parlementaire democratie</strong> werd: van een land waar de koning regeerde naar een staat met <strong>grondrechten</strong>, <strong>machtenscheiding</strong> en <strong>algemeen kiesrecht</strong>.</div><div class="sam-head">Wat is een rechtsstaat?</div><p>In een <strong>rechtsstaat</strong> is de macht van de overheid aan wetten gebonden en worden burgers beschermd tegen willekeur. De kernprincipes:</p><table class="sam-table"><thead><tr><th>Principe</th><th>Betekenis</th></tr></thead><tbody><tr><td>Legaliteitsbeginsel</td><td>de overheid mag alleen handelen op basis van de wet</td></tr><tr><td>Machtenscheiding</td><td>trias politica: wetgevend, uitvoerend, rechterlijk gescheiden</td></tr><tr><td>Grondrechten</td><td>vrijheden van burgers (meningsuiting, godsdienst, gelijkheid)</td></tr><tr><td>Onafhankelijke rechtspraak</td><td>rechters oordelen zonder inmenging</td></tr></tbody></table><div class="sam-head">De weg naar democratie in Nederland</div><p>De parlementaire democratie ontstond stap voor stap. Enkele ijkpunten:</p><div class="sam-figure"><svg viewBox="0 0 340 130" role="img" aria-label="Tijdbalk van de democratisering van Nederland met de grondwet van 1848, evenredige vertegenwoordiging in 1917 en vrouwenkiesrecht in 1919"><line x1="30" y1="72" x2="330" y2="72" stroke="var(--mu)" stroke-width="2"/><g font-size="8" fill="var(--mu)" text-anchor="middle"><text x="40" y="92">1800</text><text x="130" y="92">1850</text><text x="220" y="92">1900</text><text x="310" y="92">1950</text></g><g stroke="var(--mu)" stroke-width="1"><line x1="40" y1="67" x2="40" y2="77"/><line x1="130" y1="67" x2="130" y2="77"/><line x1="220" y1="67" x2="220" y2="77"/><line x1="310" y1="67" x2="310" y2="77"/></g><g fill="var(--or)"><circle cx="126" cy="72" r="4"/><circle cx="250" cy="72" r="4"/><circle cx="254" cy="72" r="4"/></g><g font-size="7.5" font-weight="700" fill="var(--dk)" text-anchor="middle"><text x="126" y="52">1848</text><text x="126" y="42">Grondwet</text><text x="250" y="30">1917/1919</text><text x="250" y="20">kiesrecht</text></g><g font-size="6.5" fill="var(--mu)" text-anchor="middle"><text x="126" y="108">Thorbecke:</text><text x="126" y="117">min. verantw.</text><text x="250" y="108">evenredig +</text><text x="250" y="117">vrouwenkiesrecht</text></g></svg><div class="sam-figcap"><strong>Democratisering:</strong> in 1848 legde Thorbecke de basis (grondwet, ministeriële verantwoordelijkheid). In 1917 kwam de evenredige vertegenwoordiging en algemeen mannenkiesrecht, in 1919 het vrouwenkiesrecht.</div></div><div class="sam-head">Parlementaire democratie</div><p>In een <strong>parlementaire democratie</strong> controleert het gekozen parlement de regering. Dankzij de <strong>ministeriële verantwoordelijkheid</strong> (1848) moeten ministers zich verantwoorden tegenover de Staten-Generaal, niet de koning.</p><div class="sam-tip">1848 is het scharnierjaar: Thorbecke's grondwet maakte ministers verantwoordelijk aan het parlement en beperkte de macht van de koning — het begin van de parlementaire democratie.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave</div><div class="sam-worked-q">Waarom is de invoering van het algemeen kiesrecht (1917/1919) een belangrijke stap in de democratisering?</div><ol class="sam-worked-steps"><li>Vóór 1917 mocht alleen een beperkte, welgestelde groep mannen stemmen (censuskiesrecht).</li><li>Met algemeen kiesrecht kregen alle volwassen mannen (1917) en vrouwen (1919) stemrecht.</li><li>Daardoor werd het parlement een afspiegeling van de hele bevolking.</li></ol><div class="sam-worked-ans">✅ Het kiesrecht werd van een klein deel uitgebreid naar iedereen — de kern van democratisering.</div></div></div>`,
'vwo_bi_D':`<div class="sam-intro"><strong>Interactie</strong> gaat over beïnvloeding: hoe een biologische eenheid haar omgeving beïnvloedt én erdoor wordt beïnvloed, en hoe ze daarop reageert. Je bekijkt dat op oplopende schaal — van <strong>moleculen</strong> en <strong>cellen</strong> via het <strong>gedrag</strong> van een organisme tot hele <strong>ecosystemen</strong>.</div><div class="sam-head">Wat je voor het examen moet kennen (syllabus)</div><p>Domein D bestaat uit de subdomeinen hieronder. <strong>D4 (Seksualiteit)</strong> is vooral schoolexamenstof en valt buiten deze samenvatting.</p><table class="sam-table"><thead><tr><th>Sub</th><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>D1</td><td>Moleculaire interactie</td><td>signaalmolecuul + receptor (sleutel–slot)</td></tr><tr><td>D2</td><td>Cellulaire interactie</td><td>cellen communiceren: synaps, hormonen, afweer</td></tr><tr><td>D3</td><td>Gedrag en interactie</td><td>prikkel → verwerking → reactie; gedrag</td></tr><tr><td>D5</td><td>Interactie in ecosystemen</td><td>symbiose, concurrentie, predator–prooi</td></tr></tbody></table><div class="sam-head">D1 · Moleculaire interactie</div><p>Communicatie in en tussen cellen begint bij <strong>moleculen die op elkaar passen</strong>. Een <strong>signaalmolecuul</strong> (ligand, bv. een hormoon of neurotransmitter) bindt aan een <strong>receptor</strong> met een precies passende vorm — het <strong>sleutel–slot-principe</strong>. Alleen de juiste combinatie geeft een reactie.</p><div class="sam-figure"><svg viewBox="0 0 320 130" role="img" aria-label="Een signaalmolecuul past als een sleutel in een receptor en zet in de cel een respons in gang"><defs><marker id="giD1" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--or)"/></marker></defs><rect x="150" y="20" width="170" height="94" fill="var(--mu)" opacity=".08"/><line x1="150" y1="20" x2="150" y2="114" stroke="var(--mu)" stroke-width="2"/><text x="238" y="107" font-size="7.5" fill="var(--mu)" text-anchor="middle">binnenkant cel</text><circle cx="60" cy="52" r="16" fill="var(--or)" opacity=".8"/><text x="60" y="34" font-size="7.5" fill="var(--dk)" text-anchor="middle">signaalmolecuul</text><path d="M150,44 h-18 a10,10 0 0 0 0,20 h18" fill="none" stroke="var(--or)" stroke-width="1.6"/><text x="150" y="80" font-size="7.5" fill="var(--dk)" text-anchor="middle">receptor</text><line x1="80" y1="52" x2="126" y2="53" stroke="var(--or)" stroke-width="1.5" marker-end="url(#giD1)"/><line x1="168" y1="54" x2="250" y2="54" stroke="var(--or)" stroke-width="1.5" marker-end="url(#giD1)"/><text x="210" y="47" font-size="7.5" fill="var(--or)" text-anchor="middle">respons in de cel</text></svg><div class="sam-figcap"><strong>Sleutel–slot:</strong> alleen een signaalmolecuul met de juiste vorm bindt aan de receptor. Die binding zet ín de cel een reactie in gang (bijvoorbeeld een enzym activeren of een gen aanzetten).</div></div><p>Dezelfde specifieke binding zie je bij <strong>enzym en substraat</strong>, bij <strong>antigeen en antilichaam</strong> en bij <strong>hormoon en receptor</strong>. Een molecuul dat de receptor bezet maar géén respons geeft, werkt als <strong>remmer</strong>.</p><div class="sam-head">D2 · Cellulaire interactie</div><p>Cellen stemmen hun activiteit op elkaar af via signalen. De twee hoofdsystemen ken je uit domein B, maar hier draait het om de <strong>communicatie tussen de cellen</strong>:</p><div class="sam-compare"><div class="sam-compare-col"><div class="sam-compare-head">Zenuwstelsel</div><ul><li>snel, kortdurend, gericht</li><li>signaal via de synaps</li><li>neurotransmitter → volgende cel</li></ul></div><div class="sam-compare-col"><div class="sam-compare-head">Hormoonstelsel</div><ul><li>trager, langdurig, breed</li><li>hormoon via het bloed</li><li>werkt alleen op doelcellen met de juiste receptor</li></ul></div></div><div class="sam-figure"><svg viewBox="0 0 320 128" role="img" aria-label="In de synaps geeft de zendende cel neurotransmitter af die op receptoren van de ontvangende cel bindt"><defs><marker id="giD2" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--mu)"/></marker></defs><rect x="8" y="34" width="120" height="60" rx="8" fill="var(--or)" opacity=".14" stroke="var(--or)" stroke-width="1.2"/><text x="68" y="30" font-size="8" fill="var(--dk)" text-anchor="middle">zendende cel</text><rect x="192" y="34" width="120" height="60" rx="8" fill="var(--or)" opacity=".14" stroke="var(--or)" stroke-width="1.2"/><text x="252" y="30" font-size="8" fill="var(--dk)" text-anchor="middle">ontvangende cel</text><text x="160" y="112" font-size="7.5" fill="var(--mu)" text-anchor="middle">synapsspleet</text><circle cx="150" cy="52" r="4" fill="var(--or)"/><circle cx="162" cy="64" r="4" fill="var(--or)"/><circle cx="150" cy="76" r="4" fill="var(--or)"/><line x1="128" y1="64" x2="140" y2="64" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#giD2)"/><line x1="172" y1="64" x2="190" y2="64" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#giD2)"/><text x="160" y="46" font-size="7" fill="var(--or)" text-anchor="middle">neurotransmitter</text></svg><div class="sam-figcap"><strong>Synaps:</strong> bij een impuls geeft de zendende cel neurotransmitter af in de synapsspleet; dat molecuul bindt aan receptoren van de ontvangende cel (weer sleutel–slot, D1) en geeft de prikkel door.</div></div><p>Ook het <strong>afweersysteem</strong> werkt via cel-cel-herkenning: cellen herkennen met receptoren lichaamsvreemde antigenen en waarschuwen elkaar met signaalstoffen.</p><div class="sam-head">D3 · Gedrag en interactie</div><p><strong>Gedrag</strong> is alles wat een organisme waarneembaar doet als reactie op prikkels. De basisketen loopt van prikkel naar reactie:</p><div class="sam-figure"><svg viewBox="0 0 336 74" role="img" aria-label="Reactieketen: prikkel wordt door een zintuig opgevangen, door het zenuwstelsel verwerkt en door een effector omgezet in een reactie"><defs><marker id="giD3" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--or)"/></marker></defs><g font-size="8" font-weight="700" fill="var(--dk)" text-anchor="middle"><rect x="4" y="26" width="56" height="30" rx="5" fill="var(--mu)" opacity=".12" stroke="var(--mu)" stroke-width="1.1"/><text x="32" y="44">prikkel</text><rect x="80" y="26" width="56" height="30" rx="5" fill="var(--or)" opacity=".14" stroke="var(--or)" stroke-width="1.1"/><text x="108" y="44">zintuig</text><rect x="156" y="22" width="70" height="38" rx="5" fill="var(--or)" opacity=".16" stroke="var(--or)" stroke-width="1.2"/><text x="191" y="38">zenuw-</text><text x="191" y="49">stelsel</text><rect x="246" y="26" width="56" height="30" rx="5" fill="var(--or)" opacity=".14" stroke="var(--or)" stroke-width="1.1"/><text x="274" y="44">effector</text></g><text x="322" y="45" font-size="8" font-weight="700" fill="var(--dk)" text-anchor="start">→ reactie</text><line x1="60" y1="41" x2="78" y2="41" stroke="var(--or)" stroke-width="1.4" marker-end="url(#giD3)"/><line x1="136" y1="41" x2="154" y2="41" stroke="var(--or)" stroke-width="1.4" marker-end="url(#giD3)"/><line x1="226" y1="41" x2="244" y2="41" stroke="var(--or)" stroke-width="1.4" marker-end="url(#giD3)"/></svg><div class="sam-figcap"><strong>Reactieketen:</strong> een <strong>zintuig</strong> vangt de prikkel op, het <strong>zenuwstelsel</strong> verwerkt de informatie en een <strong>effector</strong> (spier of klier) voert de reactie uit.</div></div><table class="sam-table"><thead><tr><th>Type gedrag</th><th>Kenmerk</th></tr></thead><tbody><tr><td>Aangeboren</td><td>vastgelegd in het DNA, meteen aanwezig (bv. reflex, instinct)</td></tr><tr><td>Aangeleerd</td><td>ontstaat door ervaring (bv. conditionering, inprenting)</td></tr></tbody></table><p>Gedrag heeft altijd een <strong>functie</strong>: het vergroot de overlevings- of voortplantingskans. Denk aan <strong>communicatie</strong> tussen organismen (geur, geluid, houding) en aan reageren op <strong>abiotische</strong> factoren (licht, temperatuur).</p><div class="sam-tip">Bij een examenvraag over gedrag: benoem eerst de <strong>prikkel</strong>, dan de <strong>reactie</strong>, en verklaar de reactie via het <strong>voordeel</strong> voor overleving of voortplanting.</div><div class="sam-head">D5 · Interactie in ecosystemen</div><p>Tussen soorten in een ecosysteem bestaan vaste relaties. Ze verklaren waarom populaties groeien, krimpen of samen in evenwicht blijven.</p><table class="sam-table"><thead><tr><th>Relatie</th><th>Soort 1 / Soort 2</th><th>Voorbeeld</th></tr></thead><tbody><tr><td>Mutualisme</td><td>voordeel / voordeel</td><td>bij en bloem</td></tr><tr><td>Commensalisme</td><td>voordeel / geen effect</td><td>zeepok op walvis</td></tr><tr><td>Parasitisme</td><td>voordeel / nadeel</td><td>teek op gastheer</td></tr><tr><td>Predatie</td><td>eet / wordt gegeten</td><td>vos en konijn</td></tr><tr><td>Competitie</td><td>nadeel / nadeel</td><td>strijd om voedsel/ruimte</td></tr></tbody></table><p><strong>Concurrentie</strong> kan <strong>intraspecifiek</strong> zijn (binnen één soort — meestal het hevigst, want gelijke behoeften) of <strong>interspecifiek</strong> (tussen soorten). Predator en prooi houden elkaar in een <strong>schommelend evenwicht</strong>:</p><div class="sam-figure"><svg viewBox="0 0 330 168" role="img" aria-label="Predator-prooi grafiek: de prooipopulatie piekt en daarna volgt met vertraging de predatorpopulatie"><defs><marker id="giD5" markerWidth="9" markerHeight="9" refX="5" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L7,3 L0,6 Z" fill="var(--mu)"/></marker></defs><line x1="40" y1="150" x2="322" y2="150" stroke="var(--mu)" stroke-width="1.5" marker-end="url(#giD5)"/><line x1="40" y1="150" x2="40" y2="18" stroke="var(--mu)" stroke-width="1.5" marker-end="url(#giD5)"/><text x="326" y="164" font-size="8" fill="var(--mu)" text-anchor="end">tijd</text><text x="8" y="24" font-size="8" fill="var(--mu)">aantal</text><path d="M40,120 C70,60 100,52 130,96 C160,138 190,138 220,96 C250,56 280,58 310,110" fill="none" stroke="var(--or)" stroke-width="2.4" stroke-linecap="round"/><path d="M40,140 C75,128 104,86 134,80 C168,74 196,104 226,120 C256,134 286,112 312,86" fill="none" stroke="var(--mu)" stroke-width="2.2" stroke-linecap="round" stroke-dasharray="5 4"/><text x="96" y="44" font-size="8" fill="var(--or)">prooi</text><text x="150" y="70" font-size="8" fill="var(--mu)">predator</text></svg><div class="sam-figcap"><strong>Predator–prooi-cyclus:</strong> veel prooi → predatoren nemen toe → prooi wordt opgegeten en daalt → predatoren krijgen voedseltekort en dalen → prooi herstelt. De predatorpiek volgt steeds ná die van de prooi.</div></div><div class="sam-warn"><strong>Veelgemaakte fout:</strong> de predatorpopulatie loopt <strong>achter</strong> op de prooipopulatie, niet gelijk op. Eerst stijgt de prooi, dán pas (met vertraging) de predator. Zet in een grafiek de pieken dus niet op dezelfde plek.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — receptorspecificiteit</div><div class="sam-worked-q">Een medicijn bezet de receptor voor een hormoon, maar geeft zelf geen respons. Wat is het effect op de cel, en hoe heet zo'n stof?</div><ol class="sam-worked-steps"><li>Het hormoon kan niet meer aan de receptor binden — de plaats is bezet (sleutel–slot, D1).</li><li>Zonder binding van het hormoon komt de respons in de cel niet op gang.</li><li>Een stof die de receptor blokkeert zonder respons heet een <strong>remmer</strong> (antagonist).</li></ol><div class="sam-worked-ans">✅ Het hormoonsignaal wordt geblokkeerd; de stof werkt als remmer/antagonist.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — predator en prooi</div><div class="sam-worked-q">In een gebied neemt eerst het aantal hazen sterk toe, en pas daarna het aantal vossen. Verklaar deze volgorde.</div><ol class="sam-worked-steps"><li>Meer hazen betekent meer voedsel voor de vossen.</li><li>Door het ruime voedsel overleven meer jonge vossen en groeit de vossenpopulatie — maar dat kost tijd (draagtijd, opgroeien).</li><li>Daardoor stijgt het aantal vossen pas ná de piek van de hazen.</li></ol><div class="sam-worked-ans">✅ De predator (vos) reageert met vertraging op de toename van de prooi (haas).</div></div>`,
'vwo_bi_C':`<div class="sam-intro"><strong>Zelforganisatie</strong> is het vermogen van een biologisch systeem om vanuit de delen zélf nieuwe, geordende structuren te vormen. Daarbij ontstaan op elk hoger niveau <strong>emergente eigenschappen</strong>: eigenschappen die de losse onderdelen niet hebben. Je bekijkt dit op drie schalen — de <strong>cel</strong>, het <strong>organisme</strong> en het <strong>ecosysteem</strong>.</div><div class="sam-head">Wat je voor het examen moet kennen (syllabus)</div><p>Domein C bestaat uit drie subdomeinen. Deze samenvatting dekt ze alle drie:</p><table class="sam-table"><thead><tr><th>Sub</th><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>C1</td><td>Zelforganisatie van cellen</td><td>genexpressie, genregulatie, celdifferentiatie</td></tr><tr><td>C2</td><td>Zelforganisatie van het organisme</td><td>organisatieniveaus, weefsels, ontwikkeling</td></tr><tr><td>C3</td><td>Zelforganisatie van ecosystemen</td><td>voedselrelaties, kringlopen, successie</td></tr></tbody></table><div class="sam-head">C1 · Zelforganisatie van cellen</div><p>Alle cellen van een organisme bevatten hetzelfde <strong>DNA</strong>, en tóch is een spiercel iets heel anders dan een zenuwcel. Dat komt doordat in elke cel <strong>andere genen aan- of uitstaan</strong>. Twee begrippen staan centraal: <strong>genexpressie</strong> en <strong>celdifferentiatie</strong>.</p><ul><li><strong>Genexpressie</strong>: het tot uiting komen van een gen doordat het wordt afgelezen tot eiwit (DNA → mRNA → eiwit; zie domein B1). Alleen een <em>afgelezen</em> gen bepaalt wat de cel doet.</li><li><strong>Genregulatie</strong>: mechanismen die bepalen wélke genen in een cel worden afgelezen. Regeleiwitten (transcriptiefactoren) kunnen een gen aan- of uitzetten; ook stoffen van buiten de cel sturen dit.</li></ul><div class="sam-figure"><svg viewBox="0 0 330 132" role="img" aria-label="Dezelfde stamcel vormt door verschillende genregulatie verschillende gespecialiseerde cellen"><defs><marker id="giC1" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--mu)"/></marker></defs><rect x="10" y="50" width="80" height="34" rx="17" fill="var(--or)" opacity=".16" stroke="var(--or)" stroke-width="1.3"/><text x="50" y="65" font-size="9" font-weight="700" fill="var(--dk)" text-anchor="middle">stamcel</text><text x="50" y="77" font-size="7" fill="var(--mu)" text-anchor="middle">alle genen mogelijk</text><rect x="230" y="10" width="92" height="30" rx="6" fill="var(--mu)" opacity=".12" stroke="var(--mu)" stroke-width="1.1"/><text x="276" y="29" font-size="8.5" font-weight="700" fill="var(--dk)" text-anchor="middle">spiercel</text><rect x="230" y="52" width="92" height="30" rx="6" fill="var(--mu)" opacity=".12" stroke="var(--mu)" stroke-width="1.1"/><text x="276" y="71" font-size="8.5" font-weight="700" fill="var(--dk)" text-anchor="middle">zenuwcel</text><rect x="230" y="94" width="92" height="30" rx="6" fill="var(--mu)" opacity=".12" stroke="var(--mu)" stroke-width="1.1"/><text x="276" y="113" font-size="8.5" font-weight="700" fill="var(--dk)" text-anchor="middle">kliercel</text><path d="M90,63 C150,50 170,30 228,25" fill="none" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#giC1)"/><path d="M90,67 C150,67 170,67 228,67" fill="none" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#giC1)"/><path d="M90,71 C150,84 170,104 228,109" fill="none" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#giC1)"/><text x="158" y="94" font-size="7.5" fill="var(--or)" text-anchor="middle">celdifferentiatie</text></svg><div class="sam-figcap"><strong>Celdifferentiatie:</strong> een ongespecialiseerde <strong>stamcel</strong> vormt door verschillende genregulatie gespecialiseerde cellen. Elke cel heeft hetzelfde DNA, maar leest andere genen af.</div></div><ul><li><strong>Stamcellen</strong> zijn cellen die zich nog kunnen delen én differentiëren. <strong>Embryonale</strong> stamcellen kunnen elk celtype worden; <strong>adulte</strong> stamcellen (bv. in beenmerg) zijn beperkter.</li><li><strong>Emergente eigenschap</strong> op celniveau: uit de ordening van moleculen ontstaat een levende cel met eigenschappen (stofwisseling, deling) die losse moleculen niet hebben.</li></ul><div class="sam-tip">Onthoud het onderscheid: <strong>differentiatie</strong> = specialiseren (welke genen aan/uit), <strong>deling</strong> = vermeerderen (mitose). Een cel doet vaak eerst het een, dan het ander.</div><div class="sam-head">C2 · Zelforganisatie van het organisme</div><p>Cellen organiseren zich tot steeds grotere gehelen. Op elk niveau ontstaan nieuwe, <strong>emergente</strong> eigenschappen:</p><div class="sam-figure"><svg viewBox="0 0 340 92" role="img" aria-label="Organisatieniveaus van cel naar weefsel naar orgaan naar orgaanstelsel naar organisme"><defs><marker id="giC2" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--or)"/></marker></defs><g font-size="8" font-weight="700" fill="var(--dk)" text-anchor="middle"><rect x="6" y="34" width="52" height="30" rx="5" fill="var(--or)" opacity=".12" stroke="var(--or)" stroke-width="1.1"/><text x="32" y="52">cel</text><rect x="76" y="34" width="56" height="30" rx="5" fill="var(--or)" opacity=".14" stroke="var(--or)" stroke-width="1.1"/><text x="104" y="52">weefsel</text><rect x="150" y="34" width="56" height="30" rx="5" fill="var(--or)" opacity=".16" stroke="var(--or)" stroke-width="1.2"/><text x="178" y="52">orgaan</text><rect x="224" y="30" width="60" height="38" rx="5" fill="var(--or)" opacity=".18" stroke="var(--or)" stroke-width="1.2"/><text x="254" y="46">orgaan-</text><text x="254" y="57">stelsel</text><rect x="302" y="34" width="34" height="30" rx="5" fill="var(--or)" opacity=".22" stroke="var(--or)" stroke-width="1.3"/><text x="319" y="49">orga-</text><text x="319" y="59">nisme</text></g><line x1="58" y1="49" x2="74" y2="49" stroke="var(--or)" stroke-width="1.4" marker-end="url(#giC2)"/><line x1="132" y1="49" x2="148" y2="49" stroke="var(--or)" stroke-width="1.4" marker-end="url(#giC2)"/><line x1="206" y1="49" x2="222" y2="49" stroke="var(--or)" stroke-width="1.4" marker-end="url(#giC2)"/><line x1="284" y1="49" x2="300" y2="49" stroke="var(--or)" stroke-width="1.4" marker-end="url(#giC2)"/></svg><div class="sam-figcap"><strong>Organisatieniveaus:</strong> gespecialiseerde cellen van dezelfde soort vormen samen een <strong>weefsel</strong>, weefsels een <strong>orgaan</strong>, organen een <strong>orgaanstelsel</strong> en die samen het <strong>organisme</strong>. Elk niveau heeft nieuwe eigenschappen.</div></div><table class="sam-table"><thead><tr><th>Weefsels (voorbeelden)</th><th>Functie</th></tr></thead><tbody><tr><td>Dekweefsel (epitheel)</td><td>bedekt en beschermt oppervlakken, opname/afgifte</td></tr><tr><td>Bind- en steunweefsel</td><td>verbindt en ondersteunt (bv. bot, kraakbeen)</td></tr><tr><td>Spierweefsel</td><td>samentrekken → beweging</td></tr><tr><td>Zenuwweefsel</td><td>impulsen geleiden en verwerken</td></tr></tbody></table><p>Een organisme ontstaat door <strong>embryonale ontwikkeling</strong> uit één bevruchte eicel. Daarbij spelen samen:</p><ul><li><strong>Celdeling</strong> (mitose): meer cellen, met identiek DNA.</li><li><strong>Celdifferentiatie</strong>: cellen specialiseren (C1).</li><li><strong>Morfogenese</strong>: vormgeving — cellen komen op de juiste plaats en vormen de bouw van het lichaam.</li><li><strong>Inductie</strong>: cellen sturen elkaars ontwikkeling met signaalstoffen. <strong>Apoptose</strong> (geprogrammeerde celdood) verwijdert overtollige cellen (bv. tussen vingers).</li></ul><div class="sam-warn"><strong>Let op het verschil:</strong> <strong>groei</strong> is toename van het aantal cellen of celgrootte; <strong>ontwikkeling</strong> is het ontstaan van vorm en specialisatie. Een organisme kan zich ontwikkelen zonder te groeien en omgekeerd.</div><div class="sam-head">C3 · Zelforganisatie van ecosystemen</div><p>Ook boven het organisme gaat de ordening door. Een <strong>ecosysteem</strong> is een begrensd gebied met alle <strong>biotische</strong> factoren (het levende: planten, dieren, micro-organismen) en <strong>abiotische</strong> factoren (het niet-levende: licht, temperatuur, water, bodem) samen.</p><div class="sam-figure"><svg viewBox="0 0 320 96" role="img" aria-label="Organisatieniveaus in de ecologie van individu naar populatie naar levensgemeenschap naar ecosysteem"><defs><marker id="giC3a" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--mu)"/></marker></defs><g font-size="8" font-weight="700" fill="var(--dk)" text-anchor="middle"><rect x="6" y="34" width="58" height="30" rx="5" fill="var(--mu)" opacity=".1" stroke="var(--mu)" stroke-width="1.1"/><text x="35" y="52">individu</text><rect x="82" y="34" width="62" height="30" rx="5" fill="var(--mu)" opacity=".13" stroke="var(--mu)" stroke-width="1.1"/><text x="113" y="52">populatie</text><rect x="162" y="30" width="70" height="38" rx="5" fill="var(--mu)" opacity=".16" stroke="var(--mu)" stroke-width="1.1"/><text x="197" y="46">levens-</text><text x="197" y="57">gemeenschap</text><rect x="250" y="30" width="66" height="38" rx="5" fill="var(--or)" opacity=".18" stroke="var(--or)" stroke-width="1.2"/><text x="283" y="46">eco-</text><text x="283" y="57">systeem</text></g><line x1="64" y1="49" x2="80" y2="49" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#giC3a)"/><line x1="144" y1="49" x2="160" y2="49" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#giC3a)"/><line x1="232" y1="49" x2="248" y2="49" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#giC3a)"/></svg><div class="sam-figcap"><strong>Ecologische niveaus:</strong> individuen van één soort vormen een <strong>populatie</strong>, alle populaties samen de <strong>levensgemeenschap</strong>, en die met de abiotische omgeving het <strong>ecosysteem</strong>.</div></div><p>In een ecosysteem hangen soorten samen via <strong>voedselrelaties</strong>. De rollen:</p><ul><li><strong>Producenten</strong> (planten): leggen met fotosynthese energie vast — het begin van elke keten.</li><li><strong>Consumenten</strong> (dieren): eten andere organismen (herbivoor, carnivoor, omnivoor).</li><li><strong>Reducenten</strong> (bacteriën, schimmels): breken dood materiaal af tot mineralen die planten weer opnemen.</li></ul><div class="sam-figure"><svg viewBox="0 0 300 150" role="img" aria-label="Energiepiramide: van producenten naar toppredator neemt de beschikbare energie per niveau sterk af"><g stroke="var(--or)" stroke-width="1.2"><polygon points="40,26 260,26 218,58 82,58" fill="var(--or)" opacity=".28"/><polygon points="82,62 218,62 190,94 110,94" fill="var(--or)" opacity=".2"/><polygon points="110,98 190,98 168,130 132,130" fill="var(--or)" opacity=".13"/></g><g font-size="8.5" font-weight="700" fill="var(--dk)" text-anchor="middle"><text x="150" y="46">producenten</text><text x="150" y="82">herbivoren</text><text x="150" y="118">carnivoren</text></g><text x="286" y="30" font-size="8" fill="var(--mu)" text-anchor="end">veel energie</text><text x="286" y="132" font-size="8" fill="var(--mu)" text-anchor="end">weinig energie</text></svg><div class="sam-figcap"><strong>Energiepiramide:</strong> per trofisch niveau gaat ± 90% van de energie verloren (vooral als warmte bij dissimilatie). Daardoor is er steeds minder energie en zijn er weinig toppredatoren.</div></div><p>Stoffen daarentegen gaan <strong>rond</strong> in <strong>kringlopen</strong> — ze raken niet op. Ken de <strong>koolstofkringloop</strong> (CO₂ ↔ organische stof via fotosynthese en verbranding/dissimilatie) en de <strong>stikstofkringloop</strong> (bacteriën zetten stikstof om in opneembare vorm en weer terug).</p><table class="sam-table"><thead><tr><th>Begrip</th><th>Betekenis</th></tr></thead><tbody><tr><td>Successie</td><td>geleidelijke verandering van levensgemeenschap: van <strong>pioniers</strong> naar een stabiel <strong>climaxstadium</strong></td></tr><tr><td>Draagkracht</td><td>maximale populatiegrootte die een gebied blijvend kan onderhouden</td></tr><tr><td>Dynamisch evenwicht</td><td>aantallen schommelen rond een gemiddelde; het systeem herstelt zich na een verstoring</td></tr><tr><td>Biodiversiteit</td><td>de soortenrijkdom; meer diversiteit → stabieler ecosysteem</td></tr></tbody></table><div class="sam-tip">Rode draad door het hele domein: <strong>energie stroomt (eenrichting, gaat verloren als warmte), stoffen gaan rond (kringloop).</strong> Verwar deze twee nooit in een examenvraag.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — genregulatie</div><div class="sam-worked-q">Een spiercel en een zenuwcel uit hetzelfde lichaam bevatten precies hetzelfde DNA. Leg uit hoe ze tóch verschillende eiwitten kunnen bevatten.</div><ol class="sam-worked-steps"><li>Alle lichaamscellen ontstaan door mitose uit één cel en hebben dus identiek DNA.</li><li>Door <strong>genregulatie</strong> staan in elke cel andere genen aan of uit.</li><li>Alleen de afgelezen (tot expressie gebrachte) genen leveren eiwit; daardoor verschilt de eiwitinhoud.</li></ol><div class="sam-worked-ans">✅ Niet het DNA verschilt, maar wélke genen tot expressie komen (genregulatie → celdifferentiatie).</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — energie in een keten</div><div class="sam-worked-q">In een keten gras → konijn → vos is er per niveau steeds minder biomassa en energie. Geef de biologische verklaring.</div><ol class="sam-worked-steps"><li>Elk organisme gebruikt het grootste deel van de opgenomen energie zelf voor stofwisseling (dissimilatie); die energie verdwijnt als warmte.</li><li>Slechts ± 10% wordt vastgelegd in nieuwe biomassa en is beschikbaar voor het volgende niveau.</li><li>Daardoor daalt de energie (en biomassa) sterk per trofisch niveau — de energiepiramide.</li></ol><div class="sam-worked-ans">✅ Energieverlies als warmte bij elke stap; energie stroomt in één richting en gaat niet rond.</div></div>`,
'vwo_ec_H':`<div class="sam-intro"><strong>Welvaart en groei</strong> gaat over hoe rijk een land is en waarom dat toeneemt. Je meet de productie met het <strong>bbp</strong>, onderscheidt <strong>welvaart in enge en brede zin</strong>, verklaart <strong>economische groei</strong> uit productiefactoren en productiviteit, en bekijkt hoe het inkomen verdeeld is.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Deel</th><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>1</td><td>Welvaart</td><td>enge (materieel) vs. brede welvaart</td></tr><tr><td>2</td><td>Bbp</td><td>productie meten; nominaal vs. reëel</td></tr><tr><td>3</td><td>Economische groei</td><td>bronnen: productiefactoren + productiviteit</td></tr><tr><td>4</td><td>Inkomensverdeling</td><td>primair/secundair, Lorenzcurve, (de)nivellering</td></tr></tbody></table><div class="sam-head">1 · Welvaart</div><p><strong>Welvaart</strong> is de mate waarin mensen in hun behoeften kunnen voorzien met schaarse middelen. Twee opvattingen:</p><div class="sam-compare"><div class="sam-compare-col"><div class="sam-compare-head">Welvaart in enge zin</div><ul><li>alleen wat met geld te koop is</li><li>gemeten via het bbp</li></ul></div><div class="sam-compare-col"><div class="sam-compare-head">Welvaart in brede zin</div><ul><li>óók milieu, vrije tijd, gezondheid, veiligheid</li><li>"brede welvaart"</li></ul></div></div><div class="sam-head">2 · Bbp: de productie meten</div><p>Het <strong>bruto binnenlands product (bbp)</strong> is de totale waarde van alle in een land geproduceerde goederen en diensten in een jaar. Om groei zuiver te meten, corrigeer je voor prijsstijging (inflatie):</p><div class="sam-formula-box"><div class="sam-formula-label">Nominaal en reëel bbp</div><div class="sam-formula-eq">reëel bbp = (nominaal bbp / prijsindexcijfer) × 100</div><div class="sam-formula-note"><strong>Nominaal</strong> = tegen lopende prijzen. <strong>Reëel</strong> = gecorrigeerd voor inflatie. Alleen een stijging van het <em>reële</em> bbp betekent dat er écht meer is geproduceerd.</div></div><div class="sam-warn"><strong>Veelgemaakte fout:</strong> een hoger nominaal bbp betekent niet automatisch meer welvaart. Als alleen de prijzen stegen (inflatie), is het reële bbp gelijk gebleven en is er niet meer geproduceerd.</div><div class="sam-head">3 · Economische groei</div><p><strong>Economische groei</strong> is de procentuele toename van het reële bbp. Ze komt uit twee bronnen: méér <strong>productiefactoren</strong> inzetten en die factoren <strong>productiever</strong> maken.</p><div class="sam-figure"><svg viewBox="0 0 300 128" role="img" aria-label="Bronnen van economische groei: meer productiefactoren en hogere arbeidsproductiviteit leiden tot een hoger bbp"><defs><marker id="giEH1" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--or)"/></marker></defs><g font-size="7.5" fill="var(--dk)" text-anchor="middle"><rect x="8" y="14" width="120" height="26" rx="5" fill="var(--mu)" opacity=".12" stroke="var(--mu)" stroke-width="1"/><text x="68" y="30">meer productiefactoren</text><rect x="8" y="54" width="120" height="34" rx="5" fill="var(--mu)" opacity=".12" stroke="var(--mu)" stroke-width="1"/><text x="68" y="68">hogere arbeids-</text><text x="68" y="80">productiviteit</text><rect x="210" y="40" width="82" height="40" rx="5" fill="var(--or)" opacity=".18" stroke="var(--or)" stroke-width="1.2"/><text x="251" y="58" font-weight="700">hoger</text><text x="251" y="70" font-weight="700">reëel bbp</text></g><text x="46" y="112" font-size="6.5" fill="var(--mu)" text-anchor="middle">arbeid, kapitaal, natuur</text><text x="60" y="102" font-size="6.5" fill="var(--mu)" text-anchor="middle">techniek, kennis, scholing</text><line x1="128" y1="30" x2="208" y2="52" stroke="var(--or)" stroke-width="1.5" marker-end="url(#giEH1)"/><line x1="128" y1="70" x2="208" y2="66" stroke="var(--or)" stroke-width="1.5" marker-end="url(#giEH1)"/></svg><div class="sam-figcap"><strong>Bronnen van groei:</strong> meer <strong>productiefactoren</strong> (arbeid, kapitaal, natuur) én een hogere <strong>arbeidsproductiviteit</strong> (door techniek, kennis en scholing) vergroten het reële bbp.</div></div><div class="sam-formula-box"><div class="sam-formula-label">Arbeidsproductiviteit en groei</div><div class="sam-formula-eq">arbeidsproductiviteit = productie / aantal arbeidsjaren<br>groei (%) = (reëel bbp<sub>nieuw</sub> − reëel bbp<sub>oud</sub>) / reëel bbp<sub>oud</sub> × 100%</div><div class="sam-formula-note">Groei per hoofd van de bevolking zegt meer over de welvaart dan totale groei, omdat ook het inwonertal verandert.</div></div><div class="sam-tip"><strong>Duurzame (brede) groei:</strong> groei van het bbp kan ten koste gaan van milieu of grondstoffen. Bij <strong>brede welvaart</strong> weeg je die kosten mee — groei is pas duurzaam als ze de welvaart van latere generaties niet aantast.</div><div class="sam-head">4 · Inkomensverdeling</div><p>Het <strong>primaire inkomen</strong> verdien je met productiefactoren (loon, huur, rente, winst). Na belastingen en uitkeringen houd je het <strong>secundaire inkomen</strong> over. De overheid kan zo <strong>nivelleren</strong> (verschillen kleiner maken) of <strong>denivelleren</strong>.</p><div class="sam-figure"><svg viewBox="0 0 200 170" role="img" aria-label="Lorenzcurve: de kromme wijkt af van de diagonale lijn van volledige gelijkheid"><defs><marker id="giEH2" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--mu)"/></marker></defs><line x1="30" y1="150" x2="185" y2="150" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#giEH2)"/><line x1="30" y1="160" x2="30" y2="12" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#giEH2)"/><text x="180" y="164" font-size="7" fill="var(--mu)" text-anchor="end">% huishoudens</text><text x="12" y="20" font-size="7" fill="var(--mu)">% ink.</text><line x1="30" y1="150" x2="170" y2="20" stroke="var(--mu)" stroke-width="1.4" stroke-dasharray="4 3"/><text x="92" y="70" font-size="6.5" fill="var(--mu)" transform="rotate(-42 92 70)">volledige gelijkheid</text><path d="M30,150 C90,146 140,110 170,20" fill="none" stroke="var(--or)" stroke-width="2.4"/><text x="150" y="96" font-size="7.5" fill="var(--or)">Lorenzcurve</text></svg><div class="sam-figcap"><strong>Lorenzcurve:</strong> hoe verder de kromme van de diagonaal (volledige gelijkheid) af buigt, hoe <strong>schever</strong> het inkomen verdeeld is. Nivellering trekt de curve naar de diagonaal toe.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — reëel bbp</div><div class="sam-worked-q">Het nominale bbp stijgt in een jaar met 5%; de prijzen stijgen met 3%. Is er economische groei? Ongeveer hoeveel?</div><ol class="sam-worked-steps"><li>Economische groei = groei van het réële bbp.</li><li>Reële groei ≈ nominale groei − inflatie = 5% − 3%.</li><li>≈ 2%.</li></ol><div class="sam-worked-ans">✅ Ja, ongeveer 2% reële groei: er is echt meer geproduceerd, niet alleen duurder.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — brede welvaart</div><div class="sam-worked-q">Een land laat het bbp groeien door meer fabrieken, maar de luchtvervuiling neemt sterk toe. Stijgt de welvaart?</div><ol class="sam-worked-steps"><li>In enge zin (bbp) stijgt de welvaart: er wordt meer geproduceerd.</li><li>In brede zin telt ook het milieu mee.</li><li>De vervuiling verlaagt de brede welvaart; het totale effect is onzeker.</li></ol><div class="sam-worked-ans">✅ Welvaart in enge zin stijgt, maar in brede zin niet per se — de milieuschade werkt de andere kant op.</div></div>`,
'vwo_na_E':`<div class="sam-intro"><strong>Straling en materie</strong> gaat over de wisselwerking tussen straling en stof: hoe atomen licht <strong>uitzenden en opnemen</strong> (spectra), en hoe onstabiele kernen <strong>ioniserende straling</strong> uitzenden bij radioactief verval. Zo lees je uit sterlicht de samenstelling van een ster af en bepaal je de ouderdom van materiaal.</div><div class="sam-head">Wat je voor het examen moet kennen (syllabus)</div><p>De CE-kern van dit domein is <strong>E2</strong>. <strong>E3</strong> (kernprocessen) is een keuze-/verdiepingsonderwerp dat vaak wordt getoetst; <strong>E1</strong> (eigenschappen van stoffen) hoort bij het schoolexamen.</p><table class="sam-table"><thead><tr><th>Sub</th><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>E2</td><td>Elektromagnetische straling en materie</td><td>EM-spectrum, foton, emissie- en absorptiespectra</td></tr><tr><td>E3</td><td>Kern- en deeltjesprocessen</td><td>α/β/γ-straling, verval, halveringstijd, E = m·c²</td></tr></tbody></table><div class="sam-head">E2 · Elektromagnetische straling</div><p>Licht is een <strong>elektromagnetische golf</strong>. Het hele <strong>EM-spectrum</strong> loopt van laagfrequente radiogolven tot hoogfrequente gammastraling; zichtbaar licht is maar een smalle band. Hoe hoger de frequentie, hoe hoger de <strong>stralingsenergie</strong>.</p><div class="sam-figure"><svg viewBox="0 0 300 78" role="img" aria-label="Elektromagnetisch spectrum van radiogolven tot gammastraling met zichtbaar licht in het midden"><defs><linearGradient id="emg" x1="0" x2="1"><stop offset="0" stop-color="var(--mu)" stop-opacity=".25"/><stop offset="1" stop-color="var(--or)" stop-opacity=".85"/></linearGradient></defs><rect x="16" y="26" width="268" height="20" fill="url(#emg)"/><g font-size="6.5" fill="var(--dk)" text-anchor="middle"><text x="34" y="40">radio</text><text x="86" y="40">infrarood</text><text x="132" y="40">licht</text><text x="176" y="40">UV</text><text x="220" y="40">röntgen</text><text x="264" y="40">gamma</text></g><text x="16" y="60" font-size="7" fill="var(--mu)" text-anchor="start">lage f, grote λ</text><text x="284" y="60" font-size="7" fill="var(--or)" text-anchor="end">hoge f, veel energie</text><rect x="120" y="24" width="26" height="24" fill="none" stroke="var(--dk)" stroke-width="1"/></svg><div class="sam-figcap"><strong>EM-spectrum:</strong> alle soorten zijn in wezen dezelfde elektromagnetische straling, alleen met andere frequentie/golflengte. Rechts (gamma, röntgen) zit de meeste energie per foton.</div></div><div class="sam-formula-box"><div class="sam-formula-label">Stralingsenergie van een foton</div><div class="sam-formula-eq">E<sub>f</sub> = h · f = h · c / λ</div><div class="sam-formula-note">h = 6,626·10⁻³⁴ J·s (constante van Planck). Straling bestaat uit energiepakketjes (<strong>fotonen</strong>); het quantumgedrag hiervan hoort bij domein F.</div></div><p>Atomen kunnen alleen bepaalde energieën hebben (<strong>energieniveaus</strong>). Springt een elektron terug naar een lager niveau, dan zendt het atoom een foton uit met precies dat energieverschil — daardoor bestaat het spectrum van een stof uit vaste <strong>lijnen</strong>:</p><div class="sam-figure"><svg viewBox="0 0 300 96" role="img" aria-label="Emissiespectrum als heldere lijnen en absorptiespectrum als donkere lijnen in een continu spectrum"><g><text x="8" y="22" font-size="7.5" fill="var(--dk)">emissie</text><rect x="70" y="12" width="220" height="20" fill="#111"/><g stroke="var(--or)" stroke-width="2"><line x1="100" y1="12" x2="100" y2="32"/><line x1="150" y1="12" x2="150" y2="32"/><line x1="205" y1="12" x2="205" y2="32"/><line x1="250" y1="12" x2="250" y2="32"/></g></g><g><text x="8" y="66" font-size="7.5" fill="var(--dk)">absorptie</text><rect x="70" y="56" width="220" height="20" fill="url(#emg)" opacity=".6"/><rect x="70" y="56" width="220" height="20" fill="none" stroke="var(--mu)" stroke-width=".5"/><g stroke="#111" stroke-width="2"><line x1="100" y1="56" x2="100" y2="76"/><line x1="150" y1="56" x2="150" y2="76"/><line x1="205" y1="56" x2="205" y2="76"/><line x1="250" y1="56" x2="250" y2="76"/></g></g></svg><div class="sam-figcap"><strong>Spectra:</strong> een heet gas zendt licht uit op vaste golflengtes (<strong>emissie</strong>, heldere lijnen). Schijnt wit licht door een koeler gas, dan ontbreken juist díe golflengtes (<strong>absorptie</strong>, donkere lijnen). Zo bepaal je de samenstelling van een ster.</div></div><div class="sam-head">E3 · Radioactief verval en straling</div><p>Onstabiele atoomkernen vervallen en zenden daarbij <strong>ioniserende straling</strong> uit. Drie soorten, met sterk verschillend doordringend vermogen:</p><div class="sam-figure"><svg viewBox="0 0 300 108" role="img" aria-label="Doordringend vermogen: alfa gestopt door papier, bèta door aluminium, gamma pas door lood"><g font-size="8" font-weight="700" fill="var(--dk)"><text x="6" y="28">α</text><text x="6" y="58">β</text><text x="6" y="88">γ</text></g><g stroke-width="2"><line x1="24" y1="24" x2="120" y2="24" stroke="var(--or)"/><line x1="24" y1="54" x2="188" y2="54" stroke="var(--or)"/><line x1="24" y1="84" x2="286" y2="84" stroke="var(--or)"/></g><g font-size="6.5" fill="var(--mu)" text-anchor="middle"><rect x="120" y="10" width="8" height="88" fill="var(--mu)" opacity=".3"/><text x="124" y="106">papier</text><rect x="188" y="10" width="10" height="88" fill="var(--mu)" opacity=".45"/><text x="193" y="106">aluminium</text><rect x="270" y="10" width="16" height="88" fill="var(--mu)" opacity=".7"/><text x="278" y="106">lood</text></g></svg><div class="sam-figcap"><strong>Doordringend vermogen:</strong> <strong>α</strong>-straling (heliumkern) stopt al bij papier, <strong>β</strong>-straling (elektron) bij een laagje aluminium, en de energierijke <strong>γ</strong>-straling (foton) pas bij dik lood.</div></div><p>Verval verloopt volgens een vaste <strong>halveringstijd</strong> t<sub>½</sub>: de tijd waarin de helft van de kernen vervalt. De activiteit neemt daardoor <strong>exponentieel</strong> af.</p><div class="sam-figure"><svg viewBox="0 0 300 150" role="img" aria-label="Exponentiële vervalcurve: elke halveringstijd halveert het aantal kernen"><defs><marker id="giNE" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--mu)"/></marker></defs><line x1="36" y1="128" x2="290" y2="128" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#giNE)"/><line x1="36" y1="138" x2="36" y2="14" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#giNE)"/><text x="288" y="142" font-size="8" fill="var(--mu)" text-anchor="end">t</text><text x="10" y="22" font-size="8" fill="var(--mu)">N</text><path d="M36,24 C70,54 96,86 130,102 C170,120 210,124 288,126" fill="none" stroke="var(--or)" stroke-width="2.4"/><g stroke="var(--mu)" stroke-width="1" stroke-dasharray="3 3"><line x1="99" y1="76" x2="99" y2="128"/><line x1="162" y1="102" x2="162" y2="128"/></g><g font-size="7" fill="var(--mu)" text-anchor="middle"><text x="99" y="140">t½</text><text x="162" y="140">2·t½</text></g><line x1="36" y1="76" x2="99" y2="76" stroke="var(--mu)" stroke-width="1" stroke-dasharray="3 3"/><text x="30" y="79" font-size="7" fill="var(--mu)" text-anchor="end">½N₀</text></svg><div class="sam-figcap"><strong>Halveringstijd:</strong> na elke t<sub>½</sub> is nog de helft over: N₀ → ½N₀ → ¼N₀ → … De curve nadert de as maar bereikt nooit nul.</div></div><div class="sam-formula-box"><div class="sam-formula-label">Verval en massa-energie</div><div class="sam-formula-eq">N = N<sub>0</sub> · (½)<sup>t / t½</sup><br>E = m · c²   (c = 2,998·10⁸ m/s)</div><div class="sam-formula-note">Bij kernreacties geldt behoud van lading en massagetal. Een klein <strong>massaverschil</strong> komt vrij als energie volgens E = m·c².</div></div><div class="sam-warn"><strong>Let op het verschil:</strong> <strong>halveringstijd</strong> is een eigenschap van de stof en verandert niet. De <strong>activiteit</strong> (aantal vervallen per seconde) daalt wél in de tijd, evenredig met het aantal nog aanwezige kernen.</div><div class="sam-tip">B2 <strong>Medische beeldvorming</strong> (domein B) gebruikt deze straling: röntgen en CT met ioniserende straling, en bestraling in de radiotherapie. Afweging: diagnostisch nut versus de schadelijke dosis.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — halveringstijd</div><div class="sam-worked-q">Een bron bevat 8,0·10¹¹ radioactieve kernen. De halveringstijd is 6,0 uur. Hoeveel kernen zijn er na 18 uur nog over?</div><ol class="sam-worked-steps"><li>Aantal halveringstijden: 18 / 6,0 = 3.</li><li>N = N₀ · (½)³ = N₀ · 1/8.</li><li>N = 8,0·10¹¹ / 8 = 1,0·10¹¹.</li></ol><div class="sam-worked-ans">✅ Na 18 uur zijn er nog 1,0·10¹¹ kernen over.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — foton-energie</div><div class="sam-worked-q">Waarom is UV-straling schadelijker voor de huid dan zichtbaar licht, terwijl beide "licht" zijn?</div><ol class="sam-worked-steps"><li>UV heeft een hogere frequentie dan zichtbaar licht.</li><li>Uit E = h·f volgt: hogere f betekent meer energie per foton.</li><li>UV-fotonen dragen genoeg energie om moleculen (bv. DNA) te beschadigen; zichtbaar licht niet.</li></ol><div class="sam-worked-ans">✅ Door de hogere frequentie hebben UV-fotonen meer energie (E = h·f) en werken ze ioniserend/schadelijk.</div></div>`,
'vwo_ec_C':`<div class="sam-intro"><strong>Ruil</strong> maakt mensen rijker: door je te <strong>specialiseren</strong> in wat je relatief het best kunt en de rest te <strong>ruilen</strong>, is er in totaal meer. <strong>Geld</strong> smeert die ruil. Zo ontstaat arbeidsverdeling, handel en een geldkringloop.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Deel</th><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>1</td><td>Arbeidsverdeling</td><td>specialisatie verhoogt de productie</td></tr><tr><td>2</td><td>Comparatief voordeel</td><td>ruilen loont ook bij een minder efficiënte partij</td></tr><tr><td>3</td><td>Geld</td><td>functies van geld; ruil in natura vs. geldruil</td></tr><tr><td>4</td><td>Toegevoegde waarde</td><td>waarde die in elke schakel wordt toegevoegd</td></tr></tbody></table><div class="sam-head">1 · Arbeidsverdeling en specialisatie</div><p>Bij <strong>arbeidsverdeling</strong> doet ieder een deeltaak in plaats van alles zelf. Door <strong>specialisatie</strong> word je sneller en beter, gebruik je machines efficiënter en stijgt de totale productie. De keerzijde: je wordt afhankelijk van anderen en moet dus <strong>ruilen</strong>.</p><div class="sam-head">2 · Comparatief voordeel</div><p>Ruil loont zelfs als één partij álles efficiënter kan. Wat telt is het <strong>comparatieve voordeel</strong>: specialiseer je in het product waarin je de <strong>laagste opofferingskosten</strong> hebt, en ruil de rest. Dan is er in totaal méér dan wanneer ieder alles zelf maakt.</p><div class="sam-figure"><svg viewBox="0 0 300 118" role="img" aria-label="Twee gespecialiseerde producenten ruilen en hebben samen meer dan wanneer elk alles zelf maakt"><defs><marker id="giEC1" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--or)"/></marker></defs><rect x="12" y="40" width="86" height="36" rx="6" fill="var(--or)" opacity=".16" stroke="var(--or)" stroke-width="1.2"/><text x="55" y="56" font-size="8" font-weight="700" fill="var(--dk)" text-anchor="middle">land A</text><text x="55" y="68" font-size="7" fill="var(--mu)" text-anchor="middle">maakt brood</text><rect x="202" y="40" width="86" height="36" rx="6" fill="var(--or)" opacity=".16" stroke="var(--or)" stroke-width="1.2"/><text x="245" y="56" font-size="8" font-weight="700" fill="var(--dk)" text-anchor="middle">land B</text><text x="245" y="68" font-size="7" fill="var(--mu)" text-anchor="middle">maakt kaas</text><path d="M100,50 L200,50" stroke="var(--or)" stroke-width="1.6" marker-end="url(#giEC1)"/><path d="M200,66 L100,66" stroke="var(--or)" stroke-width="1.6" marker-end="url(#giEC1)"/><text x="150" y="46" font-size="7" fill="var(--or)" text-anchor="middle">brood →</text><text x="150" y="80" font-size="7" fill="var(--or)" text-anchor="middle">← kaas</text></svg><div class="sam-figcap"><strong>Ruil na specialisatie:</strong> elk land maakt waarin het het beste (relatief) is en ruilt. Samen produceren en consumeren ze méér dan zonder ruil — dat is de <strong>ruilwinst</strong>.</div></div><div class="sam-head">3 · Geld en zijn functies</div><p>Zonder geld moet je <strong>ruilen in natura</strong>: dat vraagt een "dubbele samenloop van behoeften" (jij wilt wat de ander heeft én andersom). <strong>Geld</strong> lost dat op en heeft drie functies:</p><ul><li><strong>Ruilmiddel</strong>: je kunt het overal voor betalen (geen dubbele samenloop nodig).</li><li><strong>Rekenmiddel</strong>: alle prijzen in dezelfde eenheid → makkelijk vergelijken.</li><li><strong>Oppotmiddel</strong>: je kunt waarde bewaren voor later.</li></ul><div class="sam-warn"><strong>Let op:</strong> bij hoge <strong>inflatie</strong> werkt geld slechter als oppotmiddel: de koopkracht van opgespaard geld daalt. De ruil- en rekenfunctie blijven wel bestaan.</div><div class="sam-head">4 · Toegevoegde waarde en de kringloop</div><p>In elke schakel van de productieketen wordt <strong>toegevoegde waarde</strong> gemaakt: de verkoopwaarde min de waarde van de ingekochte grond- en hulpstoffen. De som van alle toegevoegde waarde in een land is het <strong>bbp</strong> (domein H). Betalingen en goederen stromen rond in de <strong>economische kringloop</strong>.</p><div class="sam-formula-box"><div class="sam-formula-label">Toegevoegde waarde</div><div class="sam-formula-eq">toegevoegde waarde = verkoopwaarde − ingekochte grond- en hulpstoffen</div><div class="sam-formula-note">Alleen de tóégevoegde waarde telt mee voor het bbp; anders zou je de grondstoffen dubbel tellen.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — toegevoegde waarde</div><div class="sam-worked-q">Een bakker koopt voor € 0,30 aan meel en grondstoffen per brood en verkoopt het brood voor € 1,10. Hoeveel waarde voegt hij toe?</div><ol class="sam-worked-steps"><li>Toegevoegde waarde = verkoopwaarde − ingekochte grond-/hulpstoffen.</li><li>= € 1,10 − € 0,30.</li><li>= € 0,80.</li></ol><div class="sam-worked-ans">✅ De bakker voegt € 0,80 per brood toe; alleen dát bedrag telt mee voor het bbp.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — functie van geld</div><div class="sam-worked-q">Waarom is ruilen met geld handiger dan ruilen in natura? Noem de kernreden.</div><ol class="sam-worked-steps"><li>Ruil in natura vereist een dubbele samenloop van behoeften.</li><li>Met geld hoef je alleen iemand te vinden die verkoopt wat jij wilt.</li><li>Geld werkt zo als algemeen aanvaard ruilmiddel.</li></ol><div class="sam-worked-ans">✅ Geld heft de dubbele samenloop van behoeften op: je kunt altijd betalen, wat de ruil enorm vergemakkelijkt.</div></div>`,
'vwo_ec_B':`<div class="sam-intro"><strong>Schaarste</strong> is het startpunt van de hele economie: er zijn <strong>onbeperkte behoeften</strong> maar <strong>beperkte middelen</strong>. Daardoor moet je steeds <strong>kiezen</strong>, en elke keuze kost het beste alternatief dat je opgeeft: de <strong>opofferingskosten</strong>.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Deel</th><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>1</td><td>Schaarste en keuze</td><td>behoeften &gt; middelen → kiezen</td></tr><tr><td>2</td><td>Opofferingskosten</td><td>het opgegeven beste alternatief</td></tr><tr><td>3</td><td>Productiefactoren</td><td>arbeid, kapitaal, natuur, ondernemerschap</td></tr><tr><td>4</td><td>Rationeel keuzegedrag</td><td>kosten tegen baten afwegen</td></tr></tbody></table><div class="sam-head">1 · Schaarste en keuze</div><p>Een goed is <strong>schaars</strong> als er middelen (tijd, geld, grondstoffen) nodig zijn om het te maken. Schaars betekent dus <em>niet</em> "zeldzaam", maar "niet gratis en onbeperkt beschikbaar". Omdat behoeften vrijwel onbeperkt zijn en middelen niet, moet iedereen — mensen, bedrijven, de overheid — voortdurend <strong>keuzes</strong> maken.</p><div class="sam-warn"><strong>Veelgemaakte fout:</strong> "schaars" is niet hetzelfde als "weinig". Water is niet zeldzaam, maar wél schaars: je moet er middelen voor inzetten om het schoon bij de kraan te krijgen. Een <strong>vrij goed</strong> (bv. buitenlucht) is niet schaars.</p><div class="sam-head">2 · Opofferingskosten</div><p>Elke keuze sluit een alternatief uit. De <strong>opofferingskosten</strong> (alternatieve kosten) zijn de waarde van het <strong>beste alternatief dat je opgeeft</strong>. Wie een uur studeert, kan datzelfde uur niet werken: het gemiste loon is de opofferingskost.</p><div class="sam-figure"><svg viewBox="0 0 280 120" role="img" aria-label="Een keuze voor optie A betekent dat het beste alternatief B wordt opgeofferd"><defs><marker id="giEB1" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--or)"/></marker><marker id="giEB2" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--mu)"/></marker></defs><rect x="10" y="46" width="70" height="30" rx="5" fill="var(--mu)" opacity=".12" stroke="var(--mu)" stroke-width="1.1"/><text x="45" y="65" font-size="8" fill="var(--dk)" text-anchor="middle">middelen</text><path d="M80,52 L150,30" stroke="var(--or)" stroke-width="1.8" marker-end="url(#giEB1)"/><path d="M80,70 L150,92" stroke="var(--mu)" stroke-width="1.6" stroke-dasharray="4 3" marker-end="url(#giEB2)"/><rect x="152" y="16" width="86" height="28" rx="5" fill="var(--or)" opacity=".18" stroke="var(--or)" stroke-width="1.2"/><text x="195" y="34" font-size="8" font-weight="700" fill="var(--dk)" text-anchor="middle">keuze A</text><rect x="152" y="80" width="120" height="28" rx="5" fill="var(--mu)" opacity=".1" stroke="var(--mu)" stroke-width="1"/><text x="212" y="98" font-size="7.5" fill="var(--dk)" text-anchor="middle">alternatief B = opoffering</text></svg><div class="sam-figcap"><strong>Opofferingskosten:</strong> met dezelfde middelen kies je A óf B. Kies je A, dan zijn de opofferingskosten de waarde van het beste alternatief B dat je laat schieten.</div></div><div class="sam-head">3 · Productiefactoren</div><p>Om te produceren zijn <strong>productiefactoren</strong> nodig. Elke factor levert een eigen inkomen op:</p><table class="sam-table"><thead><tr><th>Productiefactor</th><th>Beloning</th></tr></thead><tbody><tr><td>Arbeid</td><td>loon</td></tr><tr><td>Kapitaal (machines, gebouwen)</td><td>rente/interest</td></tr><tr><td>Natuur (grond, grondstoffen)</td><td>pacht/huur</td></tr><tr><td>Ondernemerschap</td><td>winst</td></tr></tbody></table><div class="sam-head">4 · Rationeel keuzegedrag</div><p>De economie gaat ervan uit dat mensen <strong>rationeel</strong> kiezen: ze wegen de <strong>baten</strong> tegen de <strong>kosten</strong> af en kiezen wat hun het meeste oplevert (het grootste <strong>nut</strong>). Je gaat door met een activiteit zolang een extra (marginale) eenheid meer <strong>oplevert</strong> dan hij <strong>kost</strong>.</p><div class="sam-tip"><strong>Marginaal denken:</strong> beslissingen gaan om het volgende stapje. Neem een extra eenheid zolang de <strong>marginale baten</strong> groter zijn dan de <strong>marginale kosten</strong>. Zodra ze gelijk zijn, is het optimum bereikt.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — opofferingskosten</div><div class="sam-worked-q">Je kunt een zaterdag werken voor € 60, of gratis naar een festival waarvoor een kaartje normaal € 40 kost. Je kiest het festival. Wat zijn de opofferingskosten?</div><ol class="sam-worked-steps"><li>Door te kiezen voor het festival mis je het loon van € 60.</li><li>Opofferingskosten = waarde van het beste opgegeven alternatief.</li><li>Het beste alternatief is werken (€ 60).</li></ol><div class="sam-worked-ans">✅ De opofferingskosten zijn € 60 (het gemiste loon).</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — schaars of niet?</div><div class="sam-worked-q">Leg uit waarom drinkwater uit de kraan een schaars goed is, maar de lucht die je inademt niet.</div><ol class="sam-worked-steps"><li>Voor schoon kraanwater zijn middelen nodig: zuivering, leidingen, energie.</li><li>Er hangt dus een prijs aan → schaars goed.</li><li>Buitenlucht is zonder inzet van middelen beschikbaar → vrij goed, niet schaars.</li></ol><div class="sam-worked-ans">✅ Kraanwater kost middelen (schaars); buitenlucht niet (vrij goed).</div></div>`,
'vwo_ec_G':`<div class="sam-intro"><strong>Risico en informatie</strong> gaat over kiezen bij <strong>onzekerheid</strong>. Je rekent met de <strong>verwachte waarde</strong>, ziet waarom mensen zich <strong>verzekeren</strong>, en leert hoe <strong>ongelijke informatie</strong> tussen partijen markten kan verstoren.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Deel</th><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>1</td><td>Risico en verwachte waarde</td><td>kans × uitkomst</td></tr><tr><td>2</td><td>Verzekeren</td><td>risico delen; risicoaversie</td></tr><tr><td>3</td><td>Asymmetrische informatie</td><td>averechtse selectie &amp; moreel wangedrag</td></tr><tr><td>4</td><td>Risico spreiden</td><td>diversificatie</td></tr></tbody></table><div class="sam-head">1 · Risico en verwachte waarde</div><p><strong>Risico</strong> is onzekerheid over de uitkomst. Om keuzes bij onzekerheid te vergelijken, bereken je de <strong>verwachte waarde</strong>: de som van elke mogelijke uitkomst, gewogen met zijn kans.</p><div class="sam-formula-box"><div class="sam-formula-label">Verwachte waarde</div><div class="sam-formula-eq">verwachte waarde = Σ (kans × uitkomst)</div><div class="sam-formula-note">Voorbeeld: 10% kans op € 100 en 90% kans op € 0 → 0,10 × 100 + 0,90 × 0 = € 10.</div></div><div class="sam-head">2 · Verzekeren en risicoaversie</div><p>De meeste mensen zijn <strong>risicomijdend</strong> (risicoavers): ze betalen liever een kleine, zekere <strong>premie</strong> dan dat ze een kleine kans op een grote schade lopen. Een <strong>verzekering</strong> bundelt de risico's van velen: de premies van de hele groep betalen de schade van de enkeling die pech heeft.</p><div class="sam-figure"><svg viewBox="0 0 280 118" role="img" aria-label="Verzekering: veel verzekerden betalen premie in een pot waaruit de schade van enkelen wordt betaald"><defs><marker id="giEG1" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--or)"/></marker></defs><g fill="var(--mu)"><circle cx="24" cy="24" r="7"/><circle cx="24" cy="50" r="7"/><circle cx="24" cy="76" r="7"/><circle cx="24" cy="102" r="7"/></g><text x="24" y="116" font-size="6.5" fill="var(--mu)" text-anchor="middle">premies</text><rect x="96" y="40" width="80" height="40" rx="8" fill="var(--or)" opacity=".16" stroke="var(--or)" stroke-width="1.2"/><text x="136" y="64" font-size="8" font-weight="700" fill="var(--dk)" text-anchor="middle">verzekeraar</text><g stroke="var(--or)" stroke-width="1.4"><line x1="34" y1="26" x2="94" y2="52" marker-end="url(#giEG1)"/><line x1="34" y1="50" x2="94" y2="56" marker-end="url(#giEG1)"/><line x1="34" y1="76" x2="94" y2="64" marker-end="url(#giEG1)"/><line x1="34" y1="100" x2="94" y2="70" marker-end="url(#giEG1)"/></g><circle cx="250" cy="60" r="10" fill="var(--dk)"/><text x="250" y="86" font-size="6.5" fill="var(--dk)" text-anchor="middle">schade</text><line x1="176" y1="60" x2="238" y2="60" stroke="var(--or)" stroke-width="1.6" marker-end="url(#giEG1)"/><text x="207" y="54" font-size="7" fill="var(--or)" text-anchor="middle">uitkering</text></svg><div class="sam-figcap"><strong>Risico's poolen:</strong> veel verzekerden betalen een kleine premie in een gezamenlijke pot; wie schade heeft, krijgt een uitkering. Zo wordt een groot individueel risico een klein gedeeld risico.</div></div><div class="sam-head">3 · Asymmetrische informatie</div><p>Vaak weet de ene partij méér dan de andere: <strong>asymmetrische informatie</strong>. Dat geeft twee problemen:</p><div class="sam-compare"><div class="sam-compare-col"><div class="sam-compare-head">Averechtse selectie</div><ul><li>vóór het contract</li><li>vooral "slechte risico's" melden zich aan</li><li>bv. juist zieke mensen willen een zorgverzekering</li></ul></div><div class="sam-compare-col"><div class="sam-compare-head">Moreel wangedrag</div><ul><li>ná het contract</li><li>je gedraagt je roekelozer</li><li>bv. minder voorzichtig omdat je toch verzekerd bent</li></ul></div></div><div class="sam-warn"><strong>Onthoud het tijdstip:</strong> <strong>averechtse selectie</strong> speelt vóór het sluiten van het contract (wie meldt zich aan?), <strong>moreel wangedrag</strong> erná (hoe gedraag je je?). Verzekeraars bestrijden dit met een eigen risico, keuringen en no-claimkortingen.</div><div class="sam-head">4 · Risico spreiden: diversificatie</div><p>Je kunt risico verkleinen door te <strong>spreiden</strong> (diversificatie): "niet alles op één paard wedden". Wie zijn geld over veel verschillende beleggingen verdeelt, loopt minder risico dan wie alles in één aandeel stopt.</p><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — verwachte waarde</div><div class="sam-worked-q">Een loterijlot kost € 5. Er is 1% kans op € 200 en verder niets. Is het lot "eerlijk" geprijsd op basis van de verwachte waarde?</div><ol class="sam-worked-steps"><li>Verwachte waarde = 0,01 × € 200 + 0,99 × € 0.</li><li>= € 2.</li><li>De prijs (€ 5) is hoger dan de verwachte waarde (€ 2).</li></ol><div class="sam-worked-ans">✅ Nee: je betaalt € 5 voor een verwachte opbrengst van € 2 — ongunstig (de aanbieder verdient het verschil).</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — welk informatieprobleem?</div><div class="sam-worked-q">Iemand sluit een reisverzekering en laat daarna zijn koffer onbeheerd achter omdat "het toch verzekerd is". Welk probleem is dit?</div><ol class="sam-worked-steps"><li>Het gedrag verandert ná het sluiten van het contract.</li><li>De verzekerde neemt meer risico dan zonder verzekering.</li><li>Dat is precies de definitie van moreel wangedrag.</li></ol><div class="sam-worked-ans">✅ Moreel wangedrag (moral hazard): risicovoller gedrag ná het afsluiten van de verzekering.</div></div>`,
'vwo_ec_F':`<div class="sam-intro"><strong>Samenwerken en onderhandelen</strong> gaat over situaties waarin het gezamenlijke belang botst met het eigenbelang. Vaak leidt individueel <strong>rationeel</strong> gedrag tot een collectief <strong>slechtere</strong> uitkomst — het <strong>gevangenendilemma</strong>. Afspraken, instituties en de overheid kunnen dat oplossen.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Deel</th><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>1</td><td>Gevangenendilemma</td><td>eigenbelang → collectief slechter</td></tr><tr><td>2</td><td>Collectieve actie</td><td>meeliftgedrag (free-riders)</td></tr><tr><td>3</td><td>Externe effecten &amp; collectieve goederen</td><td>markt schiet tekort → overheid</td></tr><tr><td>4</td><td>Onderhandelen &amp; marktmacht</td><td>kartel, vakbond, cao</td></tr></tbody></table><div class="sam-head">1 · Het gevangenendilemma</div><p>Twee partijen kunnen kiezen tussen <strong>samenwerken</strong> en <strong>niet-samenwerken</strong>. Voor ieder apart lijkt niet-samenwerken het beste, maar als beiden dat doen, zijn ze samen slechter af dan wanneer ze wél hadden samengewerkt.</p><div class="sam-figure"><svg viewBox="0 0 260 150" role="img" aria-label="Uitbetalingsmatrix van een gevangenendilemma met twee spelers"><g stroke="var(--bo)" stroke-width="1.2" fill="none"><rect x="90" y="40" width="80" height="45"/><rect x="170" y="40" width="80" height="45"/><rect x="90" y="85" width="80" height="45"/><rect x="170" y="85" width="80" height="45"/></g><g font-size="7.5" font-weight="700" fill="var(--mu)" text-anchor="middle"><text x="130" y="32">samenw.</text><text x="210" y="32">niet</text></g><g font-size="7.5" font-weight="700" fill="var(--mu)" text-anchor="middle"><text x="70" y="66">samenw.</text><text x="78" y="111">niet</text></g><g font-size="9" font-weight="700" text-anchor="middle"><text x="130" y="66" fill="var(--or)">3 / 3</text><text x="210" y="66" fill="var(--dk)">0 / 5</text><text x="130" y="111" fill="var(--dk)">5 / 0</text><text x="210" y="111" fill="var(--mu)">1 / 1</text></g><text x="14" y="66" font-size="7" fill="var(--dk)">speler A</text><text x="130" y="16" font-size="7" fill="var(--dk)" text-anchor="middle">speler B</text></svg><div class="sam-figcap"><strong>Uitbetalingsmatrix</strong> (winst A / winst B): samen samenwerken levert 3+3 op. Toch kiest ieder voor "niet" (want dat is individueel beter, wat de ander ook doet), zodat ze in <strong>1 / 1</strong> belanden — samen slechter.</div></div><div class="sam-head">2 · Collectieve actie en meeliften</div><p>Bij een <strong>collectief goed</strong> kan iedereen <strong>meeliften</strong> (free-rider): profiteren zonder mee te betalen. Omdat iedereen dat denkt, komt het goed niet vanzelf tot stand. Denk aan dijken, straatverlichting of afspraken over het milieu.</p><div class="sam-head">3 · Externe effecten en collectieve goederen</div><p>Soms werkt de markt niet goed:</p><ul><li><strong>Externe effecten</strong>: kosten of baten voor derden die niet in de prijs zitten. Negatief (vervuiling) of positief (onderwijs, vaccinatie).</li><li><strong>Collectieve goederen</strong>: <em>niet-uitsluitbaar</em> en <em>niet-rivaliserend</em> (bv. defensie). De markt levert ze niet, dus doet de <strong>overheid</strong> dat.</li></ul><div class="sam-tip">De overheid corrigeert marktfalen: een <strong>heffing</strong> op vervuiling (negatief extern effect duurder maken) of <strong>subsidie</strong> op onderwijs (positief extern effect stimuleren). Zo komen de maatschappelijke kosten en baten wél in de prijs.</div><div class="sam-head">4 · Onderhandelen en marktmacht</div><p>Partijen die samenwerken vergroten hun <strong>marktmacht</strong>. Aanbieders die prijsafspraken maken vormen een <strong>kartel</strong> (meestal verboden); werknemers verenigen zich in een <strong>vakbond</strong> en onderhandelen met werkgevers over een <strong>cao</strong>. De uitkomst hangt af van de onderhandelingspositie van beide kanten.</p><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — gevangenendilemma</div><div class="sam-worked-q">Twee bedrijven kunnen een hoge of lage prijs vragen. Bij beide hoog verdienen ze allebei veel; verlaagt één de prijs, dan pakt die alle klanten. Waarom eindigen ze vaak allebei met een lage prijs?</div><ol class="sam-worked-steps"><li>Wat de ander ook doet, zelf de prijs verlagen levert individueel meer op.</li><li>Beide bedrijven redeneren zo en verlagen de prijs.</li><li>Ze belanden in de uitkomst "beide laag" — samen slechter dan "beide hoog".</li></ol><div class="sam-worked-ans">✅ Individueel rationeel gedrag leidt tot een collectief slechtere uitkomst: het gevangenendilemma. Een (verboden) prijsafspraak zou dit "oplossen".</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — extern effect</div><div class="sam-worked-q">Een fabriek loost afval in een rivier. Waarom is de marktprijs van het product "te laag", en wat kan de overheid doen?</div><ol class="sam-worked-steps"><li>De vervuiling is een negatief extern effect: de kosten liggen bij derden, niet in de prijs.</li><li>Daardoor is de prijs lager dan de maatschappelijke kosten en wordt er te veel geproduceerd.</li><li>De overheid kan een heffing op de vervuiling leggen.</li></ol><div class="sam-worked-ans">✅ De prijs mist de milieukosten; een heffing rekent die door, zodat prijs en productie kloppen met de echte kosten.</div></div>`,
'vwo_ec_E':`<div class="sam-intro"><strong>Ruilen over de tijd</strong> gaat over geld nú tegenover geld later: <strong>sparen</strong> (consumptie uitstellen) en <strong>lenen</strong> (consumptie naar voren halen). De prijs die tijd en risico verbindt is de <strong>rente</strong>. Daarmee reken je toekomstige en huidige bedragen naar elkaar om.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Deel</th><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>1</td><td>Sparen en lenen</td><td>consumptie verschuiven in de tijd</td></tr><tr><td>2</td><td>Rente</td><td>prijs van tijd; samengestelde interest</td></tr><tr><td>3</td><td>Contante waarde</td><td>toekomstig geld terugrekenen naar nu</td></tr><tr><td>4</td><td>Nominaal en reëel</td><td>rente corrigeren voor inflatie</td></tr></tbody></table><div class="sam-head">1 · Sparen en lenen</div><p>Wie <strong>spaart</strong>, stelt consumptie uit naar later en krijgt daarvoor <strong>rente</strong> als beloning. Wie <strong>leent</strong>, haalt consumptie naar voren en betaalt rente als vergoeding. Zo kun je je bestedingen loskoppelen van je inkomen op dit moment.</p><div class="sam-head">2 · Rente en samengestelde interest</div><p>De <strong>rente</strong> is de prijs van geld over tijd: een vergoeding voor uitstel én voor het risico dat je geld niet terugkrijgt. Bij sparen krijg je vaak <strong>rente op rente</strong> (samengestelde interest): het spaarbedrag groeit exponentieel.</p><div class="sam-figure"><svg viewBox="0 0 280 140" role="img" aria-label="Samengestelde interest: een spaarbedrag groeit steeds sneller doordat je rente over rente krijgt"><defs><marker id="giEE1" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--mu)"/></marker></defs><line x1="32" y1="120" x2="268" y2="120" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#giEE1)"/><line x1="32" y1="130" x2="32" y2="12" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#giEE1)"/><text x="266" y="134" font-size="7.5" fill="var(--mu)" text-anchor="end">jaren</text><text x="14" y="20" font-size="7.5" fill="var(--mu)">saldo</text><path d="M32,104 C120,96 190,76 256,26" fill="none" stroke="var(--or)" stroke-width="2.4"/><line x1="32" y1="104" x2="256" y2="60" stroke="var(--mu)" stroke-width="1.4" stroke-dasharray="4 3"/><text x="196" y="52" font-size="7" fill="var(--mu)">enkelvoudig</text><text x="150" y="70" font-size="7" fill="var(--or)">samengesteld</text></svg><div class="sam-figcap"><strong>Samengestelde interest:</strong> doordat je ook rente krijgt over de eerder bijgeschreven rente, groeit het saldo steeds sneller (oranje) — sneller dan bij enkelvoudige rente (gestippeld).</div></div><div class="sam-formula-box"><div class="sam-formula-label">Eindwaarde bij samengestelde interest</div><div class="sam-formula-eq">eindwaarde = beginbedrag × (1 + r)<sup>n</sup></div><div class="sam-formula-note">r = rente per periode (als kommagetal), n = aantal perioden. Bij 4% is r = 0,04.</div></div><div class="sam-head">3 · Contante waarde</div><p>Andersom kun je een <strong>toekomstig</strong> bedrag terugrekenen naar nu: de <strong>contante waarde</strong>. Zo vergelijk je geldbedragen op verschillende momenten eerlijk.</p><div class="sam-formula-box"><div class="sam-formula-label">Contante waarde</div><div class="sam-formula-eq">contante waarde = toekomstig bedrag / (1 + r)<sup>n</sup></div><div class="sam-formula-note">€ 100 volgend jaar is nu minder waard dan € 100 nu — want € 100 nu kun je op de bank zetten en laten groeien.</div></div><div class="sam-head">4 · Nominale en reële rente</div><p>De <strong>nominale rente</strong> is het percentage dat je krijgt of betaalt. Wat je er écht mee opschiet, is de <strong>reële rente</strong>: gecorrigeerd voor inflatie.</p><div class="sam-formula-box"><div class="sam-formula-label">Reële rente (benadering)</div><div class="sam-formula-eq">reële rente ≈ nominale rente − inflatie</div><div class="sam-formula-note">Is de inflatie hoger dan de spaarrente, dan is de reële rente negatief: je koopkracht daalt ondanks de bijgeschreven rente.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — samengestelde interest</div><div class="sam-worked-q">Je zet € 1000 op een spaarrekening met 3% rente per jaar. Hoeveel staat er na 2 jaar (rente op rente)?</div><ol class="sam-worked-steps"><li>Eindwaarde = beginbedrag × (1 + r)ⁿ, met r = 0,03 en n = 2.</li><li>= 1000 × (1,03)² = 1000 × 1,0609.</li><li>= € 1060,90.</li></ol><div class="sam-worked-ans">✅ Na 2 jaar staat er € 1060,90 (€ 60,90 rente, waarvan € 0,90 rente over rente).</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — reële rente</div><div class="sam-worked-q">De spaarrente is 1,5%; de inflatie is 3%. Wordt je spaargeld meer of minder waard in koopkracht?</div><ol class="sam-worked-steps"><li>Reële rente ≈ nominale rente − inflatie.</li><li>≈ 1,5% − 3% = −1,5%.</li><li>De reële rente is negatief.</li></ol><div class="sam-worked-ans">✅ Minder waard: je koopkracht daalt met ongeveer 1,5% per jaar, ondanks de rente.</div></div>`,
'vwo_in_B':`<div class="sam-intro">Onder elke app zit hardware en software: computers werken met <strong>binaire</strong> getallen en <strong>Booleaanse logica</strong>, een <strong>besturingssysteem</strong> beheert de bronnen, en <strong>netwerken</strong> koppelen alles via afgesproken protocollen. Data bescherm je met <strong>encryptie</strong>.</div><div class="sam-head">Digitale representatie</div><p>Een computer kent maar twee toestanden: 0 en 1 (een <strong>bit</strong>). Alle data — getallen, tekst, beeld — wordt <strong>binair</strong> opgeslagen. Acht bits vormen een <strong>byte</strong>.</p><div class="sam-formula-box"><div class="sam-formula-label">Binair naar decimaal</div><div class="sam-formula-eq">1011₂ = 1·8 + 0·4 + 1·2 + 1·1 = 11</div><div class="sam-formula-note">Elke positie is een macht van 2 (…, 8, 4, 2, 1). Hexadecimaal (grondtal 16) kort binair af: 4 bits = 1 hex-cijfer.</div></div><div class="sam-head">Booleaanse logica</div><p>Digitale schakelingen rekenen met <strong>logische poorten</strong> die 0/1 (onwaar/waar) combineren.</p><table class="sam-table"><thead><tr><th>Poort</th><th>Waar als…</th></tr></thead><tbody><tr><td>AND</td><td>beide ingangen 1 zijn</td></tr><tr><td>OR</td><td>minstens één ingang 1 is</td></tr><tr><td>NOT</td><td>de ingang 0 is (keert om)</td></tr></tbody></table><div class="sam-head">Computernetwerken</div><p>Apparaten communiceren via het internet volgens het <strong>TCP/IP</strong>-protocol. <strong>DNS</strong> vertaalt een domeinnaam (slagio.nl) naar een IP-adres; een <strong>server</strong> stuurt de gevraagde gegevens terug naar de <strong>client</strong>.</p><div class="sam-figure"><svg viewBox="0 0 300 130" role="img" aria-label="Netwerkschema waarin een client via een router en het internet een server bereikt"><defs><marker id="inBa" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--mu)"/></marker></defs><rect x="12" y="48" width="52" height="34" rx="4" fill="var(--mu)" opacity=".12" stroke="var(--mu)" stroke-width="1.1"/><text x="38" y="62" font-size="8.5" font-weight="700" fill="var(--dk)" text-anchor="middle">client</text><text x="38" y="74" font-size="7" fill="var(--mu)" text-anchor="middle">browser</text><ellipse cx="150" cy="65" rx="42" ry="26" fill="var(--or)" opacity=".12" stroke="var(--or)" stroke-width="1.3" stroke-dasharray="4 3"/><text x="150" y="62" font-size="9" font-weight="700" fill="var(--dk)" text-anchor="middle">internet</text><text x="150" y="74" font-size="7" fill="var(--mu)" text-anchor="middle">TCP/IP · DNS</text><rect x="236" y="48" width="52" height="34" rx="4" fill="var(--mu)" opacity=".12" stroke="var(--mu)" stroke-width="1.1"/><text x="262" y="62" font-size="8.5" font-weight="700" fill="var(--dk)" text-anchor="middle">server</text><text x="262" y="74" font-size="7" fill="var(--mu)" text-anchor="middle">website</text><line x1="65" y1="60" x2="106" y2="60" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#inBa)"/><line x1="194" y1="70" x2="235" y2="70" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#inBa)"/><text x="80" y="53" font-size="7" fill="var(--or)">verzoek</text><text x="205" y="63" font-size="7" fill="var(--or)">data</text></svg><div class="sam-figcap"><strong>Client-server:</strong> de client stuurt een verzoek via het internet (waar DNS de naam naar een IP-adres vertaalt); de server stuurt de gevraagde data terug.</div></div><div class="sam-head">Beveiliging en databases</div><p>Gevoelige data wordt <strong>versleuteld</strong> (encryptie): alleen met de juiste sleutel lees je het bericht. <strong>Hashing</strong> maakt een onomkeerbare 'vingerafdruk' (bijv. van wachtwoorden). Gestructureerde gegevens sla je op in een <strong>database</strong>, die je bevraagt met <strong>SQL</strong>.</p><div class="sam-tip"><strong>Hashing ≠ encryptie:</strong> encryptie is met de sleutel terug te draaien, hashing niet. Daarom bewaar je wachtwoorden gehasht, niet versleuteld.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave</div><div class="sam-worked-q">Zet het binaire getal 1101 om naar decimaal.</div><ol class="sam-worked-steps"><li>Posities (macht van 2): 8, 4, 2, 1.</li><li>1·8 + 1·4 + 0·2 + 1·1.</li><li>= 8 + 4 + 0 + 1 = 13.</li></ol><div class="sam-worked-ans">✅ 1101₂ = 13.</div></div></div>`,
'vwo_in_A':`<div class="sam-intro">Algoritmisch denken is de kern van informatica: een probleem oplossen met een <strong>algoritme</strong> — een eindige, ondubbelzinnige reeks stappen. Je legt het vast in een <strong>flowchart</strong> of <strong>pseudocode</strong>, met <strong>selectie</strong>, <strong>iteratie</strong> en soms <strong>recursie</strong>.</div><div class="sam-head">Algoritme en flowchart</div><p>Een <strong>flowchart</strong> tekent de stappen als blokken: een ovaal voor start/eind, een rechthoek voor een bewerking en een <strong>ruit</strong> voor een beslissing (voorwaarde). Hieronder een lus die de getallen 1 t/m 10 afdrukt:</p><div class="sam-figure"><svg viewBox="0 0 260 240" role="img" aria-label="Flowchart van een lus die telt van 1 tot en met 10 en elk getal afdrukt"><defs><marker id="inAa" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--mu)"/></marker></defs><ellipse cx="130" cy="18" rx="32" ry="12" fill="var(--or)" opacity=".18" stroke="var(--or)" stroke-width="1.3"/><text x="130" y="22" font-size="9" font-weight="700" fill="var(--dk)" text-anchor="middle">Start</text><rect x="95" y="38" width="70" height="22" rx="3" fill="var(--mu)" opacity=".12" stroke="var(--mu)" stroke-width="1.1"/><text x="130" y="53" font-size="9" fill="var(--dk)" text-anchor="middle">i = 1</text><polygon points="130,70 172,92 130,114 88,92" fill="var(--or)" opacity=".14" stroke="var(--or)" stroke-width="1.3"/><text x="130" y="95" font-size="8.5" fill="var(--dk)" text-anchor="middle">i ≤ 10 ?</text><rect x="92" y="128" width="76" height="22" rx="3" fill="var(--mu)" opacity=".12" stroke="var(--mu)" stroke-width="1.1"/><text x="130" y="143" font-size="8.5" fill="var(--dk)" text-anchor="middle">druk i af</text><rect x="92" y="158" width="76" height="22" rx="3" fill="var(--mu)" opacity=".12" stroke="var(--mu)" stroke-width="1.1"/><text x="130" y="173" font-size="8.5" fill="var(--dk)" text-anchor="middle">i = i + 1</text><ellipse cx="34" cy="92" rx="30" ry="12" fill="var(--dk)" opacity=".12" stroke="var(--mu)" stroke-width="1.1"/><text x="34" y="96" font-size="9" font-weight="700" fill="var(--dk)" text-anchor="middle">Einde</text><g stroke="var(--mu)" stroke-width="1.3" fill="none"><line x1="130" y1="30" x2="130" y2="37" marker-end="url(#inAa)"/><line x1="130" y1="60" x2="130" y2="69" marker-end="url(#inAa)"/><line x1="130" y1="114" x2="130" y2="127" marker-end="url(#inAa)"/><path d="M168,171 L210,171 L210,92 L173,92" marker-end="url(#inAa)"/><line x1="88" y1="92" x2="65" y2="92" marker-end="url(#inAa)"/></g><text x="136" y="124" font-size="8" font-weight="700" fill="var(--or)">ja</text><text x="72" y="86" font-size="8" font-weight="700" fill="var(--or)">nee</text></svg><div class="sam-figcap"><strong>Iteratie (lus):</strong> zolang de voorwaarde 'i ≤ 10' waar is, wordt i afgedrukt en met 1 verhoogd. Is de voorwaarde onwaar, dan stopt de lus.</div></div><div class="sam-head">Bouwstenen van een algoritme</div><table class="sam-table"><thead><tr><th>Structuur</th><th>Betekenis</th><th>Voorbeeld</th></tr></thead><tbody><tr><td>Sequentie</td><td>stappen na elkaar</td><td>regel 1, dan 2</td></tr><tr><td>Selectie</td><td>keuze op voorwaarde</td><td>if … else</td></tr><tr><td>Iteratie</td><td>herhaling (lus)</td><td>for / while</td></tr></tbody></table><div class="sam-head">Variabelen en recursie</div><p>Een <strong>variabele</strong> bewaart een waarde van een bepaald <strong>datatype</strong> (int, string, boolean). Bij <strong>recursie</strong> roept een functie zichzelf aan met een kleiner probleem, tot een <strong>basisgeval</strong> de herhaling stopt.</p><div class="sam-warn"><strong>Let op bij recursie:</strong> zonder een goed <strong>basisgeval</strong> (stopvoorwaarde) blijft de functie zichzelf aanroepen — een oneindige lus die crasht (stack overflow).</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave</div><div class="sam-worked-q">Wat drukt deze pseudocode af?  <em>i = 1; zolang i ≤ 3: druk i af; i = i + 2</em></div><ol class="sam-worked-steps"><li>i = 1 → 1 ≤ 3, druk 1 af, i wordt 3.</li><li>i = 3 → 3 ≤ 3, druk 3 af, i wordt 5.</li><li>i = 5 → 5 ≤ 3 is onwaar, stop.</li></ol><div class="sam-worked-ans">✅ De uitvoer is: 1 3.</div></div></div>`,
'vwo_wa_C':`<div class="sam-intro">In domein C herken je welk <strong>verband</strong> achter een tabel of grafiek zit — <strong>lineair, kwadratisch, exponentieel, logaritmisch</strong> of <strong>periodiek</strong> — en bereken je met de <strong>bepaalde integraal</strong> oppervlaktes en afgelegde afstanden.</div><div class="sam-chips"><span class="sam-chip sam-chip-lead">Kern</span><span class="sam-chip">Standaardverbanden</span><span class="sam-chip">Groeifactor</span><span class="sam-chip">Bepaalde integraal</span><span class="sam-chip">Oppervlakte</span><span class="sam-chip">Periodiek</span></div><div class="sam-head">Standaardverbanden</div><table class="sam-table"><thead><tr><th>Verband</th><th>Vorm</th><th>Kenmerk</th></tr></thead><tbody><tr><td>Lineair</td><td>y = ax + b</td><td>constante toename</td></tr><tr><td>Kwadratisch</td><td>y = ax² + bx + c</td><td>parabool, top</td></tr><tr><td>Exponentieel</td><td>y = b·gˣ</td><td>vaste groeifactor</td></tr><tr><td>Periodiek</td><td>y = a·sin(b(x−c)) + d</td><td>amplitude a, periode 2π/b</td></tr></tbody></table><div class="sam-head">De bepaalde integraal als oppervlakte</div><p>De <strong>bepaalde integraal</strong> van a tot b is gelijk aan de <strong>oppervlakte</strong> tussen de grafiek en de x-as. Je berekent hem met de primitieve F: het verschil F(b) − F(a).</p><div class="sam-figure"><svg viewBox="0 0 340 172" role="img" aria-label="Oppervlakte onder een grafiek tussen x is a en x is b als bepaalde integraal"><defs><marker id="waCa" markerWidth="9" markerHeight="9" refX="5" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L7,3 L0,6 Z" fill="var(--mu)"/></marker></defs><path d="M110,150 L110.0,131.7 L129.5,123.8 L149.0,114.6 L168.5,104.3 L188.0,92.8 L207.5,80.0 L227.0,66.0 L240,56.0 L240,150 Z" fill="var(--or)" opacity=".18"/><line x1="40" y1="150" x2="332" y2="150" stroke="var(--mu)" stroke-width="1.5" marker-end="url(#waCa)"/><line x1="40" y1="158" x2="40" y2="24" stroke="var(--mu)" stroke-width="1.5" marker-end="url(#waCa)"/><path d="M40.0,150.0 L73.4,143.2 L106.9,132.8 L140.3,118.9 L173.7,101.3 L207.1,80.2 L240.6,55.5 L270.3,30.6 L300,28" fill="none" stroke="var(--or)" stroke-width="2.4" stroke-linecap="round"/><line x1="110" y1="150" x2="110" y2="131" stroke="var(--dk)" stroke-width="1" stroke-dasharray="2 2"/><line x1="240" y1="150" x2="240" y2="56" stroke="var(--dk)" stroke-width="1" stroke-dasharray="2 2"/><text x="106" y="164" font-size="10" font-weight="700" fill="var(--dk)">a</text><text x="236" y="164" font-size="10" font-weight="700" fill="var(--dk)">b</text><text x="150" y="120" font-size="10" font-weight="700" fill="var(--or)">oppervlakte</text></svg><div class="sam-figcap"><strong>Oppervlakte = integraal:</strong> het gekleurde gebied onder de grafiek tussen x = a en x = b is precies de waarde van de bepaalde integraal ∫<sub>a</sub><sup>b</sup> f(x) dx.</div></div><div class="sam-formula-box"><div class="sam-formula-label">Hoofdstelling van de integraalrekening</div><div class="sam-formula-eq">∫<sub>a</sub><sup>b</sup> f(x) dx = F(b) − F(a)</div><div class="sam-formula-note">F is een primitieve van f. Integreren is dus het omgekeerde van differentiëren.</div></div><div class="sam-tip"><strong>Snelheid en afstand:</strong> de afgelegde afstand is de integraal van de snelheid: s = ∫v(t) dt. Andersom is de snelheid de afgeleide van de plaats.</div><div class="sam-head">Periodieke functies</div><p>Bij f(x) = a·sin(b(x−c)) + d is a de <strong>amplitude</strong>, d de <strong>evenwichtsstand</strong>, c de horizontale verschuiving en de <strong>periode</strong> gelijk aan 2π/b.</p><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave</div><div class="sam-worked-q">Bereken de oppervlakte onder f(x) = 2x tussen x = 1 en x = 3.</div><ol class="sam-worked-steps"><li>Primitieve: F(x) = x².</li><li>∫₁³ 2x dx = F(3) − F(1) = 9 − 1.</li><li>= 8.</li></ol><div class="sam-worked-ans">✅ De oppervlakte is 8.</div></div><div class="sam-head">Welk verband herken je?</div><table class="sam-table"><thead><tr><th>In de tabel/grafiek</th><th>Verband</th></tr></thead><tbody><tr><td>gelijke stappen erbij</td><td>lineair (constante toename)</td></tr><tr><td>gelijke factor per stap</td><td>exponentieel (groeifactor)</td></tr><tr><td>symmetrische top/dal</td><td>kwadratisch (parabool)</td></tr><tr><td>herhaalt zich (golf)</td><td>periodiek (sinusoïde)</td></tr></tbody></table><div class="sam-definitie"><div class="sam-definitie-term">Groeifactor</div><div class="sam-definitie-body">Het getal g waarmee je per tijdstap vermenigvuldigt bij exponentiële groei: y = b·gˣ. g &gt; 1 is groei, 0 &lt; g &lt; 1 is afname. Bij p% groei is g = 1 + p/100.</div></div><div class="sam-head">Oppervlakte tussen twee grafieken</div><p>Ligt f boven g op [a, b], dan is de oppervlakte tussen de twee krommen ∫<sub>a</sub><sup>b</sup> (f(x) − g(x)) dx — dus altijd <strong>boven min onder</strong>. Bepaal eerst de <strong>snijpunten</strong> (die geven de grenzen a en b).</p><div class="sam-val"><ul><li><strong>Primitieve en afgeleide</strong> verwisselen bij integreren.</li><li>Grenzen omdraaien → het teken van de integraal klapt om.</li><li>Periode van a·sin(bx) is <strong>2π/b</strong>, niet b.</li><li>Bij oppervlakte "boven − onder" vergeten → negatieve uitkomst.</li></ul></div><div class="sam-onthoud"><ul style="margin:0;padding-left:16px"><li style="margin-bottom:3px">∫<sub>a</sub><sup>b</sup> f dx = F(b) − F(a) = oppervlakte.</li><li style="margin-bottom:3px">Exponentieel = vaste groeifactor g; p% → g = 1 + p/100.</li><li style="margin-bottom:3px">Oppervlakte tussen krommen = ∫(boven − onder).</li><li style="margin-bottom:3px">Periode van een sinus = 2π/b.</li></ul></div></div>`,
'vwo_wa_E':`<div class="sam-intro">Statistiek en kansrekening is de kern van wiskunde A: van <strong>kansregels</strong> en de <strong>binomiale verdeling</strong> tot de <strong>normale verdeling</strong> en het <strong>hypothesetoetsen</strong>. Je rekent veel met de grafische rekenmachine (GR).</div><div class="sam-chips"><span class="sam-chip sam-chip-lead">Kern</span><span class="sam-chip">Kansregels</span><span class="sam-chip">Binomiaal</span><span class="sam-chip">Normale verdeling</span><span class="sam-chip">Hypothesetoets</span><span class="sam-chip">GR</span></div><div class="sam-head">Kansregels</div><table class="sam-table"><thead><tr><th>Regel</th><th>Formule</th><th>Wanneer</th></tr></thead><tbody><tr><td>Productregel</td><td>P(A én B) = P(A)·P(B)</td><td>onafhankelijk ('en')</td></tr><tr><td>Somregel</td><td>P(A of B) = P(A)+P(B)</td><td>elkaar uitsluitend</td></tr><tr><td>Complement</td><td>P(niet A) = 1 − P(A)</td><td>'minstens één'</td></tr></tbody></table><div class="sam-head">Binomiale verdeling</div><p>Bij n onafhankelijke pogingen met succeskans p is het aantal successen <strong>binomiaal verdeeld</strong>: B(n, p). Op de GR: binompdf (precies k) en binomcdf (hoogstens k).</p><div class="sam-formula-box"><div class="sam-formula-label">Binomiale kans</div><div class="sam-formula-eq">P(X = k) = C(n,k) · pᵏ · (1−p)ⁿ⁻ᵏ</div><div class="sam-formula-note">n het aantal pogingen, p de succeskans, k het aantal successen. Verwachting: µ = n·p.</div></div><div class="sam-head">Normale verdeling</div><p>Veel grootheden (lengte, gewicht) zijn <strong>normaal verdeeld</strong>: een symmetrische klokvorm rond het gemiddelde µ, met spreiding σ. De <strong>68-95-99,7-regel</strong> geeft snel de kansen.</p><div class="sam-figure"><svg viewBox="0 0 340 172" role="img" aria-label="Normaalverdeling met de 68-95-99,7 procent regel rond het gemiddelde"><defs><marker id="waDa" markerWidth="9" markerHeight="9" refX="5" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L7,3 L0,6 Z" fill="var(--mu)"/></marker></defs><path d="M40.0,149.6 L74.2,145.4 L102.2,130.2 L120.9,109.1 L136.4,85.8 L152.0,61.9 L167.6,44.7 L180.0,40.0 L192.4,44.7 L208.0,61.9 L223.6,85.8 L239.1,109.1 L257.8,130.2 L285.8,145.4 L320.0,149.6" fill="var(--or)" opacity=".15"/><line x1="30" y1="150" x2="332" y2="150" stroke="var(--mu)" stroke-width="1.5" marker-end="url(#waDa)"/><path d="M40.0,149.6 L74.2,145.4 L102.2,130.2 L120.9,109.1 L136.4,85.8 L152.0,61.9 L167.6,44.7 L180.0,40.0 L192.4,44.7 L208.0,61.9 L223.6,85.8 L239.1,109.1 L257.8,130.2 L285.8,145.4 L320.0,149.6" fill="none" stroke="var(--or)" stroke-width="2.4"/><g stroke="var(--mu)" stroke-width="1" stroke-dasharray="3 3"><line x1="180" y1="40" x2="180" y2="150"/><line x1="138" y1="72" x2="138" y2="150"/><line x1="222" y1="72" x2="222" y2="150"/><line x1="96" y1="126" x2="96" y2="150"/><line x1="264" y1="126" x2="264" y2="150"/></g><g font-size="8.5" fill="var(--mu)" text-anchor="middle"><text x="180" y="164">µ</text><text x="138" y="164">−σ</text><text x="222" y="164">+σ</text><text x="96" y="164">−2σ</text><text x="264" y="164">+2σ</text></g><text x="180" y="120" font-size="9" font-weight="700" fill="var(--dk)" text-anchor="middle">68%</text></svg><div class="sam-figcap"><strong>68-95-99,7-regel:</strong> 68% van de waarnemingen ligt binnen 1σ van het gemiddelde, 95% binnen 2σ en 99,7% binnen 3σ.</div></div><div class="sam-head">Hypothesetoets</div><p>Je toetst een <strong>nulhypothese</strong> H₀ tegen een alternatief H₁. Is de <strong>p-waarde</strong> kleiner dan het significantieniveau α (vaak 5%), dan verwerp je H₀.</p><div class="sam-warn"><strong>Let op:</strong> een niet-verworpen H₀ is niet 'bewezen'. Je concludeert alleen dat er <em>onvoldoende bewijs</em> is om H₀ te verwerpen.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave</div><div class="sam-worked-q">Je gooit 10 keer met een eerlijke munt. Wat is de kans op precies 6 keer kop? (p = 0,5)</div><ol class="sam-worked-steps"><li>X ~ B(10; 0,5), gevraagd P(X = 6).</li><li>P(X=6) = C(10,6)·0,5⁶·0,5⁴ = 210 · 0,5¹⁰.</li><li>= 210 / 1024 ≈ 0,205.</li></ol><div class="sam-worked-ans">✅ De kans is ongeveer 0,21 (21%).</div></div><div class="sam-head">Binomiaal of normaal?</div><div class="sam-compare"><div class="sam-compare-col"><div class="sam-compare-head">Binomiaal B(n, p)</div><ul><li>discreet: je telt <strong>successen</strong></li><li>vast aantal pogingen n</li><li>GR: binompdf / binomcdf</li></ul></div><div class="sam-compare-col"><div class="sam-compare-head">Normaal N(µ, σ)</div><ul><li>continu: klokvorm</li><li>lengte, gewicht, tijd…</li><li>GR: normalcdf / invNorm</li></ul></div></div><div class="sam-definitie"><div class="sam-definitie-term">Significantieniveau α</div><div class="sam-definitie-body">De grens (vaak 5%) waaronder je de nulhypothese verwerpt. Is de p-waarde &lt; α, dan is het resultaat "significant" en verwerp je H₀; anders niet.</div></div><div class="sam-head">Hypothesetoets — stappenplan</div><div class="sam-proces"><div class="sam-proces-step"><span class="sam-proces-num">1</span><span>Stel H₀ en H₁ op (één- of tweezijdig).</span></div><div class="sam-proces-step"><span class="sam-proces-num">2</span><span>Kies het significantieniveau α.</span></div><div class="sam-proces-step"><span class="sam-proces-num">3</span><span>Bereken de p-waarde met de GR (binomcdf/normalcdf).</span></div><div class="sam-proces-step"><span class="sam-proces-num">4</span><span>Vergelijk: p &lt; α → verwerp H₀.</span></div><div class="sam-proces-step"><span class="sam-proces-num">5</span><span>Formuleer de conclusie <strong>in de context</strong>.</span></div></div><div class="sam-val"><ul><li>Een niet-verworpen H₀ als "<strong>bewezen</strong>" opschrijven — het is alleen "onvoldoende bewijs".</li><li><strong>binompdf</strong> (precies k) en <strong>binomcdf</strong> (hoogstens k) verwisselen.</li><li>Eén- vs. <strong>tweezijdig</strong> toetsen door elkaar halen (α wel/niet delen).</li><li>Spreiding σ en variantie σ² verwarren.</li></ul></div><div class="sam-onthoud"><ul style="margin:0;padding-left:16px"><li style="margin-bottom:3px">Binomiaal = tellen van successen; normaal = continue klokvorm.</li><li style="margin-bottom:3px">µ = n·p bij de binomiale verdeling.</li><li style="margin-bottom:3px">68-95-99,7-regel: binnen 1σ / 2σ / 3σ.</li><li style="margin-bottom:3px">p &lt; α → verwerp H₀; conclusie altijd in context.</li></ul></div></div>`,
'vwo_wb_C':`<div class="sam-intro">Analyse is het hart van wiskunde B: <strong>differentiëren</strong> en <strong>integreren</strong> met alle regels, <strong>limieten</strong> en <strong>asymptoten</strong>, en het volledig <strong>onderzoeken van functies</strong> (extremen, buigpunten, verloop).</div><div class="sam-chips"><span class="sam-chip sam-chip-lead">Kern</span><span class="sam-chip">Afgeleide</span><span class="sam-chip">Ketting-/product-/quotiëntregel</span><span class="sam-chip">Extremen</span><span class="sam-chip">Buigpunten</span><span class="sam-chip">Integreren</span></div><div class="sam-head">Differentieerregels</div><table class="sam-table"><thead><tr><th>Regel</th><th>Formule</th></tr></thead><tbody><tr><td>Kettingregel</td><td>(f(g(x)))′ = f′(g(x))·g′(x)</td></tr><tr><td>Productregel</td><td>(f·g)′ = f′g + fg′</td></tr><tr><td>Quotiëntregel</td><td>(f/g)′ = (f′g − fg′)/g²</td></tr></tbody></table><div class="sam-head">De afgeleide als helling</div><p>De afgeleide f′(x) is de <strong>richtingscoëfficiënt</strong> van de <strong>raaklijn</strong> in een punt. Waar f′(x) = 0 ligt een <strong>extreem</strong> (top of dal); waar f″(x) van teken wisselt, ligt een <strong>buigpunt</strong>.</p><div class="sam-figure"><svg viewBox="0 0 340 172" role="img" aria-label="Grafiek van een functie met de raaklijn in een punt, waarvan de helling de afgeleide is"><defs><marker id="wbBa" markerWidth="9" markerHeight="9" refX="5" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L7,3 L0,6 Z" fill="var(--mu)"/></marker></defs><line x1="30" y1="156" x2="332" y2="156" stroke="var(--mu)" stroke-width="1.5" marker-end="url(#wbBa)"/><line x1="40" y1="164" x2="40" y2="20" stroke="var(--mu)" stroke-width="1.5" marker-end="url(#wbBa)"/><path d="M40.0,141.4 L66.0,104.9 L92.0,76.5 L118.0,56.2 L144.0,44.1 L167.1,40.1 L190.2,42.5 L216.2,52.8 L242.2,71.3 L268.2,97.9 L294.2,132.6 L300,141" fill="none" stroke="var(--or)" stroke-width="2.4" stroke-linecap="round"/><line x1="210" y1="40" x2="290" y2="117" stroke="var(--dk)" stroke-width="2" stroke-dasharray="5 3"/><circle cx="250" cy="78.4" r="4" fill="var(--dk)"/><text x="256" y="74" font-size="9" font-weight="700" fill="var(--dk)">raakpunt</text><text x="150" y="36" font-size="10" font-weight="700" fill="var(--or)">y = f(x)</text><text x="230" y="130" font-size="9" fill="var(--mu)">helling = f′(x)</text></svg><div class="sam-figcap"><strong>Raaklijn:</strong> de gestippelde lijn raakt de grafiek in één punt. De richtingscoëfficiënt van die raaklijn is de waarde van de afgeleide f′(x) in dat punt.</div></div><div class="sam-head">Integreren</div><p>Naast standaardprimitieven gebruik je op VWO twee technieken:</p><div class="sam-compare"><div class="sam-compare-col"><div class="sam-compare-head">Substitutie</div><ul><li>voor samengestelde functies</li><li>vervang de binnenkant door u</li><li>omgekeerde kettingregel</li></ul></div><div class="sam-compare-col"><div class="sam-compare-head">Partieel integreren</div><ul><li>voor producten van functies</li><li>∫u dv = uv − ∫v du</li><li>omgekeerde productregel</li></ul></div></div><div class="sam-head">Limieten en asymptoten</div><p>Een <strong>limiet</strong> beschrijft het gedrag van f(x) als x een waarde nadert (of naar ±∞ gaat). Daaruit volgen <strong>asymptoten</strong>: lijnen die de grafiek steeds dichter nadert.</p><div class="sam-formula-box"><div class="sam-formula-label">Raaklijn in een punt</div><div class="sam-formula-eq">y = f(a) + f′(a)·(x − a)</div><div class="sam-formula-note">a de x-coördinaat van het raakpunt. f(a) geeft de hoogte, f′(a) de helling van de raaklijn.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave</div><div class="sam-worked-q">Bepaal de vergelijking van de raaklijn aan f(x) = x² in het punt x = 3.</div><ol class="sam-worked-steps"><li>f(3) = 9 en f′(x) = 2x, dus f′(3) = 6.</li><li>y = f(3) + f′(3)(x − 3) = 9 + 6(x − 3).</li><li>y = 6x − 9.</li></ol><div class="sam-worked-ans">✅ De raaklijn is y = 6x − 9.</div></div><div class="sam-head">Functieonderzoek — stappenplan</div><p>"Onderzoek de functie" is een klassieke examenvraag. Werk hem altijd in dezelfde volgorde af:</p><div class="sam-proces"><div class="sam-proces-step"><span class="sam-proces-num">1</span><span>Bepaal het <strong>domein</strong> (waar is f gedefinieerd?).</span></div><div class="sam-proces-step"><span class="sam-proces-num">2</span><span>Bereken de <strong>afgeleide</strong> f′(x).</span></div><div class="sam-proces-step"><span class="sam-proces-num">3</span><span>Los <strong>f′(x) = 0</strong> op → mogelijke extremen.</span></div><div class="sam-proces-step"><span class="sam-proces-num">4</span><span>Maak een <strong>tekenschema</strong> van f′ → stijgen/dalen, minimum of maximum.</span></div><div class="sam-proces-step"><span class="sam-proces-num">5</span><span>Onderzoek f″ voor <strong>buigpunten</strong> en de vorm (bol/hol).</span></div></div><div class="sam-definitie"><div class="sam-definitie-term">Buigpunt</div><div class="sam-definitie-body">Een punt waar de grafiek van hol naar bol (of omgekeerd) overgaat. Daar wisselt de tweede afgeleide f″ van teken; de raaklijn snijdt de grafiek in dat punt.</div></div><div class="sam-head">Welke integratietechniek?</div><p>Herken het type integraal en kies gericht: een <strong>samengestelde</strong> functie → substitutie (omgekeerde kettingregel); een <strong>product</strong> van twee functies → partieel integreren (omgekeerde productregel).</p><div class="sam-val"><ul><li>Kettingregel: de afgeleide van de <strong>binnenkant</strong> vergeten (·g′(x)).</li><li>Quotiëntregel: de <strong>volgorde</strong> in de teller omdraaien (f′g − fg′, niet fg′ − f′g).</li><li>Een extreem claimen zonder <strong>tekenonderzoek</strong> — f′ = 0 kan ook een buigpunt zijn.</li><li>Bij een bepaalde integraal de grenzen niet <strong>meesubstitueren</strong>.</li></ul></div><div class="sam-onthoud"><ul style="margin:0;padding-left:16px"><li style="margin-bottom:3px">f′ = helling van de raaklijn; f′ = 0 → mogelijk extreem.</li><li style="margin-bottom:3px">f″ wisselt van teken → buigpunt.</li><li style="margin-bottom:3px">Functieonderzoek: domein → f′ → f′=0 → tekenschema → f″.</li><li style="margin-bottom:3px">Substitutie voor samengesteld, partieel voor product.</li></ul></div></div>`,
'vwo_wb_D':`<div class="sam-intro">Goniometrie beschrijft draaiingen en periodieke verschijnselen met <strong>sinus</strong>, <strong>cosinus</strong> en <strong>tangens</strong>. De <strong>eenheidscirkel</strong> is je kompas, en met de <strong>optellings-</strong> en <strong>dubbele-hoekformules</strong> herschrijf en bewijs je identiteiten.</div><div class="sam-chips"><span class="sam-chip sam-chip-lead">Kern</span><span class="sam-chip">Eenheidscirkel</span><span class="sam-chip">sin/cos/tan</span><span class="sam-chip">Radialen</span><span class="sam-chip">Optellingsformules</span><span class="sam-chip">Periodiek</span></div><div class="sam-head">De eenheidscirkel</div><p>Op de <strong>eenheidscirkel</strong> (straal 1) hoort bij een hoek α een punt (cos α, sin α). De sinus is de <strong>hoogte</strong> (y), de cosinus de <strong>horizontale</strong> afstand (x).</p><div class="sam-figure"><svg viewBox="0 0 300 210" role="img" aria-label="Eenheidscirkel met een hoek alfa en de projecties cosinus en sinus"><defs><marker id="wbCa" markerWidth="9" markerHeight="9" refX="5" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L7,3 L0,6 Z" fill="var(--mu)"/></marker></defs><circle cx="120" cy="120" r="75" fill="none" stroke="var(--mu)" stroke-width="1.5"/><line x1="30" y1="120" x2="230" y2="120" stroke="var(--mu)" stroke-width="1.2" marker-end="url(#wbCa)"/><line x1="120" y1="205" x2="120" y2="30" stroke="var(--mu)" stroke-width="1.2" marker-end="url(#wbCa)"/><line x1="120" y1="120" x2="168" y2="62" stroke="var(--or)" stroke-width="2.4"/><circle cx="168" cy="62" r="4" fill="var(--or)"/><line x1="168" y1="120" x2="168" y2="62" stroke="var(--dk)" stroke-width="2" stroke-dasharray="4 2"/><line x1="120" y1="120" x2="168" y2="120" stroke="var(--dk)" stroke-width="2"/><path d="M148,120 A28,28 0 0,0 138,101" fill="none" stroke="var(--dk)" stroke-width="1.2"/><text x="143" y="114" font-size="10" font-weight="700" fill="var(--dk)">α</text><text x="138" y="135" font-size="9" fill="var(--dk)">cos α</text><text x="172" y="95" font-size="9" fill="var(--dk)">sin α</text><text x="228" y="134" font-size="9" fill="var(--mu)">x</text><text x="126" y="36" font-size="9" fill="var(--mu)">y</text></svg><div class="sam-figcap"><strong>Eenheidscirkel:</strong> bij hoek α hoort het punt (cos α, sin α). De tangens is sin α / cos α — de helling van de straal.</div></div><div class="sam-formula-box"><div class="sam-formula-label">Grondformule van de goniometrie</div><div class="sam-formula-eq">sin²α + cos²α = 1  ·  tan α = sin α / cos α</div><div class="sam-formula-note">Volgt direct uit de stelling van Pythagoras op de eenheidscirkel. Hiermee herschrijf je uitdrukkingen en bewijs je identiteiten.</div></div><div class="sam-head">Optellings- en dubbele-hoekformules</div><div class="sam-formula-box"><div class="sam-formula-label">Optellingsformules</div><div class="sam-formula-eq">sin(α±β) = sin α cos β ± cos α sin β<br>cos(α±β) = cos α cos β ∓ sin α sin β</div><div class="sam-formula-note">Hieruit volgen de dubbele-hoekformules: sin 2α = 2 sin α cos α en cos 2α = cos²α − sin²α = 1 − 2sin²α.</div></div><div class="sam-head">Goniometrische vergelijkingen</div><p>Een vergelijking als sin x = c heeft <strong>oneindig veel</strong> oplossingen. Je geeft ze met een periode: bijvoorbeeld x = … + k·2π. Gebruik de eenheidscirkel om alle hoeken in één omwenteling te vinden.</p><div class="sam-tip">Onthoud de standaardwaarden: sin 30° = ½, sin 45° = ½√2, sin 60° = ½√3 (en cos precies andersom).</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave</div><div class="sam-worked-q">Vereenvoudig sin 2α als sin α = 0,6 en cos α = 0,8.</div><ol class="sam-worked-steps"><li>Dubbele hoek: sin 2α = 2 sin α cos α.</li><li>= 2 × 0,6 × 0,8.</li><li>= 0,96.</li></ol><div class="sam-worked-ans">✅ sin 2α = 0,96.</div></div><div class="sam-head">Radialen en graden</div><p>Op VWO reken je meestal in <strong>radialen</strong>. Een volledige cirkel is 2π rad = 360°. Reken om met de verhouding π rad = 180°.</p><div class="sam-formula-box"><div class="sam-formula-label">Graden ↔ radialen</div><div class="sam-formula-eq">radialen = graden × π/180  ·  graden = radialen × 180/π</div><div class="sam-formula-note">Zet je rekenmachine in de juiste stand (RAD of DEG) — een verkeerde modus is een klassieke examenfout.</div></div><div class="sam-head">Standaardhoeken</div><table class="sam-table"><thead><tr><th>hoek</th><th>sin</th><th>cos</th><th>tan</th></tr></thead><tbody><tr><td>0</td><td>0</td><td>1</td><td>0</td></tr><tr><td>π/6 (30°)</td><td>½</td><td>½√3</td><td>⅓√3</td></tr><tr><td>π/4 (45°)</td><td>½√2</td><td>½√2</td><td>1</td></tr><tr><td>π/3 (60°)</td><td>½√3</td><td>½</td><td>√3</td></tr><tr><td>π/2 (90°)</td><td>1</td><td>0</td><td>—</td></tr></tbody></table><div class="sam-definitie"><div class="sam-definitie-term">Radiaal</div><div class="sam-definitie-body">De hoek waarbij de booglengte gelijk is aan de straal. 1 rad ≈ 57,3°; een halve cirkel (180°) is precies π rad.</div></div><div class="sam-val"><ul><li>Rekenmachine in de <strong>verkeerde modus</strong> (DEG i.p.v. RAD).</li><li>Bij sin x = c maar <strong>één</strong> oplossing geven — er zijn er twee per omwenteling, plus de periode + k·2π.</li><li>Oplossingen buiten het <strong>gevraagde interval</strong> laten staan (of ze juist missen).</li><li>Grondformule verkeerd toepassen: sin²α + cos²α = 1, níét sin α + cos α = 1.</li></ul></div><div class="sam-onthoud"><ul style="margin:0;padding-left:16px"><li style="margin-bottom:3px">Eenheidscirkel: punt (cos α, sin α), tan α = sin/cos.</li><li style="margin-bottom:3px">sin²α + cos²α = 1 (grondformule).</li><li style="margin-bottom:3px">π rad = 180°; check RAD/DEG-modus.</li><li style="margin-bottom:3px">sin x = c → oneindig veel oplossingen: … + k·2π.</li></ul></div></div>`,
'vwo_wb_E':`<div class="sam-intro">In de <strong>ruimtemeetkunde</strong> reken je met <strong>vectoren</strong> in drie dimensies. Met het <strong>inproduct</strong> vind je hoeken en loodrechte stand, met het <strong>uitproduct</strong> een normaalvector, en zo stel je vergelijkingen van <strong>lijnen</strong> en <strong>vlakken</strong> op.</div><div class="sam-chips"><span class="sam-chip sam-chip-lead">Kern</span><span class="sam-chip">Vectoren 3D</span><span class="sam-chip">Lengte</span><span class="sam-chip">Inproduct</span><span class="sam-chip">Uitproduct</span><span class="sam-chip">Normaalvector</span><span class="sam-chip">Vlakken</span></div><div class="sam-head">Vectoren in 3D</div><p>Een <strong>vector</strong> heeft een lengte en een richting. Je telt vectoren componentsgewijs op en vermenigvuldigt met een getal (scalair).</p><div class="sam-figure"><svg viewBox="0 0 300 200" role="img" aria-label="Een driedimensionaal assenstelsel met een vector vanuit de oorsprong"><defs><marker id="wbDx" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--mu)"/></marker><marker id="wbDv" markerWidth="9" markerHeight="9" refX="5" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L7,3 L0,6 Z" fill="var(--or)"/></marker></defs><line x1="110" y1="140" x2="260" y2="140" stroke="var(--mu)" stroke-width="1.3" marker-end="url(#wbDx)"/><line x1="110" y1="140" x2="110" y2="25" stroke="var(--mu)" stroke-width="1.3" marker-end="url(#wbDx)"/><line x1="110" y1="140" x2="45" y2="185" stroke="var(--mu)" stroke-width="1.3" marker-end="url(#wbDx)"/><text x="252" y="156" font-size="10" fill="var(--mu)">x</text><text x="98" y="30" font-size="10" fill="var(--mu)">z</text><text x="36" y="188" font-size="10" fill="var(--mu)">y</text><line x1="110" y1="140" x2="205" y2="70" stroke="var(--or)" stroke-width="2.6" marker-end="url(#wbDv)"/><text x="180" y="92" font-size="11" font-weight="700" fill="var(--or)">a⃗</text><circle cx="110" cy="140" r="3" fill="var(--dk)"/><text x="88" y="152" font-size="9" fill="var(--mu)">O</text></svg><div class="sam-figcap"><strong>Vector in de ruimte:</strong> a⃗ = (a₁, a₂, a₃) vanuit de oorsprong O. De lengte volgt uit Pythagoras in drie dimensies.</div></div><div class="sam-formula-box"><div class="sam-formula-label">Lengte van een vector</div><div class="sam-formula-eq">|a⃗| = √(a₁² + a₂² + a₃²)</div><div class="sam-formula-note">De driedimensionale versie van de stelling van Pythagoras.</div></div><div class="sam-head">Inproduct: hoek en loodrechte stand</div><p>Het <strong>inproduct</strong> (dot-product) koppelt twee vectoren aan de hoek ertussen. Is het inproduct 0, dan staan de vectoren <strong>loodrecht</strong> op elkaar.</p><div class="sam-formula-box"><div class="sam-formula-label">Inproduct</div><div class="sam-formula-eq">a⃗ · b⃗ = a₁b₁ + a₂b₂ + a₃b₃ = |a⃗||b⃗|·cos φ</div><div class="sam-formula-note">φ de hoek tussen de vectoren. Uit de laatste gelijkheid bereken je die hoek. a⃗ · b⃗ = 0 ⇔ loodrecht.</div></div><div class="sam-head">Uitproduct en normaalvector</div><p>Het <strong>uitproduct</strong> (kruisproduct) a⃗ × b⃗ geeft een vector die <strong>loodrecht</strong> op beide staat — precies de <strong>normaalvector</strong> die je nodig hebt voor een vlak.</p><div class="sam-head">Lijnen en vlakken</div><div class="sam-compare"><div class="sam-compare-col"><div class="sam-compare-head">Lijn (vectorvorm)</div><ul><li>r⃗ = a⃗ + t·d⃗</li><li>a⃗ steunpunt, d⃗ richting</li><li>t is de parameter</li></ul></div><div class="sam-compare-col"><div class="sam-compare-head">Vlak</div><ul><li>n⃗ · r⃗ = d</li><li>n⃗ de normaalvector</li><li>loodrecht op het vlak</li></ul></div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave</div><div class="sam-worked-q">Staan a⃗ = (2, −1, 3) en b⃗ = (1, 2, 0) loodrecht op elkaar?</div><ol class="sam-worked-steps"><li>a⃗ · b⃗ = 2·1 + (−1)·2 + 3·0.</li><li>= 2 − 2 + 0 = 0.</li></ol><div class="sam-worked-ans">✅ Het inproduct is 0, dus ja: de vectoren staan loodrecht.</div></div><div class="sam-head">Hoek tussen twee vectoren berekenen</div><p>Met het inproduct bereken je de hoek φ tussen twee vectoren. Werk in vaste stappen:</p><ol class="sam-steps"><li>Bereken het inproduct a⃗ · b⃗ = a₁b₁ + a₂b₂ + a₃b₃.</li><li>Bereken de lengtes |a⃗| en |b⃗|.</li><li>Vul in: cos φ = (a⃗ · b⃗) / (|a⃗|·|b⃗|).</li><li>φ = cos⁻¹(…) — let op RAD/DEG.</li></ol><div class="sam-definitie"><div class="sam-definitie-term">Normaalvector</div><div class="sam-definitie-body">Een vector n⃗ die loodrecht op een vlak staat. Je vindt hem als het uitproduct van twee richtingsvectoren van het vlak; de coëfficiënten (a, b, c) in de vlakvergelijking ax + by + cz = d zíjn de normaalvector.</div></div><div class="sam-head">Vergelijking van een vlak opstellen</div><p>Heb je een <strong>punt</strong> in het vlak en een <strong>normaalvector</strong> n⃗ = (a, b, c), dan is de vlakvergelijking ax + by + cz = d. De waarde van d vind je door de coördinaten van het bekende punt in te vullen.</p><div class="sam-val"><ul><li><strong>Inproduct</strong> (getal) en <strong>uitproduct</strong> (vector) door elkaar halen.</li><li>Loodrecht-test: a⃗ · b⃗ = 0 betekent loodrecht — niet a⃗ × b⃗ = 0.</li><li>Bij de hoek de <strong>lengtes</strong> vergeten te delen (cos φ moet tussen −1 en 1 liggen).</li><li>Tekenfout bij een component in het inproduct.</li></ul></div><div class="sam-onthoud"><ul style="margin:0;padding-left:16px"><li style="margin-bottom:3px">|a⃗| = √(a₁² + a₂² + a₃²).</li><li style="margin-bottom:3px">a⃗ · b⃗ = 0 ⇔ loodrecht; anders cos φ = (a⃗·b⃗)/(|a⃗||b⃗|).</li><li style="margin-bottom:3px">Uitproduct → normaalvector (loodrecht op beide).</li><li style="margin-bottom:3px">Vlak: ax + by + cz = d met (a,b,c) = normaalvector.</li></ul></div></div>`,
'vwo_bi_B':`<div class="sam-intro"><strong>Zelfregulatie</strong> is hét vermogen van een biologisch systeem om zichzelf in stand te houden — van het <strong>molecuul</strong> (eiwitsynthese) via de <strong>cel</strong> en het <strong>orgaan</strong> tot het hele <strong>organisme</strong>. De rode draad: <strong>homeostase</strong> (een constant intern milieu) via <strong>negatieve terugkoppeling</strong>.</div><div class="sam-head">Wat je voor het examen moet kennen (syllabus)</div><p>Dit domein bestaat uit vijf subdomeinen. Deze samenvatting dekt ze allemaal:</p><table class="sam-table"><thead><tr><th>Sub</th><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>B1</td><td>Eiwitsynthese</td><td>DNA → mRNA → eiwit</td></tr><tr><td>B2</td><td>Stofwisseling van de cel</td><td>assimilatie/dissimilatie, transport</td></tr><tr><td>B3</td><td>Stofwisseling van het organisme</td><td>organen, vertering, ademhaling, uitscheiding</td></tr><tr><td>B4</td><td>Zelfregulatie van het organisme</td><td>homeostase, hormonaal + neuraal</td></tr><tr><td>B5</td><td>Afweer van het organisme</td><td>aangeboren + verworven immuniteit</td></tr></tbody></table><div class="sam-head">B1 · Eiwitsynthese</div><p>Eiwitten bepalen wat een cel doet. Het bouwvoorschrift staat als <strong>genen</strong> in het <strong>DNA</strong>. Van gen naar eiwit gaat in twee stappen:</p><div class="sam-figure"><svg viewBox="0 0 320 118" role="img" aria-label="Eiwitsynthese: DNA wordt via transcriptie mRNA en via translatie in het ribosoom een eiwit"><defs><marker id="giB1" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--mu)"/></marker></defs><rect x="10" y="40" width="66" height="36" rx="6" fill="var(--or)" opacity=".14" stroke="var(--or)" stroke-width="1.2"/><text x="43" y="56" font-size="9.5" font-weight="700" fill="var(--dk)" text-anchor="middle">DNA</text><text x="43" y="68" font-size="7" fill="var(--mu)" text-anchor="middle">(celkern)</text><rect x="128" y="40" width="66" height="36" rx="6" fill="var(--mu)" opacity=".12" stroke="var(--mu)" stroke-width="1.1"/><text x="161" y="56" font-size="9.5" font-weight="700" fill="var(--dk)" text-anchor="middle">mRNA</text><text x="161" y="68" font-size="7" fill="var(--mu)" text-anchor="middle">kopie van gen</text><rect x="246" y="40" width="66" height="36" rx="6" fill="var(--or)" opacity=".2" stroke="var(--or)" stroke-width="1.3"/><text x="279" y="56" font-size="9.5" font-weight="700" fill="var(--dk)" text-anchor="middle">eiwit</text><text x="279" y="68" font-size="7" fill="var(--mu)" text-anchor="middle">(ribosoom)</text><line x1="76" y1="58" x2="126" y2="58" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#giB1)"/><text x="101" y="51" font-size="7.5" fill="var(--or)" text-anchor="middle">transcriptie</text><line x1="194" y1="58" x2="244" y2="58" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#giB1)"/><text x="219" y="51" font-size="7.5" fill="var(--or)" text-anchor="middle">translatie</text></svg><div class="sam-figcap"><strong>Van gen naar eiwit:</strong> bij de <strong>transcriptie</strong> (in de kern) maakt RNA-polymerase van een gen een mRNA-kopie; bij de <strong>translatie</strong> leest het ribosoom het mRNA en rijgt tRNA de aminozuren aaneen tot een eiwit.</div></div><ul><li><strong>Codon</strong>: een basentriplet op het mRNA dat codeert voor één aminozuur. Met 4 basen zijn er 4³ = 64 codons (incl. start- en stopcodon).</li><li><strong>tRNA</strong> heeft een anticodon en brengt het bijpassende aminozuur aan.</li><li>Bij eukaryoten wordt het pre-mRNA eerst bewerkt: <strong>introns</strong> eruit, <strong>exons</strong> aaneen (splicing).</li></ul><div class="sam-tip">De volgorde van de basen bepaalt de volgorde van de aminozuren, en die bepaalt de vorm en functie van het eiwit. Een fout in het DNA (mutatie) kan zo het eiwit veranderen.</div><div class="sam-head">B2 · Stofwisseling van de cel</div><p>De <strong>stofwisseling</strong> (het metabolisme) is het geheel van alle chemische omzettingen in de cel. Twee richtingen:</p><div class="sam-figure"><svg viewBox="0 0 300 120" role="img" aria-label="Assimilatie bouwt macromoleculen op en kost energie, dissimilatie breekt ze af en levert ATP"><defs><marker id="giB2" markerWidth="9" markerHeight="9" refX="5" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L7,3 L0,6 Z" fill="var(--or)"/></marker></defs><rect x="14" y="42" width="88" height="36" rx="6" fill="var(--mu)" opacity=".12" stroke="var(--mu)" stroke-width="1.1"/><text x="58" y="58" font-size="9" font-weight="700" fill="var(--dk)" text-anchor="middle">bouwstenen</text><text x="58" y="70" font-size="7" fill="var(--mu)" text-anchor="middle">klein</text><rect x="198" y="42" width="88" height="36" rx="6" fill="var(--or)" opacity=".16" stroke="var(--or)" stroke-width="1.2"/><text x="242" y="58" font-size="9" font-weight="700" fill="var(--dk)" text-anchor="middle">macromolecuul</text><text x="242" y="70" font-size="7" fill="var(--mu)" text-anchor="middle">groot</text><path d="M104,52 C140,40 160,40 196,52" fill="none" stroke="var(--or)" stroke-width="1.8" marker-end="url(#giB2)"/><text x="150" y="36" font-size="7.5" fill="var(--or)" text-anchor="middle">assimilatie — kost energie</text><path d="M196,68 C160,80 140,80 104,68" fill="none" stroke="var(--or)" stroke-width="1.8" marker-end="url(#giB2)"/><text x="150" y="98" font-size="7.5" fill="var(--or)" text-anchor="middle">dissimilatie — levert ATP</text></svg><div class="sam-figcap"><strong>Assimilatie</strong> (opbouw) maakt van kleine bouwstenen grote moleculen en kost energie; <strong>dissimilatie</strong> (afbraak) breekt ze af en levert energie in de vorm van <strong>ATP</strong>.</div></div><table class="sam-table"><thead><tr><th>Transport door membraan</th><th>Hoe</th></tr></thead><tbody><tr><td>Diffusie</td><td>van hoge naar lage concentratie, passief (geen energie)</td></tr><tr><td>Osmose</td><td>diffusie van wáter door een membraan</td></tr><tr><td>Actief transport</td><td>tegen de gradiënt in, kost ATP (bv. natrium-kaliumpomp)</td></tr></tbody></table><p>Enzymen versnellen deze reacties en zijn <strong>substraatspecifiek</strong>. Een <strong>prokaryote</strong> cel (bacterie) heeft geen kern; een <strong>eukaryote</strong> cel wel, met organellen.</p><div class="sam-head">B3 · Stofwisseling van het organisme</div><p>Bij een veelcellig organisme werken <strong>organen</strong> samen om stoffen op te nemen, te verwerken en af te voeren:</p><table class="sam-table"><thead><tr><th>Orgaan(stelsel)</th><th>Functie</th></tr></thead><tbody><tr><td>Verteringsstelsel</td><td>voedsel → kleine moleculen; opname in het bloed</td></tr><tr><td>Ademhalingsstelsel</td><td>O₂ opnemen, CO₂ afvoeren (longen)</td></tr><tr><td>Bloedsomloop (hart)</td><td>transport van stoffen door het lichaam</td></tr><tr><td>Nieren</td><td>uitscheiding van afvalstoffen (ureum) en waterregeling</td></tr></tbody></table><div class="sam-formula-box"><div class="sam-formula-label">Fotosynthese en celademhaling</div><div class="sam-formula-eq">6 CO₂ + 6 H₂O + licht → C₆H₁₂O₆ + 6 O₂  (assimilatie)<br>C₆H₁₂O₆ + 6 O₂ → 6 CO₂ + 6 H₂O + energie  (dissimilatie)</div><div class="sam-formula-note">Planten leggen in de bladgroenkorrels energie vast in glucose (fotosynthese); álle cellen halen die energie er via celademhaling weer uit als ATP.</div></div><div class="sam-head">B4 · Zelfregulatie van het organisme</div><p><strong>Homeostase</strong> is het constant houden van het interne milieu (temperatuur, bloedglucose, pH, water). Dat gebeurt via <strong>negatieve terugkoppeling</strong>: een afwijking van het <strong>setpoint</strong> wordt gemeten en tegengewerkt.</p><div class="sam-figure"><svg viewBox="0 0 320 150" role="img" aria-label="Negatieve terugkoppeling: een afwijking wordt gemeten door een sensor, verwerkt en door een effector tegengewerkt"><defs><marker id="giB4" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--or)"/></marker></defs><rect x="110" y="12" width="100" height="30" rx="6" fill="var(--or)" opacity=".14" stroke="var(--or)" stroke-width="1.2"/><text x="160" y="31" font-size="9" font-weight="700" fill="var(--dk)" text-anchor="middle">afwijking setpoint</text><rect x="228" y="60" width="84" height="30" rx="6" fill="var(--mu)" opacity=".12" stroke="var(--mu)" stroke-width="1.1"/><text x="270" y="79" font-size="8.5" font-weight="700" fill="var(--dk)" text-anchor="middle">sensor meet</text><rect x="118" y="108" width="84" height="30" rx="6" fill="var(--mu)" opacity=".12" stroke="var(--mu)" stroke-width="1.1"/><text x="160" y="127" font-size="8.5" font-weight="700" fill="var(--dk)" text-anchor="middle">verwerker</text><rect x="8" y="60" width="84" height="30" rx="6" fill="var(--or)" opacity=".16" stroke="var(--or)" stroke-width="1.2"/><text x="50" y="76" font-size="8.5" font-weight="700" fill="var(--dk)" text-anchor="middle">effector</text><text x="50" y="86" font-size="7" fill="var(--mu)" text-anchor="middle">werkt tegen</text><path d="M210,30 C250,35 268,45 270,58" fill="none" stroke="var(--or)" stroke-width="1.5" marker-end="url(#giB4)"/><path d="M258,90 C230,104 210,110 204,116" fill="none" stroke="var(--or)" stroke-width="1.5" marker-end="url(#giB4)"/><path d="M116,124 C86,116 66,104 58,92" fill="none" stroke="var(--or)" stroke-width="1.5" marker-end="url(#giB4)"/><path d="M50,58 C52,42 78,32 108,29" fill="none" stroke="var(--or)" stroke-width="1.5" marker-end="url(#giB4)"/></svg><div class="sam-figcap"><strong>Negatieve terugkoppeling:</strong> de afwijking wordt gemeten (sensor), verwerkt en door de effector tegengewerkt, zodat de waarde terugkeert naar het setpoint. De lus herhaalt zich continu.</div></div><p>Er zijn twee regelsystemen, die elkaar aanvullen:</p><div class="sam-compare"><div class="sam-compare-col"><div class="sam-compare-head">Zenuwstelsel (neuraal)</div><ul><li>zeer snel, kortdurend</li><li>elektrische impuls: actiepotentiaal</li><li>synaps: Ca²⁺ → neurotransmitter</li></ul></div><div class="sam-compare-col"><div class="sam-compare-head">Hormoonstelsel</div><ul><li>trager, langdurig</li><li>via het bloed</li><li>bv. insuline, glucagon, adrenaline, ADH</li></ul></div></div><div class="sam-figure"><svg viewBox="0 0 340 172" role="img" aria-label="Verloop van een actiepotentiaal met rust, depolarisatie, repolarisatie en hyperpolarisatie"><defs><marker id="giAP" markerWidth="9" markerHeight="9" refX="5" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L7,3 L0,6 Z" fill="var(--mu)"/></marker></defs><line x1="44" y1="160" x2="332" y2="160" stroke="var(--mu)" stroke-width="1.5" marker-end="url(#giAP)"/><line x1="44" y1="168" x2="44" y2="28" stroke="var(--mu)" stroke-width="1.5" marker-end="url(#giAP)"/><line x1="44" y1="140" x2="320" y2="140" stroke="var(--mu)" stroke-width="1" stroke-dasharray="3 3"/><text x="4" y="143" font-size="8.5" fill="var(--mu)">−70</text><text x="8" y="44" font-size="8.5" fill="var(--mu)">+30</text><text x="10" y="24" font-size="8.5" fill="var(--mu)">mV</text><path d="M44,140 L77,140 L88,125 L105,40 L127,90 L149,148 L165,156 L196,143 L251,140 L320,140" fill="none" stroke="var(--or)" stroke-width="2.4" stroke-linecap="round" stroke-linejoin="round"/><text x="98" y="36" font-size="8" fill="var(--or)">depolarisatie (Na⁺ in)</text><text x="150" y="172" font-size="8" fill="var(--mu)">repolarisatie (K⁺ uit)</text></svg><div class="sam-figcap"><strong>Actiepotentiaal:</strong> bij de drempel gaan Na⁺-kanalen open (depolarisatie, piek +30 mV); daarna stromen K⁺-ionen uit (repolarisatie) met een korte hyperpolarisatie voor de rust terugkeert.</div></div><table class="sam-table"><thead><tr><th>Hormoon</th><th>Effect</th></tr></thead><tbody><tr><td>Insuline</td><td>verlaagt bloedglucose (opslag als glycogeen)</td></tr><tr><td>Glucagon</td><td>verhoogt bloedglucose (afbraak glycogeen)</td></tr><tr><td>Adrenaline</td><td>vecht-of-vlucht: hartslag en glucose omhoog</td></tr><tr><td>ADH</td><td>waterhuishouding: terugresorptie in de nier</td></tr></tbody></table><div class="sam-warn"><strong>Verstoring — diabetes:</strong> bij <strong>type 1</strong> maakt het lichaam geen insuline (aangeboren, alvleesklier), bij <strong>type 2</strong> reageren de cellen er slecht op. In beide gevallen blijft het bloedglucose te hoog; behandeling: insuline spuiten of leefstijl/medicatie.</div><div class="sam-head">B5 · Afweer van het organisme</div><p>Het afweersysteem beschermt tegen ziekteverwekkers in twee lagen:</p><div class="sam-compare"><div class="sam-compare-col"><div class="sam-compare-head">Aangeboren (niet-specifiek)</div><ul><li>direct aanwezig</li><li>huid, slijmvliezen, fagocyten</li><li>koorts en ontstekingsreactie</li><li>geen geheugen</li></ul></div><div class="sam-compare-col"><div class="sam-compare-head">Verworven (specifiek)</div><ul><li>ontwikkelt zich, gericht</li><li>B-cellen → antilichamen</li><li>T-cellen (cellulaire afweer)</li><li>vormt geheugencellen</li></ul></div></div><ul><li><strong>Antigeen</strong>: lichaamsvreemde stof die een afweerreactie oproept.</li><li><strong>Antilichaam</strong>: eiwit dat plasmacellen (uit B-cellen) maken en dat specifiek aan een antigeen bindt.</li><li><strong>Actieve immuniteit</strong> (vaccinatie): je maakt zélf antilichamen en geheugencellen. <strong>Passieve immuniteit</strong>: je krijgt kant-en-klare antilichamen (bv. via de moedermelk).</li></ul><div class="sam-tip">Bij een tweede besmetting met dezelfde ziekteverwekker reageren de <strong>geheugencellen</strong> veel sneller en sterker — daarom word je van veel ziekten maar één keer echt ziek, en werkt vaccinatie.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — eiwitsynthese</div><div class="sam-worked-q">Een gen bevat de basenvolgorde (mRNA) AUG-GCC-UAA. Uit hoeveel aminozuren bestaat het eiwit?</div><ol class="sam-worked-steps"><li>Elk codon (triplet) codeert voor één aminozuur.</li><li>AUG = start (methionine), GCC = één aminozuur, UAA = stopcodon (codeert niet voor een aminozuur).</li><li>Dus: 2 aminozuren worden ingebouwd, daarna stopt de translatie.</li></ol><div class="sam-worked-ans">✅ Het eiwit(fragment) bestaat uit 2 aminozuren; het stopcodon beëindigt de synthese.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — homeostase</div><div class="sam-worked-q">Na een koolhydraatrijke maaltijd stijgt het bloedglucose. Beschrijf de negatieve terugkoppeling die volgt.</div><ol class="sam-worked-steps"><li>De alvleesklier (sensor + verwerker) meet de hoge glucosewaarde en scheidt <strong>insuline</strong> af.</li><li>Insuline (effector-signaal) zet lever- en spiercellen aan glucose op te nemen en als glycogeen op te slaan.</li><li>Het bloedglucose daalt naar het setpoint; de insulineafgifte stopt.</li></ol><div class="sam-worked-ans">✅ De afwijking wordt gemeten en tegengewerkt — klassieke negatieve terugkoppeling (B4).</div></div></div>`,
'vwo_bi_E':`<div class="sam-intro"><strong>Reproductie</strong> is het vermogen van biologische eenheden om zichzelf te vermenigvuldigen — van het kopiëren van <strong>DNA</strong> en de <strong>cel</strong> tot de voortplanting van het hele <strong>organisme</strong>. Belangrijk: reproductie is géén exact kopiëren. Door <strong>mutatie</strong> en <strong>recombinatie</strong> ontstaat <strong>variatie</strong>, de grondstof voor evolutie (domein F).</div><div class="sam-head">Wat je voor het examen moet kennen (syllabus)</div><p>Domein E bestaat uit drie subdomeinen. Deze samenvatting dekt ze alle drie:</p><table class="sam-table"><thead><tr><th>Sub</th><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>E1</td><td>DNA-replicatie</td><td>semiconservatief verdubbelen van DNA</td></tr><tr><td>E2</td><td>Levenscyclus van de cel</td><td>celcyclus, mitose én meiose</td></tr><tr><td>E3</td><td>Reproductie van het organisme</td><td>voortplanting en erfelijkheid</td></tr></tbody></table><div class="sam-head">E1 · DNA-replicatie</div><p>Vóór een cel deelt, moet al het DNA worden verdubbeld, zodat beide dochtercellen een complete kopie krijgen. Dat gebeurt <strong>semiconservatief</strong>: de dubbele helix gaat open en elke oude streng dient als <strong>mal (template)</strong> voor een nieuwe streng. Elke nieuwe DNA-molecuul bestaat dus uit één oude en één nieuwe streng.</p><div class="sam-figure"><svg viewBox="0 0 300 140" role="img" aria-label="Semiconservatieve replicatie: de dubbele helix splitst en elke oude streng krijgt een nieuwe complementaire streng"><defs><marker id="giE1" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--mu)"/></marker></defs><line x1="40" y1="16" x2="40" y2="124" stroke="var(--dk)" stroke-width="2"/><line x1="52" y1="16" x2="52" y2="124" stroke="var(--dk)" stroke-width="2"/><text x="46" y="136" font-size="7.5" fill="var(--mu)" text-anchor="middle">origineel</text><path d="M60,70 C90,64 96,40 96,20" fill="none" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#giE1)"/><path d="M60,70 C90,76 96,100 96,120" fill="none" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#giE1)"/><g><line x1="150" y1="16" x2="150" y2="124" stroke="var(--dk)" stroke-width="2"/><line x1="162" y1="16" x2="162" y2="124" stroke="var(--or)" stroke-width="2"/></g><g><line x1="220" y1="16" x2="220" y2="124" stroke="var(--or)" stroke-width="2"/><line x1="232" y1="16" x2="232" y2="124" stroke="var(--dk)" stroke-width="2"/></g><text x="226" y="136" font-size="7.5" fill="var(--mu)" text-anchor="middle">2 kopieën</text><rect x="270" y="18" width="10" height="20" fill="var(--dk)"/><text x="288" y="32" font-size="7.5" fill="var(--mu)">oud</text><rect x="270" y="44" width="10" height="20" fill="var(--or)"/><text x="288" y="58" font-size="7.5" fill="var(--mu)">nieuw</text></svg><div class="sam-figcap"><strong>Semiconservatief:</strong> het enzym <strong>DNA-polymerase</strong> plaatst tegenover elke base de complementaire base (A–T, C–G). Beide kopieën bevatten één oude (zwarte) en één nieuwe (oranje) streng.</div></div><div class="sam-warn"><strong>Let op:</strong> replicatie (DNA verdubbelen) is iets anders dan transcriptie (mRNA maken van een gen, domein B1). Replicatie kopieert álle DNA vóór een celdeling; transcriptie leest één gen af om een eiwit te maken.</div><div class="sam-head">E2 · Levenscyclus van de cel</div><p>Een cel doorloopt de <strong>celcyclus</strong>: een lange <strong>interfase</strong> (groeien en DNA verdubbelen) gevolgd door de <strong>celdeling</strong>. Er zijn twee soorten kerndeling met een heel verschillend doel:</p><div class="sam-compare"><div class="sam-compare-col"><div class="sam-compare-head">Mitose (gewone deling)</div><ul><li>voor groei en herstel</li><li>1 cel → <strong>2</strong> dochtercellen</li><li>dochtercellen <strong>identiek</strong> aan elkaar</li><li>diploïd (2n) → diploïd (2n)</li></ul></div><div class="sam-compare-col"><div class="sam-compare-head">Meiose (reductiedeling)</div><ul><li>voor geslachtscellen (gameten)</li><li>1 cel → <strong>4</strong> dochtercellen</li><li>dochtercellen <strong>verschillend</strong></li><li>diploïd (2n) → haploïd (n)</li></ul></div></div><div class="sam-figure"><svg viewBox="0 0 320 132" role="img" aria-label="Meiose: een diploïde cel deelt in twee stappen tot vier haploïde geslachtscellen"><defs><marker id="giE2" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--or)"/></marker></defs><circle cx="34" cy="66" r="20" fill="var(--or)" opacity=".18" stroke="var(--or)" stroke-width="1.3"/><text x="34" y="69" font-size="9" font-weight="700" fill="var(--dk)" text-anchor="middle">2n</text><circle cx="150" cy="36" r="15" fill="var(--or)" opacity=".14" stroke="var(--or)" stroke-width="1.1"/><text x="150" y="40" font-size="8" font-weight="700" fill="var(--dk)" text-anchor="middle">n</text><circle cx="150" cy="96" r="15" fill="var(--or)" opacity=".14" stroke="var(--or)" stroke-width="1.1"/><text x="150" y="100" font-size="8" font-weight="700" fill="var(--dk)" text-anchor="middle">n</text><g fill="var(--or)" opacity=".12" stroke="var(--or)" stroke-width="1"><circle cx="270" cy="20" r="13"/><circle cx="270" cy="52" r="13"/><circle cx="270" cy="80" r="13"/><circle cx="270" cy="112" r="13"/></g><g font-size="7.5" font-weight="700" fill="var(--dk)" text-anchor="middle"><text x="270" y="23">n</text><text x="270" y="55">n</text><text x="270" y="83">n</text><text x="270" y="115">n</text></g><path d="M54,58 C90,44 110,40 134,38" fill="none" stroke="var(--or)" stroke-width="1.5" marker-end="url(#giE2)"/><path d="M54,74 C90,88 110,92 134,94" fill="none" stroke="var(--or)" stroke-width="1.5" marker-end="url(#giE2)"/><path d="M165,32 C200,24 230,20 255,20" fill="none" stroke="var(--or)" stroke-width="1.4" marker-end="url(#giE2)"/><path d="M165,40 C200,46 230,50 255,50" fill="none" stroke="var(--or)" stroke-width="1.4" marker-end="url(#giE2)"/><path d="M165,92 C200,86 230,82 255,80" fill="none" stroke="var(--or)" stroke-width="1.4" marker-end="url(#giE2)"/><path d="M165,100 C200,106 230,110 255,110" fill="none" stroke="var(--or)" stroke-width="1.4" marker-end="url(#giE2)"/><text x="100" y="20" font-size="7.5" fill="var(--or)" text-anchor="middle">meiose I</text><text x="215" y="128" font-size="7.5" fill="var(--or)" text-anchor="middle">meiose II</text></svg><div class="sam-figcap"><strong>Meiose:</strong> in twee delingen ontstaan uit één diploïde cel (2n) vier haploïde geslachtscellen (n). Door <strong>crossing-over</strong> en de toevallige verdeling van chromosomen is elke gameet uniek.</div></div><div class="sam-tip">Variatie in gameten ontstaat op twee manieren tijdens de meiose: <strong>crossing-over</strong> (chromosomen wisselen stukken uit) en de <strong>onafhankelijke verdeling</strong> van de chromosomenparen. Bij de bevruchting komt daar de toevallige combinatie van twee gameten nog bovenop.</div><div class="sam-head">E3 · Reproductie van het organisme</div><p>Organismen planten zich <strong>ongeslachtelijk</strong> voort (één ouder, identieke nakomelingen — klonen) of <strong>geslachtelijk</strong> (twee ouders, gameten versmelten bij de <strong>bevruchting</strong> tot een diploïde zygote — variatie). Hoe eigenschappen overerven, beschrijf je met de genetica:</p><table class="sam-table"><thead><tr><th>Begrip</th><th>Betekenis</th></tr></thead><tbody><tr><td>Genotype / fenotype</td><td>de genen die je hebt / hoe je eruitziet (genen + milieu)</td></tr><tr><td>Allel</td><td>een variant van een gen (bv. A of a)</td></tr><tr><td>Dominant / recessief</td><td>komt altijd tot uiting / alleen bij twee dezelfde allelen</td></tr><tr><td>Homozygoot / heterozygoot</td><td>twee gelijke allelen (AA, aa) / twee verschillende (Aa)</td></tr></tbody></table><p>Met een <strong>kruisingsschema</strong> voorspel je de verhoudingen bij de nakomelingen. Een kruising van twee dragers (Aa × Aa):</p><div class="sam-figure"><svg viewBox="0 0 220 150" role="img" aria-label="Kruisingsschema Aa maal Aa geeft één AA, twee Aa en één aa"><g stroke="var(--bo)" stroke-width="1.2" fill="none"><rect x="60" y="40" width="70" height="45"/><rect x="130" y="40" width="70" height="45"/><rect x="60" y="85" width="70" height="45"/><rect x="130" y="85" width="70" height="45"/></g><g font-size="13" font-weight="700" fill="var(--mu)" text-anchor="middle"><text x="95" y="30">A</text><text x="165" y="30">a</text></g><g font-size="13" font-weight="700" fill="var(--mu)" text-anchor="middle"><text x="45" y="67">A</text><text x="45" y="112">a</text></g><g font-size="14" font-weight="700" text-anchor="middle"><text x="95" y="68" fill="var(--or)">AA</text><text x="165" y="68" fill="var(--dk)">Aa</text><text x="95" y="113" fill="var(--dk)">Aa</text><text x="165" y="113" fill="var(--mu)">aa</text></g></svg><div class="sam-figcap"><strong>Kruisingsschema (Punnett):</strong> Aa × Aa geeft een genotype-verhouding <strong>1 AA : 2 Aa : 1 aa</strong>. Is A dominant, dan is de fenotype-verhouding <strong>3 dominant : 1 recessief</strong>.</div></div><ul><li><strong>Autosomaal</strong>: het gen ligt op een gewoon chromosoom (niet het geslachtschromosoom).</li><li><strong>X-chromosomaal</strong>: het gen ligt op het X-chromosoom; mannen (XY) hebben er maar één van, dus een recessieve eigenschap komt bij hen vaker tot uiting (bv. kleurenblindheid).</li></ul><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — mitose of meiose?</div><div class="sam-worked-q">Een menselijke huidcel bevat 46 chromosomen. Hoeveel chromosomen hebben de cellen die ontstaan na (a) mitose en (b) meiose?</div><ol class="sam-worked-steps"><li>Mitose houdt het aantal gelijk: elke dochtercel is diploïd (2n).</li><li>Meiose halveert het aantal (reductiedeling): elke gameet is haploïd (n).</li><li>2n = 46, dus n = 23.</li></ol><div class="sam-worked-ans">✅ (a) na mitose: 46 chromosomen; (b) na meiose: 23 chromosomen.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — kruising</div><div class="sam-worked-q">Bruine ogen (B) zijn dominant over blauwe (b). Twee bruinogige ouders krijgen een blauwogig kind. Wat zijn de genotypen van de ouders?</div><ol class="sam-worked-steps"><li>Het kind is blauwogig → genotype bb, dus het kreeg van elke ouder een b-allel.</li><li>Beide ouders zijn bruinogig maar dragen een b: ze zijn dus heterozygoot (Bb).</li><li>Controle: Bb × Bb geeft kans op bb (blauw) = 1/4. Dat klopt.</li></ol><div class="sam-worked-ans">✅ Beide ouders zijn <strong>Bb</strong> (heterozygoot, drager van blauw).</div></div>`,
'vwo_bi_F':`<div class="sam-intro"><strong>Evolutie</strong> verklaart hoe soorten in de loop van vele generaties veranderen en hoe nieuwe soorten ontstaan. De motor is <strong>natuurlijke selectie</strong> die inwerkt op de <strong>variatie</strong> binnen een populatie — variatie die voortkomt uit mutatie en recombinatie (domein E).</div><div class="sam-head">Wat je voor het examen moet kennen (syllabus)</div><p>Domein F bestaat uit twee subdomeinen. Deze samenvatting dekt ze allebei:</p><table class="sam-table"><thead><tr><th>Sub</th><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>F1</td><td>Selectie</td><td>variatie + selectiedruk → aanpassing</td></tr><tr><td>F2</td><td>Soortvorming</td><td>isolatie → nieuwe soorten; bewijs voor evolutie</td></tr></tbody></table><div class="sam-head">F1 · Selectie</div><p>Binnen een populatie verschillen individuen erfelijk van elkaar (<strong>variatie</strong>). Er worden méér nakomelingen geboren dan er kunnen overleven, dus is er <strong>concurrentie</strong> om voedsel, ruimte en partners. Individuen wier eigenschappen het best bij het milieu passen, hebben de grootste kans om te overleven en zich voort te planten — ze geven hun allelen vaker door. Zo verschuift over generaties de <strong>allelfrequentie</strong> in de populatie.</p><div class="sam-figure"><svg viewBox="0 0 320 138" role="img" aria-label="Natuurlijke selectie: uit een gevarieerde populatie overleven de best aangepaste vormen, die de volgende generatie gaan overheersen"><defs><marker id="giF1" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--or)"/></marker></defs><text x="52" y="16" font-size="8" font-weight="700" fill="var(--dk)" text-anchor="middle">variatie</text><g><circle cx="30" cy="40" r="7" fill="var(--dk)"/><circle cx="52" cy="34" r="7" fill="var(--mu)" opacity=".5"/><circle cx="74" cy="42" r="7" fill="var(--dk)"/><circle cx="40" cy="60" r="7" fill="var(--mu)" opacity=".5"/><circle cx="64" cy="62" r="7" fill="var(--dk)"/><circle cx="30" cy="80" r="7" fill="var(--mu)" opacity=".5"/><circle cx="60" cy="84" r="7" fill="var(--dk)"/></g><text x="160" y="16" font-size="8" font-weight="700" fill="var(--dk)" text-anchor="middle">selectiedruk</text><text x="160" y="66" font-size="7.5" fill="var(--or)" text-anchor="middle">lichte vorm valt op</text><text x="160" y="79" font-size="7.5" fill="var(--or)" text-anchor="middle">→ opgegeten</text><line x1="90" y1="60" x2="230" y2="60" stroke="var(--or)" stroke-width="1.6" marker-end="url(#giF1)"/><text x="286" y="16" font-size="8" font-weight="700" fill="var(--dk)" text-anchor="middle">volgende generatie</text><g><circle cx="264" cy="42" r="7" fill="var(--dk)"/><circle cx="286" cy="38" r="7" fill="var(--dk)"/><circle cx="308" cy="44" r="7" fill="var(--dk)"/><circle cx="274" cy="62" r="7" fill="var(--dk)"/><circle cx="298" cy="64" r="7" fill="var(--dk)"/><circle cx="286" cy="82" r="7" fill="var(--mu)" opacity=".5"/></g></svg><div class="sam-figcap"><strong>Natuurlijke selectie:</strong> in een donkere omgeving worden lichte vormen vaker gezien en opgegeten. De donkere vorm plant zich vaker voort, zodat die in de volgende generatie overheerst (bekend voorbeeld: de <strong>berkenspanner</strong>).</div></div><ul><li><strong>Selectiedruk</strong>: de mate waarin het milieu bepaalde eigenschappen bevoordeelt of benadeelt.</li><li><strong>Adaptatie</strong>: een erfelijke aanpassing die de overlevings- of voortplantingskans vergroot.</li><li><strong>Fitness</strong>: de mate waarin een individu bijdraagt aan de volgende generatie (aantal nakomelingen dat zelf overleeft).</li></ul><div class="sam-warn"><strong>Veelgemaakte fout:</strong> een organisme past zich niet <em>doelgericht</em> aan. Mutaties ontstaan <strong>toevallig</strong>; het milieu <strong>selecteert</strong> achteraf welke toevallige varianten het best werken. Zeg dus nooit "de spanner werd donker omdat hij dat nodig had".</div><div class="sam-tip">Voorwaarden voor natuurlijke selectie: (1) er is erfelijke variatie, (2) er worden meer nakomelingen geboren dan overleven, (3) de variatie beïnvloedt de overlevings-/voortplantingskans. Voldoe je aan alle drie, dan treedt selectie op.</div><div class="sam-head">F2 · Soortvorming</div><p>Een <strong>soort</strong> is een groep organismen die zich onderling kan voortplanten en daarbij <strong>vruchtbare</strong> nakomelingen krijgt. Nieuwe soorten ontstaan wanneer delen van een populatie <strong>geïsoleerd</strong> raken en geen genen meer uitwisselen.</p><div class="sam-figure"><svg viewBox="0 0 320 140" role="img" aria-label="Soortvorming: een populatie wordt door een barrière gescheiden, de delen evolueren apart en worden twee soorten"><defs><marker id="giF2" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--mu)"/></marker></defs><ellipse cx="42" cy="70" rx="30" ry="24" fill="var(--or)" opacity=".2" stroke="var(--or)" stroke-width="1.2"/><text x="42" y="73" font-size="8" font-weight="700" fill="var(--dk)" text-anchor="middle">1 soort</text><line x1="128" y1="34" x2="128" y2="106" stroke="var(--mu)" stroke-width="2" stroke-dasharray="4 3"/><text x="128" y="122" font-size="7.5" fill="var(--mu)" text-anchor="middle">barrière</text><path d="M72,60 C95,50 108,46 118,44" fill="none" stroke="var(--mu)" stroke-width="1.3" marker-end="url(#giF2)"/><path d="M72,80 C95,90 108,94 118,96" fill="none" stroke="var(--mu)" stroke-width="1.3" marker-end="url(#giF2)"/><ellipse cx="210" cy="42" rx="26" ry="18" fill="var(--mu)" opacity=".18" stroke="var(--mu)" stroke-width="1.1"/><ellipse cx="210" cy="100" rx="26" ry="18" fill="var(--mu)" opacity=".18" stroke="var(--mu)" stroke-width="1.1"/><text x="210" y="45" font-size="7.5" fill="var(--dk)" text-anchor="middle">evolueert apart</text><text x="210" y="103" font-size="7.5" fill="var(--dk)" text-anchor="middle">evolueert apart</text><line x1="238" y1="42" x2="268" y2="42" stroke="var(--mu)" stroke-width="1.3" marker-end="url(#giF2)"/><line x1="238" y1="100" x2="268" y2="100" stroke="var(--mu)" stroke-width="1.3" marker-end="url(#giF2)"/><ellipse cx="292" cy="42" rx="24" ry="17" fill="var(--or)" opacity=".22" stroke="var(--or)" stroke-width="1.2"/><ellipse cx="292" cy="100" rx="24" ry="17" fill="var(--or)" opacity=".22" stroke="var(--or)" stroke-width="1.2"/><text x="292" y="45" font-size="7.5" font-weight="700" fill="var(--dk)" text-anchor="middle">soort A</text><text x="292" y="103" font-size="7.5" font-weight="700" fill="var(--dk)" text-anchor="middle">soort B</text></svg><div class="sam-figcap"><strong>Soortvorming:</strong> een <strong>geografische barrière</strong> (rivier, gebergte) scheidt de populatie. Door verschillende selectiedruk en toeval evolueren de delen apart. Kunnen ze zich later niet meer onderling voortplanten, dan zijn het aparte soorten.</div></div><p><strong>Adaptieve radiatie</strong>: vanuit één soort ontstaan in korte tijd veel nieuwe soorten die elk een eigen leefwijze hebben (klassiek voorbeeld: de <strong>Darwinvinken</strong> met elk een eigen snavelvorm).</p><table class="sam-table"><thead><tr><th>Bewijs voor evolutie</th><th>Wat het laat zien</th></tr></thead><tbody><tr><td>Fossielen</td><td>overgangsvormen en verandering door de tijd</td></tr><tr><td>Homologie</td><td>zelfde bouwplan (bv. voorpoot zoogdieren) → gemeenschappelijke voorouder</td></tr><tr><td>DNA-vergelijking</td><td>hoe meer DNA-overeenkomst, hoe nauwer verwant</td></tr><tr><td>Embryologie</td><td>vroege embryo's van gewervelden lijken sterk op elkaar</td></tr></tbody></table><div class="sam-tip">In een <strong>evolutionaire stamboom</strong> (fylogenie) staat elk splitsingspunt voor een gemeenschappelijke voorouder. Soorten die pas laat splitsen, zijn nauwer verwant — dat zie je ook terug in hun DNA-overeenkomst.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — antibioticaresistentie</div><div class="sam-worked-q">In een bacteriepopulatie overleven na een antibioticakuur alleen resistente bacteriën. Verklaar dit met natuurlijke selectie — en waarom is "de bacteriën werden resistent door het antibioticum" fout?</div><ol class="sam-worked-steps"><li>Door toevallige mutaties was er al vóór de kuur variatie: enkele bacteriën waren resistent.</li><li>Het antibioticum vormt de selectiedruk: gevoelige bacteriën sterven, resistente overleven.</li><li>De overlevers planten zich voort; hun resistentie-allel overheerst nu de populatie.</li></ol><div class="sam-worked-ans">✅ Het antibioticum <strong>selecteert</strong> bestaande resistente varianten; het <strong>veroorzaakt</strong> de resistentie niet. De mutatie was er al, toevallig.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — één soort of twee?</div><div class="sam-worked-q">Twee gescheiden vogelpopulaties worden herenigd. Ze paren wel, maar de eieren komen niet uit. Zijn het één of twee soorten? Leg uit.</div><ol class="sam-worked-steps"><li>Het biologische soortbegrip vraagt om <strong>vruchtbare</strong> nakomelingen.</li><li>Er komen geen (levensvatbare) nakomelingen: er is reproductieve isolatie.</li><li>Dus de genenuitwisseling is definitief verbroken.</li></ol><div class="sam-worked-ans">✅ Het zijn <strong>twee soorten</strong>: de soortvorming is voltooid doordat ze samen geen vruchtbare nakomelingen krijgen.</div></div>`,
'vwo_sk_B':`<div class="sam-intro">De <strong>bindingssoort</strong> bepaalt de eigenschappen van een stof. Je onderscheidt <strong>ion-</strong>, <strong>atoom-</strong> (covalente) en <strong>metaalbinding</strong>, voorspelt de <strong>molecuulvorm</strong> met VSEPR en verklaart smelt- en kookpunten uit de <strong>intermoleculaire krachten</strong>.</div><div class="sam-head">Ionbinding en covalente binding</div><p>Bij een <strong>ionbinding</strong> worden elektronen overgedragen (metaal + niet-metaal) en trekken tegengestelde ionen elkaar aan in een <strong>ionrooster</strong>. Bij een <strong>covalente binding</strong> delen niet-metalen elektronenparen.</p><table class="sam-table"><thead><tr><th>Binding</th><th>Deeltjes</th><th>Kenmerk</th></tr></thead><tbody><tr><td>Ionbinding</td><td>metaal + niet-metaal</td><td>hoog smeltpunt, geleidt opgelost</td></tr><tr><td>Covalent (molecuul)</td><td>niet-metalen</td><td>lager smeltpunt, geleidt niet</td></tr><tr><td>Metaalbinding</td><td>metaalatomen + vrije e⁻</td><td>geleidt, buigzaam, glanzend</td></tr></tbody></table><div class="sam-head">Molecuulvorm (VSEPR) en polariteit</div><p>Het <strong>VSEPR-model</strong> zegt dat elektronenparen elkaar zoveel mogelijk afstoten; daaruit volgt de <strong>molecuulgeometrie</strong>. Staat er een verschil in elektronegativiteit én is het molecuul niet-symmetrisch, dan is het <strong>polair</strong> (het heeft een dipool).</p><div class="sam-figure"><svg viewBox="0 0 300 170" role="img" aria-label="Watermolecuul met gebogen vorm, partiele ladingen en een netto dipoolvector"><defs><marker id="skCd" markerWidth="9" markerHeight="9" refX="5" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L7,3 L0,6 Z" fill="var(--or)"/></marker></defs><line x1="150" y1="60" x2="108" y2="118" stroke="var(--mu)" stroke-width="2.5"/><line x1="150" y1="60" x2="192" y2="118" stroke="var(--mu)" stroke-width="2.5"/><circle cx="150" cy="60" r="17" fill="var(--dk)"/><text x="150" y="65" font-size="13" font-weight="700" fill="#fff" text-anchor="middle">O</text><circle cx="108" cy="118" r="12" fill="var(--mu)"/><text x="108" y="122" font-size="10" font-weight="700" fill="#fff" text-anchor="middle">H</text><circle cx="192" cy="118" r="12" fill="var(--mu)"/><text x="192" y="122" font-size="10" font-weight="700" fill="#fff" text-anchor="middle">H</text><text x="175" y="48" font-size="11" font-weight="700" fill="var(--or)">δ−</text><text x="80" y="126" font-size="11" font-weight="700" fill="var(--or)">δ+</text><text x="204" y="126" font-size="11" font-weight="700" fill="var(--or)">δ+</text><line x1="150" y1="95" x2="150" y2="40" stroke="var(--or)" stroke-width="2" stroke-dasharray="4 2" marker-end="url(#skCd)"/><text x="156" y="90" font-size="9.5" fill="var(--or)">dipool</text><text x="120" y="90" font-size="9" fill="var(--mu)">104,5°</text></svg><div class="sam-figcap"><strong>Water is polair:</strong> de gebogen vorm (104,5°) zorgt dat de δ−-kant (O) en de δ+-kant (H's) niet samenvallen — er blijft een netto dipool over.</div></div><div class="sam-head">Intermoleculaire krachten</div><p>Tussen moleculen werken zwakkere krachten die het smelt- en kookpunt bepalen. Van zwak naar sterk:</p><table class="sam-table"><thead><tr><th>Kracht</th><th>Waar</th><th>Sterkte</th></tr></thead><tbody><tr><td>Vanderwaals</td><td>alle moleculen</td><td>zwak (sterker bij grotere massa)</td></tr><tr><td>Dipool-dipool</td><td>polaire moleculen</td><td>gemiddeld</td></tr><tr><td>Waterstofbrug</td><td>O–H, N–H, F–H</td><td>sterk</td></tr></tbody></table><div class="sam-tip">Water heeft door zijn <strong>waterstofbruggen</strong> een opvallend hoog kookpunt (100 °C) voor zo'n klein molecuul.</div><div class="sam-warn"><strong>Denkfout:</strong> bij smelten of koken verbreek je de <em>intermoleculaire</em> krachten, niet de sterke covalente bindingen bínnen het molecuul. Water dat kookt blijft H₂O.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave</div><div class="sam-worked-q">Waarom heeft CO₂ geen dipool, terwijl H₂O die wel heeft? Beide hebben polaire bindingen.</div><ol class="sam-worked-steps"><li>CO₂ is lineair (O=C=O): de twee bindingsdipolen wijzen precies tegengesteld.</li><li>Ze heffen elkaar op → netto dipool nul → apolair.</li><li>H₂O is gebogen: de dipolen heffen elkaar niet op → netto dipool.</li></ol><div class="sam-worked-ans">✅ De molecuulvorm bepaalt of de bindingsdipolen elkaar opheffen. CO₂ is apolair, H₂O polair.</div></div></div><div class="sam-intro">De <strong>organische chemie</strong> gaat over koolstofverbindingen. Je herkent stofklassen aan hun <strong>functionele groep</strong>, voorspelt reacties (<strong>substitutie</strong>, <strong>additie</strong>, <strong>condensatie</strong>) en begrijpt hoe kleine bouwstenen tot <strong>polymeren</strong> aaneenrijgen.</div><div class="sam-head">Koolwaterstoffen: alkanen, alkenen, alkynen</div><p>Koolwaterstoffen bevatten alleen C en H. Het aantal bindingen tussen de koolstofatomen bepaalt de klasse en de reactiviteit.</p><table class="sam-table"><thead><tr><th>Klasse</th><th>Binding</th><th>Uitgang</th></tr></thead><tbody><tr><td>Alkaan</td><td>enkele C–C (verzadigd)</td><td>-aan</td></tr><tr><td>Alkeen</td><td>dubbele C=C (onverzadigd)</td><td>-een</td></tr><tr><td>Alkyn</td><td>drievoudige C≡C</td><td>-yn</td></tr></tbody></table><div class="sam-head">Functionele groepen</div><p>De <strong>functionele groep</strong> bepaalt de eigenschappen en de naam. Deze moet je herkennen:</p><table class="sam-table"><thead><tr><th>Groep</th><th>Kenmerk</th><th>Voorbeeld</th></tr></thead><tbody><tr><td>Alcohol</td><td>–OH</td><td>ethanol</td></tr><tr><td>Carbonzuur</td><td>–COOH</td><td>azijnzuur</td></tr><tr><td>Ester</td><td>–COO–</td><td>geur/aroma's</td></tr><tr><td>Amine</td><td>–NH₂</td><td>aminozuren</td></tr></tbody></table><div class="sam-head">Substitutie en additie</div><p>Een <strong>verzadigd</strong> molecuul (alkaan) reageert via <strong>substitutie</strong>: een atoom wordt vervangen. Een <strong>onverzadigd</strong> molecuul (alkeen) reageert via <strong>additie</strong>: de dubbele band gaat open en er komen atomen bij.</p><div class="sam-figure"><svg viewBox="0 0 300 150" role="img" aria-label="Additiereactie waarbij een dubbele koolstofbinding opengaat en twee broomatomen worden toegevoegd"><text x="20" y="60" font-size="13" font-weight="700" fill="var(--dk)">C</text><text x="70" y="60" font-size="13" font-weight="700" fill="var(--dk)">C</text><line x1="34" y1="52" x2="64" y2="52" stroke="var(--or)" stroke-width="2"/><line x1="34" y1="58" x2="64" y2="58" stroke="var(--or)" stroke-width="2"/><text x="24" y="90" font-size="9" fill="var(--mu)">alkeen (C=C)</text><text x="105" y="58" font-size="11" fill="var(--mu)">+ Br₂</text><defs><marker id="skBa" markerWidth="9" markerHeight="9" refX="5" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L7,3 L0,6 Z" fill="var(--mu)"/></marker></defs><line x1="150" y1="53" x2="185" y2="53" stroke="var(--mu)" stroke-width="1.5" marker-end="url(#skBa)"/><text x="210" y="60" font-size="13" font-weight="700" fill="var(--dk)">C</text><text x="260" y="60" font-size="13" font-weight="700" fill="var(--dk)">C</text><line x1="224" y1="55" x2="254" y2="55" stroke="var(--dk)" stroke-width="2"/><line x1="216" y1="46" x2="216" y2="28" stroke="var(--dk)" stroke-width="1.5"/><text x="211" y="24" font-size="10" font-weight="700" fill="var(--or)">Br</text><line x1="266" y1="46" x2="266" y2="28" stroke="var(--dk)" stroke-width="1.5"/><text x="261" y="24" font-size="10" font-weight="700" fill="var(--or)">Br</text><text x="214" y="90" font-size="9" fill="var(--mu)">verzadigd product</text></svg><div class="sam-figcap"><strong>Additie:</strong> de dubbele binding gaat open en de twee broomatomen hechten aan de koolstofatomen. Het onverzadigde alkeen wordt een verzadigd product.</div></div><div class="sam-tip">Toets voor onverzadigdheid: broomwater (bruin) <strong>ontkleurt</strong> bij een alkeen (additie), maar niet bij een alkaan.</div><div class="sam-head">Polymerisatie</div><p>Kleine moleculen (<strong>monomeren</strong>) rijgen aaneen tot een <strong>polymeer</strong>. Twee typen:</p><div class="sam-compare"><div class="sam-compare-col"><div class="sam-compare-head">Additiepolymerisatie</div><ul><li>alkenen koppelen via de dubbele band</li><li>geen bijproduct</li><li>bijv. polytheen (PE), PVC</li></ul></div><div class="sam-compare-col"><div class="sam-compare-head">Condensatiepolymerisatie</div><ul><li>groepen reageren (–OH + –COOH)</li><li>klein bijproduct (vaak H₂O)</li><li>bijv. polyester, nylon</li></ul></div></div><div class="sam-head">Isomerie en benzeen</div><p><strong>Isomeren</strong> hebben dezelfde molecuulformule maar een andere structuur (en dus andere eigenschappen). <strong>Benzeen</strong> (C₆H₆) is een ringvormige aromatische verbinding met bijzonder stabiele, gedelokaliseerde elektronen.</p><div class="sam-warn"><strong>Let op:</strong> benzeen reageert ondanks zijn 'dubbele banden' niet via additie maar via <strong>substitutie</strong> — de aromatische ring is te stabiel om open te breken.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave</div><div class="sam-worked-q">Etheen (C₂H₄) reageert met water tot ethanol. Welk reactietype is dit en waarom?</div><ol class="sam-worked-steps"><li>Etheen is onverzadigd (C=C).</li><li>Het watermolecuul (H en OH) wordt aan de dubbele band toegevoegd; de band gaat open.</li><li>Er komt geen atoom vrij — het is dus geen substitutie.</li></ol><div class="sam-worked-ans">✅ Een additiereactie: C₂H₄ + H₂O → C₂H₅OH.</div></div></div>`,
'vwo_sk_C':`<div class="sam-intro">Bij een <strong>omkeerbare reactie</strong> lopen de heen- en teruggaande reactie tegelijk. Zijn hun snelheden gelijk, dan is er een <strong>dynamisch evenwicht</strong>: de concentraties blijven constant, maar de reacties gaan door. De <strong>evenwichtsconstante K</strong> en het <strong>principe van Le Chatelier</strong> vertellen je waar dat evenwicht ligt en hoe het verschuift.</div><div class="sam-head">Dynamisch evenwicht</div><p>In een gesloten systeem daalt de concentratie van de <strong>reactanten</strong> en stijgt die van de <strong>producten</strong>, tot beide snelheden gelijk zijn. Vanaf dat moment veranderen de concentraties niet meer, ook al blijven de reacties in beide richtingen doorgaan.</p><div class="sam-figure"><svg viewBox="0 0 360 172" role="img" aria-label="Concentratie-tijddiagram waarin reactanten dalen en producten stijgen tot een evenwicht"><defs><marker id="skT" markerWidth="9" markerHeight="9" refX="5" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L7,3 L0,6 Z" fill="var(--mu)"/></marker></defs><line x1="44" y1="150" x2="350" y2="150" stroke="var(--mu)" stroke-width="1.5" marker-end="url(#skT)"/><line x1="44" y1="150" x2="44" y2="24" stroke="var(--mu)" stroke-width="1.5" marker-end="url(#skT)"/><path d="M44.0,42.0 L47.7,46.0 L51.4,49.8 L55.1,53.3 L58.8,56.6 L62.5,59.7 L66.2,62.6 L69.9,65.4 L73.6,68.0 L77.3,70.4 L81.0,72.7 L84.7,74.8 L88.4,76.8 L92.1,78.7 L95.8,80.5 L99.5,82.2 L103.2,83.7 L106.9,85.2 L110.6,86.6 L114.3,87.9 L118.0,89.1 L121.7,90.2 L125.4,91.3 L129.1,92.3 L132.8,93.3 L136.5,94.2 L140.2,95.0 L143.9,95.8 L147.6,96.5 L151.3,97.2 L155.0,97.9 L158.7,98.5 L162.4,99.1 L166.1,99.6 L169.8,100.1 L173.5,100.6 L177.2,101.0 L180.9,101.5 L184.6,101.9 L188.3,102.2 L192.0,102.6 L195.7,102.9 L199.4,103.2 L203.1,103.5 L206.8,103.8 L210.5,104.0 L221.6,104.7 L240.1,105.6 L262.3,106.3 L291.9,107.0 L340.0,107.6" fill="none" stroke="var(--or)" stroke-width="2.4" stroke-linecap="round" stroke-linejoin="round"/><path d="M44.0,150.0 L47.7,145.3 L51.4,140.8 L55.1,136.7 L58.8,132.7 L62.5,129.1 L66.2,125.6 L69.9,122.4 L73.6,119.3 L77.3,116.4 L81.0,113.8 L84.7,111.2 L88.4,108.8 L92.1,106.6 L95.8,104.5 L99.5,102.5 L103.2,100.7 L106.9,99.0 L110.6,97.3 L114.3,95.8 L118.0,94.3 L121.7,93.0 L125.4,91.7 L129.1,90.5 L132.8,89.4 L136.5,88.3 L140.2,87.4 L143.9,86.4 L147.6,85.6 L151.3,84.7 L155.0,84.0 L158.7,83.2 L162.4,82.6 L166.1,81.9 L169.8,81.3 L173.5,80.8 L177.2,80.2 L180.9,79.7 L184.6,79.3 L188.3,78.8 L199.4,77.7 L214.2,76.4 L232.7,75.2 L258.6,74.1 L291.9,73.2 L340.0,72.5" fill="none" stroke="var(--dk)" stroke-width="2.4" stroke-linecap="round" stroke-linejoin="round"/><line x1="210" y1="24" x2="210" y2="150" stroke="var(--mu)" stroke-width="1" stroke-dasharray="3 3"/><text x="216" y="36" font-size="9.5" font-weight="700" fill="var(--mu)">evenwicht</text><text x="300" y="103" font-size="10" font-weight="700" fill="var(--or)">reactant</text><text x="300" y="69" font-size="10" font-weight="700" fill="var(--dk)">product</text><text x="30" y="30" font-size="9.5" fill="var(--mu)">[ ]</text><text x="344" y="164" font-size="9.5" fill="var(--mu)">t</text></svg><div class="sam-figcap"><strong>Instellen van het evenwicht:</strong> de concentraties veranderen eerst snel en daarna steeds trager, tot ze na de stippellijn constant blijven. Het evenwicht is <strong>dynamisch</strong>, niet stilstaand.</div></div><table class="sam-table"><thead><tr><th>Begrip</th><th>Betekenis</th></tr></thead><tbody><tr><td>Omkeerbare reactie</td><td>verloopt zowel heen (→) als terug (←), genoteerd met ⇌</td></tr><tr><td>Dynamisch evenwicht</td><td>heen- en teruggaande reactiesnelheid zijn gelijk</td></tr><tr><td>Ligging van het evenwicht</td><td>welke kant (reactanten/producten) overheerst</td></tr><tr><td>Aflopende reactie</td><td>gaat vrijwel volledig naar rechts (zeer grote K)</td></tr></tbody></table><div class="sam-head">Evenwichtsconstante K</div><p>Voor een evenwicht <em>a</em>A + <em>b</em>B ⇌ <em>c</em>C + <em>d</em>D geldt een vaste verhouding tussen de concentraties, mits de temperatuur constant blijft.</p><div class="sam-formula-box"><div class="sam-formula-label">Evenwichtsvoorwaarde</div><div class="sam-formula-eq">K = ([C]<sup>c</sup> · [D]<sup>d</sup>) / ([A]<sup>a</sup> · [B]<sup>b</sup>)</div><div class="sam-formula-note">De concentraties zijn die in de evenwichtstoestand (mol/L). Zuivere vaste stoffen en zuiver water reken je niet mee. K hangt alleen af van de temperatuur.</div></div><ul><li><strong>K ≫ 1</strong>: het evenwicht ligt rechts, veel product (bijna aflopend).</li><li><strong>K ≪ 1</strong>: het evenwicht ligt links, weinig product.</li><li>Een <strong>katalysator</strong> verandert K niet: het evenwicht wordt alleen sneller bereikt.</li></ul><div class="sam-head">Principe van Le Chatelier</div><p>Verstoor je een evenwicht, dan verschuift het zó dat het de verstoring <strong>tegenwerkt</strong>. Drie soorten verstoring:</p><div class="sam-compare"><div class="sam-compare-col"><div class="sam-compare-head">Verschuift naar rechts als…</div><ul><li>je een reactant toevoegt</li><li>je een product afvoert</li><li>de druk stijgt en rechts staan minder mol gas</li></ul></div><div class="sam-compare-col"><div class="sam-compare-head">Verschuift naar links als…</div><ul><li>je een product toevoegt</li><li>je een reactant afvoert</li><li>de druk stijgt en links staan minder mol gas</li></ul></div></div><div class="sam-warn"><strong>Temperatuur is anders:</strong> alleen temperatuur verandert de waarde van <strong>K</strong>. Bij een <strong>exotherme</strong> reactie (warmte is een 'product') verschuift het evenwicht bij verwarming naar links en daalt K. Bij een <strong>endotherme</strong> reactie stijgt K bij verwarming.</div><div class="sam-head">Zuur-base-evenwichten en pH</div><p>Zuren en basen stellen zich in water in op een evenwicht. Sterke zuren reageren vrijwel volledig; zwakke zuren maar gedeeltelijk.</p><div class="sam-formula-box"><div class="sam-formula-label">pH en de waterconstante</div><div class="sam-formula-eq">pH = −log[H₃O⁺]  ·  pH + pOH = 14</div><div class="sam-formula-note">Bij 25 °C geldt K<sub>w</sub> = [H₃O⁺]·[OH⁻] = 1,0·10⁻¹⁴. Een lagere pH betekent een hogere [H₃O⁺] en dus een zuurdere oplossing.</div></div><div class="sam-formula-box"><div class="sam-formula-label">Zuurconstante van een zwak zuur</div><div class="sam-formula-eq">K<sub>z</sub> = ([H₃O⁺] · [A⁻]) / [HA]</div><div class="sam-formula-note">Hoe groter K<sub>z</sub>, hoe sterker het zuur. Voor een zwak zuur met beginconcentratie c geldt bij benadering [H₃O⁺] = √(K<sub>z</sub> · c).</div></div><div class="sam-head">Buffers</div><p>Een <strong>buffer</strong> bevat een zwak zuur én zijn geconjugeerde base in vergelijkbare hoeveelheden. Toegevoegd H₃O⁺ wordt weggevangen door de base, toegevoegd OH⁻ door het zuur, zodat de pH nauwelijks verandert.</p><div class="sam-tip">Een buffer werkt het best als [zuur] ≈ [base]; de pH ligt dan dicht bij de pK<sub>z</sub> van het zwakke zuur.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave</div><div class="sam-worked-q">Bereken de pH van een oplossing met 0,10 mol/L azijnzuur (K<sub>z</sub> = 1,8·10⁻⁵).</div><ol class="sam-worked-steps"><li>Azijnzuur is een zwak zuur, gebruik [H₃O⁺] = √(K<sub>z</sub> · c).</li><li>[H₃O⁺] = √(1,8·10⁻⁵ × 0,10) = √(1,8·10⁻⁶) = 1,34·10⁻³ mol/L.</li><li>pH = −log(1,34·10⁻³) = 2,87.</li></ol><div class="sam-worked-ans">✅ pH ≈ 2,9 — duidelijk zuur, maar minder dan bij een even sterk sterk zuur (dat pH 1,0 zou geven).</div></div></div><div class="sam-intro">De <strong>elektrochemie</strong> koppelt redoxreacties aan elektrische stroom. In een <strong>galvanische cel</strong> levert een spontane reactie spanning; bij <strong>elektrolyse</strong> dwing je met stroom juist een reactie af. De <strong>reductiepotentiaal</strong> voorspelt wat er gebeurt.</div><div class="sam-head">Redox: oxidatie en reductie</div><p>Bij een <strong>redoxreactie</strong> worden elektronen overgedragen. De ene stof staat elektronen af (oxidatie), de andere neemt ze op (reductie).</p><table class="sam-table"><thead><tr><th>Halfreactie</th><th>Elektronen</th><th>Elektrode</th></tr></thead><tbody><tr><td>Oxidatie</td><td>staat e⁻ af</td><td>anode (−)</td></tr><tr><td>Reductie</td><td>neemt e⁻ op</td><td>kathode (+)</td></tr></tbody></table><div class="sam-head">Galvanische cel (Daniell-cel)</div><p>Twee <strong>halfcellen</strong> zijn verbonden door een draad (voor de elektronen) en een <strong>zoutbrug</strong> (voor de ionbalans). De onedele metaal-elektrode wordt de anode; de edelere de kathode.</p><div class="sam-figure"><svg viewBox="0 0 300 190" role="img" aria-label="Daniell-cel met zink- en koperelektrode, zoutbrug en elektronenstroom door de draad"><defs><marker id="skEe" markerWidth="9" markerHeight="9" refX="5" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L7,3 L0,6 Z" fill="var(--or)"/></marker></defs><path d="M30,80 L30,175 L120,175 L120,80" fill="none" stroke="var(--mu)" stroke-width="1.5"/><path d="M180,80 L180,175 L270,175 L270,80" fill="none" stroke="var(--mu)" stroke-width="1.5"/><rect x="30" y="120" width="90" height="55" fill="var(--mu)" opacity=".08"/><rect x="180" y="120" width="90" height="55" fill="var(--or)" opacity=".10"/><rect x="68" y="70" width="10" height="80" fill="var(--dk)"/><rect x="222" y="70" width="10" height="80" fill="var(--dk)"/><path d="M73,70 L73,45 L227,45 L227,70" fill="none" stroke="var(--dk)" stroke-width="2"/><line x1="120" y1="45" x2="180" y2="45" stroke="var(--or)" stroke-width="2.4" marker-end="url(#skEe)"/><text x="135" y="38" font-size="9" font-weight="700" fill="var(--or)">e⁻</text><path d="M120,95 Q150,72 180,95" fill="none" stroke="var(--mu)" stroke-width="6" opacity=".35"/><text x="128" y="80" font-size="8" fill="var(--mu)">zoutbrug</text><text x="45" y="60" font-size="10" font-weight="700" fill="var(--dk)">Zn</text><text x="30" y="190" font-size="8.5" fill="var(--mu)">Zn / Zn²⁺  (anode −)</text><text x="215" y="60" font-size="10" font-weight="700" fill="var(--dk)">Cu</text><text x="182" y="190" font-size="8.5" fill="var(--mu)">Cu / Cu²⁺  (kathode +)</text></svg><div class="sam-figcap"><strong>Daniell-cel:</strong> zink (onedel) lost op en staat elektronen af; die lopen door de draad naar de koperelektrode, waar Cu²⁺ neerslaat. De zoutbrug houdt beide oplossingen neutraal.</div></div><div class="sam-head">Reductiepotentiaal en celspanning</div><p>De <strong>standaard reductiepotentiaal E°</strong> (BiNaS) geeft aan hoe graag een halfreactie elektronen opneemt. De celspanning is het verschil tussen de twee halfcellen.</p><div class="sam-formula-box"><div class="sam-formula-label">Bronspanning van de cel</div><div class="sam-formula-eq">E°<sub>cel</sub> = E°<sub>kathode</sub> − E°<sub>anode</sub></div><div class="sam-formula-note">Een positieve E°<sub>cel</sub> betekent een spontane reactie. De <strong>Nernst-vergelijking</strong> corrigeert E voor afwijkende concentraties.</div></div><div class="sam-head">Elektrolyse en Faraday</div><p>Bij <strong>elektrolyse</strong> dwingt een uitwendige spanning een niet-spontane reactie af. De hoeveelheid omgezette stof volgt uit de <strong>lading</strong>.</p><div class="sam-formula-box"><div class="sam-formula-label">Wet van Faraday</div><div class="sam-formula-eq">Q = I · t  ·  n(e⁻) = Q / F</div><div class="sam-formula-note">Q de lading (C), I de stroom (A), t de tijd (s), F = 9,65·10⁴ C/mol (constante van Faraday). Zo bereken je hoeveel mol stof neerslaat of vrijkomt.</div></div><div class="sam-tip"><strong>Corrosie</strong> (roesten) is een ongewenste redoxreactie. Bescherming: verven, verzinken (opofferingsanode) of kathodische bescherming met een onedeler metaal.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave</div><div class="sam-worked-q">Door een elektrolyse-opstelling loopt 2,0 A gedurende 30 minuten. Hoeveel mol elektronen is er verplaatst? (F = 9,65·10⁴ C/mol)</div><ol class="sam-worked-steps"><li>Q = I·t = 2,0 × (30 × 60) = 2,0 × 1800 = 3600 C.</li><li>n(e⁻) = Q / F = 3600 / 9,65·10⁴.</li><li>n(e⁻) = 3,7·10⁻² mol.</li></ol><div class="sam-worked-ans">✅ Er is 0,037 mol elektronen verplaatst.</div></div></div>`,
'vwo_na_B':`<div class="sam-intro"><strong>Golven</strong> draait om <strong>trillingen</strong> die zich voortplanten en zo informatie of energie overbrengen — van geluid en licht tot medische beeldvorming. Je beschrijft ze met diagrammen en met de golfvergelijking <strong>v = f·λ</strong>, en analyseert staande golven, interferentie, breking en het Doppler-effect.</div><div class="sam-head">Wat je voor het examen moet kennen (syllabus)</div><p>Domein B bestaat uit twee subdomeinen. De kernnatuurkunde (B1) staat hieronder volledig; B2 leunt op deze golf- en stralingskennis.</p><table class="sam-table"><thead><tr><th>Sub</th><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>B1</td><td>Informatieoverdracht</td><td>trillingen, golven, staande golven, interferentie, breking, Doppler</td></tr><tr><td>B2</td><td>Medische beeldvorming</td><td>echografie (geluid) &amp; röntgen/CT — zie ook domein E (straling)</td></tr></tbody></table><div class="sam-head">B1 · Trillingen</div><p>Een <strong>harmonische trilling</strong> heeft een sinusvormig <strong>(u,t)-diagram</strong>. De belangrijke grootheden zijn de <strong>amplitude</strong> A (maximale uitwijking), de <strong>periode</strong> T (duur van één trilling) en de <strong>frequentie</strong> f (aantal trillingen per seconde).</p><div class="sam-figure"><svg viewBox="0 0 300 130" role="img" aria-label="u,t-diagram van een harmonische trilling met amplitude A en periode T"><defs><marker id="giNB1" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--mu)"/></marker></defs><line x1="24" y1="65" x2="290" y2="65" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#giNB1)"/><line x1="30" y1="120" x2="30" y2="14" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#giNB1)"/><text x="288" y="60" font-size="8" fill="var(--mu)" text-anchor="end">t</text><text x="14" y="20" font-size="8" fill="var(--mu)">u</text><path d="M30,65 C55,20 80,20 105,65 C130,110 155,110 180,65 C205,20 230,20 255,65" fill="none" stroke="var(--or)" stroke-width="2.4"/><line x1="30" y1="30" x2="105" y2="30" stroke="var(--mu)" stroke-width="1" stroke-dasharray="3 3"/><text x="66" y="26" font-size="7.5" fill="var(--or)" text-anchor="middle">A</text><line x1="30" y1="30" x2="30" y2="65" stroke="var(--or)" stroke-width="1.4"/><line x1="105" y1="72" x2="180" y2="72" stroke="var(--mu)" stroke-width="1"/><text x="142" y="84" font-size="7.5" fill="var(--mu)" text-anchor="middle">T</text></svg><div class="sam-figcap"><strong>(u,t)-diagram:</strong> de <strong>amplitude</strong> A is de maximale uitwijking, de <strong>periode</strong> T de tijd van één volledige trilling.</div></div><div class="sam-formula-box"><div class="sam-formula-label">Frequentie en fase</div><div class="sam-formula-eq">f = 1 / T     (f in hertz)<br>gereduceerde fase φ = t / T</div><div class="sam-formula-note">Een <strong>massa-veersysteem</strong> heeft een eigenfrequentie; drijf je het met díe frequentie aan, dan treedt <strong>resonantie</strong> op (grote amplitude).</div></div><div class="sam-head">B1 · Golven</div><p>Plant een trilling zich voort, dan ontstaat een <strong>golf</strong>. In een <strong>(u,x)-diagram</strong> lees je de <strong>golflengte</strong> λ af: de afstand tussen twee punten in dezelfde fase.</p><div class="sam-compare"><div class="sam-compare-col"><div class="sam-compare-head">Transversale golf</div><ul><li>trilling ⟂ voortplanting</li><li>bv. licht, golf in een touw</li></ul></div><div class="sam-compare-col"><div class="sam-compare-head">Longitudinale golf</div><ul><li>trilling ∥ voortplanting</li><li>bv. geluid (lucht)</li></ul></div></div><div class="sam-formula-box"><div class="sam-formula-label">Golfvergelijking</div><div class="sam-formula-eq">v = f · λ</div><div class="sam-formula-note">v is de voortplantingssnelheid. Voor geluid in lucht ≈ 343 m/s; voor licht c = 2,998·10⁸ m/s. Het <strong>faseverschil</strong> tussen twee punten is Δφ = Δx / λ.</div></div><div class="sam-head">B1 · Staande golven en resonantie</div><p>Lopen twee gelijke golven elkaar tegemoet (bv. een golf en zijn weerkaatsing), dan ontstaat een <strong>staande golf</strong> met vaste <strong>knopen</strong> (geen uitwijking) en <strong>buiken</strong> (maximale uitwijking).</p><div class="sam-figure"><svg viewBox="0 0 300 100" role="img" aria-label="Staande golf met twee knopen aan de uiteinden en buiken ertussen"><line x1="20" y1="50" x2="280" y2="50" stroke="var(--mu)" stroke-width="1" stroke-dasharray="3 3"/><path d="M40,50 C70,14 100,14 130,50 C160,86 190,86 220,50 C240,26 255,32 260,50" fill="none" stroke="var(--or)" stroke-width="2.2"/><path d="M40,50 C70,86 100,86 130,50 C160,14 190,14 220,50 C240,74 255,68 260,50" fill="none" stroke="var(--or)" stroke-width="2.2" opacity=".45"/><g fill="var(--dk)"><circle cx="40" cy="50" r="3"/><circle cx="130" cy="50" r="3"/><circle cx="220" cy="50" r="3"/></g><text x="40" y="70" font-size="7.5" fill="var(--dk)" text-anchor="middle">knoop</text><text x="85" y="12" font-size="7.5" fill="var(--or)" text-anchor="middle">buik</text></svg><div class="sam-figcap"><strong>Staande golf:</strong> tussen twee knopen zit een halve golflengte. Bij een snaar met twee vaste uiteinden past er een geheel aantal halve golflengtes: L = n · ½λ (n = 1, 2, 3…). Dit is de basis van <strong>resonantie</strong> in snaren en buizen.</div></div><div class="sam-head">B1 · Interferentie en diffractie</div><p>Golven die elkaar ontmoeten <strong>interfereren</strong>: ze versterken of doven elkaar uit, afhankelijk van het <strong>weglengteverschil</strong> Δx.</p><ul><li><strong>Versterking</strong> (in fase): Δx = n · λ</li><li><strong>Uitdoving</strong> (in tegenfase): Δx = (n + ½) · λ</li></ul><p><strong>Diffractie</strong> is het buigen van golven om een obstakel of door een opening; hoe kleiner de opening t.o.v. λ, hoe sterker de buiging. Bij een <strong>tralie</strong> ontstaan scherpe maxima.</p><div class="sam-head">B1 · Breking en Doppler</div><p>Gaat een golf van het ene medium naar het andere, dan verandert de snelheid en dus de <strong>richting</strong>: <strong>breking</strong>. Dit beschrijf je met de wet van Snellius.</p><div class="sam-figure"><svg viewBox="0 0 240 140" role="img" aria-label="Breking van een lichtstraal aan een grensvlak volgens de wet van Snellius"><defs><marker id="giNB2" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--or)"/></marker></defs><rect x="20" y="70" width="200" height="60" fill="var(--mu)" opacity=".1"/><line x1="20" y1="70" x2="220" y2="70" stroke="var(--mu)" stroke-width="1.3"/><line x1="120" y1="14" x2="120" y2="126" stroke="var(--mu)" stroke-width="1" stroke-dasharray="4 3"/><line x1="60" y1="20" x2="120" y2="70" stroke="var(--or)" stroke-width="2.2" marker-end="url(#giNB2)"/><line x1="120" y1="70" x2="165" y2="122" stroke="var(--or)" stroke-width="2.2" marker-end="url(#giNB2)"/><text x="128" y="40" font-size="8" fill="var(--dk)">θ₁</text><text x="128" y="104" font-size="8" fill="var(--dk)">θ₂</text><text x="40" y="60" font-size="7.5" fill="var(--mu)">medium 1</text><text x="175" y="96" font-size="7.5" fill="var(--mu)">medium 2 (dichter)</text></svg><div class="sam-figcap"><strong>Wet van Snellius:</strong> in het dichtere medium (grotere n) breekt de straal <em>naar de normaal toe</em>. De hoeken meet je altijd t.o.v. de normaal (de stippellijn).</div></div><div class="sam-formula-box"><div class="sam-formula-label">Wet van Snellius</div><div class="sam-formula-eq">n<sub>1</sub> · sin θ<sub>1</sub> = n<sub>2</sub> · sin θ<sub>2</sub></div><div class="sam-formula-note">n is de brekingsindex van het medium. Bij het <strong>Doppler-effect</strong> beweegt bron of waarnemer: nadert de bron, dan is de waargenomen frequentie <em>hoger</em> (kortere golflengte), verwijdert hij zich, dan <em>lager</em>.</div></div><div class="sam-tip">B2 <strong>Medische beeldvorming</strong> past deze natuurkunde toe: <strong>echografie</strong> gebruikt weerkaatsing van (ultra)geluidsgolven, terwijl <strong>röntgen en CT</strong> ioniserende straling gebruiken — die stralingskennis staat in domein E (Straling en materie).</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — golfvergelijking</div><div class="sam-worked-q">Een geluidsgolf heeft een frequentie van 680 Hz. De geluidssnelheid is 343 m/s. Bereken de golflengte.</div><ol class="sam-worked-steps"><li>Golfvergelijking: v = f · λ, dus λ = v / f.</li><li>λ = 343 / 680 = 0,504… m.</li><li>Afronden op 2 significante cijfers.</li></ol><div class="sam-worked-ans">✅ λ ≈ 0,50 m.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — interferentie</div><div class="sam-worked-q">Twee luidsprekers zenden hetzelfde geluid (λ = 0,40 m) in fase uit. In een punt is het weglengteverschil 0,60 m. Hoor je daar versterking of uitdoving?</div><ol class="sam-worked-steps"><li>Deel het weglengteverschil door λ: 0,60 / 0,40 = 1,5.</li><li>1,5 = (1 + ½) → dit is (n + ½)·λ met n = 1.</li><li>Dat is de voorwaarde voor uitdoving (tegenfase).</li></ol><div class="sam-worked-ans">✅ Uitdoving: in dat punt hoor je (bijna) niets.</div></div>`,
'vwo_na_C':`<div class="sam-intro"><strong>Beweging en wisselwerking</strong> is het hart van de mechanica: hoe <strong>krachten</strong> de beweging van voorwerpen veranderen (Newton), hoe <strong>energie</strong> daarbij van vorm wisselt maar behouden blijft, en hoe <strong>gravitatie</strong> planeten en satellieten in hun baan houdt. Reken altijd in SI-eenheden (m, s, kg, N, J).</div><div class="sam-head">Wat je voor het examen moet kennen (syllabus)</div><p>Domein C bestaat uit drie subdomeinen. Deze samenvatting dekt ze alle drie:</p><table class="sam-table"><thead><tr><th>Sub</th><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>C1</td><td>Kracht en beweging</td><td>bewegingsdiagrammen, krachten, wetten van Newton</td></tr><tr><td>C2</td><td>Energie en wisselwerking</td><td>arbeid, energiebehoud, vermogen, rendement</td></tr><tr><td>C3</td><td>Gravitatie</td><td>cirkelbeweging, middelpuntzoekende + gravitatiekracht</td></tr></tbody></table><div class="sam-head">C1 · Kracht en beweging</div><p>Beweging beschrijf je met <strong>diagrammen</strong>. In een <strong>(x,t)-diagram</strong> is de <strong>helling</strong> de snelheid; in een <strong>(v,t)-diagram</strong> is de helling de versnelling en de <strong>oppervlakte onder de grafiek</strong> de afgelegde afstand.</p><div class="sam-figure"><svg viewBox="0 0 300 160" role="img" aria-label="Snelheid-tijd-diagram van een eenparig versnelde beweging; de oppervlakte onder de lijn is de afstand"><defs><marker id="giNC1" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--mu)"/></marker></defs><line x1="40" y1="140" x2="288" y2="140" stroke="var(--mu)" stroke-width="1.5" marker-end="url(#giNC1)"/><line x1="40" y1="150" x2="40" y2="18" stroke="var(--mu)" stroke-width="1.5" marker-end="url(#giNC1)"/><text x="286" y="154" font-size="8.5" fill="var(--mu)" text-anchor="end">t (s)</text><text x="16" y="24" font-size="8.5" fill="var(--mu)">v (m/s)</text><polygon points="40,140 240,140 240,44" fill="var(--or)" opacity=".14"/><line x1="40" y1="140" x2="240" y2="44" stroke="var(--or)" stroke-width="2.4"/><line x1="240" y1="140" x2="240" y2="44" stroke="var(--mu)" stroke-width="1" stroke-dasharray="3 3"/><text x="150" y="128" font-size="8.5" fill="var(--or)" text-anchor="middle">oppervlakte = afstand</text><text x="150" y="70" font-size="8" fill="var(--mu)" text-anchor="middle" transform="rotate(-19 150 70)">helling = versnelling a</text></svg><div class="sam-figcap"><strong>Eenparig versnelde beweging:</strong> de snelheid neemt recht evenredig toe (constante <em>a</em>). De oppervlakte van de driehoek onder de lijn is de afgelegde afstand.</div></div><div class="sam-formula-box"><div class="sam-formula-label">Eenparig versnelde beweging (a constant)</div><div class="sam-formula-eq">v = v<sub>0</sub> + a·t<br>x = v<sub>0</sub>·t + ½·a·t²</div><div class="sam-formula-note">Bij eenparige beweging (a = 0) geldt simpelweg v = constant en x = v·t.</div></div><p>Een <strong>kracht</strong> (in N) is een vectorgrootheid: hij heeft grootte én richting. Je mag krachten <strong>samenstellen</strong> tot een resultante of juist <strong>ontbinden</strong> in twee richtingen — handig op een hellend vlak:</p><div class="sam-figure"><svg viewBox="0 0 300 150" role="img" aria-label="Blok op een hellend vlak; de zwaartekracht wordt ontbonden langs en loodrecht op de helling"><defs><marker id="giNC1b" markerWidth="9" markerHeight="9" refX="5" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L7,3 L0,6 Z" fill="var(--or)"/></marker></defs><polygon points="30,130 270,130 30,40" fill="var(--mu)" opacity=".12" stroke="var(--mu)" stroke-width="1.2"/><rect x="96" y="86" width="26" height="18" fill="var(--or)" opacity=".3" stroke="var(--or)" stroke-width="1.1" transform="rotate(-20.6 109 95)"/><line x1="109" y1="95" x2="109" y2="140" stroke="var(--or)" stroke-width="2.2" marker-end="url(#giNC1b)"/><text x="116" y="138" font-size="8" fill="var(--or)">F<tspan baseline-shift="sub" font-size="6">z</tspan></text><line x1="109" y1="95" x2="140" y2="107" stroke="var(--or)" stroke-width="2" marker-end="url(#giNC1b)"/><text x="140" y="103" font-size="7.5" fill="var(--or)">langs helling</text><line x1="109" y1="95" x2="88" y2="147" stroke="var(--mu)" stroke-width="1" stroke-dasharray="3 2"/><text x="46" y="60" font-size="8" fill="var(--mu)">helling α</text></svg><div class="sam-figcap"><strong>Ontbinden op een helling:</strong> de zwaartekracht F<sub>z</sub> splits je in een component <em>langs</em> de helling (F<sub>z</sub>·sin α, versnelt het blok) en <em>loodrecht</em> erop (F<sub>z</sub>·cos α, in evenwicht met de normaalkracht).</div></div><p>De <strong>drie wetten van Newton</strong> verbinden kracht en beweging:</p><ul><li><strong>Newton I (traagheid):</strong> zonder resulterende kracht blijft een voorwerp in rust of in eenparige beweging (F<sub>res</sub> = 0 → v constant).</li><li><strong>Newton II:</strong> een resulterende kracht geeft een versnelling.</li><li><strong>Newton III (actie = reactie):</strong> oefent A een kracht uit op B, dan oefent B een even grote, tegengestelde kracht uit op A.</li></ul><div class="sam-formula-box"><div class="sam-formula-label">Tweede wet van Newton</div><div class="sam-formula-eq">F<sub>res</sub> = m · a</div><div class="sam-formula-note">F<sub>res</sub> is de <strong>som van alle krachten</strong> (als vectoren). Zwaartekracht: F<sub>z</sub> = m·g met g = 9,81 m/s².</div></div><div class="sam-warn"><strong>Veelgemaakte fout:</strong> actie en reactie (Newton III) werken op <em>twee verschillende voorwerpen</em> en heffen elkaar dus nooit op. Evenwicht (F<sub>res</sub> = 0) gaat juist over krachten op <em>hetzelfde</em> voorwerp.</div><div class="sam-head">C2 · Energie en wisselwerking</div><p><strong>Arbeid</strong> is energie die door een kracht wordt overgedragen: W = F·s (met F in de bewegingsrichting). Energie komt in vormen die in elkaar overgaan, maar de <strong>totale energie blijft behouden</strong>.</p><table class="sam-table"><thead><tr><th>Energievorm</th><th>Formule</th></tr></thead><tbody><tr><td>Kinetische energie</td><td>E<sub>k</sub> = ½·m·v²</td></tr><tr><td>Zwaarte-energie</td><td>E<sub>z</sub> = m·g·h</td></tr><tr><td>Veerenergie</td><td>E<sub>v</sub> = ½·C·u²</td></tr><tr><td>Warmte</td><td>Q = c·m·ΔT</td></tr></tbody></table><div class="sam-figure"><svg viewBox="0 0 300 140" role="img" aria-label="Vallend voorwerp: zwaarte-energie wordt omgezet in kinetische energie, de som blijft gelijk"><g font-size="8" font-weight="700" text-anchor="middle"><rect x="34" y="24" width="70" height="16" fill="var(--or)" opacity=".35"/><rect x="34" y="24" width="0" height="16" fill="var(--mu)"/><text x="69" y="17" fill="var(--dk)">boven</text><text x="69" y="36" font-size="7" fill="var(--dk)">E<tspan baseline-shift="sub" font-size="5">z</tspan> groot</text><rect x="34" y="70" width="35" height="16" fill="var(--or)" opacity=".35"/><rect x="69" y="70" width="35" height="16" fill="var(--mu)" opacity=".4"/><text x="69" y="63" fill="var(--dk)">halverwege</text><rect x="34" y="112" width="70" height="16" fill="var(--mu)" opacity=".4"/><text x="69" y="105" fill="var(--dk)">onder</text><text x="69" y="124" font-size="7" fill="var(--dk)">E<tspan baseline-shift="sub" font-size="5">k</tspan> groot</text></g><rect x="150" y="24" width="16" height="104" fill="var(--or)" opacity=".18"/><line x1="140" y1="24" x2="176" y2="24" stroke="var(--dk)" stroke-width="1.4" stroke-dasharray="4 3"/><text x="230" y="28" font-size="8" fill="var(--dk)" text-anchor="middle">E<tspan baseline-shift="sub" font-size="6">totaal</tspan> = constant</text><g font-size="7.5" fill="var(--mu)"><rect x="196" y="104" width="10" height="10" fill="var(--or)" opacity=".35"/><text x="210" y="112" text-anchor="start">zwaarte</text><rect x="196" y="118" width="10" height="10" fill="var(--mu)" opacity=".4"/><text x="210" y="126" text-anchor="start">kinetisch</text></g></svg><div class="sam-figcap"><strong>Behoud van energie:</strong> bij een vrije val zet zwaarte-energie zich om in kinetische energie. Zonder wrijving is de som (E<sub>z</sub> + E<sub>k</sub>) op elke hoogte gelijk.</div></div><div class="sam-formula-box"><div class="sam-formula-label">Vermogen en rendement</div><div class="sam-formula-eq">P = W / t = E / t     (W in watt)<br>η = (E<sub>nuttig</sub> / E<sub>in</sub>) × 100%</div><div class="sam-formula-note">Vermogen is energie per seconde. Het rendement η is altijd &lt; 100%: een deel gaat verloren als warmte.</div></div><div class="sam-head">C3 · Gravitatie</div><p>Bij een <strong>eenparige cirkelbeweging</strong> is de grootte van de snelheid constant, maar de <strong>richting</strong> verandert steeds. Daarvoor is een naar het middelpunt gerichte kracht nodig: de <strong>middelpuntzoekende kracht</strong>.</p><div class="sam-figure"><svg viewBox="0 0 260 160" role="img" aria-label="Cirkelbeweging: de snelheid staat raaklijnig, de middelpuntzoekende kracht wijst naar het midden"><defs><marker id="giNC3" markerWidth="9" markerHeight="9" refX="5" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L7,3 L0,6 Z" fill="var(--or)"/></marker><marker id="giNC3b" markerWidth="9" markerHeight="9" refX="5" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L7,3 L0,6 Z" fill="var(--mu)"/></marker></defs><circle cx="120" cy="80" r="60" fill="none" stroke="var(--mu)" stroke-width="1.3" stroke-dasharray="4 3"/><circle cx="120" cy="80" r="6" fill="var(--mu)"/><text x="120" y="76" font-size="8" fill="var(--mu)" text-anchor="middle">M</text><circle cx="180" cy="80" r="7" fill="var(--or)" opacity=".8"/><line x1="180" y1="80" x2="122" y2="80" stroke="var(--or)" stroke-width="2" marker-end="url(#giNC3)"/><text x="150" y="74" font-size="8" fill="var(--or)" text-anchor="middle">F<tspan baseline-shift="sub" font-size="6">mpz</tspan></text><line x1="180" y1="80" x2="180" y2="26" stroke="var(--mu)" stroke-width="2" marker-end="url(#giNC3b)"/><text x="196" y="40" font-size="8" fill="var(--mu)">v</text><line x1="120" y1="80" x2="180" y2="80" stroke="var(--mu)" stroke-width="1" stroke-dasharray="2 2"/><text x="150" y="94" font-size="7.5" fill="var(--mu)" text-anchor="middle">straal r</text></svg><div class="sam-figcap"><strong>Cirkelbeweging:</strong> de snelheid <em>v</em> staat raaklijnig aan de baan; de middelpuntzoekende kracht F<sub>mpz</sub> wijst steeds naar het middelpunt M en verandert alleen de <em>richting</em> van v.</div></div><div class="sam-formula-box"><div class="sam-formula-label">Cirkelbeweging en gravitatie</div><div class="sam-formula-eq">v = 2π·r / T     F<sub>mpz</sub> = m·v² / r<br>F<sub>g</sub> = G·m<sub>1</sub>·m<sub>2</sub> / r²   (G = 6,67·10⁻¹¹ N·m²/kg²)</div><div class="sam-formula-note">Bij een satelliet of planeet is de <strong>gravitatiekracht</strong> precies de middelpuntzoekende kracht: F<sub>g</sub> = F<sub>mpz</sub>.</div></div><div class="sam-tip">Baanberekening satelliet: stel F<sub>g</sub> = F<sub>mpz</sub>, dus G·M·m/r² = m·v²/r. De massa <em>m</em> van de satelliet valt weg → v = √(G·M/r). Handig: de baansnelheid hangt niet af van de massa van de satelliet zelf.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — energiebehoud</div><div class="sam-worked-q">Een steen van 0,50 kg valt van 20 m hoogte (g = 9,81 m/s²; verwaarloos luchtwrijving). Hoe groot is zijn snelheid vlak boven de grond?</div><ol class="sam-worked-steps"><li>Boven: E<sub>z</sub> = m·g·h = 0,50 · 9,81 · 20 = 98 J. E<sub>k</sub> = 0.</li><li>Behoud van energie: onder is E<sub>k</sub> = 98 J (alle E<sub>z</sub> omgezet).</li><li>½·m·v² = 98 → v = √(2·98 / 0,50) = √392 ≈ 20 m/s.</li></ol><div class="sam-worked-ans">✅ v ≈ 20 m/s. (Sneller: v = √(2gh) = √(2·9,81·20).)</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — tweede wet van Newton</div><div class="sam-worked-q">Op een kar van 4,0 kg werkt een voorwaartse kracht van 20 N en een wrijvingskracht van 8,0 N. Bereken de versnelling.</div><ol class="sam-worked-steps"><li>F<sub>res</sub> = 20 − 8,0 = 12 N (wrijving werkt tegen de beweging in).</li><li>Newton II: a = F<sub>res</sub> / m.</li><li>a = 12 / 4,0 = 3,0 m/s².</li></ol><div class="sam-worked-ans">✅ De versnelling is 3,0 m/s², in de richting van de resulterende kracht.</div></div>`,
'vwo_na_D':`<div class="sam-intro">Een <strong>stroomkring</strong> beschrijf je met de wet van Ohm en de regels voor serie- en parallelschakelingen. Rondom een stroomdraad ontstaat een <strong>magnetisch veld</strong>, en een <strong>veranderend</strong> veld wekt weer spanning op (inductie) — de basis van generators en transformatoren.</div><div class="sam-head">Wet van Ohm en vermogen</div><p>De stroomsterkte door een weerstand is recht evenredig met de spanning erover. Het <strong>vermogen</strong> is de energie die per seconde wordt omgezet.</p><div class="sam-formula-box"><div class="sam-formula-label">Ohm en elektrisch vermogen</div><div class="sam-formula-eq">U = I · R  ·  P = U · I = I² · R</div><div class="sam-formula-note">U de spanning (V), I de stroomsterkte (A), R de weerstand (Ω), P het vermogen (W). Energie: E = P·t (J).</div></div><div class="sam-head">Serie- en parallelschakeling</div><table class="sam-table"><thead><tr><th></th><th>Serie</th><th>Parallel</th></tr></thead><tbody><tr><td>Stroom</td><td>overal gelijk</td><td>verdeelt zich</td></tr><tr><td>Spanning</td><td>verdeelt zich</td><td>overal gelijk</td></tr><tr><td>Vervangings-R</td><td>R = R₁ + R₂</td><td>1/R = 1/R₁ + 1/R₂</td></tr></tbody></table><div class="sam-tip">Een parallelschakeling heeft altijd een <strong>kleinere</strong> vervangingsweerstand dan de kleinste deelweerstand.</div><div class="sam-head">Condensator en RC-kring</div><p>Een <strong>condensator</strong> slaat lading op. De opgeslagen lading is evenredig met de spanning.</p><div class="sam-formula-box"><div class="sam-formula-label">Lading op een condensator</div><div class="sam-formula-eq">Q = C · U</div><div class="sam-formula-note">Q de lading (C), C de capaciteit (F), U de spanning (V). In een <strong>RC-kring</strong> laadt/ontlaadt de condensator via een weerstand met een karakteristieke tijd τ = R·C.</div></div><div class="sam-head">Magnetisch veld van een stroomdraad</div><p>Om een rechte stroomdraad lopen de veldlijnen als <strong>concentrische cirkels</strong>. De richting volgt uit de <strong>rechterhandregel</strong>: duim in de stroomrichting, vingers wijzen met het veld mee.</p><div class="sam-figure"><svg viewBox="0 0 300 200" role="img" aria-label="Magnetisch veld als concentrische cirkels rond een stroomdraad die uit het vlak komt"><defs><marker id="naDb" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--or)"/></marker></defs><circle cx="150" cy="100" r="26" fill="none" stroke="var(--or)" stroke-width="1.8"/><circle cx="150" cy="100" r="46" fill="none" stroke="var(--or)" stroke-width="1.8"/><circle cx="150" cy="100" r="66" fill="none" stroke="var(--or)" stroke-width="1.8"/><path d="M176,100 a26,26 0 0,1 -0.5,0" stroke="var(--or)" stroke-width="1.8" fill="none" marker-end="url(#naDb)"/><path d="M196,100 a46,46 0 0,1 -0.5,0" stroke="var(--or)" stroke-width="1.8" fill="none" marker-end="url(#naDb)"/><path d="M216,100 a66,66 0 0,1 -0.5,0" stroke="var(--or)" stroke-width="1.8" fill="none" marker-end="url(#naDb)"/><circle cx="150" cy="100" r="8" fill="none" stroke="var(--dk)" stroke-width="1.8"/><circle cx="150" cy="100" r="2.5" fill="var(--dk)"/><text x="150" y="88" font-size="10" font-weight="700" fill="var(--dk)" text-anchor="middle">I</text><text x="224" y="104" font-size="11" font-weight="700" fill="var(--or)">B</text></svg><div class="sam-figcap"><strong>Veld om een draad:</strong> de stroom I komt uit het vlak (⊙), het magnetisch veld B loopt in cirkels eromheen. Dichter bij de draad is het veld sterker.</div></div><div class="sam-head">Inductie (Faraday)</div><p>Een <strong>veranderende</strong> magnetische flux door een spoel wekt een spanning op. Dat is het begin van domein E: generators, transformatoren en wisselstroom.</p><div class="sam-warn"><strong>Let op het verschil:</strong> een <em>constante</em> stroom geeft een <em>constant</em> magnetisch veld, maar induceert géén spanning. Alleen een <strong>verandering</strong> van de flux (sterkte, oppervlak of hoek) wekt een inductiespanning op.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave</div><div class="sam-worked-q">Twee weerstanden van 30 Ω en 60 Ω staan parallel op een bron van 12 V. Bereken de vervangingsweerstand en de totale stroom.</div><ol class="sam-worked-steps"><li>1/R = 1/30 + 1/60 = 2/60 + 1/60 = 3/60, dus R = 20 Ω.</li><li>I = U/R = 12 / 20 = 0,60 A.</li></ol><div class="sam-worked-ans">✅ R = 20 Ω en I<sub>totaal</sub> = 0,60 A.</div></div></div><div class="sam-intro">Elektromagnetisme verbindt elektriciteit en magnetisme. Een lading in een magnetisch veld voelt de <strong>Lorentzkracht</strong>, een <strong>veranderende flux</strong> wekt spanning op (<strong>Faraday</strong>), en dat principe zit achter <strong>generators</strong>, <strong>transformatoren</strong> en <strong>wisselstroom</strong>.</div><div class="sam-head">Elektrisch veld en potentiaal</div><p>Rondom een lading heerst een <strong>elektrisch veld</strong> E. Tussen twee platen (condensator) is dat veld homogeen.</p><div class="sam-formula-box"><div class="sam-formula-label">Elektrisch veld tussen platen</div><div class="sam-formula-eq">E = U / d  ·  F = q · E</div><div class="sam-formula-note">E de veldsterkte (V/m of N/C), U de spanning (V), d de plaatafstand (m), q de lading (C). Een lading in het veld voelt kracht F = q·E.</div></div><div class="sam-head">Lorentzkracht</div><p>Een lading die dwars door een magnetisch veld beweegt, voelt een kracht loodrecht op zowel de snelheid als het veld: de <strong>Lorentzkracht</strong>. De richting volgt uit de rechterhandregel (voor positieve lading).</p><div class="sam-figure"><svg viewBox="0 0 300 200" role="img" aria-label="Lorentzkracht op een positieve lading die door een magnetisch veld het vlak in beweegt"><g stroke="var(--mu)" stroke-width="1.2" fill="none"><circle cx="90" cy="55" r="6"/><circle cx="150" cy="55" r="6"/><circle cx="210" cy="55" r="6"/><circle cx="90" cy="150" r="6"/><circle cx="210" cy="150" r="6"/></g><g stroke="var(--mu)" stroke-width="1.2"><path d="M85.8,50.8 L94.2,59.2 M94.2,50.8 L85.8,59.2"/><path d="M145.8,50.8 L154.2,59.2 M154.2,50.8 L145.8,59.2"/><path d="M205.8,50.8 L214.2,59.2 M214.2,50.8 L205.8,59.2"/><path d="M85.8,145.8 L94.2,154.2 M94.2,145.8 L85.8,154.2"/><path d="M205.8,145.8 L214.2,154.2 M214.2,145.8 L205.8,154.2"/></g><text x="230" y="45" font-size="9" fill="var(--mu)">B (vlak in)</text><defs><marker id="naEv" markerWidth="9" markerHeight="9" refX="5" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L7,3 L0,6 Z" fill="var(--or)"/></marker><marker id="naEf" markerWidth="9" markerHeight="9" refX="5" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L7,3 L0,6 Z" fill="var(--dk)"/></marker></defs><circle cx="150" cy="115" r="9" fill="var(--or)"/><text x="150" y="119" font-size="11" font-weight="700" fill="#fff" text-anchor="middle">+</text><line x1="159" y1="115" x2="225" y2="115" stroke="var(--or)" stroke-width="2.4" marker-end="url(#naEv)"/><text x="205" y="132" font-size="11" font-weight="700" fill="var(--or)">v</text><line x1="150" y1="106" x2="150" y2="55" stroke="var(--dk)" stroke-width="2.4" marker-end="url(#naEf)"/><text x="156" y="70" font-size="11" font-weight="700" fill="var(--dk)">F</text></svg><div class="sam-figcap"><strong>Lorentzkracht:</strong> de lading + beweegt met snelheid v naar rechts, het veld B wijst het vlak in (⊗). De kracht F staat loodrecht op beide.</div></div><div class="sam-formula-box"><div class="sam-formula-label">Lorentzkracht</div><div class="sam-formula-eq">F = B · q · v  ·  (op een draad: F = B · I · ℓ)</div><div class="sam-formula-note">B de magnetische veldsterkte (T), q de lading (C), v de snelheid (m/s), I de stroom (A), ℓ de draadlengte (m). Geldt maximaal als v (of I) loodrecht op B staat.</div></div><div class="sam-head">Elektromagnetische inductie</div><p>Verandert de <strong>magnetische flux</strong> Φ door een spoel, dan ontstaat een inductiespanning. Dit is de <strong>wet van Faraday</strong>.</p><div class="sam-formula-box"><div class="sam-formula-label">Inductiespanning (Faraday)</div><div class="sam-formula-eq">U<sub>ind</sub> = −N · (ΔΦ / Δt)</div><div class="sam-formula-note">N het aantal windingen, Φ de flux (Wb), Δt de tijd (s). Het minteken (wet van Lenz) geeft aan dat de inductiestroom de verandering tegenwerkt.</div></div><div class="sam-head">Transformator en wisselstroom</div><p>Een <strong>transformator</strong> zet met twee spoelen om een gezamenlijke kern een wisselspanning om. De spanningen verhouden zich als de windingsaantallen.</p><div class="sam-formula-box"><div class="sam-formula-label">Transformatorvergelijking</div><div class="sam-formula-eq">U<sub>p</sub> / U<sub>s</sub> = N<sub>p</sub> / N<sub>s</sub></div><div class="sam-formula-note">p = primair, s = secundair. Bij een ideale transformator geldt bovendien U<sub>p</sub>·I<sub>p</sub> = U<sub>s</sub>·I<sub>s</sub> (behoud van vermogen).</div></div><div class="sam-tip">Hoogspanning transporteert energie met weinig verlies: bij hogere U hoort bij gelijk vermogen een lagere I, en de verliezen P = I²R dalen kwadratisch.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave</div><div class="sam-worked-q">Een elektron (q = 1,6·10⁻¹⁹ C) beweegt met 2,0·10⁶ m/s loodrecht door een veld van 0,50 T. Bereken de Lorentzkracht.</div><ol class="sam-worked-steps"><li>Gebruik F = B·q·v.</li><li>F = 0,50 × 1,6·10⁻¹⁹ × 2,0·10⁶.</li><li>F = 1,6·10⁻¹³ N.</li></ol><div class="sam-worked-ans">✅ F = 1,6·10⁻¹³ N — klein, maar op de lichte elektronmassa geeft dat een enorme versnelling.</div></div></div>`,
'vwo_na_F':`<div class="sam-intro"><strong>Quantumwereld en relativiteit</strong> laat zien dat de natuurkunde bij het heel kleine (atomen, fotonen) en het heel snelle (bijna de lichtsnelheid) anders werkt dan je gewend bent. Kernidee van de quantumwereld: licht en materie hebben zowel <strong>golf-</strong> als <strong>deeltjeseigenschappen</strong>.</div><div class="sam-head">Wat je voor het examen moet kennen (syllabus)</div><p><strong>F1 (Quantumwereld)</strong> is de CE-kern. <strong>F2 (Relativiteitstheorie)</strong> is een keuze-/verdiepingsonderwerp; beide horen bij de domeinnaam.</p><table class="sam-table"><thead><tr><th>Sub</th><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>F1</td><td>Quantumwereld</td><td>golf-deeltjedualiteit, foton, foto-elektrisch effect, energieniveaus</td></tr><tr><td>F2</td><td>Relativiteitstheorie</td><td>lichtsnelheid, tijddilatatie, lengtecontractie</td></tr></tbody></table><div class="sam-head">F1 · Golf-deeltjedualiteit en het foton</div><p>Licht gedraagt zich soms als een <strong>golf</strong> (interferentie, buiging) en soms als een stroom <strong>deeltjes</strong>: <strong>fotonen</strong>. Elk foton draagt een energiepakketje dat afhangt van de frequentie.</p><div class="sam-formula-box"><div class="sam-formula-label">Foton-energie en materiegolf</div><div class="sam-formula-eq">E<sub>f</sub> = h · f = h · c / λ<br>de Broglie: λ = h / p = h / (m·v)</div><div class="sam-formula-note">h = 6,626·10⁻³⁴ J·s. Niet alleen licht, ook <strong>materie</strong> (elektronen) heeft een golflengte — daarop berust de elektronenmicroscoop.</div></div><div class="sam-head">F1 · Het foto-elektrisch effect</div><p>Schijnt licht op een metaal, dan kunnen <strong>elektronen vrijkomen</strong> — maar alleen als een foton genoeg energie heeft. Dit is het bewijs voor het deeltjeskarakter van licht: niet de <em>hoeveelheid</em> licht telt, maar de <strong>energie per foton</strong>.</p><div class="sam-figure"><svg viewBox="0 0 300 118" role="img" aria-label="Foto-elektrisch effect: een foton raakt een metaaloppervlak en maakt een elektron vrij"><defs><marker id="giNF1" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--or)"/></marker></defs><rect x="30" y="70" width="240" height="34" fill="var(--mu)" opacity=".18" stroke="var(--mu)" stroke-width="1"/><text x="150" y="94" font-size="8" fill="var(--dk)" text-anchor="middle">metaal (elektronen)</text><path d="M60,14 L140,66" stroke="var(--or)" stroke-width="2" marker-end="url(#giNF1)"/><text x="78" y="24" font-size="8" fill="var(--or)">foton (E = h·f)</text><circle cx="150" cy="66" r="5" fill="var(--dk)"/><path d="M160,60 L232,26" stroke="var(--dk)" stroke-width="1.8" marker-end="url(#giNF1)"/><text x="214" y="20" font-size="8" fill="var(--dk)">elektron</text></svg><div class="sam-figcap"><strong>Foto-elektrisch effect:</strong> een foton geeft zijn energie in één keer aan een elektron. Is die energie groter dan de <strong>uittree-energie</strong> W, dan komt het elektron vrij; de rest wordt kinetische energie.</div></div><div class="sam-formula-box"><div class="sam-formula-label">Energiebalans foto-elektrisch effect</div><div class="sam-formula-eq">E<sub>kin,max</sub> = h · f − W</div><div class="sam-formula-note">W is de uittree-energie (werk om een elektron los te maken). Is h·f &lt; W, dan komt er géén elektron vrij, hoe fel je ook schijnt.</div></div><div class="sam-head">F1 · Energieniveaus en quantisatie</div><p>Een atoom kan alleen <strong>bepaalde</strong> energiewaarden hebben: de <strong>energieniveaus</strong>. Een elektron dat naar een lager niveau springt, zendt een foton uit met precies het energieverschil — daarom zijn atoomspectra lijnenspectra (zie ook domein E).</p><div class="sam-figure"><svg viewBox="0 0 280 120" role="img" aria-label="Energieniveauschema: een elektron valt terug naar een lager niveau en zendt een foton uit"><defs><marker id="giNF2" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--or)"/></marker></defs><g stroke="var(--dk)" stroke-width="1.6"><line x1="40" y1="20" x2="180" y2="20"/><line x1="40" y1="52" x2="180" y2="52"/><line x1="40" y1="96" x2="180" y2="96"/></g><g font-size="8" fill="var(--mu)"><text x="188" y="23">E₃</text><text x="188" y="55">E₂</text><text x="188" y="99">E₁ (grondtoestand)</text></g><line x1="70" y1="22" x2="70" y2="94" stroke="var(--or)" stroke-width="2" marker-end="url(#giNF2)"/><path d="M92,58 q18,10 0,20 q-18,10 0,20" stroke="var(--or)" stroke-width="1.6" fill="none"/><text x="120" y="76" font-size="8" fill="var(--or)">foton uit</text></svg><div class="sam-figcap"><strong>Energieniveaus:</strong> de energie van het uitgezonden foton is E<sub>f</sub> = E<sub>hoog</sub> − E<sub>laag</sub>. Omdat de niveaus vast zijn, zijn ook de mogelijke fotonenergieën vast: een lijnenspectrum.</div></div><div class="sam-warn"><strong>Heisenberg (het aspect dat je moet kennen):</strong> je kunt niet tegelijk het golfgedrag én het deeltjesgedrag van een quantumdeeltje waarnemen. Welke kant zich toont, hangt af van de proef die je doet. Rekenen met golffuncties of de Schrödingervergelijking hoeft niet.</div><div class="sam-head">F2 · Relativiteitstheorie (keuze)</div><p>Einsteins uitgangspunt: de <strong>lichtsnelheid c</strong> is in elk referentiestelsel even groot, hoe snel je zelf ook beweegt. Daaruit volgen twee opvallende gevolgen bij snelheden dicht bij c:</p><div class="sam-compare"><div class="sam-compare-col"><div class="sam-compare-head">Tijddilatatie</div><ul><li>een bewegende klok loopt langzamer</li><li>Δt = γ · Δt<sub>0</sub></li></ul></div><div class="sam-compare-col"><div class="sam-compare-head">Lengtecontractie</div><ul><li>een bewegend voorwerp is korter</li><li>in de bewegingsrichting</li></ul></div></div><div class="sam-formula-box"><div class="sam-formula-label">Lorentzfactor</div><div class="sam-formula-eq">γ = 1 / √(1 − v²/c²)</div><div class="sam-formula-note">Bij alledaagse snelheden is v ≪ c, dus γ ≈ 1 en merk je niets. Pas dicht bij c wordt γ groot en worden de effecten merkbaar.</div></div><div class="sam-tip"><strong>Gelijktijdigheid is relatief:</strong> twee gebeurtenissen die voor de ene waarnemer tegelijk zijn, hoeven dat voor een bewegende waarnemer niet te zijn. Er is geen absolute "nu".</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — foto-elektrisch effect</div><div class="sam-worked-q">De uittree-energie van een metaal is 3,0·10⁻¹⁹ J. Er valt licht op met fotonenergie 5,0·10⁻¹⁹ J. Hoe groot is de maximale kinetische energie van een vrijgemaakt elektron?</div><ol class="sam-worked-steps"><li>Energiebalans: E<sub>kin,max</sub> = h·f − W.</li><li>E<sub>kin,max</sub> = 5,0·10⁻¹⁹ − 3,0·10⁻¹⁹.</li><li>= 2,0·10⁻¹⁹ J.</li></ol><div class="sam-worked-ans">✅ E<sub>kin,max</sub> = 2,0·10⁻¹⁹ J. (Was de fotonenergie kleiner dan W, dan kwam er geen elektron vrij.)</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — energieniveaus</div><div class="sam-worked-q">Een atoom valt van E₃ = −1,5 eV naar E₁ = −13,6 eV. Wat is de energie van het uitgezonden foton?</div><ol class="sam-worked-steps"><li>E<sub>f</sub> = E<sub>hoog</sub> − E<sub>laag</sub> = E₃ − E₁.</li><li>= −1,5 − (−13,6) = 12,1 eV.</li><li>Het foton heeft precies dit energieverschil.</li></ol><div class="sam-worked-ans">✅ Het uitgezonden foton heeft een energie van 12,1 eV.</div></div>`,
'vwo_ec_D':`<div class="sam-intro">Op een <strong>markt</strong> komen <strong>vraag</strong> en <strong>aanbod</strong> samen en ontstaat een <strong>prijs</strong>. Je leert de markt tekenen en lezen, meten hoe gevoelig vragers en aanbieders voor de prijs zijn (<strong>elasticiteit</strong>), en hoe de uitkomst verschilt per <strong>marktvorm</strong> — van volkomen concurrentie tot monopolie.</div><div class="sam-head">Wat je voor het examen moet kennen</div><p>Dit domein bestaat uit de volgende bouwstenen:</p><table class="sam-table"><thead><tr><th>Deel</th><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>1</td><td>Vraag en aanbod</td><td>curves, verschuiving vs. beweging langs de lijn</td></tr><tr><td>2</td><td>Marktevenwicht</td><td>evenwichtsprijs en -hoeveelheid</td></tr><tr><td>3</td><td>Elasticiteit</td><td>prijsgevoeligheid meten</td></tr><tr><td>4</td><td>Marktvormen</td><td>volkomen concurrentie → monopolie</td></tr><tr><td>5</td><td>Welvaart en overheid</td><td>surplus, prijsregulering</td></tr></tbody></table><div class="sam-head">1 · Vraag en aanbod</div><p>De <strong>vraaglijn</strong> loopt dalend: bij een lagere prijs willen consumenten méér kopen. De <strong>aanbodlijn</strong> loopt stijgend: bij een hogere prijs willen producenten méér leveren.</p><div class="sam-figure"><svg viewBox="0 0 260 180" role="img" aria-label="Vraag- en aanbodcurve die elkaar snijden in het marktevenwicht"><defs><marker id="giED1" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--mu)"/></marker></defs><line x1="34" y1="150" x2="240" y2="150" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#giED1)"/><line x1="34" y1="160" x2="34" y2="16" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#giED1)"/><text x="238" y="164" font-size="8" fill="var(--mu)" text-anchor="end">hoeveelheid</text><text x="16" y="22" font-size="8" fill="var(--mu)">prijs</text><line x1="50" y1="30" x2="210" y2="140" stroke="var(--or)" stroke-width="2.2"/><text x="200" y="130" font-size="8" fill="var(--or)">aanbod</text><line x1="50" y1="140" x2="210" y2="30" stroke="var(--dk)" stroke-width="2.2"/><text x="196" y="40" font-size="8" fill="var(--dk)">vraag</text><line x1="130" y1="85" x2="130" y2="150" stroke="var(--mu)" stroke-width="1" stroke-dasharray="3 3"/><line x1="34" y1="85" x2="130" y2="85" stroke="var(--mu)" stroke-width="1" stroke-dasharray="3 3"/><circle cx="130" cy="85" r="3.5" fill="var(--or)"/><text x="28" y="88" font-size="7.5" fill="var(--dk)" text-anchor="end">p*</text><text x="130" y="162" font-size="7.5" fill="var(--dk)" text-anchor="middle">q*</text></svg><div class="sam-figcap"><strong>De markt:</strong> waar vraag en aanbod elkaar snijden ligt het <strong>marktevenwicht</strong>: de evenwichtsprijs p* en de evenwichtshoeveelheid q*.</div></div><div class="sam-warn"><strong>Belangrijk onderscheid:</strong> verandert de <em>prijs</em>, dan beweeg je <strong>langs</strong> de lijn. Verandert een <em>andere</em> factor (inkomen, voorkeuren, prijs van een ander goed), dan <strong>verschuift</strong> de hele lijn. Verwar deze twee nooit.</div><div class="sam-head">2 · Marktevenwicht</div><p>Bij de evenwichtsprijs is de gevraagde hoeveelheid precies gelijk aan de aangeboden hoeveelheid (Q<sub>v</sub> = Q<sub>a</sub>). Ligt de prijs daarboven, dan is er een <strong>overschot</strong> (aanbod &gt; vraag) en daalt de prijs; ligt hij eronder, dan is er een <strong>tekort</strong> en stijgt de prijs. Zo trekt de markt zich vanzelf naar het evenwicht.</p><div class="sam-figure"><svg viewBox="0 0 260 180" role="img" aria-label="Toename van de vraag verschuift de vraaglijn naar rechts; prijs en hoeveelheid stijgen"><defs><marker id="giED2" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--mu)"/></marker><marker id="giED2b" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--or)"/></marker></defs><line x1="34" y1="150" x2="240" y2="150" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#giED2)"/><line x1="34" y1="160" x2="34" y2="16" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#giED2)"/><line x1="50" y1="30" x2="210" y2="140" stroke="var(--or)" stroke-width="2.2"/><text x="200" y="132" font-size="7.5" fill="var(--or)">aanbod</text><line x1="50" y1="120" x2="180" y2="30" stroke="var(--mu)" stroke-width="2" stroke-dasharray="5 3"/><line x1="86" y1="140" x2="216" y2="50" stroke="var(--dk)" stroke-width="2.2"/><text x="70" y="132" font-size="7.5" fill="var(--mu)">V₁</text><text x="210" y="64" font-size="7.5" fill="var(--dk)">V₂</text><path d="M120,70 L150,60" stroke="var(--or)" stroke-width="1.5" marker-end="url(#giED2b)"/><circle cx="112" cy="94" r="3" fill="var(--mu)"/><circle cx="150" cy="103" r="3.5" fill="var(--or)"/></svg><div class="sam-figcap"><strong>Verschuiving:</strong> stijgt de vraag (bv. door een hoger inkomen), dan schuift de vraaglijn naar rechts (V₁ → V₂). Het nieuwe evenwicht heeft een <strong>hogere prijs én hoeveelheid</strong>.</div></div><div class="sam-head">3 · Elasticiteit</div><p>De <strong>prijselasticiteit van de vraag</strong> meet hoe sterk de gevraagde hoeveelheid reageert op een prijsverandering.</p><div class="sam-formula-box"><div class="sam-formula-label">Prijselasticiteit van de vraag</div><div class="sam-formula-eq">E<sub>v</sub> = (% verandering gevraagde hoeveelheid) / (% verandering prijs)</div><div class="sam-formula-note">E<sub>v</sub> is meestal negatief. Is |E<sub>v</sub>| &gt; 1 dan is de vraag <strong>elastisch</strong> (sterke reactie, bv. luxe); is |E<sub>v</sub>| &lt; 1 dan <strong>inelastisch</strong> (zwakke reactie, bv. eerste levensbehoeften).</div></div><div class="sam-tip">Verband met omzet: bij een <strong>inelastische</strong> vraag stijgt de omzet als je de prijs verhoogt (mensen blijven toch kopen). Bij een <strong>elastische</strong> vraag daalt de omzet juist, want de afzet loopt hard terug.</div><div class="sam-head">4 · Marktvormen</div><p>Hoeveel invloed een aanbieder op de prijs heeft, hangt af van de <strong>marktvorm</strong>:</p><table class="sam-table"><thead><tr><th>Marktvorm</th><th>Aanbieders</th><th>Product</th><th>Prijs</th></tr></thead><tbody><tr><td>Volkomen concurrentie</td><td>heel veel</td><td>homogeen</td><td>prijs<strong>nemer</strong></td></tr><tr><td>Monopolistische concurrentie</td><td>veel</td><td>heterogeen</td><td>enige invloed</td></tr><tr><td>Oligopolie</td><td>enkele</td><td>homogeen/heterogeen</td><td>veel invloed</td></tr><tr><td>Monopolie</td><td>één</td><td>uniek</td><td>prijs<strong>zetter</strong></td></tr></tbody></table><p>Bij <strong>volkomen concurrentie</strong> is de aanbieder prijsnemer: hij moet de marktprijs accepteren. Bij een <strong>monopolie</strong> bepaalt de enige aanbieder zelf de prijs (rekening houdend met de vraag).</p><div class="sam-head">5 · Welvaart en overheid</div><p>De <strong>welvaart</strong> op een markt meet je met surplus. Het <strong>consumentensurplus</strong> is het verschil tussen wat consumenten wilden betalen en de prijs die ze betaalden; het <strong>producentensurplus</strong> tussen de prijs en de kosten. Samen vormen ze het <strong>totale surplus</strong>.</p><p>De <strong>overheid</strong> kan ingrijpen met een <strong>maximumprijs</strong> (onder het evenwicht → tekort, bv. huurbescherming) of een <strong>minimumprijs</strong> (boven het evenwicht → overschot, bv. minimumloon). Beide verstoren het marktevenwicht.</p><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — elasticiteit</div><div class="sam-worked-q">Een winkel verhoogt de prijs van een product met 10%. De gevraagde hoeveelheid daalt met 4%. Bereken de prijselasticiteit en zeg of de vraag elastisch is.</div><ol class="sam-worked-steps"><li>E<sub>v</sub> = %ΔQ / %Δp = −4% / +10%.</li><li>E<sub>v</sub> = −0,4.</li><li>|−0,4| &lt; 1, dus de vraag is <strong>inelastisch</strong>.</li></ol><div class="sam-worked-ans">✅ E<sub>v</sub> = −0,4 (inelastisch). De omzet stijgt zelfs, want de afzet daalt minder dan de prijs stijgt.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — verschuiving</div><div class="sam-worked-q">Door een hittegolf willen mensen veel meer ventilatoren. Wat gebeurt er met de evenwichtsprijs en -hoeveelheid van ventilatoren?</div><ol class="sam-worked-steps"><li>De vraag naar ventilatoren neemt toe: de vraaglijn schuift naar rechts.</li><li>Het aanbod verandert (op korte termijn) niet.</li><li>Nieuw snijpunt: hogere prijs én hogere hoeveelheid.</li></ol><div class="sam-worked-ans">✅ Zowel de evenwichtsprijs als de evenwichtshoeveelheid stijgen.</div></div>`,
'vwo_ec_I':`<div class="sam-intro">De economie groeit niet gelijkmatig: er zijn <strong>goede tijden</strong> (hoogconjunctuur) en <strong>slechte tijden</strong> (laagconjunctuur). Deze <strong>conjunctuur</strong> wordt gedreven door de <strong>bestedingen</strong>. Te weinig vraag geeft <strong>werkloosheid</strong>, te veel vraag geeft <strong>inflatie</strong> — en de overheid en centrale bank proberen bij te sturen.</div><div class="sam-head">Wat je voor het examen moet kennen</div><table class="sam-table"><thead><tr><th>Deel</th><th>Onderwerp</th><th>Kern</th></tr></thead><tbody><tr><td>1</td><td>Conjunctuur</td><td>schommeling rond de trend</td></tr><tr><td>2</td><td>Bestedingen</td><td>effectieve vraag; onder- en overbesteding</td></tr><tr><td>3</td><td>Werkloosheid en inflatie</td><td>soorten en oorzaken</td></tr><tr><td>4</td><td>Beleid</td><td>begrotingsbeleid en monetair beleid</td></tr></tbody></table><div class="sam-head">1 · De conjunctuur</div><p>De <strong>conjunctuur</strong> is de op- en neergaande beweging van de economische bedrijvigheid rond de <strong>trend</strong> (de langetermijngroei). In <strong>hoogconjunctuur</strong> groeit de productie bovengemiddeld; in <strong>laagconjunctuur</strong> ondergemiddeld. Twee kwartalen krimp achter elkaar heet een <strong>recessie</strong>.</p><div class="sam-figure"><svg viewBox="0 0 300 150" role="img" aria-label="Conjunctuurgolf die op en neer beweegt rond een stijgende trendlijn"><defs><marker id="giEI1" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--mu)"/></marker></defs><line x1="30" y1="135" x2="290" y2="135" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#giEI1)"/><line x1="30" y1="145" x2="30" y2="12" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#giEI1)"/><text x="286" y="148" font-size="8" fill="var(--mu)" text-anchor="end">tijd</text><text x="10" y="20" font-size="8" fill="var(--mu)">bbp</text><line x1="30" y1="120" x2="280" y2="30" stroke="var(--mu)" stroke-width="1.6" stroke-dasharray="5 4"/><text x="238" y="34" font-size="7.5" fill="var(--mu)">trend</text><path d="M30,116 C70,60 96,74 120,96 C150,120 168,74 200,52 C230,32 250,58 280,50" fill="none" stroke="var(--or)" stroke-width="2.4"/><text x="92" y="58" font-size="7" fill="var(--or)" text-anchor="middle">hoog</text><text x="150" y="134" font-size="7" fill="var(--or)" text-anchor="middle">laag</text></svg><div class="sam-figcap"><strong>Conjunctuurgolf:</strong> de werkelijke productie (oranje) schommelt rond de stijgende <strong>trend</strong>. Boven de trend is het hoogconjunctuur, eronder laagconjunctuur.</div></div><div class="sam-head">2 · Bestedingen: de motor van de conjunctuur</div><p>De conjunctuur wordt bepaald door de <strong>effectieve vraag</strong> (de totale bestedingen). Die bestaat uit vier delen:</p><div class="sam-formula-box"><div class="sam-formula-label">Effectieve vraag (bestedingen)</div><div class="sam-formula-eq">EV = C + I + O + (E − M)</div><div class="sam-formula-note"><strong>C</strong> = consumptie (gezinnen), <strong>I</strong> = investeringen (bedrijven), <strong>O</strong> = overheidsbestedingen, <strong>E − M</strong> = uitvoer minus invoer (saldo buitenland).</div></div><div class="sam-compare"><div class="sam-compare-col"><div class="sam-compare-head">Onderbesteding</div><ul><li>vraag &lt; productiecapaciteit</li><li>→ voorraden lopen op, ontslagen</li><li>→ (conjuncturele) werkloosheid</li></ul></div><div class="sam-compare-col"><div class="sam-compare-head">Overbesteding</div><ul><li>vraag &gt; productiecapaciteit</li><li>→ productie kan niet mee</li><li>→ prijzen stijgen: inflatie</li></ul></div></div><div class="sam-tip"><strong>Multipliereffect:</strong> een extra besteding (bv. de overheid bouwt een weg) wordt inkomen voor anderen, die daarvan weer een deel uitgeven. Zo leidt één euro extra vraag tot méér dan één euro extra productie.</div><div class="sam-head">3 · Werkloosheid en inflatie</div><table class="sam-table"><thead><tr><th>Verschijnsel</th><th>Soort</th><th>Oorzaak</th></tr></thead><tbody><tr><td>Werkloosheid</td><td>conjunctureel</td><td>te weinig bestedingen (laagconjunctuur)</td></tr><tr><td></td><td>structureel/frictie</td><td>mismatch of tussen twee banen in</td></tr><tr><td>Inflatie</td><td>bestedingsinflatie</td><td>te veel vraag (overbesteding)</td></tr><tr><td></td><td>kosteninflatie</td><td>duurdere grondstoffen of lonen</td></tr></tbody></table><p><strong>Inflatie</strong> meet je met het <strong>prijsindexcijfer</strong>: de gemiddelde prijsstijging van een pakket goederen. Bij inflatie daalt de <strong>koopkracht</strong> als de lonen minder hard stijgen dan de prijzen.</p><div class="sam-head">4 · Beleid: bijsturen</div><p>De overheid en de centrale bank proberen de conjunctuur te dempen (<strong>anticyclisch</strong>):</p><ul><li><strong>Begrotingsbeleid</strong> (overheid): in laagconjunctuur méér uitgeven of belasting verlagen om de vraag aan te jagen; in hoogconjunctuur juist afremmen.</li><li><strong>Monetair beleid</strong> (centrale bank, ECB): de <strong>rente</strong> aanpassen. Een lagere rente maakt lenen goedkoper → meer bestedingen en investeringen; een hogere rente remt af en bestrijdt inflatie.</li></ul><div class="sam-warn"><strong>Let op:</strong> beleid werkt met vertraging en de overheid moet in slechte tijden vaak méér lenen (begrotingstekort). Anticyclisch beleid botst daardoor soms met de wens om de staatsschuld beperkt te houden.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 1 — bestedingen</div><div class="sam-worked-q">Tijdens een recessie daalt het consumentenvertrouwen sterk. Leg met de effectieve vraag uit wat er met de werkloosheid gebeurt.</div><ol class="sam-worked-steps"><li>Laag vertrouwen → gezinnen consumeren minder: C daalt.</li><li>Daardoor daalt de effectieve vraag (EV = C + I + O + (E−M)).</li><li>Bedrijven verkopen minder, produceren minder en ontslaan personeel.</li></ol><div class="sam-worked-ans">✅ De (conjuncturele) werkloosheid stijgt: minder bestedingen → minder productie → minder werk.</div></div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave 2 — monetair beleid</div><div class="sam-worked-q">De inflatie is te hoog. Wat doet de centrale bank met de rente, en waarom werkt dat?</div><ol class="sam-worked-steps"><li>Te hoge inflatie komt vaak door te veel bestedingen (overbesteding).</li><li>De centrale bank <strong>verhoogt</strong> de rente.</li><li>Lenen wordt duurder → gezinnen en bedrijven besteden minder → de vraag en dus de prijsdruk daalt.</li></ol><div class="sam-worked-ans">✅ De rente omhoog: dat remt de bestedingen af en drukt zo de inflatie.</div></div>`,
'vwo_ak_B':`<div class="sam-intro">Domein B gaat over de <strong>verweven wereld</strong>: <strong>globalisering</strong>, <strong>migratie</strong>, <strong>ongelijkheid</strong> tussen arm en rijk, en de <strong>demografische transitie</strong> die landen doorlopen naarmate ze zich ontwikkelen.</div><div class="sam-head">Globalisering</div><p><strong>Globalisering</strong> is de toenemende wereldwijde verwevenheid — economisch, cultureel en politiek. Goederen, geld, mensen en informatie stromen steeds sneller over de wereld via lange <strong>handelsketens</strong>.</p><div class="sam-head">Demografische transitie</div><p>Naarmate een land zich ontwikkelt, dalen eerst het <strong>sterftecijfer</strong> (betere zorg, voeding) en later het <strong>geboortecijfer</strong>. Het verschil ertussen bepaalt de bevolkingsgroei.</p><div class="sam-figure"><svg viewBox="0 0 340 172" role="img" aria-label="Demografisch transitiemodel met dalend sterftecijfer en later dalend geboortecijfer"><defs><marker id="akBa" markerWidth="9" markerHeight="9" refX="5" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L7,3 L0,6 Z" fill="var(--mu)"/></marker></defs><line x1="44" y1="150" x2="332" y2="150" stroke="var(--mu)" stroke-width="1.5" marker-end="url(#akBa)"/><line x1="44" y1="158" x2="44" y2="28" stroke="var(--mu)" stroke-width="1.5" marker-end="url(#akBa)"/><path d="M44,45 L140.6,45 L182,70 L246.4,108.9 L264.8,120 L320,120" fill="none" stroke="var(--or)" stroke-width="2.4" stroke-linecap="round"/><path d="M44,48 L76.2,48 L122.2,79.8 L182,122 L320,122" fill="none" stroke="var(--dk)" stroke-width="2.4" stroke-linecap="round"/><text x="150" y="40" font-size="9" font-weight="700" fill="var(--or)">geboortecijfer</text><text x="60" y="66" font-size="9" font-weight="700" fill="var(--dk)">sterftecijfer</text><g font-size="8" fill="var(--mu)" text-anchor="middle"><text x="90" y="164">fase 1</text><text x="150" y="164">2</text><text x="215" y="164">3</text><text x="290" y="164">4</text></g></svg><div class="sam-figcap"><strong>Demografisch transitiemodel:</strong> in fase 2 daalt het sterftecijfer sterk (snelle groei); pas in fase 3 daalt ook het geboortecijfer. De kloof ertussen is de bevolkingsgroei.</div></div><div class="sam-head">Migratie</div><p>Mensen migreren door <strong>pushfactoren</strong> (wat hen wegdrijft) en <strong>pullfactoren</strong> (wat hen aantrekt).</p><div class="sam-compare"><div class="sam-compare-col"><div class="sam-compare-head">Pushfactoren</div><ul><li>armoede, werkloosheid</li><li>oorlog en onveiligheid</li><li>klimaat/natuurrampen</li></ul></div><div class="sam-compare-col"><div class="sam-compare-head">Pullfactoren</div><ul><li>werk en hoger loon</li><li>veiligheid en vrijheid</li><li>onderwijs, familie</li></ul></div></div><div class="sam-head">Ontwikkeling en ongelijkheid</div><p>Verschillen in ontwikkeling meet je met de <strong>HDI</strong> (welvaart, levensverwachting én onderwijs). Landen in de <strong>periferie</strong> exporteren vaak goedkope grondstoffen en zijn economisch afhankelijk van het rijkere <strong>centrum</strong>.</p><div class="sam-tip"><strong>Geopolitiek:</strong> de controle over grondstoffen, handelsroutes en invloedssferen leidt tot samenwerking én conflicten tussen landen.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave</div><div class="sam-worked-q">In fase 2 van de demografische transitie groeit de bevolking het snelst. Verklaar waarom.</div><ol class="sam-worked-steps"><li>Het sterftecijfer daalt sterk door betere zorg en voeding.</li><li>Het geboortecijfer blijft in fase 2 nog hoog.</li><li>Het grote verschil tussen beide geeft een snelle natuurlijke aanwas.</li></ol><div class="sam-worked-ans">✅ Hoge geboorten en sterk gedaalde sterfte samen geven de snelste groei.</div></div></div>`,
'vwo_ak_C':`<div class="sam-intro">Domein A gaat over het <strong>natuurlijke systeem Aarde</strong>: het <strong>klimaat</strong> en het <strong>broeikaseffect</strong>, de <strong>platentektoniek</strong>, de grote <strong>kringlopen</strong> en de menselijke invloed via <strong>klimaatverandering</strong>.</div><div class="sam-head">Het broeikaseffect</div><p>De zon stuurt kortgolvige straling naar de aarde. Het aardoppervlak warmt op en zendt <strong>langgolvige</strong> (warmte)straling terug. <strong>Broeikasgassen</strong> (CO₂, CH₄, waterdamp) houden een deel daarvan vast — zonder dat effect zou de aarde ijskoud zijn; teveel ervan geeft <strong>opwarming</strong>.</p><div class="sam-figure"><svg viewBox="0 0 300 180" role="img" aria-label="Het broeikaseffect: inkomende zonnestraling en langgolvige straling die deels wordt vastgehouden door de atmosfeer"><rect x="20" y="150" width="260" height="20" fill="var(--mu)" opacity=".18"/><line x1="20" y1="70" x2="280" y2="70" stroke="var(--mu)" stroke-width="1.3" stroke-dasharray="5 4"/><text x="212" y="64" font-size="8.5" fill="var(--mu)">atmosfeer (broeikasgassen)</text><circle cx="45" cy="30" r="15" fill="var(--or)"/><text x="45" y="34" font-size="8" font-weight="700" fill="#fff" text-anchor="middle">zon</text><defs><marker id="akAs" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--or)"/></marker><marker id="akAw" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--dk)"/></marker></defs><line x1="60" y1="45" x2="120" y2="148" stroke="var(--or)" stroke-width="2" marker-end="url(#akAs)"/><line x1="80" y1="42" x2="150" y2="148" stroke="var(--or)" stroke-width="2" marker-end="url(#akAs)"/><text x="58" y="110" font-size="8" fill="var(--or)">kortgolvig</text><line x1="180" y1="148" x2="205" y2="74" stroke="var(--dk)" stroke-width="2" marker-end="url(#akAw)"/><line x1="210" y1="72" x2="235" y2="148" stroke="var(--dk)" stroke-width="2" marker-end="url(#akAw)"/><text x="214" y="120" font-size="8" fill="var(--dk)">teruggekaatst</text><line x1="245" y1="148" x2="270" y2="60" stroke="var(--dk)" stroke-width="2" opacity=".5" marker-end="url(#akAw)"/><text x="30" y="166" font-size="8" fill="var(--mu)">aardoppervlak</text></svg><div class="sam-figcap"><strong>Broeikaseffect:</strong> kortgolvige zonnestraling warmt het oppervlak op; de langgolvige warmtestraling wordt deels door broeikasgassen teruggekaatst naar de aarde.</div></div><div class="sam-head">Platentektoniek</div><p>De aardkorst bestaat uit <strong>platen</strong> die bewegen op de vloeibare mantel. Aan plaatgrenzen ontstaan <strong>vulkanen</strong>, <strong>aardbevingen</strong> en gebergten.</p><table class="sam-table"><thead><tr><th>Plaatgrens</th><th>Beweging</th><th>Gevolg</th></tr></thead><tbody><tr><td>Divergent</td><td>platen uit elkaar</td><td>oceaanrug, nieuwe korst</td></tr><tr><td>Convergent</td><td>platen naar elkaar</td><td>gebergte, subductie, vulkanen</td></tr><tr><td>Transform</td><td>platen langs elkaar</td><td>aardbevingen (breuk)</td></tr></tbody></table><div class="sam-head">Kringlopen</div><p>Stoffen circuleren in gesloten <strong>kringlopen</strong>. In de <strong>koolstofkringloop</strong> wordt CO₂ opgenomen door planten (fotosynthese) en vrijgemaakt door ademhaling en verbranding van fossiele brandstoffen — die extra uitstoot verstoort het evenwicht.</p><div class="sam-warn"><strong>Klimaatverandering:</strong> het verbranden van fossiele brandstoffen verhoogt de CO₂-concentratie, versterkt het broeikaseffect en leidt tot opwarming, zeespiegelstijging en extremer weer. <strong>Adaptatie</strong> (aanpassen) en <strong>mitigatie</strong> (uitstoot beperken, duurzame energie) zijn de antwoorden.</p><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave</div><div class="sam-worked-q">Leg uit waarom ontbossing het broeikaseffect versterkt (noem twee stappen).</div><ol class="sam-worked-steps"><li>Bomen nemen via fotosynthese CO₂ op; minder bomen betekent minder opname.</li><li>Bij verbranding/rotting van het hout komt de opgeslagen CO₂ juist vrij.</li></ol><div class="sam-worked-ans">✅ Minder opname én extra uitstoot verhogen de CO₂-concentratie, wat het broeikaseffect versterkt.</div></div></div>`,
'vwo_gs_A':`<div class="sam-intro">Domein A gaat niet over losse feiten, maar over <strong>historisch redeneren</strong>: gebeurtenissen in hun <strong>context</strong> plaatsen, <strong>oorzaken en gevolgen</strong> onderscheiden, <strong>bronnen</strong> beoordelen en <strong>continuïteit en verandering</strong> herkennen.</div><div class="sam-head">Oorzaak en gevolg</div><p>Historici onderscheiden <strong>oorzaken</strong> (waarom iets gebeurde) van <strong>gevolgen</strong> (wat eruit voortkwam), en <strong>directe</strong> aanleidingen van dieperliggende <strong>structurele</strong> oorzaken.</p><div class="sam-figure"><svg viewBox="0 0 320 130" role="img" aria-label="Schema van oorzaken die leiden tot een gebeurtenis en daaruit voortvloeiende gevolgen"><defs><marker id="gsAa" markerWidth="9" markerHeight="9" refX="6" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L7,3 L0,6 Z" fill="var(--mu)"/></marker></defs><rect x="14" y="45" width="80" height="42" rx="6" fill="var(--mu)" opacity=".12" stroke="var(--mu)" stroke-width="1.2"/><text x="54" y="63" font-size="10" font-weight="700" fill="var(--dk)" text-anchor="middle">Oorzaken</text><text x="54" y="77" font-size="7.5" fill="var(--mu)" text-anchor="middle">structureel + direct</text><rect x="120" y="45" width="80" height="42" rx="6" fill="var(--or)" opacity=".15" stroke="var(--or)" stroke-width="1.4"/><text x="160" y="63" font-size="10" font-weight="700" fill="var(--dk)" text-anchor="middle">Gebeurtenis</text><text x="160" y="77" font-size="7.5" fill="var(--mu)" text-anchor="middle">in context</text><rect x="226" y="45" width="80" height="42" rx="6" fill="var(--mu)" opacity=".12" stroke="var(--mu)" stroke-width="1.2"/><text x="266" y="63" font-size="10" font-weight="700" fill="var(--dk)" text-anchor="middle">Gevolgen</text><text x="266" y="77" font-size="7.5" fill="var(--mu)" text-anchor="middle">korte + lange termijn</text><line x1="96" y1="66" x2="118" y2="66" stroke="var(--mu)" stroke-width="1.8" marker-end="url(#gsAa)"/><line x1="202" y1="66" x2="224" y2="66" stroke="var(--mu)" stroke-width="1.8" marker-end="url(#gsAa)"/></svg><div class="sam-figcap"><strong>Causaal redeneren:</strong> een gebeurtenis komt voort uit meerdere oorzaken (structureel én direct) en heeft gevolgen op korte en lange termijn. Alles staat in zijn historische context.</div></div><div class="sam-head">Bronnen beoordelen</div><table class="sam-table"><thead><tr><th>Bron</th><th>Wat</th><th>Let op</th></tr></thead><tbody><tr><td>Primair</td><td>uit de tijd zelf (brief, foto)</td><td>ooggetuige, maar gekleurd</td></tr><tr><td>Secundair</td><td>later geschreven (studie)</td><td>overzicht, maar interpretatie</td></tr></tbody></table><div class="sam-tip">Beoordeel een bron altijd op <strong>representativiteit</strong> en <strong>betrouwbaarheid</strong>: wie maakte hem, wanneer, met welk doel en voor welk publiek?</div><div class="sam-head">Continuïteit en verandering</div><p>Niet alles verandert tegelijk. <strong>Continuïteit</strong> (dingen die blijven) en <strong>verandering</strong> bestaan naast elkaar. Kernbegrippen om processen te duiden zijn <strong>revolutie</strong>, <strong>modernisering</strong> en <strong>emancipatie</strong>.</p><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave</div><div class="sam-worked-q">Waarom is een dagboek uit 1943 een primaire bron, en waarom moet je er toch kritisch mee omgaan?</div><ol class="sam-worked-steps"><li>Het is uit de tijd zelf geschreven → primair, ooggetuige.</li><li>De schrijver ziet maar een deel en heeft een persoonlijk, gekleurd perspectief.</li></ol><div class="sam-worked-ans">✅ Primair én waardevol, maar niet automatisch representatief of objectief.</div></div></div>`,
'vwo_gs_B':`<div class="sam-intro">De <strong>Moderne Tijd</strong> (1900–heden) is het belangrijkste examendomein: twee <strong>wereldoorlogen</strong>, de opkomst van <strong>totalitaire regimes</strong>, de <strong>Holocaust</strong>, <strong>dekolonisatie</strong>, de <strong>Koude Oorlog</strong> en de <strong>Europese integratie</strong>.</div><div class="sam-head">De eeuw in één oogopslag</div><div class="sam-figure"><svg viewBox="0 0 340 130" role="img" aria-label="Tijdbalk van 1900 tot 2000 met de belangrijkste gebeurtenissen van de twintigste eeuw"><line x1="30" y1="70" x2="330" y2="70" stroke="var(--mu)" stroke-width="2"/><g font-size="8" fill="var(--mu)" text-anchor="middle"><text x="30" y="90">1900</text><text x="115" y="90">1925</text><text x="200" y="90">1950</text><text x="285" y="90">1975</text><text x="325" y="90">2000</text></g><g stroke="var(--mu)" stroke-width="1"><line x1="30" y1="65" x2="30" y2="75"/><line x1="115" y1="65" x2="115" y2="75"/><line x1="200" y1="65" x2="200" y2="75"/><line x1="285" y1="65" x2="285" y2="75"/><line x1="325" y1="65" x2="325" y2="75"/></g><g fill="var(--or)"><circle cx="78" cy="70" r="4"/><circle cx="163" cy="70" r="4"/><circle cx="197" cy="70" r="4"/><circle cx="230" cy="70" r="4"/></g><g font-size="7.5" font-weight="700" fill="var(--dk)" text-anchor="middle"><text x="78" y="52">WO I</text><text x="78" y="42">1914</text><text x="163" y="30">WO II</text><text x="163" y="20">1939</text><text x="230" y="52">Koude</text><text x="230" y="42">Oorlog</text></g><g font-size="7" fill="var(--mu)" text-anchor="middle"><text x="120" y="110">interbellum</text><text x="270" y="110">dekolonisatie / EU</text></g></svg><div class="sam-figcap"><strong>Tijdbalk 20e eeuw:</strong> WO I (1914–18), het interbellum met de opkomst van dictaturen, WO II (1939–45), en daarna de Koude Oorlog, dekolonisatie en Europese eenwording.</div></div><div class="sam-head">Wereldoorlogen en totalitarisme</div><p>Na WO I schoof het <strong>Verdrag van Versailles</strong> de schuld op Duitsland. De economische crisis (beurskrach 1929) voedde de opkomst van <strong>totalitaire</strong> regimes: fascisme (Italië), nazisme (Duitsland) en stalinisme (USSR). WO II leidde tot de <strong>Holocaust</strong>, de systematische massamoord op zes miljoen Joden.</p><table class="sam-table"><thead><tr><th>Regime</th><th>Land</th><th>Kern</th></tr></thead><tbody><tr><td>Fascisme</td><td>Italië</td><td>nationalisme, leiderscultus</td></tr><tr><td>Nazisme</td><td>Duitsland</td><td>racisme, Lebensraum</td></tr><tr><td>Stalinisme</td><td>USSR</td><td>communisme, staatsterreur</td></tr></tbody></table><div class="sam-head">Koude Oorlog en Europa</div><p>Na 1945 stonden de VS (kapitalisme) en de USSR (communisme) tegenover elkaar: de <strong>Koude Oorlog</strong> (1947–1991), met het <strong>IJzeren Gordijn</strong> en de Berlijnse Muur als symbolen. Tegelijk werden koloniën onafhankelijk (<strong>dekolonisatie</strong>) en groeide de <strong>Europese samenwerking</strong> uit tot de EU.</p><div class="sam-tip">De Koude Oorlog bleef 'koud' door de <strong>afschrikking</strong> van kernwapens: een directe oorlog zou beide kanten vernietigen (MAD).</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave</div><div class="sam-worked-q">Noem een structurele en een directe oorzaak van de opkomst van Hitler.</div><ol class="sam-worked-steps"><li>Structureel: de vernedering en herstelbetalingen van het Verdrag van Versailles.</li><li>Direct: de economische crisis na de beurskrach van 1929 (massawerkloosheid).</li></ol><div class="sam-worked-ans">✅ Structurele onvrede + acute crisis maakten de NSDAP aantrekkelijk.</div></div></div>`,
'vwo_mw_B':`<div class="sam-intro">Domein B gaat over de <strong>samenleving</strong>: hoe mensen via <strong>socialisatie</strong> normen en waarden leren, hoe de maatschappij in <strong>lagen</strong> is verdeeld (stratificatie), en hoe <strong>verzorgingsstaat</strong> en <strong>multiculturaliteit</strong> daarmee samenhangen.</div><div class="sam-head">Socialisatie</div><p><strong>Socialisatie</strong> is het proces waarin je de cultuur (normen, waarden, rollen) van je samenleving leert. <strong>Primaire</strong> socialisatie gebeurt in het gezin; <strong>secundaire</strong> socialisatie op school, via vrienden, werk en media.</p><table class="sam-table"><thead><tr><th>Begrip</th><th>Betekenis</th></tr></thead><tbody><tr><td>Norm</td><td>concrete gedragsregel</td></tr><tr><td>Waarde</td><td>nastrevenswaardig ideaal</td></tr><tr><td>Rol</td><td>verwacht gedrag bij een positie</td></tr><tr><td>Socialiserende instantie</td><td>gezin, school, media, peers</td></tr></tbody></table><div class="sam-head">Sociale stratificatie</div><p>Een samenleving is verdeeld in <strong>lagen</strong> met verschillende hoeveelheden geld, macht en status. <strong>Sociale mobiliteit</strong> is de beweging tussen die lagen — omhoog of omlaag.</p><div class="sam-figure"><svg viewBox="0 0 300 160" role="img" aria-label="Piramide van sociale stratificatie met een boven-, midden- en onderlaag en een pijl voor sociale mobiliteit"><polygon points="150,20 210,70 90,70" fill="var(--or)" opacity=".22" stroke="var(--mu)" stroke-width="1"/><polygon points="90,72 210,72 245,118 55,118" fill="var(--or)" opacity=".14" stroke="var(--mu)" stroke-width="1"/><polygon points="55,120 245,120 280,150 20,150" fill="var(--or)" opacity=".07" stroke="var(--mu)" stroke-width="1"/><text x="150" y="55" font-size="9" font-weight="700" fill="var(--dk)" text-anchor="middle">bovenlaag</text><text x="150" y="100" font-size="9" font-weight="700" fill="var(--dk)" text-anchor="middle">middenlaag</text><text x="150" y="140" font-size="9" font-weight="700" fill="var(--dk)" text-anchor="middle">onderlaag</text><defs><marker id="mwBa" markerWidth="9" markerHeight="9" refX="5" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L7,3 L0,6 Z" fill="var(--dk)"/></marker></defs><line x1="265" y1="145" x2="265" y2="45" stroke="var(--dk)" stroke-width="1.6" stroke-dasharray="4 3" marker-end="url(#mwBa)"/><text x="272" y="100" font-size="7.5" fill="var(--mu)" transform="rotate(90,272,100)">mobiliteit</text></svg><div class="sam-figcap"><strong>Sociale stratificatie:</strong> de samenleving als piramide met een kleine bovenlaag en brede onderlaag. Via sociale mobiliteit kunnen mensen tussen de lagen bewegen.</div></div><div class="sam-head">Verzorgingsstaat en samenleving</div><p>De <strong>verzorgingsstaat</strong> beschermt burgers tegen risico's (ziekte, werkloosheid, ouderdom) via collectieve voorzieningen.</p><div class="sam-compare"><div class="sam-compare-col"><div class="sam-compare-head">Voordelen</div><ul><li>bestaanszekerheid</li><li>minder ongelijkheid</li><li>sociale samenhang</li></ul></div><div class="sam-compare-col"><div class="sam-compare-head">Nadelen</div><ul><li>hoge kosten/belastingen</li><li>risico op afhankelijkheid</li><li>vergrijzing zet druk</li></ul></div></div><div class="sam-head">Deviantie</div><p><strong>Deviant</strong> gedrag wijkt af van de norm; als het strafbaar is, heet het <strong>criminaliteit</strong>. <strong>Stereotypering</strong> en <strong>discriminatie</strong> ontstaan wanneer groepen op basis van kenmerken ongelijk worden behandeld.</p><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave</div><div class="sam-worked-q">Geef een voorbeeld van primaire en van secundaire socialisatie.</div><ol class="sam-worked-steps"><li>Primair: je ouders leren je 'dank je wel' zeggen (in het gezin).</li><li>Secundair: op school leer je op je beurt wachten en samenwerken.</li></ol><div class="sam-worked-ans">✅ Primair = gezin (eerste jaren), secundair = school/media/werk (later).</div></div></div>`,
'vwo_mw_C':`<div class="sam-intro">Domein A gaat over <strong>politiek en democratie</strong>: hoe <strong>macht</strong> wordt verdeeld en gelegitimeerd, hoe <strong>partijen</strong> en <strong>ideologieën</strong> verschillen, en hoe het Nederlandse <strong>kiesstelsel</strong> tot coalities leidt.</div><div class="sam-head">Democratie en macht</div><p>In een <strong>democratie</strong> ligt de macht bij het volk. Bij een <strong>directe</strong> democratie stemt iedereen zelf; bij een <strong>representatieve</strong> democratie kiezen burgers vertegenwoordigers. Macht is pas stabiel als ze <strong>legitiem</strong> is: als burgers het gezag als rechtvaardig aanvaarden.</p><div class="sam-head">Trias politica</div><p>Om machtsmisbruik te voorkomen wordt de macht gescheiden in drie onafhankelijke delen die elkaar <strong>controleren</strong> (checks and balances).</p><div class="sam-figure"><svg viewBox="0 0 320 130" role="img" aria-label="De trias politica met de wetgevende, uitvoerende en rechterlijke macht die elkaar controleren"><defs><marker id="mwAa" markerWidth="8" markerHeight="8" refX="4" refY="3" orient="auto" markerUnits="userSpaceOnUse"><path d="M0,0 L6,3 L0,6 Z" fill="var(--mu)"/></marker></defs><rect x="12" y="40" width="90" height="50" rx="6" fill="var(--or)" opacity=".14" stroke="var(--or)" stroke-width="1.4"/><text x="57" y="60" font-size="9.5" font-weight="700" fill="var(--dk)" text-anchor="middle">Wetgevend</text><text x="57" y="74" font-size="7.5" fill="var(--mu)" text-anchor="middle">parlement</text><rect x="115" y="40" width="90" height="50" rx="6" fill="var(--or)" opacity=".14" stroke="var(--or)" stroke-width="1.4"/><text x="160" y="60" font-size="9.5" font-weight="700" fill="var(--dk)" text-anchor="middle">Uitvoerend</text><text x="160" y="74" font-size="7.5" fill="var(--mu)" text-anchor="middle">regering</text><rect x="218" y="40" width="90" height="50" rx="6" fill="var(--or)" opacity=".14" stroke="var(--or)" stroke-width="1.4"/><text x="263" y="60" font-size="9.5" font-weight="700" fill="var(--dk)" text-anchor="middle">Rechterlijk</text><text x="263" y="74" font-size="7.5" fill="var(--mu)" text-anchor="middle">rechters</text><line x1="104" y1="58" x2="113" y2="58" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#mwAa)"/><line x1="113" y1="72" x2="104" y2="72" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#mwAa)"/><line x1="207" y1="58" x2="216" y2="58" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#mwAa)"/><line x1="216" y1="72" x2="207" y2="72" stroke="var(--mu)" stroke-width="1.4" marker-end="url(#mwAa)"/><text x="160" y="24" font-size="9" font-weight="700" fill="var(--mu)" text-anchor="middle">scheiding der machten</text></svg><div class="sam-figcap"><strong>Trias politica:</strong> de wetgevende (parlement), uitvoerende (regering) en rechterlijke macht (rechters) zijn gescheiden en houden elkaar in evenwicht.</div></div><div class="sam-head">Partijen en ideologieën</div><p>Politieke partijen verschillen langs een <strong>links–rechts</strong>-as (rol van de overheid in de economie) en een <strong>progressief–conservatief</strong>-as (omgang met tradities).</p><table class="sam-table"><thead><tr><th>Stroming</th><th>Kernidee</th></tr></thead><tbody><tr><td>Socialisme (links)</td><td>gelijkheid, sterke overheid</td></tr><tr><td>Liberalisme (rechts)</td><td>vrijheid, vrije markt</td></tr><tr><td>Christendemocratie</td><td>gemeenschap, rentmeesterschap</td></tr></tbody></table><div class="sam-head">Kiesstelsel en coalities</div><p>Nederland kent <strong>evenredige vertegenwoordiging</strong>: het aandeel stemmen bepaalt het aantal zetels. Omdat geen partij een meerderheid haalt, is een <strong>coalitie</strong> nodig.</p><div class="sam-tip">Evenredige vertegenwoordiging geeft veel partijen een stem (representatief), maar maakt kabinetsvorming complex — een <strong>districtenstelsel</strong> geeft juist stabielere meerderheden maar minder evenredigheid.</div><div class="sam-worked"><div class="sam-worked-h">✍️ Voorbeeldopgave</div><div class="sam-worked-q">Waarom is machtenscheiding belangrijk in een rechtsstaat?</div><ol class="sam-worked-steps"><li>Als één orgaan alle macht heeft, kan het die misbruiken.</li><li>Door scheiding controleren de machten elkaar (checks and balances).</li></ol><div class="sam-worked-ans">✅ De trias politica beschermt burgers tegen willekeur en machtsmisbruik.</div></div></div>`,
});
